34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;0&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;单个聚合数据的子配置大小上限，单位为字节，0表示使用默认值&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`max_history_count`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;unsigned&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;0&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;最大变更历史数量&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`gmt_create`&lt;/span&gt; datetime &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;2010-05-05 00:00:00&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;创建时间&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`gmt_modified`&lt;/span&gt; datetime &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;2010-05-05 00:00:00&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;修改时间&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  PRIMARY &lt;span class=&#34;keyword&#34;&gt;KEY&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;`id`&lt;/span&gt;),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;UNIQUE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;KEY&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;`uk_tenant_id`&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;`tenant_id`&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;) &lt;span class=&#34;keyword&#34;&gt;ENGINE&lt;/span&gt;=&lt;span class=&#34;keyword&#34;&gt;InnoDB&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;CHARSET&lt;/span&gt;=utf8 &lt;span class=&#34;keyword&#34;&gt;COLLATE&lt;/span&gt;=utf8_bin &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;租户容量信息表&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;CREATE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;TABLE&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;`tenant_info`&lt;/span&gt; (&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`id`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;bigint&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;20&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; AUTO_INCREMENT &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;id&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`kp`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;kp&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`tenant_id`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;default&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;tenant_id&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`tenant_name`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;default&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#x27;&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;tenant_name&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`tenant_desc`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;256&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;tenant_desc&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`create_source`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;32&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;create_source&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`gmt_create`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;bigint&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;20&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;创建时间&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;`gmt_modified`&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;bigint&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;20&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;修改时间&amp;#x27;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  PRIMARY &lt;span class=&#34;keyword&#34;&gt;KEY&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;`id`&lt;/span&gt;),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;UNIQUE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;KEY&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;`uk_tenant_info_kptenantid`&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;`kp`&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;`tenant_id`&lt;/span&gt;),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;KEY&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;`idx_tenant_id`&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;`tenant_id`&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;) &lt;span class=&#34;keyword&#34;&gt;ENGINE&lt;/span&gt;=&lt;span class=&#34;keyword&#34;&gt;InnoDB&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;DEFAULT&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;CHARSET&lt;/span&gt;=utf8 &lt;span class=&#34;keyword&#34;&gt;COLLATE&lt;/span&gt;=utf8_bin &lt;span class=&#34;keyword&#34;&gt;COMMENT&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;tenant_info&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;CREATE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;TABLE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;users&lt;/span&gt; (&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	username &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt; PRIMARY &lt;span class=&#34;keyword&#34;&gt;KEY&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;password&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;500&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	enabled &lt;span class=&#34;built_in&#34;&gt;boolean&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;CREATE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;TABLE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;roles&lt;/span&gt; (&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	username &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;role&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;constraint&lt;/span&gt; uk_username_role &lt;span class=&#34;keyword&#34;&gt;UNIQUE&lt;/span&gt; (username,&lt;span class=&#34;keyword&#34;&gt;role&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;CREATE&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;TABLE&lt;/span&gt; permissions (&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;role&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;resource&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;512&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;action&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;varchar&lt;/span&gt;(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;NOT&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;constraint&lt;/span&gt; uk_role_permission &lt;span class=&#34;keyword&#34;&gt;UNIQUE&lt;/span&gt; (&lt;span class=&#34;keyword&#34;&gt;role&lt;/span&gt;,&lt;span class=&#34;keyword&#34;&gt;resource&lt;/span&gt;,&lt;span class=&#34;keyword&#34;&gt;action&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;INSERT&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;INTO&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;users&lt;/span&gt; (username, &lt;span class=&#34;keyword&#34;&gt;password&lt;/span&gt;, enabled) &lt;span class=&#34;keyword&#34;&gt;VALUES&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;nacos&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;$2a$10$EuWPZHzz32dJN7jexM34MOeYirDdFAZm2kuWj7VEOJhhZkDrxfvUu&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;literal&#34;&gt;TRUE&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;INSERT&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;INTO&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;roles&lt;/span&gt; (username, &lt;span class=&#34;keyword&#34;&gt;role&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;VALUES&lt;/span&gt; (&lt;span class=&#34;string&#34;&gt;&amp;#x27;nacos&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;ROLE_ADMIN&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;修改配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#修改配置&#34;&gt;#&lt;/a&gt; 修改配置&lt;/h4&gt;
&lt;p&gt;application.properties 内容替换为&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;spring&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.contextPath=/nacos&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.servlet.contextPath=/nacos&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.port=8848&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;management.metrics.export.elastic.enabled=false&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;management.metrics.export.influx.enabled=false&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.tomcat.accesslog.enabled=true&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.tomcat.accesslog.pattern=%h %l %u %t &amp;quot;%r&amp;quot; %s %b %D %&amp;#123;User-Agent&amp;#125;i&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.tomcat.basedir=&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;nacos.security.ignore.urls=/,/**/*.css,/**/*.js,/**/*.html,/**/*.map,/**/*.svg,/**/*.png,/**/*.ico,/console-fe/public/**,/v1/auth/login,/v1/console/health/**,/v1/cs/**,/v1/ns/**,/v1/cmdb/**,/actuator/**,/v1/console/server/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;spring.datasource.platform=mysql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db.num=1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db.url.0=jdbc:mysql://&amp;lt;ip&amp;gt;:&amp;lt;port&amp;gt;/nacos?characterEncoding=utf8&amp;amp;connectTimeout=1000&amp;amp;socketTimeout=3000&amp;amp;autoReconnect=true&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db.user=root&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;db.password=password&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;Windows 任务管理器进程中，可以查看到我们电脑运行了那些程序，有时候电脑莫名其妙很卡的时候，查看进程的时候，会发现多了很多一样名称的进程让电脑很卡，如果一个个结束，效率低不说，还麻烦，今天给大家带来的批量结束进程的方法。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;操作一：打开 Windows 任务管理器的方法有，按 Ctrl+shift+Esc 组合键，或右键点击任务栏空白处，在打开的菜单项中，选择启动任务管理器；&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://exp-picture.cdn.bcebos.com/19587f20a7cd0c6ebdd4f107fed7997bbaf4ddbe.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; alt=&#34;Cmd批量结束所有进程命令kill使用方法&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://exp-picture.cdn.bcebos.com/19587f20a7cd0c6ebdd4f107fed7997bbaf4ddbe.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;操作二：Windows 任务管理器中，可以在进程选项卡下，找到需要批量结束的进程，比如这里红色框标记的 notepad.exe 记事本进程；&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://exp-picture.cdn.bcebos.com/0fb94656d53da82480cf3f66306651598440cbbe.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; alt=&#34;Cmd批量结束所有进程命令kill使用方法&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://exp-picture.cdn.bcebos.com/0fb94656d53da82480cf3f66306651598440cbbe.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;操作三：既然知道需要结束那个进程，那就按 Win + R 组合键，打开运行，并输入：cmd 命令，确定或回车，可以快速打开命令提示符窗口；&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://exp-picture.cdn.bcebos.com/a151a233ec3834bb7fc951eb8714c27bd3823dbf.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; alt=&#34;Cmd批量结束所有进程命令kill使用方法&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://exp-picture.cdn.bcebos.com/a151a233ec3834bb7fc951eb8714c27bd3823dbf.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;操作四：命令提示符窗口中，输入：taskkill /f/im notepad.exe 命令，然后按回车执行命令，其中 notepad.exe 是你要批量结束的进程，这里千万不要搞错；&lt;/p&gt;
   &lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;taskkill /f /im notepad.exe&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 支持通配符&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;taskkill /f /im WPS*&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;https://exp-picture.cdn.bcebos.com/7efc527c34b33c41409c20f5887de137c8762ebf.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; alt=&#34;Cmd批量结束所有进程命令kill使用方法&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://exp-picture.cdn.bcebos.com/7efc527c34b33c41409c20f5887de137c8762ebf.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;操作五：回车执行 taskkill /f/im notepad.exe 命令，成功的话，会提示成功：已终止进程，还有 PID 为多少那样；&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://exp-picture.cdn.bcebos.com/04d7a614f4d0b50349f4b54acc4ec28332bf20bf.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; alt=&#34;Cmd批量结束所有进程命令kill使用方法&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://exp-picture.cdn.bcebos.com/04d7a614f4d0b50349f4b54acc4ec28332bf20bf.jpg?x-bce-process=image%2Fresize%2Cm_lfit%2Cw_500%2Climit_1%2Fformat%2Cf_jpg%2Fquality%2Cq_80&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;操作六：最后，再打开 Windows 任务管理器，按进程选项卡，可以发现刚才的 notepad.exe 记事本进程已经被结束；&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/fb738d9c2cf7dfb24c3f3d98d01b1edef5dc13bf.jpg&#34; alt=&#34;Cmd批量结束所有进程命令kill使用方法&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/fb738d9c2cf7dfb24c3f3d98d01b1edef5dc13bf.jpg&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;&lt;strong&gt;第三方 jar 包在开发工具中引入后编译没问题，启动调试包括打包时会提示找不到 jar 包的错误。需要上传到 maven 仓库中，并在 pom 文件内引入.&lt;/strong&gt;&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;maven 命令:&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;安装指定文件到本地仓库命令：mvn install:install-file&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-DgroupId&amp;#x3D;&amp;lt;groupId&amp;gt;       : 设置上传到仓库的包名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-DartifactId&amp;#x3D;&amp;lt;artifactId&amp;gt; : 设置该包所属的模块名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-Dversion&amp;#x3D;1.0.0           : 设置该包的版本号&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-Dpackaging&amp;#x3D;jar           : 设置该包的类型(很显然jar包)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-Dfile&amp;#x3D;&amp;lt;myfile.jar&amp;gt;       : 设置该jar包文件所在的路径与文件名&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;一。上传 jar 包 win+r cmd 打开命令行输入以下命令:&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mvn install:install-file -DgroupId&amp;#x3D;com.zebra -DartifactId&amp;#x3D;ZSDK_API -Dversion&amp;#x3D;v2.12.3782 -Dpackaging&amp;#x3D;jar -Dfile&amp;#x3D;E:\perslib\ZSDK_API.jar&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mvn install:install-file -DgroupId&amp;#x3D;com.zebra -DartifactId&amp;#x3D;ZSDK_CARD_API -Dversion&amp;#x3D;v2.12.3782 -Dpackaging&amp;#x3D;jar -Dfile&amp;#x3D;E:\perslib\ZSDK_CARD_API.jar&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mvn install:install-file -DgroupId&amp;#x3D;com.jacob -DartifactId&amp;#x3D;jacob -Dversion&amp;#x3D;1.19 -Dpackaging&amp;#x3D;jar -Dfile&amp;#x3D;jacob.jar&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;出现以下 success 说明成功了.&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2018.cnblogs.com/blog/917633/201810/917633-20181022135853625-157850255.png&#34;&gt;&lt;img src=&#34;/img/917633-20181022135853625-157850255.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/917633-20181022135853625-157850255.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;到 maven 仓库查看:&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://img2018.cnblogs.com/blog/917633/201810/917633-20181022141949167-1559238206.png&#34;&gt;&lt;img src=&#34;/img/917633-20181022141949167-1559238206.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/917633-20181022141949167-1559238206.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;二。在 pom 文件中引入 jar 包&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;groupId&amp;gt;com.zebra&amp;lt;&amp;#x2F;groupId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;artifactId&amp;gt;ZSDK_API&amp;lt;&amp;#x2F;artifactId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;version&amp;gt;v2.12.3782&amp;lt;&amp;#x2F;version&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;&amp;#x2F;dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;groupId&amp;gt;com.zebra&amp;lt;&amp;#x2F;groupId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;artifactId&amp;gt;ZSDK_CARD_API&amp;lt;&amp;#x2F;artifactId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;version&amp;gt;v2.12.3782&amp;lt;&amp;#x2F;version&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;&amp;#x2F;dependency&amp;gt; &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;注意:&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;jar 包所在路径不要带中文，不要带中文，不要带中文！&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;另外，不通过这种方式直接放在项目目录下，通过 pom 引用不导入 maven 仓库也是可以的。如下图:&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;a href=&#34;https://img2020.cnblogs.com/blog/917633/202010/917633-20201027224436808-358780583.png&#34;&gt;&lt;img src=&#34;/img/917633-20201027224436808-358780583.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/917633-20201027224436808-358780583.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/a&gt;&lt;/strong&gt;&lt;/p&gt;

 &lt;p&gt;docker - 修改容器的挂载目录三种方式&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;方式一修改配置文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方式一修改配置文件&#34;&gt;#&lt;/a&gt; 方式一：修改配置文件&lt;/h3&gt;
&lt;p&gt;（需停止 docker 服务）&lt;br&gt;
1、停止 docker 服务&lt;br&gt;
 systemctl stop docker.service（关键，修改之前必须停止 docker 服务）&lt;br&gt;
2、vim /var/lib/docker/containers/container-ID/config.v2.json&lt;br&gt;
 修改配置文件中的目录位置，然后保存退出&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;quot;MountPoints&amp;quot;:&amp;#123;&amp;quot;/home&amp;quot;:&amp;#123;&amp;quot;Source&amp;quot;:&amp;quot;/docker&amp;quot;,&amp;quot;Destination&amp;quot;:&amp;quot;/home&amp;quot;,&amp;quot;RW&amp;quot;:true,&amp;quot;Name&amp;quot;:&amp;quot;&amp;quot;,&amp;quot;Driver&amp;quot;:&amp;quot;&amp;quot;,&amp;quot;Type&amp;quot;:&amp;quot;bind&amp;quot;,&amp;quot;Propagation&amp;quot;:&amp;quot;rprivate&amp;quot;,&amp;quot;Spec&amp;quot;:&amp;#123;&amp;quot;Type&amp;quot;:&amp;quot;bind&amp;quot;,&amp;quot;Source&amp;quot;:&amp;quot;//docker/&amp;quot;,&amp;quot;Target&amp;quot;:&amp;quot;/home&amp;quot;&amp;#125;&amp;#125;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3、启动 docker 服务&lt;br&gt;
 systemctl start docker.service&lt;br&gt;
4、启动 docker 容器&lt;br&gt;
 docker start &amp;lt;container-name/ID&amp;gt;&lt;/p&gt;
&lt;h3 id=&#34;方式二提交现有容器为新镜像然后重新运行它&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方式二提交现有容器为新镜像然后重新运行它&#34;&gt;#&lt;/a&gt; 方式二：提交现有容器为新镜像，然后重新运行它&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;$&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; docker ps  -a&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;CONTAINER ID        IMAGE                 COMMAND                  CREATED              STATUS                          PORTS               NAMES&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   5a3422adeead        ubuntu:14.04          &amp;quot;/bin/bash&amp;quot;              About a minute ago   Exited (0) About a minute ago                       agitated_newton&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;$&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; docker commit 5a3422adeead newimagename&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;$&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; docker run -ti -v &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$PWD&lt;/span&gt;/dir1&amp;quot;&lt;/span&gt;:/dir1 -v &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$PWD&lt;/span&gt;/dir2&amp;quot;&lt;/span&gt;:/dir2 newimagename /bin/bash&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后停止旧容器，并使用这个新容器，如果由于某种原因需要新容器使用旧名称，请在删除旧容器后使用 docker rename。&lt;/p&gt;
&lt;h3 id=&#34;方式三export容器为镜像然后import为新镜像&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方式三export容器为镜像然后import为新镜像&#34;&gt;#&lt;/a&gt; 方式三：export 容器为镜像，然后 import 为新镜像&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;$&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;docker container &lt;span class=&#34;built_in&#34;&gt;export&lt;/span&gt; -o ./myimage.docker 容器ID&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;$&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;docker import ./myimage.docker newimagename&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;$&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;docker run -ti -v &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$PWD&lt;/span&gt;/dir1&amp;quot;&lt;/span&gt;:/dir1 -v &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$PWD&lt;/span&gt;/dir2&amp;quot;&lt;/span&gt;:/dir2 newimagename /bin/bash&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后停止旧容器，并使用这个新容器，如果由于某种原因需要新容器使用旧名称，请在删除旧容器后使用 docker rename。&lt;/p&gt;

 &lt;p&gt;在使用案例云或其他厂商的云服务器时遇到的 80 端口被占用问题，如何释放 80 端口？问题主要出现在 Windows Server 服务器上，Linux 服务器上暂且还没有遇到类似情况。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;问题：80 端口被占用？如何释放 80 端口&lt;br&gt;
第一步、win+r 输入 cmd&lt;br&gt;
 第二步、在控制台输入 &lt;code&gt;netstat -aon | findstr&lt;/code&gt;  &amp;quot;80&amp;quot; 命令。找出类型为 TCP 端口 80 的，然后记录 PID (最后一行为 PID) 如下图&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20200307110151419.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20200307110151419.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;第三步、在控制台输入 &lt;code&gt;tasklist | findstr&lt;/code&gt;  “PID 数值”&lt;br&gt;
 第四步、打开任务管理器，查看 PID=4 是一个 system 进程，其对应的进程描述是 NT kernel &amp;amp; system。&lt;br&gt;
第五步、win+r 输入 &lt;code&gt;regedit&lt;/code&gt;  回车，找到 &lt;code&gt;HKEY_LOCAL_MACHINE\SYSTEM\CurrentControlSet\Services\HTTP&lt;/code&gt; ，并修改&lt;br&gt;
 Start 的数值数据为 4.（如下图）&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20200307110236185.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20200307110236185.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;第六步、修改注册表后要重启电脑才会生效&lt;/p&gt;

 &lt;p&gt;idea 利用 docker 插件打包上传镜像 &lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;1idea环境准备&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1idea环境准备&#34;&gt;#&lt;/a&gt; 1：idea 环境准备&lt;/h2&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;点击 file&amp;gt;settings&amp;gt;plugins&amp;gt;搜索docker下载  如下图&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210122095457335.png&#34; alt=&#34;image-20210122095457335&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122095457335.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;2docker服务环境准备&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2docker服务环境准备&#34;&gt;#&lt;/a&gt; 2：docker 服务环境准备&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;正常安装 docker 环境&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;第一步：配置 Docker，开启远程访问（注：仅供学习参考，实际生产环境万万不可，会产生很大的安全风险），默认端口是 2375，也可以修改为其他端口&lt;/p&gt;
&lt;p&gt;1、修改 /lib/systemd/system/docker.service 文件&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;vim /lib/systemd/system/docker.service&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;在 &lt;code&gt;ExecStart&lt;/code&gt;  后面追加  &lt;code&gt;-H tcp://0.0.0.0:2375 -H unix://var/run/docker.sock&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210122095822612.png&#34; alt=&#34;image-20210122095822612&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122095822612.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;修改完保存退出命令 :wq&lt;/p&gt;
&lt;p&gt;2、重新加载配置文件，重启 docker，使得刚才的配置生效&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;重新加载配置文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl daemon-reload&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;重启docker服务&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl restart docker&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3、使用 curl 命令检查是否开启&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;curl下载docker的服务信息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;curl http://127.0.0.1:2375/info&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;如果有返回说明，就证明开启成功了，可以看到我的 Docker 版本，镜像加速器地址等其他信息，但是这时候远程可能依然访问不了&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210122095914492.png&#34; alt=&#34;image-20210122095914492&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122095914492.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;开放端口后，可以远程访问，直接在服务器中也可以验证&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210122100013090.png&#34; alt=&#34;image-20210122100013090&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122100013090.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;3idea远程连接docker&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3idea远程连接docker&#34;&gt;#&lt;/a&gt; 3：idea 远程连接 docker&lt;/h2&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;点击 file&amp;gt;settings&amp;gt;docker  如下图&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;注意我所标记的地方，地址填写 docker 访问地址，端口 2375 为固定的，记得服务器需要开放端口，不然连接不上。&lt;br&gt;
连接成功下面会显示：Connection successful； 表示连接成功&lt;br&gt;
&lt;img src=&#34;/img/image-20210122100131336.png&#34; alt=&#34;image-20210122100131336&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122100131336.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;连接成功后 idea 下方会有一个 docker 窗口，可以镜像和容器进行操作，如下图&lt;br&gt;
&lt;img src=&#34;/img/image-20210122100155280.png&#34; alt=&#34;image-20210122100155280&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122100155280.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
&lt;strong&gt; 以上表示 idea 已经远程成功连接 docker&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;4利用idea远程发布springboot项目&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4利用idea远程发布springboot项目&#34;&gt;#&lt;/a&gt; 4：利用 idea 远程发布 springboot 项目&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;1：新建 Dockerfile 文件，注意文件位置，和文件名称一定不能搞错，文件在项目的根目录下，与 src 同级&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;配置文件可以在打包时指定位置&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Dokcerfile 文件内容&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#打包需要用到的jdk&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;FROM openjdk:&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;-jdk-alpine&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#前面是idea打包的jar包路径，路径不能错，  后面是 添加到docker的jar包名称，可自定义&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ADD /target/eureka-server1-&lt;span class=&#34;number&#34;&gt;0.0&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;-SNAPSHOT.jar eureka-server1-&lt;span class=&#34;number&#34;&gt;0.0&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;-SNAPSHOT.jar&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#容器的端口映射&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;EXPOSE &lt;span class=&#34;number&#34;&gt;10001&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;10001&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#运行jar命令&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ENTRYPOINT [&lt;span class=&#34;string&#34;&gt;&amp;quot;java&amp;quot;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;-jar&amp;quot;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;/eureka-server1-0.0.1-SNAPSHOT.jar&amp;quot;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;Dockerfile 文件位置&lt;/strong&gt;&lt;br&gt;
&lt;img src=&#34;/img/image-20210122100252540.png&#34; alt=&#34;image-20210122100252540&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122100252540.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;2：项目添加 docker 运行并上传&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;2.1：首先点击下图1下拉选择 Edit Configurations&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2.2：点击如下图2位置的加号。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;3：dockeer 参数设置&lt;/strong&gt;&lt;br&gt;
&lt;img src=&#34;/img/image-20210122100515829.png&#34; alt=&#34;image-20210122100515829&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122100515829.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;4：直接运行 dockerfile 配置自动上传&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210122100642183.png&#34; alt=&#34;image-20210122100642183&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122100642183.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;Netty 是 &lt;em&gt;一个异步事件驱动的网络应用程序框架，&lt;/em&gt;&lt;br&gt;
用于快速开发可维护的高性能协议服务器和客户端。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;1-官网简介&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-官网简介&#34;&gt;#&lt;/a&gt; 1、官网简介&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210119090534513.png&#34; alt=&#34;image-20210119090534513&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210119090534513.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;Netty 是一个 NIO 客户端服务器框架，可快速轻松地开发网络应用程序，例如协议服务器和客户端。它极大地简化和简化了网络编程，例如 TCP 和 UDP 套接字服务器。Netty 对 JDK 自带的 NIO 的 API 进行了良好的封装，解决了 NIO 的类库和 API 繁杂， 使用麻烦： 需要熟练掌握 Selector、 ServerSocketChannel、 SocketChannel、 ByteBuffer 等。 。且 Netty 拥有高性能、 吞吐量更高，延迟更低，减少资源消耗，最小化不必要的内存复制等优点。&lt;/p&gt;
&lt;p&gt;“快速简便” 并不意味着最终的应用程序将遭受可维护性或性能问题的困扰。Netty 经过精心设计，结合了许多协议（例如 FTP，SMTP，HTTP 以及各种基于二进制和文本的旧式协议）的实施经验。结果，Netty 成功地找到了一种无需妥协即可轻松实现开发，性能，稳定性和灵活性的方法。&lt;/p&gt;
&lt;p&gt;官网地址：&lt;a href=&#34;https://netty.io/&#34;&gt;https://netty.io/&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;设计&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#设计&#34;&gt;#&lt;/a&gt; 设计&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;适用于各种传输类型的统一 API - 阻塞和非阻塞套接字&lt;/li&gt;
&lt;li&gt;基于灵活且可扩展的事件模型，可将关注点明确分离&lt;/li&gt;
&lt;li&gt;高度可定制的线程模型 - 单线程，一个或多个线程池，例如 SEDA&lt;/li&gt;
&lt;li&gt;真正的无连接数据报套接字支持（从 3.1 开始）&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;性能&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#性能&#34;&gt;#&lt;/a&gt; 性能&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;更高的吞吐量，更低的延迟&lt;/li&gt;
&lt;li&gt;减少资源消耗&lt;/li&gt;
&lt;li&gt;减少不必要的内存复制&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;安全&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安全&#34;&gt;#&lt;/a&gt; 安全&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;完整的 SSL / TLS 和 StartTLS 支持&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;2-netty使用场景&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-netty使用场景&#34;&gt;#&lt;/a&gt; 2、Netty 使用场景&lt;/h2&gt;
&lt;h3 id=&#34;互联网行业&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#互联网行业&#34;&gt;#&lt;/a&gt; 互联网行业&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;互联网行业：在分布式系统中，各个节点之间需要远程服务调用，高性能的 RPC 框架必不可少，Netty 作为 异步高性能的通信框架，往往作为基础通信组件被这些 RPC 框架使用。&lt;/li&gt;
&lt;li&gt;典型的应用有：阿里分布式服务框架 Dubbo 的 RPC 框架使用 Dubbo 协议进行节点间通信，Dubbo 协议默 认使用 Netty 作为基础通信组件，用于实现各进程节点之间的内部通信&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;游戏行业&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#游戏行业&#34;&gt;#&lt;/a&gt; 游戏行业&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;无论是手游服务端还是大型的网络游戏，Java 语言得到了越来越广泛的应用&lt;/li&gt;
&lt;li&gt;Netty 作为高性能的基础通信组件，提供了 TCP/UDP 和 HTTP 协议栈，方便定制和开发私有协议栈，账号登 录服务器&lt;/li&gt;
&lt;li&gt;地图服务器之间可以方便的通过 Netty 进行高性能的通信&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;大数据领域&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#大数据领域&#34;&gt;#&lt;/a&gt; 大数据领域&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;经典的 Hadoop 的高性能通信和序列化组件 Avro 的 RPC 框架，默认采用 Netty 进行跨界点通信&lt;/li&gt;
&lt;li&gt;它的 Netty Service 基于 Netty 框架二次封装实现。&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;其它开源项目使用到-netty&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#其它开源项目使用到-netty&#34;&gt;#&lt;/a&gt; 其它开源项目使用到 Netty&lt;/h3&gt;
&lt;p&gt;网址: [&lt;a href=&#34;https://netty.io/wiki/related-projects.html&#34;&gt;https://netty.io/wiki/related-projects.html&lt;/a&gt;]&lt;/p&gt;
&lt;h2 id=&#34;3-基于netty的通信demo&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-基于netty的通信demo&#34;&gt;#&lt;/a&gt; 3、基于 Netty 的通信 Demo&lt;/h2&gt;
&lt;h3 id=&#34;1-添加maven依赖&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-添加maven依赖&#34;&gt;#&lt;/a&gt; 1. 添加 Maven 依赖&lt;/h3&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;io.netty&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;netty-all&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;4.1.35.Final&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-服务端&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-服务端&#34;&gt;#&lt;/a&gt; 2. 服务端&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// ----------NettyServer----------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String[] args)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//创建两个线程组bossGroup和workerGroup&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// bossGroup 接收连接请求 （如果该线程采用多个，需要分别绑定不同的端口）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// workerGroup 处理具体的业务逻辑&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    EventLoopGroup bossGroup = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; NioEventLoopGroup(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    EventLoopGroup workerGroup = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; NioEventLoopGroup(&lt;span class=&#34;number&#34;&gt;100000&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//服务器端启动对象&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ServerBootstrap bootstrap = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ServerBootstrap();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bootstrap.group(bossGroup, workerGroup)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// ......&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        	&lt;span class=&#34;comment&#34;&gt;//通过链式调用，设置两个线程组，配置参数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//启动服务器(并绑定端口)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ChannelFuture cf = bootstrap.bind(&lt;span class=&#34;number&#34;&gt;9000&lt;/span&gt;).sync();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 通过sync方法同步等待通道关闭处理完毕，方法会阻塞，直至通道关闭&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cf.channel().closeFuture().sync();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;finally&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bossGroup.shutdownGracefully();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        workerGroup.shutdownGracefully();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// ----------服务器启动对象设置----------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bootstrap.group(bossGroup, workerGroup)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 服务器的通道实现&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .channel(NioServerSocketChannel.class)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 初始化服务器连接队列大小&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .option(ChannelOption.SO_BACKLOG, &lt;span class=&#34;number&#34;&gt;1024&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 创建通道初始化对象，设置初始化参数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .childHandler(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ChannelInitializer&amp;lt;SocketChannel&amp;gt;() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;initChannel&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(SocketChannel ch)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//对workerGroup的SocketChannel设置处理器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            ch.pipeline().addLast(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; NettyServerHandler());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// ----------设置处理器----------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 需要继承netty规定好的某个HandlerAdapter(规范)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;NettyServerHandler&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ChannelInboundHandlerAdapter&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * 读取客户端发送的数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@param&lt;/span&gt; ctx 上下文对象, 含有通道channel，管道pipeline&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@param&lt;/span&gt; msg 就是客户端发送的数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;channelRead&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(ChannelHandlerContext ctx, Object msg)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ByteBuf buf = (ByteBuf) msg;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;客户端发送消息是:&amp;quot;&lt;/span&gt; + buf.toString(CharsetUtil.UTF_8));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 数据读取完毕处理方法&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;channelReadComplete&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(ChannelHandlerContext ctx)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ByteBuf buf = Unpooled.copiedBuffer(&lt;span class=&#34;string&#34;&gt;&amp;quot;HelloClient&amp;quot;&lt;/span&gt;.getBytes(CharsetUtil.UTF_8));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ctx.writeAndFlush(buf);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 处理异常, 关闭通道&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;exceptionCaught&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(ChannelHandlerContext ctx, Throwable cause)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ctx.close();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;3-服务端简单总结&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-服务端简单总结&#34;&gt;#&lt;/a&gt; 3. 服务端简单总结&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;初始化两个线程组，一个负责处理连接，一个负责同客户端联系处理业务&lt;/li&gt;
&lt;li&gt;创建一个启动对象&lt;/li&gt;
&lt;li&gt;将两个线程组同启动对象设置关联关系
&lt;ul&gt;
&lt;li&gt;启动对象设置时需要设置自定义处理器对象&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;给启动对象绑定端口，并启动&lt;/li&gt;
&lt;li&gt;对通道关闭进行监听，同步等待关闭&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;4-客户端&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-客户端&#34;&gt;#&lt;/a&gt; 4. 客户端&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// ----------客户端主启动方法----------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String[] args)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//客户端需要一个事件循环组&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    EventLoopGroup group = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; NioEventLoopGroup();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//创建客户端启动对象&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Bootstrap bootstrap = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Bootstrap();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//设置相关参数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bootstrap.group(group)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// ......  同服务端一样，链式调用设置参数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//启动客户端去连接服务器端&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ChannelFuture channelFuture = bootstrap.connect(&lt;span class=&#34;string&#34;&gt;&amp;quot;127.0.0.1&amp;quot;&lt;/span&gt;, &lt;span class=&#34;number&#34;&gt;9000&lt;/span&gt;).sync();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//对关闭通道进行监听&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        channelFuture.channel().closeFuture().sync();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;finally&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        group.shutdownGracefully();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// ----------客户端启动器参数设置----------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bootstrap.group(group) &lt;span class=&#34;comment&#34;&gt;//设置线程组&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .channel(NioSocketChannel.class) // 使用NioSocketChannel作为客户端的通道实现&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    .handler(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ChannelInitializer&amp;lt;SocketChannel&amp;gt;() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;initChannel&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(SocketChannel ch)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//加入处理器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            ch.pipeline().addLast(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; NettyClientHandler());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// ----------客户端处理器----------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 同服务端一致，需要继承Netty规定好的某个HandlerAdapter(规范)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;NettyClientHandler&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ChannelInboundHandlerAdapter&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 客户端连接服务器完成触发该方法&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;channelActive&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(ChannelHandlerContext ctx)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ByteBuf buf = Unpooled.copiedBuffer(&lt;span class=&#34;string&#34;&gt;&amp;quot;HelloServer&amp;quot;&lt;/span&gt;.getBytes(CharsetUtil.UTF_8));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ctx.writeAndFlush(buf);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//当通道有读取事件时会触发，即服务端发送数据给客户端&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;channelRead&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(ChannelHandlerContext ctx, Object msg)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ByteBuf buf = (ByteBuf) msg;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;收到服务端的消息:&amp;quot;&lt;/span&gt; + buf.toString(CharsetUtil.UTF_8));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 处理异常, 关闭通道&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;exceptionCaught&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(ChannelHandlerContext ctx, Throwable cause)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; Exception &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cause.printStackTrace();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ctx.close();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;5-客户端简单总结&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5-客户端简单总结&#34;&gt;#&lt;/a&gt; 5.  客户端简单总结&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;初始化一个事件循环组&lt;/li&gt;
&lt;li&gt;创建一个启动对象&lt;/li&gt;
&lt;li&gt;设置启动对象参数
&lt;ul&gt;
&lt;li&gt;启动对象设置时需要设置自定义处理器对象&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;给启动对象绑定服务端&lt;/li&gt;
&lt;li&gt;对通道关闭进行监听，同步等待关闭&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;6-服务端和客户端概要&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6-服务端和客户端概要&#34;&gt;#&lt;/a&gt; 6. 服务端和客户端概要&lt;/h3&gt;
&lt;p&gt;服务端和客户端基本套路相同，都是五个基本步骤&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;初始化基本参数&lt;/li&gt;
&lt;li&gt;创建启动对象&lt;/li&gt;
&lt;li&gt;设置启动对象&lt;/li&gt;
&lt;li&gt;建立关联 / 绑定关系&lt;/li&gt;
&lt;li&gt;监听关闭事件&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;4-线程模型图&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-线程模型图&#34;&gt;#&lt;/a&gt; 4、线程模型图&lt;/h2&gt;
&lt;p&gt;有了上面简单实例的理解，再看下面的线程模型图就很好理解了&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210119102410757.png&#34; alt=&#34;image-20210119102410757&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210119102410757.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;模型解释:&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;Netty 抽象出两组线程池 BossGroup 和 WorkerGroup,BossGroup 专门负责接收客户端的连接，&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;WorkerGroup 专门负责网络的读写&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;
&lt;p&gt;BossGroup 和 WorkerGroup 类型都是 NioEventLoopGroup&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;NioEventLoopGroup 相当于一个事件循环线程组，这个组中含有多个事件循环线程，每一个事件&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;循环线程是 NioEventLoop&lt;/p&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;
&lt;p&gt;每个 NioEventLoop 都有一个 selector , 用于监听注册在其上的 socketChannel 的网络通讯&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;每个 Boss NioEventLoop 线程内部循环执行的步骤有 3 步&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;处理 accept 事件，与 client 建立连接，生成 NioSocketChannel&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;将 NioSocketChannel 注册到某个 worker NIOEventLoop 上的 selector&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;处理任务队列的任务，即 runAllTasks&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;每个 worker NIOEventLoop 线程循环执行的步骤&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;轮询注册到自己 selector 上的所有 NioSocketChannel 的 read, write 事件&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;处理 I/O 事件，即 read , write 事件，在对应 NioSocketChannel 处理业务&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;runAllTasks 处理任务队列 TaskQueue 的任务，一些耗时的业务处理一般可以放入&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;TaskQueue 中慢慢处理，这样不影响数据在 pipeline 中的流动处理&lt;/p&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;每个 worker NIOEventLoop 处理 NioSocketChannel 业务时，会使用 pipeline (管道), 管道中维护&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;了很多 handler 处理器用来处理 channel 中的数据&lt;/p&gt;
&lt;h2 id=&#34;5-netty模块组件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5-netty模块组件&#34;&gt;#&lt;/a&gt; 5、Netty 模块组件&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;Bootstrap&lt;/strong&gt;、&lt;strong&gt;ServerBootstrap&lt;/strong&gt; : 客户端和服务端启动对象&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Future&lt;/strong&gt;、&lt;strong&gt;ChannelFuture&lt;/strong&gt;： 注册一个监听，当操作执行成功或失败时监听会自动触发注册的监听事件。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Channel&lt;/strong&gt; ：Netty 网络通信的组件，用于执行网络 I/O 操作&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;NioSocketChannel，异步的客户端 TCP Socket 连接。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;NioServerSocketChannel，异步的服务器端 TCP Socket 连接。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;NioDatagramChannel，异步的 UDP 连接。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;NioSctpChannel，异步的客户端 Sctp 连接。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;NioSctpServerChannel，异步的 Sctp 服务器端连接。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;Selector&lt;/strong&gt;：基于 Selector 对象实现 I/O 多路复用，通过 Selector 一个线程可以监听多个连接的 Channel 事件。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;NioEventLoop&lt;/strong&gt;：维护了一个线程和任务队列，支持异步提交执行任务，线程启动时会调用 NioEventLoop 的 run 方法，执行 I/O 任务和非 I/O 任务&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;I/O 任务，即 selectionKey 中 ready 的事件，如 accept、connect、read、write 等，由 processSelectedKeys 方法触发。&lt;/li&gt;
&lt;li&gt;非 IO 任务，添加到 taskQueue 中的任务，如 register0、bind0 等任务，由 runAllTasks 方法触发。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;NioEventLoopGroup&lt;/strong&gt;：主要管理 eventLoop 的生命周期，可以理解为一个线程池，内部维护了一组线程，每个线程 (NioEventLoop) 负责处理多个 Channel 上的事件，而一个 Channel 只对应于一个线程。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;ChannelHandler&lt;/strong&gt;：是一个接口，处理 I/O 事件或拦截 I/O 操作，并将其转发到其 ChannelPipeline (业务处理链) 中的下一个处理程序。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;ChannelHandler&lt;/strong&gt; 本身并没有提供很多方法，因为这个接口有许多的方法需要实现，方便使用期间，可以继承它的子类：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;ChannelInboundHandler&lt;/strong&gt; 用于处理入站 I/O 事件。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;ChannelOutboundHandler&lt;/strong&gt; 用于处理出站 I/O 操作。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;或者使用以下适配器类：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;ChannelInboundHandlerAdapter&lt;/strong&gt; 用于处理入站 I/O 事件。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;ChannelOutboundHandlerAdapter&lt;/strong&gt; 用于处理出站 I/O 操作。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;ChannelHandlerContext&lt;/strong&gt;：保存 Channel 相关的所有上下文信息，同时关联一个 ChannelHandler 对象。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;ChannelPipline&lt;/strong&gt;：保存 ChannelHandler 的 List，用于处理或拦截 Channel 的入站事件和出站操作。&lt;/p&gt;
&lt;h2 id=&#34;6-bytebuf特性&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6-bytebuf特性&#34;&gt;#&lt;/a&gt; 6、ByteBuf 特性&lt;/h2&gt;
&lt;h3 id=&#34;两个索引&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#两个索引&#34;&gt;#&lt;/a&gt; 两个索引&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;readerIndex：读索引&lt;/li&gt;
&lt;li&gt;writerIndex：写索引&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;capacity：字节数的长度&lt;/p&gt;
&lt;h3 id=&#34;三个方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三个方法&#34;&gt;#&lt;/a&gt; 三个方法&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;byteBuf.writeByte: 写入数据，每写入一个数据，对应的写索引会随之加 1&lt;/li&gt;
&lt;li&gt;byteBuf.getByte (i): 获取数据，获取某个索引位上的数据，但是读索引和写索引都不会改变&lt;/li&gt;
&lt;li&gt;byteBuf.readByte (i): 读取数据，读取某个索引位上的数据，对应的读索引会随之加 1&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;三个区间&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三个区间&#34;&gt;#&lt;/a&gt; 三个区间&lt;/h3&gt;
&lt;p&gt;已读区间：[0, readerIndex)&lt;/p&gt;
&lt;p&gt;可读区间：[readerIndex, writerIndex)&lt;/p&gt;
&lt;p&gt;可写区间：[writerIndex, capacity)&lt;/p&gt;

 &lt;p&gt;Docker 修改 MySQL 配置 &lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h1 id=&#34;docker-修改mysql配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#docker-修改mysql配置&#34;&gt;#&lt;/a&gt; Docker 修改 MySQL 配置&lt;/h1&gt;
&lt;p&gt;作者：YoungJ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;前言：大部分程序员在刚使用 docker 时，按照教程迅速的就装完了 mysql，在使用的过程中出现各种问题：比如中文乱码、 &lt;code&gt;com.mysql.jdbc.PacketTooBigException: Packet for query is too large (1053 &amp;gt; 1024).&lt;/code&gt;  等等，最简单的方式通过 sql 去设置，但每次重启又还原了，那么本文就是通过 docker 下 MySQL 的配置去解决该问题。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;hr&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;从安装说起，获取镜像&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker pull mysql:5.7.18&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;查看镜像&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker images&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190806154125457.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190806154125457.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;运行 docker 容器&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker run -d -p 3306:3306 --name mymysql -e MYSQL_ROOT_PASSWORD=123456 mysql:5.7.18&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;code&gt;(* 这里没有设置挂载外部的配置)&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;查看容器是否启动成功&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker ps&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190806154209392.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190806154209392.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;进入容器&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker exec -it 1383f2e49cb7 /bin/bash&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190806154239219.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190806154239219.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;查看配置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;more /etc/mysql/mysql.conf.d/mysqld.cnf&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;code&gt;（* 如果你执行到这步提示没有该文件，别着急，往下看）&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;编辑配置&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;第一种方式：将配置从容器中 copy 到宿主机（之前文章讲到过，可以去看下，如果没有该文件，那这一步省略，稍后直接将我写好的配置放到容器中就好）&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker cp mysql:/etc/mysql/mysql.conf.d/mysqld.cnf /root/mysqld.cnf&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;mysqld.cnf 脚本如下：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; Copyright (c) 2014, 2016, Oracle and/or its affiliates. All rights reserved.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; This program is free software; you can redistribute it and/or modify&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; it under the terms of the GNU General Public License as published by&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; the Free Software Foundation; version 2 of the License.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; This program is distributed &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; the hope that it will be useful,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; but WITHOUT ANY WARRANTY; without even the implied warranty of&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; GNU General Public License &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; more details.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; You should have received a copy of the GNU General Public License&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; along with this program; &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; not, write to the Free Software&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; Foundation, Inc., 51 Franklin St, Fifth Floor, Boston, MA  02110-1301 USA&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; The MySQL  Server configuration file.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; For explanations see&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; http://dev.mysql.com/doc/mysql/en/server-system-variables.html&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[mysqld]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pid-file        = /var/run/mysqld/mysqld.pid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;socket          = /var/run/mysqld/mysqld.sock&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;datadir         = /var/lib/mysql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;log&lt;/span&gt;-error      = /var/&lt;span class=&#34;built_in&#34;&gt;log&lt;/span&gt;/mysql/error.log&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; By default we only accept connections from localhost&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;bind&lt;/span&gt;-address   = 127.0.0.1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; Disabling symbolic-links is recommended to prevent assorted security risks&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;symbolic-links=0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;character_set_server=utf8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;init_connect=&amp;#x27;SET NAMES utf8&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;max_allowed_packet = 20M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[mysql]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;default-character-set = utf8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[mysql.server]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;default-character-set = utf8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[mysqld_safe]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;default-character-set = utf8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[client]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;default-character-set = utf8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;将修改后的配置copy到容器&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker cp /root/mysqld.cnf mymysql:/etc/mysql/mysql.conf.d/&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;code&gt;(* mymysql是你容器的name,不清楚的可以通过docker ps看到)&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;另一种方式，直接编辑&lt;br&gt;
在使用 docker 容器时，有时候里边没有安装 vim，敲 vim 命令时提示说：vim: command not found，这个时候就需要安装 vim，可是当你敲 apt-get install vim 命令时，提示：&lt;br&gt;
Reading package lists… Done&lt;br&gt;
Building dependency tree&lt;br&gt;
Reading state information… Done&lt;br&gt;
E: Unable to locate package vim&lt;br&gt;
 这时候需要敲：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;apt-get update&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;这个命令的作用是：同步 /etc/apt/sources.list 和 /etc/apt/sources.list.d 中列出的源的索引，这样才能获取到最新的软件包。&lt;br&gt;
等更新完毕以后再敲命令：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;apt-get install vim&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;vim /etc/mysql/mysql.conf.d/mysqld.cnf&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;接下来重启容器就可以了（可以参考之前的文章）&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker restart 1383f2e49cb7 &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;CentOS 安装 Jenkins&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;一-java-jdk-安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#一-java-jdk-安装&#34;&gt;#&lt;/a&gt; 一、Java jdk 安装&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;安装之前先检查一下系统有没有自带 open-jdk&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;命令：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;rpm -qa |grep java复制代码&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;rpm -qa |grep jdk复制代码&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;rpm -qa |grep gcj&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;复制代码&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;如果没有输入信息表示没有安装。&lt;/p&gt;
&lt;p&gt;如果安装可以使用 &lt;code&gt;rpm -qa | grep java | xargs rpm -e --nodeps&lt;/code&gt;  批量卸载所有带有 Java 的文件   这句命令的关键字是 java&lt;/p&gt;
&lt;p&gt;首先检索包含 java 的列表&lt;/p&gt;
&lt;p&gt;&lt;code&gt;yum list java*&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;检索 1.8 的列表&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yum list java-1.8* &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;安装 1.8.0 的所有文件&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yum install java-1.8.0-openjdk* -y&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;使用命令检查是否安装成功&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;java -version&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;到此安装结束了。这样安装有一个好处就是不需要对 path 进行设置，自动就设置好了&lt;/p&gt;
&lt;h2 id=&#34;二-jenkins安装和配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二-jenkins安装和配置&#34;&gt;#&lt;/a&gt; 二、jenkins 安装和配置&lt;/h2&gt;
&lt;h3 id=&#34;安装-jenkins&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装-jenkins&#34;&gt;#&lt;/a&gt; 安装 jenkins&lt;/h3&gt;
&lt;p&gt;\1. 下载依赖&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo wget -O &amp;#x2F;etc&amp;#x2F;yum.repos.d&amp;#x2F;jenkins.repo https:&amp;#x2F;&amp;#x2F;pkg.jenkins.io&amp;#x2F;redhat-stable&amp;#x2F;jenkins.repo&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;\2. 导入秘钥&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo rpm --import https:&amp;#x2F;&amp;#x2F;pkg.jenkins.io&amp;#x2F;redhat-stable&amp;#x2F;jenkins.io.key&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;\3. 安装&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yum install jenkins&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;\4. 查找 jenkins 安装路径&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;rpm -ql jenkins&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;jenkins 相关目录释义：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;/usr/lib/jenkins/&lt;/code&gt; ：jenkins 安装目录，war 包会放在这里&lt;/li&gt;
&lt;li&gt;&lt;code&gt;/etc/sysconfig/jenkins&lt;/code&gt; ：jenkins 配置文件，“端口”，“JENKINS_HOME” 等都可以在这里配置。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;/var/lib/jenkins/&lt;/code&gt; ：默认的 JENKINS_HOME。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;/var/log/jenkins/jenkins.log&lt;/code&gt; ：jenkins 日志文件。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;初始化-jenkins服务器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#初始化-jenkins服务器&#34;&gt;#&lt;/a&gt; 初始化 jenkins 服务器&lt;/h3&gt;
&lt;p&gt;\1. 编辑 jenkins 配置文件&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;为了不因为权限出现各种问题，这里直接修改用户为 root。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;vim &amp;#x2F;etc&amp;#x2F;sysconfig&amp;#x2F;jenkins&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; $JENKINS_USER&amp;#x3D;&amp;quot;root&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;\2. 修改 jenkins 端口&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;若默认 8080 端口未被占用，可不修改。若端口已被占用，则修改端口为其他端口，并将对应端口开放。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;\3. 启动 jenkins&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;推荐用 screen 工具启动 jenkins 服务，可以后台运行，不用担心远程端口关闭导致服务停止。screen 具体用法这里就不展开了，可以参考：&lt;a href=&#34;https://juejin.im/post/6844903880036204557&#34;&gt;juejin.im/post/684490…&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;启动 jenkins&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;java -jar &amp;#x2F;usr&amp;#x2F;lib&amp;#x2F;jenkins&amp;#x2F;jenkins.war --httpPort&amp;#x3D;8899&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;使用 screen 启动 jenkins （jenkins1 是为 jenkins 服务创建的会话名称）&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;screen -S jenkins1 java -jar &amp;#x2F;usr&amp;#x2F;lib&amp;#x2F;jenkins&amp;#x2F;jenkins.war --httpPort&amp;#x3D;8899&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;分离屏幕后台运行 jenkins：&lt;/p&gt;
&lt;p&gt;先按 &lt;strong&gt;control + A&lt;/strong&gt; ，再按 &lt;strong&gt;D&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;列出当前所有的 session：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;screen -ls&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;可以查看到在后台运行的 jenkins 服务，即便服务器 logout 了，Jenkins 服务依然可以使用。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/16bbaeef5be99df4&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/16bbaeef5be99df4&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;\4. 访问 jenkins 地址&lt;/p&gt;
&lt;p&gt;浏览器输入： http://[服务器 ip 地址]:[端口号]&lt;/p&gt;
&lt;p&gt;若启动成功，会出现解锁 jenkins 页面。&lt;/p&gt;
&lt;p&gt;输入命令获取密码&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cat &amp;#x2F;var&amp;#x2F;lib&amp;#x2F;jenkins&amp;#x2F;secrets&amp;#x2F;initialAdminPassword&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后按照页面一步步操作即可：解锁 jenkins -&amp;gt; 安装推荐的插件 -&amp;gt; 创建第一个管理员账号&lt;/p&gt;
&lt;p&gt;创建管理员账号这一步，也可以直接选择使用 admin 账号，需要输入上面获取到的密码。&lt;/p&gt;
&lt;p&gt;接下来就可以使用 jenkins 了。&lt;/p&gt;

 &lt;p&gt;我在部署构件至 maven nexus 私服时，有时会出现 Failed to deploy artifacts: Failed to transfer file: … Return code is: 4XX, ReasonPhrase: … 类似这样的错误，那么这些错误是怎么产生，又如何解决呢？我在此将自己在部署过程中遇到的错误整理汇总一下，供大家参阅，希望对大家有所帮助。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;一-错误的请求&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#一-错误的请求&#34;&gt;#&lt;/a&gt; &lt;strong&gt;一、错误的请求。&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;出现这个问题首先要确认上传的 jar 包的版本号&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;version&amp;gt;0.0.1-SNAPSHOT&amp;lt;&amp;#x2F;version&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;如果这个版本号有SNAPSHOT 这时会上传到 maven-snapshot上，只是一个快照，如果此时上传快照版本这个时候必须要配置快照版本的配置，否则会出现400错误&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;Return code is: 400, ReasonPhrase: Bad Request.&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227183953959.png&#34; alt=&#34;image-20210227183953959&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227183953959.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;具体错误信息如下所示：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] BUILD FAILURE&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Total time: 5.135 s&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Finished at: 2016-02-18T10:23:58+08:00&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Final Memory: 19M&amp;#x2F;174M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] Failed to execute goal org.apache.maven.plugins:maven-deploy-plugin:2.8.2:deploy (default-deploy) on project xeger: &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Failed to deploy artifacts: Could not transfer artifact nl.flotsam:xeger:jar:1.0.2 from&amp;#x2F;to nexus-releases &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        (http:&amp;#x2F;&amp;#x2F;localhost:8081&amp;#x2F;nexus&amp;#x2F;content&amp;#x2F;repositories&amp;#x2F;releases&amp;#x2F;): &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Failed to transfer file: http:&amp;#x2F;&amp;#x2F;localhost:8081&amp;#x2F;nexus&amp;#x2F;content&amp;#x2F;repositories&amp;#x2F;releases&amp;#x2F;nl&amp;#x2F;flotsam&amp;#x2F;xeger&amp;#x2F;1.0.2&amp;#x2F;xeger-1.0.2.jar. &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Return code is: 400, ReasonPhrase: Bad Request. -&amp;gt; [Help 1]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] To see the full stack trace of the errors, re-run Maven with the -e switch.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] Re-run Maven using the -X switch to enable full debug logging.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] For more information about the errors and possible solutions, please read the following articles:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] [Help 1] http:&amp;#x2F;&amp;#x2F;cwiki.apache.org&amp;#x2F;confluence&amp;#x2F;display&amp;#x2F;MAVEN&amp;#x2F;MojoExecutionException&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;400 错误的含义是 “错误的请求”，在这里的原因是往往是没有部署到 nexus 的仓库中。产生原因有如下两种：&lt;/p&gt;
&lt;p&gt;1、部署仓库错误：&lt;/p&gt;
&lt;p&gt;前面的博文有讲过 Nexus 私服有三种仓库类型：Hosted、Proxy 和 Virtual，另外还有一个 group （仓库组）用于对多个仓库进行组合。部署的时候只能部署到 Hosted 类型的宿主仓库中，如果是其他类型就会出现这个 400 错误。若是出现这个错误，只需修改 POM 文件中的部署仓库到对应的宿主仓库即可解决此问题。&lt;/p&gt;
&lt;p&gt;2、宿主仓库不允许重复部署：&lt;br&gt;
　　默认情况下重复部署构件到 Releases 仓库中也会出现 400 错误，原因是 Nexus 私服中 Releases 仓库默认的 Deployment Policy 是 “Disable Redeploy”，所以当你重复部署构件至 Releases 宿主仓库时就会出现这个 400 错误。出现这个问题，只需要将宿主仓库的 Deployment Policy 改为 “” 即可解决，解决方法如下所示：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227183839572.png&#34; alt=&#34;image-20210227183839572&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227183839572.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;二-未认证或认证不通过&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二-未认证或认证不通过&#34;&gt;#&lt;/a&gt; &lt;strong&gt;二、未认证或认证不通过。&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;Return code is: 401, ReasonPhrase: Unauthorized.&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227183901906.png&#34; alt=&#34;image-20210227183901906&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227183901906.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] BUILD FAILURE&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Total time: 2.215 s&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Finished at: 2016-02-18T10:50:56+08:00&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Final Memory: 19M&amp;#x2F;175M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] Failed to execute goal org.apache.maven.plugins:maven-deploy-plugin:2.8.2:deploy (default-deploy) on project xeger: &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Failed to deploy artifacts: Could not transfer artifact nl.flotsam:xeger:jar:1.0.2 from&amp;#x2F;to nexus-releases &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        (http:&amp;#x2F;&amp;#x2F;localhost:8081&amp;#x2F;nexus&amp;#x2F;content&amp;#x2F;repositories&amp;#x2F;releases&amp;#x2F;): Failed to transfer file: &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        http:&amp;#x2F;&amp;#x2F;localhost:8081&amp;#x2F;nexus&amp;#x2F;content&amp;#x2F;repositories&amp;#x2F;releases&amp;#x2F;nl&amp;#x2F;flotsam&amp;#x2F;xeger&amp;#x2F;1.0.2&amp;#x2F;xeger-1.0.2.jar. &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Return code is: 401, ReasonPhrase: Unauthorized. -&amp;gt; [Help 1]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] To see the full stack trace of the errors, re-run Maven with the -e switch.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] Re-run Maven using the -X switch to enable full debug logging.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] For more information about the errors and possible solutions, please read the following articles:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] [Help 1] http:&amp;#x2F;&amp;#x2F;cwiki.apache.org&amp;#x2F;confluence&amp;#x2F;display&amp;#x2F;MAVEN&amp;#x2F;MojoExecutionException&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;出现这种错误，原因如下所示：&lt;/p&gt;
&lt;p&gt;1、是未配置 Nexus 私服用户信息，或配置的账号、密码错误，均会出现 401 的错误，解决方法就是修改 maven settings.xml 配置文件，添加如下信息即可解决问题。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;?xml version&amp;#x3D;&amp;quot;1.0&amp;quot; encoding&amp;#x3D;&amp;quot;UTF-8&amp;quot;?&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;settings xmlns&amp;#x3D;&amp;quot;http:&amp;#x2F;&amp;#x2F;maven.apache.org&amp;#x2F;SETTINGS&amp;#x2F;1.0.0&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        xmlns:xsi&amp;#x3D;&amp;quot;http:&amp;#x2F;&amp;#x2F;www.w3.org&amp;#x2F;2001&amp;#x2F;XMLSchema-instance&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        xsi:schemaLocation&amp;#x3D;&amp;quot;http:&amp;#x2F;&amp;#x2F;maven.apache.org&amp;#x2F;SETTINGS&amp;#x2F;1.0.0 http:&amp;#x2F;&amp;#x2F;maven.apache.org&amp;#x2F;xsd&amp;#x2F;settings-1.0.0.xsd&amp;quot;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;servers&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;!-- Nexus 构件部署用户信息 --&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;server&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;id&amp;gt;nexus-releases&amp;lt;&amp;#x2F;id&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;username&amp;gt;fanfengping&amp;lt;&amp;#x2F;username&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;password&amp;gt;密码&amp;lt;&amp;#x2F;password&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;&amp;#x2F;server&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;server&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;id&amp;gt;nexus-snapshots&amp;lt;&amp;#x2F;id&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;username&amp;gt;fanfengping&amp;lt;&amp;#x2F;username&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;password&amp;gt;密码&amp;lt;&amp;#x2F;password&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;&amp;#x2F;server&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;&amp;#x2F;servers&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;&amp;#x2F;settings&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;2、是 maven 项目工程 POM 文件中配置的 Nexus 私服宿主仓库的 project.distributionManagement.[repository|snapshotRepository].id 在 maven settings.xml 中配置的宿主仓库 &lt;a href=&#34;http://settings.servers.server.id&#34;&gt;settings.servers.server.id&lt;/a&gt; 不存在，统一二者的 ID 后，即可解决此问题。&lt;/p&gt;
&lt;h3 id=&#34;三-连接失败&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三-连接失败&#34;&gt;#&lt;/a&gt; &lt;strong&gt;三、连接失败。&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;Connection refused: connect. 或 *&lt;em&gt;Return code is: 405*&lt;/em&gt;&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;出现这种错误，肯定是 POM 文件中配置的 url 错误，认真检查一下 url 是否正确，然后订正一下，重新部署即可。&lt;/p&gt;
&lt;h3 id=&#34;四-缺失私服仓库连接配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#四-缺失私服仓库连接配置&#34;&gt;#&lt;/a&gt; &lt;strong&gt;四、缺失私服仓库连接配置。&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;Deployment failed: repository element was not specified in the POM inside distributionManagement element or in -DaltDeploymentRepository=id::layout::url parameter&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;具体提示信息如下所示：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] BUILD FAILURE&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Total time: 1.969 s&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Finished at: 2016-02-18T10:47:22+08:00&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] Final Memory: 18M&amp;#x2F;177M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[INFO] ------------------------------------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] Failed to execute goal org.apache.maven.plugins:maven-deploy-plugin:2.8.2:deploy (default-deploy) on project xeger: &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Deployment failed: repository element was not specified in the POM inside distributionManagement element &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        or in -DaltDeploymentRepository&amp;#x3D;id::layout::url parameter -&amp;gt; [Help 1]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] To see the full stack trace of the errors, re-run Maven with the -e switch.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] Re-run Maven using the -X switch to enable full debug logging.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] For more information about the errors and possible solutions, please read the following articles:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ERROR] [Help 1] http:&amp;#x2F;&amp;#x2F;cwiki.apache.org&amp;#x2F;confluence&amp;#x2F;display&amp;#x2F;MAVEN&amp;#x2F;MojoExecutionException&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;此问题是因 POM 文件遗漏了 Nexus 私服连接配置导致的，在 POM 文件中添加 distributionManagement 节点或者在命令行执行时添加 -DaltDeploymentRepository=id::layout::url 参数即可解决。POM 文件中添加 distributionManagement 如下所示：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;project&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;developers&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;&amp;#x2F;developers&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;distributionManagement&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;repository&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;id&amp;gt;nexus-releases&amp;lt;&amp;#x2F;id&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;name&amp;gt;Nexus Releases Repository Pro&amp;lt;&amp;#x2F;name&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;url&amp;gt;http:&amp;#x2F;&amp;#x2F;localhost:8081&amp;#x2F;nexus&amp;#x2F;content&amp;#x2F;repositories&amp;#x2F;releases&amp;#x2F;&amp;lt;&amp;#x2F;url&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;&amp;#x2F;repository&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;snapshotRepository&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;id&amp;gt;nexus-snapshots&amp;lt;&amp;#x2F;id&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;name&amp;gt;Nexus Snapshots Repository Pro&amp;lt;&amp;#x2F;name&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;lt;url&amp;gt;http:&amp;#x2F;&amp;#x2F;localhost:8081&amp;#x2F;nexus&amp;#x2F;content&amp;#x2F;repositories&amp;#x2F;snapshots&amp;#x2F;&amp;lt;&amp;#x2F;url&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;&amp;#x2F;snapshotRepository&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;&amp;#x2F;distributionManagement&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;dependencies&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;&amp;#x2F;dependencies&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;build&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;&amp;#x2F;build&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;&amp;#x2F;project&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;登陆 输入 admin  admin123 直接报错&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;登陆 输入 admin  admin123 直接报错：&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714111545709.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714111545709.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;查日志 发现的确登陆不成功：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714111654972.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714111654972.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;
&lt;p&gt;后来注意到在登陆时有提示信息 ，密码保存在 /nexus-data 下的 admin.password  中。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;进入容器：docker exec -it 容器 id /bin/bash&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714111944858.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714111944858.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;说明：&lt;/p&gt;
&lt;p&gt;-it ： 这是 2 个参数。-i：保持标准输入打开，默认为 false 。 -t： 分配一个伪终端，默认为 false 。&lt;/p&gt;
&lt;p&gt;docker 详细参数说明参见另一文章：《 Docker 技术入门与实战 》读书笔记&lt;/p&gt;
&lt;p&gt;4. 进入容器后，找到 admin.password ，查看并复制密码。&lt;/p&gt;
&lt;p&gt;注意密码只有这一部分：cb424ffc-fc4b-41c1-9cbf-d7ea26efd978，紧跟后面的 bash-4.2$ 不是密码内容。&lt;/p&gt;
&lt;p&gt;我也不清楚这里为什么没有自动换行。此密码不是密文，直接登陆时输入就行。&lt;/p&gt;
&lt;p&gt;5. 退出容器命令：exit&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/2019071411210673.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/2019071411210673.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;登陆，输入密码：&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714112614259.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714112614259.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714112624992.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714112624992.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接 next，提示重置密码：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714112706688.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714112706688.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714112736920.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714112736920.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714112841839.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714112841839.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;我并没有去查这个可选项是什么，只是随手勾上了。再 next 。&lt;/p&gt;
&lt;p&gt;点击完成 。&lt;/p&gt;
&lt;p&gt;关闭浏览器，清缓存，使用新密码登陆成功：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190714113100168.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190714113100168.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;OK 了 。&lt;/p&gt;

 &lt;p&gt;docker 下 gitlab 安装配置使用 (完整版)&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;docker 安装 gitlab 以及使用&lt;/p&gt;
&lt;h2 id=&#34;一-安装及配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#一-安装及配置&#34;&gt;#&lt;/a&gt; 一、安装及配置&lt;/h2&gt;
&lt;h3 id=&#34;1gitlab镜像拉取&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1gitlab镜像拉取&#34;&gt;#&lt;/a&gt; 1.gitlab 镜像拉取&lt;/h3&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# gitlab-ce为稳定版本，后面不填写版本则默认pull最新latest版本&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ docker pull gitlab/gitlab-ce&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141137058.png&#34; alt=&#34;image-20210227141137058&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141137058.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;拉取镜像&lt;/p&gt;
&lt;h3 id=&#34;2运行gitlab镜像&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2运行gitlab镜像&#34;&gt;#&lt;/a&gt; 2. 运行 gitlab 镜像&lt;/h3&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ docker run -d  -p &lt;span class=&#34;number&#34;&gt;443&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;443&lt;/span&gt; -p &lt;span class=&#34;number&#34;&gt;80&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;80&lt;/span&gt; -p &lt;span class=&#34;number&#34;&gt;222&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;22&lt;/span&gt; --name gitlab --restart always -v /home/gitlab/config:/etc/gitlab -v /home/gitlab/logs:/&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt;/log/gitlab -v /home/gitlab/data:/&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt;/opt/gitlab gitlab/gitlab-ce&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;# -d：后台运行&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;# -p：将容器内部端口向外映射&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;# --name：命名容器名称&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;# -v：将容器内数据文件夹或者日志、配置等文件夹挂载到宿主机指定目录&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;运行成功后出现一串字符串&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141207422.png&#34; alt=&#34;image-20210227141207422&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141207422.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;运行成功&lt;/p&gt;
&lt;h3 id=&#34;3配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3配置&#34;&gt;#&lt;/a&gt; 3. 配置&lt;/h3&gt;
&lt;p&gt;按上面的方式，gitlab 容器运行没问题，但在 gitlab 上创建项目的时候，生成项目的 URL 访问地址是按容器的 hostname 来生成的，也就是容器的 id。作为 gitlab 服务器，我们需要一个固定的 URL 访问地址，于是需要配置 gitlab.rb（宿主机路径：/home/gitlab/config/gitlab.rb）。&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# gitlab.rb文件内容默认全是注释&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ vim /home/gitlab/config/gitlab.rb&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 配置http协议所使用的访问地址,不加端口号默认为80&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;external_url &lt;span class=&#34;string&#34;&gt;&amp;#x27;http://192.168.199.231&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 配置ssh协议所使用的访问地址和端口&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gitlab_rails[&lt;span class=&#34;string&#34;&gt;&amp;#x27;gitlab_ssh_host&amp;#x27;&lt;/span&gt;] = &lt;span class=&#34;string&#34;&gt;&amp;#x27;192.168.199.231&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;gitlab_rails[&lt;span class=&#34;string&#34;&gt;&amp;#x27;gitlab_shell_ssh_port&amp;#x27;&lt;/span&gt;] = &lt;span class=&#34;number&#34;&gt;222&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;# 此端口是run时22端口映射的222端口&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;symbol&#34;&gt;:wq&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;#保存配置文件并退出&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141234434.png&#34; alt=&#34;image-20210227141234434&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141234434.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;修改 gitlab.rb 文件&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 重启gitlab容器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ docker restart gitlab&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;此时项目的仓库地址就变了。如果 ssh 端口地址不是默认的 22，就会加上 ssh:// 协议头&lt;br&gt;
打开浏览器输入 ip 地址 (因为我的 gitlab 端口为 80，所以浏览器 url 不用输入端口号，如果端口号不是 80，则打开为：ip: 端口号)&lt;/p&gt;
&lt;h3 id=&#34;4创建一个项目&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4创建一个项目&#34;&gt;#&lt;/a&gt; 4. 创建一个项目&lt;/h3&gt;
&lt;p&gt;第一次进入要输入新的 root 用户密码，设置好之后确定就行&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141250217.png&#34; alt=&#34;image-20210227141250217&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141250217.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;gitlab 页面&lt;/p&gt;
&lt;p&gt;下面我们就可以新建一个项目了，点击 Create a project&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141308416.png&#34; alt=&#34;image-20210227141308416&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141308416.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;Create a project&lt;/p&gt;
&lt;p&gt;创建完成后：&lt;img src=&#34;/img/image-20210227141319942.png&#34; alt=&#34;image-20210227141319942&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141319942.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;创建完成！&lt;/p&gt;
&lt;h2 id=&#34;二-用户使用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二-用户使用&#34;&gt;#&lt;/a&gt; 二、用户使用&lt;/h2&gt;
&lt;h3 id=&#34;1下载gitexe&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1下载gitexe&#34;&gt;#&lt;/a&gt; 1. 下载 git.exe&lt;/h3&gt;
&lt;p&gt;双击 git.exe 安装 git（一直点下一步，直到完成）&lt;br&gt;
点击电脑桌面空白地方右键看到如下两行即安装成功&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141337849.png&#34; alt=&#34;image-20210227141337849&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141337849.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;image.png&lt;/p&gt;
&lt;h3 id=&#34;2登录gitlab网页&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2登录gitlab网页&#34;&gt;#&lt;/a&gt; 2. 登录 gitlab 网页&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;strong&gt;url&lt;/strong&gt;：&lt;a href=&#34;http://192.168.1.111&#34;&gt;http://192.168.1.111&lt;/a&gt;&lt;br&gt;
 填写账号密码登录&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141351085.png&#34; alt=&#34;image-20210227141351085&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141351085.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;登录页面&lt;/p&gt;
&lt;h3 id=&#34;3设置ssh&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3设置ssh&#34;&gt;#&lt;/a&gt; 3. 设置 ssh&lt;/h3&gt;
&lt;p&gt;1. 打开本地 git bash, 使用如下命令生成 ssh 公钥和私钥对&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ ssh-keygen -t rsa -C &lt;span class=&#34;string&#34;&gt;&amp;#x27;xxx@xxx.com&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后一路回车 (-C 参数是你的邮箱地址)&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141405213.png&#34; alt=&#34;image-20210227141405213&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141405213.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;生成密匙&lt;/p&gt;
&lt;p&gt;2. 然后输入命令：&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# ~表示用户目录，比如我的windows就是C:\Users\Administrator，并复制其中的内容&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ cat ~&lt;span class=&#34;regexp&#34;&gt;/.ssh/id&lt;/span&gt;_rsa.pub&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141421384.png&#34; alt=&#34;image-20210227141421384&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141421384.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;公匙&lt;/p&gt;
&lt;p&gt;3. 打开 gitlab, 找到 Profile Settings–&amp;gt;SSH Keys—&amp;gt;Add SSH Key, 并把上一步中复制的内容粘贴到 Key 所对应的文本框&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141438440.png&#34; alt=&#34;image-20210227141438440&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141438440.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https:////upload-images.jianshu.io/upload_images/15087669-f7319dc3a9d83828.png?imageMogr2/auto-orient/strip%7CimageView2/2/w/1200/format/webp&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https:////upload-images.jianshu.io/upload_images/15087669-f7319dc3a9d83828.png?imageMogr2/auto-orient/strip%7CimageView2/2/w/1200/format/webp&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;添加公匙到 gitlab&lt;/p&gt;
&lt;h2 id=&#34;4从gitlab克隆代码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4从gitlab克隆代码&#34;&gt;#&lt;/a&gt; 4. 从 gitlab 克隆代码&lt;/h2&gt;
&lt;p&gt;1. 回到 gitlab 页面点击 projects-&amp;gt;your projects&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141453567.png&#34; alt=&#34;image-20210227141453567&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141453567.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;2. 选择一个需要克隆的项目，进入&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141510681.png&#34; alt=&#34;image-20210227141510681&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141510681.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;我的项目页面&lt;/p&gt;
&lt;p&gt;3. 点击按钮复制地址&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141523914.png&#34; alt=&#34;image-20210227141523914&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141523914.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;复制 ssh 地址&lt;/p&gt;
&lt;p&gt;4. 新建一个文件夹，我在这里在我的电脑 D 盘下新建 project 文件夹&lt;/p&gt;
&lt;p&gt;5. 进入 projects 文件夹右键选择 -&amp;gt;Git Bash Here&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141542867.png&#34; alt=&#34;image-20210227141542867&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141542867.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;点击 Git Bash Here&lt;/p&gt;
&lt;p&gt;6. 设置用户名和邮箱&lt;/p&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ git config --&lt;span class=&#34;keyword&#34;&gt;global&lt;/span&gt; user.name &lt;span class=&#34;string&#34;&gt;&amp;quot;你的名字&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ git config --&lt;span class=&#34;keyword&#34;&gt;global&lt;/span&gt; user.email &lt;span class=&#34;string&#34;&gt;&amp;quot;你的邮箱&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141601043.png&#34; alt=&#34;image-20210227141601043&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141601043.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;设置名字和邮箱&lt;/p&gt;
&lt;p&gt;7. 克隆项目&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ git &lt;span class=&#34;built_in&#34;&gt;clone&lt;/span&gt; 项目地址&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141615614.png&#34; alt=&#34;image-20210227141615614&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141615614.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;克隆项目&lt;/p&gt;
&lt;p&gt;8. 查看 projects 文件夹，项目已经克隆下来了&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141629419.png&#34; alt=&#34;image-20210227141629419&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141629419.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;项目目录&lt;/p&gt;
&lt;h3 id=&#34;5提交代码到gitlab&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5提交代码到gitlab&#34;&gt;#&lt;/a&gt; 5. 提交代码到 gitlab&lt;/h3&gt;
&lt;p&gt;1. 基于以上步骤，在克隆的项目文件夹下新增一个测试文件&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141641044.png&#34; alt=&#34;image-20210227141641044&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141641044.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;新增 txt 文件&lt;/p&gt;
&lt;p&gt;2. 查看同步状态&lt;br&gt;
在项目文件夹下右键点击 -&amp;gt;Git Bash Here&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141653400.png&#34; alt=&#34;image-20210227141653400&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141653400.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;输入&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ git status&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141703602.png&#34; alt=&#34;image-20210227141703602&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141703602.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;状态&lt;/p&gt;
&lt;p&gt;可以看到红色部分有需要提交的文件&lt;br&gt;
 3. 提交代码&lt;br&gt;
输入&lt;/p&gt;
&lt;figure class=&#34;highlight csharp&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ git &lt;span class=&#34;keyword&#34;&gt;add&lt;/span&gt;  测试提交的文件.txt&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;(“git add“后加 “.” 则添加全部文件，也可以加 &amp;quot;*.txt&amp;quot; 表示添加全部需要提交的 txt 文件 )&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141717868.png&#34; alt=&#34;image-20210227141717868&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141717868.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;add 需要提交的文件&lt;/p&gt;
&lt;p&gt;然后输入以下命令提交并添加提交信息&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ git commit -m &lt;span class=&#34;string&#34;&gt;&amp;quot;message&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141732533.png&#34; alt=&#34;image-20210227141732533&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141732533.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;commit&lt;/p&gt;
&lt;p&gt;最后输出以下命令提交到 gitlab&lt;/p&gt;
&lt;figure class=&#34;highlight ruby&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ git push origin master&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141746849.png&#34; alt=&#34;image-20210227141746849&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141746849.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;push&lt;/p&gt;
&lt;p&gt;提交完成啦&lt;br&gt;
再回到 gitlab 上看该项目就可以看到多了一个 txt 测试文件&lt;/p&gt;

 &lt;p&gt;Maven 私服：Docker 安装 nexus3&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;心血来潮，想自己搭个项目试试，锻炼下架构相关的东东。其中的一步就是搭建 maven 私服，方便自己部署私包。&lt;/p&gt;
&lt;h3 id=&#34;查找nexus3镜像&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查找nexus3镜像&#34;&gt;#&lt;/a&gt; 查找 nexus3 镜像&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker search nexus3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141811676.png&#34; alt=&#34;image-20210227141811676&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141811676.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;拉取nexus3镜像&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#拉取nexus3镜像&#34;&gt;#&lt;/a&gt; 拉取 nexus3 镜像&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker pull docker.io&amp;#x2F;sonatype&amp;#x2F;nexus3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141828786.png&#34; alt=&#34;image-20210227141828786&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141828786.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;查看镜像&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看镜像&#34;&gt;#&lt;/a&gt; 查看镜像&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker images&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141843661.png&#34; alt=&#34;image-20210227141843661&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141843661.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;启动容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#启动容器&#34;&gt;#&lt;/a&gt; 启动容器&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker run -tid -p 8081:8081 --privileged=true --name nexus3 -v $PWD/nexus-data:/var/nexus-data --restart=always docker.io/sonatype/nexus3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;-tid  ：创建守护式容器 。&lt;/p&gt;
&lt;p&gt;-p 8081:8081 ：宿主机端口（对外访问端口）：容器映射端口。&lt;br&gt;
这 2 个端口可不一样。浏览器访问 URL 用前面个端口 。&lt;/p&gt;
&lt;p&gt;–privileged=true ：容器访问宿主机的多级目录时可能会权限不足，故给 root 权限 。&lt;/p&gt;
&lt;p&gt;–name nexus3 ：给容器取名，可任意设定。&lt;/p&gt;
&lt;p&gt;-v $PWD/nexus-data:/var/nexus-data ：&lt;br&gt;
把容器中的 nexus-data 目录挂载到宿主机当前路径下的 nexus-data 下。&lt;br&gt;
方便以后查看相关数据。&lt;br&gt;
$PWD ：取当前路径。此处可以写死为某个完整的确定的目录。&lt;br&gt;
挂载格式为： -v  宿主机目录 ：容器目录 。&lt;/p&gt;
&lt;p&gt;–restart=always ：服务挂后，自动重启 。&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;http://docker.io/sonatype/nexus3&#34;&gt;docker.io/sonatype/nexus3&lt;/a&gt; ：镜像名 。&lt;/p&gt;
&lt;h3 id=&#34;启动容器2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#启动容器2&#34;&gt;#&lt;/a&gt; 启动容器 2&lt;/h3&gt;
&lt;figure class=&#34;highlight kotlin&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker run -id --privileged=&lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt; --name=nexus3 --restart=always -p &lt;span class=&#34;number&#34;&gt;8081&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;8081&lt;/span&gt; -v /kichun/nexus3/nexus-&lt;span class=&#34;keyword&#34;&gt;data&lt;/span&gt;:/&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt;/nexus-&lt;span class=&#34;keyword&#34;&gt;data&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;6e9721&lt;/span&gt;ad473a（这个是容器id或名称）&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;解释：&lt;br&gt;
-id 创建守护式容器&lt;br&gt;
–privileged=true 授予 root 权限（挂载多级目录必须为 true，否则容器访问宿主机权限不足）&lt;br&gt;
–name = 名字  给你的容器起个名字&lt;br&gt;
 - p 宿主机端口：容器端口映射&lt;br&gt;
 - v 宿主机目录：容器目录 目录挂载&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141857274.png&#34; alt=&#34;image-20210227141857274&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141857274.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;注意：&lt;br&gt;
运行容器后访问主机 + 配置的宿主机映射端口无反应时，请稍等几分钟（视配置时间长短不一），等待 nexus3 完成初始化才能访问成功&lt;/p&gt;
&lt;h3 id=&#34;访问nexus3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#访问nexus3&#34;&gt;#&lt;/a&gt; 访问 nexus3&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141910506.png&#34; alt=&#34;image-20210227141910506&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141910506.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;登录&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#登录&#34;&gt;#&lt;/a&gt; 登录&lt;/h3&gt;
&lt;p&gt;默认 admin 密码 admin123&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141924143.png&#34; alt=&#34;image-20210227141924143&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141924143.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;查看仓库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看仓库&#34;&gt;#&lt;/a&gt; 查看仓库&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141936385.png&#34; alt=&#34;image-20210227141936385&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141936385.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;在项目中配置私服&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#在项目中配置私服&#34;&gt;#&lt;/a&gt; 在项目中配置私服&lt;/h3&gt;
&lt;p&gt;拷贝 public 仓库地址&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227141952818.png&#34; alt=&#34;image-20210227141952818&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227141952818.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;配置到你本地 maven 的 settings 文件&lt;br&gt;
注意：是 public group 仓库地址而不是 releases 或 snapshots 仓库，public 默认包含了这两个仓库&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;profiles&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;profile&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;dev&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;repositories&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;repository&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;local-nexus&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;url&lt;/span&gt;&amp;gt;&lt;/span&gt;http://192.168.3.128:8081/repository/maven-public/&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;url&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;releases&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;enabled&lt;/span&gt;&amp;gt;&lt;/span&gt;true&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;enabled&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;releases&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;snapshots&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;enabled&lt;/span&gt;&amp;gt;&lt;/span&gt;true&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;enabled&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;snapshots&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;repository&lt;/span&gt;&amp;gt;&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;repositories&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;profile&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;profiles&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;activeProfiles&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;activeProfile&lt;/span&gt;&amp;gt;&lt;/span&gt;dev&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;activeProfile&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;activeProfiles&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227142011753.png&#34; alt=&#34;image-20210227142011753&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227142011753.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;配置 maven settings 文件的服务器用户名密码&lt;br&gt;
注意：id 为私服中 releases 和 snapshots 仓库名，必须一致&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!-- servers&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; | This is a list of authentication profiles, keyed by the server-id used within the system.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; | Authentication profiles can be used whenever maven must make a connection to a remote server.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; |--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;servers&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;server&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;maven-releases&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;username&lt;/span&gt;&amp;gt;&lt;/span&gt;admin&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;username&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;password&lt;/span&gt;&amp;gt;&lt;/span&gt;admin123&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;password&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;server&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;server&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;maven-snapshots&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;username&lt;/span&gt;&amp;gt;&lt;/span&gt;admin&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;username&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;password&lt;/span&gt;&amp;gt;&lt;/span&gt;admin123&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;password&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;server&lt;/span&gt;&amp;gt;&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;servers&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227142027853.png&#34; alt=&#34;image-20210227142027853&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227142027853.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;在项目父 pom 文件中配置部署环境，注意 id 及 URL 必须与 nexus 仓库对应&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!--私服仓库--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;distributionManagement&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;repository&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;maven-releases&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;name&lt;/span&gt;&amp;gt;&lt;/span&gt;Nexus Release Repository&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;name&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;url&lt;/span&gt;&amp;gt;&lt;/span&gt;http://192.168.3.128:8081/repository/maven-releases/&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;url&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;repository&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;snapshotRepository&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;maven-snapshots&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;id&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;name&lt;/span&gt;&amp;gt;&lt;/span&gt;Nexus Snapshot Repository&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;name&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;url&lt;/span&gt;&amp;gt;&lt;/span&gt;http://192.168.3.128:8081/repository/maven-snapshots/&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;url&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;snapshotRepository&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;distributionManagement&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227142050650.png&#34; alt=&#34;image-20210227142050650&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227142050650.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;重新打开项目，对需要的模块进行 deploy&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210227142106796.png&#34; alt=&#34;image-20210227142106796&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210227142106796.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;在 nexus 中查看上传的 jar&lt;/p&gt;
&lt;p&gt;PS：&lt;/p&gt;
&lt;p&gt;遇到问题 1：&lt;/p&gt;
&lt;p&gt;在启动容器时我原本想换个端口，但发现不用 8081 时，tcp 的端口映射也是自动设置为 8081 的。并且换了端口后，虽然能启动容器成功，显示为运行状态，但是浏览器始终访问不到服务，报错：拒绝连接。最后还是使用了 8081 端口。&lt;/p&gt;
&lt;p&gt;遇到问题 2：&lt;/p&gt;
&lt;p&gt;登陆时始终报错，账号或密码不对，默认密码并不是 admin123。&lt;/p&gt;
&lt;p&gt;对此解决方法见文章： (Docker 方式运行 Nexus3 登陆密码不为 admin123 、重置登陆密码)&lt;/p&gt;
&lt;p&gt;遇到问题 3：&lt;/p&gt;
&lt;p&gt;容器内部的时间比服务器时间晚 8 小时。&lt;/p&gt;
&lt;p&gt;解决方法：启动容器时 加入参数：  -v /etc/localtime:/etc/localtime:ro 。ro：只读。&lt;/p&gt;
&lt;p&gt;完整启动命令为：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker run -tid -p 8081:8081 --privileged=true --name nexus3 -v $PWD/nexus-data:/var/nexus-data  -v /etc/localtime:/etc/localtime:ro --restart=always docker.io/sonatype/nexus3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;遇到问题 4：&lt;/p&gt;
&lt;p&gt;执行 mvn  deploy 命令报错：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/2019071715413379.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/2019071715413379.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;MQ 全称 Message Queue（消息队列），是在消息的传输过程中保存消息的容器。多用于分布式系统之间进行通信。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201201171613531.png&#34; alt=&#34;image-20201201171613531&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201201171613531.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201201171644352.png&#34; alt=&#34;image-20201201171644352&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201201171644352.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201201171711864.png&#34; alt=&#34;image-20201201171711864&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201201171711864.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201201171736965.png&#34; alt=&#34;image-20201201171736965&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201201171736965.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201201171811299.png&#34; alt=&#34;image-20201201171811299&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201201171811299.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;MQ 全称 Message Queue（消息队列），是在消息的传输过程中保存消息的容器。多用于分布式系统之间进行通信。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;mq的优势&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mq的优势&#34;&gt;#&lt;/a&gt; MQ 的优势&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;应用解耦&lt;/p&gt;
&lt;p&gt;提高系统容错性和可维护性&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;异步提速&lt;/p&gt;
&lt;p&gt;提升用户体验和系统吞吐量&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;削峰填谷&lt;/p&gt;
&lt;p&gt;提高系统稳定性&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;mq的劣势&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mq的劣势&#34;&gt;#&lt;/a&gt; MQ 的劣势&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;系统可用性降低&lt;/p&gt;
&lt;p&gt;系统引入的外部依赖越多，系统稳定性越差。一旦 MQ 宕机，就会对业务造成影响。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;系统复杂度提高&lt;/p&gt;
&lt;p&gt;MQ 的加入大大增加了系统的复杂度，以前系统间是同步的远程调用，现在是通过 MQ 进行异步调用。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;常见产品&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#常见产品&#34;&gt;#&lt;/a&gt; 常见产品&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;** **&lt;/th&gt;
&lt;th&gt;&lt;strong&gt;Rabbit MQ&lt;/strong&gt;&lt;/th&gt;
&lt;th&gt;&lt;strong&gt;Active MQ&lt;/strong&gt;（相对使用不多）&lt;/th&gt;
&lt;th&gt;&lt;strong&gt;Rocket MQ&lt;/strong&gt;&lt;/th&gt;
&lt;th&gt;&lt;strong&gt;Kafka&lt;/strong&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;公司 / 社区&lt;/td&gt;
&lt;td&gt;Rabbit&lt;/td&gt;
&lt;td&gt;Apache&lt;/td&gt;
&lt;td&gt;阿里&lt;/td&gt;
&lt;td&gt;Apache&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;开发语言&lt;/td&gt;
&lt;td&gt;Erlang&lt;/td&gt;
&lt;td&gt;Java&lt;/td&gt;
&lt;td&gt;Java&lt;/td&gt;
&lt;td&gt;Scala&amp;amp;Java&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;协议支持&lt;/td&gt;
&lt;td&gt;AMQP，XMPP，SMTP，STOMP&lt;/td&gt;
&lt;td&gt;OpenWire,STOMP，REST,XMPP,AMQP&lt;/td&gt;
&lt;td&gt;自定义&lt;/td&gt;
&lt;td&gt;自定义协议，社区封装了 http 协议支持&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;客户端支持语言&lt;/td&gt;
&lt;td&gt;官方支持 Erlang，Java，Ruby 等，社区产出多种 API，几乎支持所有语言&lt;/td&gt;
&lt;td&gt;Java，C，C++，Python，PHP，Perl，.net 等&lt;/td&gt;
&lt;td&gt;Java，C++（不成熟）&lt;/td&gt;
&lt;td&gt;官方支持 Java, 社区产出多种 API，如 PHP，Python 等&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;单机吞吐量&lt;/td&gt;
&lt;td&gt;万级（其次）&lt;/td&gt;
&lt;td&gt;万级（最差）&lt;/td&gt;
&lt;td&gt;十万级（最好）&lt;/td&gt;
&lt;td&gt;十万级（次之）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;消息延迟&lt;/td&gt;
&lt;td&gt;微妙级&lt;/td&gt;
&lt;td&gt;毫秒级&lt;/td&gt;
&lt;td&gt;毫秒级&lt;/td&gt;
&lt;td&gt;毫秒以内&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;功能特性&lt;/td&gt;
&lt;td&gt;并发能力强，性能极其好，延时低，社区活跃，管理界面丰富&lt;/td&gt;
&lt;td&gt;老牌产品，成熟度高，文档较多&lt;/td&gt;
&lt;td&gt;MQ 功能比较完备，扩展性佳&lt;/td&gt;
&lt;td&gt;只支持主要的 MQ 功能，毕竟是为大数据领域准备的。&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;rabbit-mq&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#rabbit-mq&#34;&gt;#&lt;/a&gt; Rabbit MQ&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;Broker&lt;/strong&gt;：接收和分发消息的应用，RabbitMQ Server 就是 Message Broker&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Virtual host&lt;/strong&gt;：出于多租户和安全因素设计的，把 AMQP 的基本组件划分到一个虚拟的分组中，类似于网络中的 name space 概念。当多个不同的用户使用同一个 RabbitMQ server 提供的服务时，可以划分出多个 vhost，每个用户在自己的 vhost 创建 exchange／queue 等&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Connection&lt;/strong&gt;： publisher／consumer 和 broker 之间的 TCP 连接&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Channel&lt;/strong&gt;：如果每一次访问 RabbitMQ 都建立一个 Connection，在消息量大的时候建立 TCP Connection 的开销将是巨大的，效率也较低。Channel 是在 connection 内部建立的逻辑连接，如果应用程序支持多线程，通常每个 thread 创建单独的 channel 进行通讯，AMQP method 包含了 channel id 帮助客户端和 message broker 识别 channel，所以 channel 之间是完全隔离的。Channel 作为轻量级的 Connection 极大减少了操作系统建立 TCP connection 的开销&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Exchange&lt;/strong&gt;： message 到达 broker 的第一站，根据分发规则，匹配查询表中的 routing key，分发消息到 queue 中去。常用的类型有：direct (point-to-point), topic (publish-subscribe) and fanout (multicast)&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Queue&lt;/strong&gt;：消息最终被送到这里等待 consumer 取走&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Binding&lt;/strong&gt;： exchange 和 queue 之间的虚拟连接，binding 中可以包含 routing key。Binding 信息被保存到 exchange 中的查询表中，用于 message 的分发依据&lt;/p&gt;
&lt;h4 id=&#34;6-种工作模式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6-种工作模式&#34;&gt;#&lt;/a&gt; 6 种工作模式&lt;/h4&gt;
&lt;p&gt;简单模式、work queues、Publish/Subscribe 发布与订阅模式、Routing 路由模式、Topics 主题模式、RPC 远程调用模式（远程调用，不太算 MQ）。&lt;br&gt;
官网对应模式介绍：&lt;a href=&#34;https://www.rabbitmq.com/getstarted.html&#34;&gt;https://www.rabbitmq.com/getstarted.html&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201128145309508.png&#34; alt=&#34;image-20201128145309508&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201128145309508.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201128145328279.png&#34; alt=&#34;image-20201128145328279&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201128145328279.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201128145148926.png&#34; alt=&#34;image-20201128145148926&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201128145148926.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201128145208118.png&#34; alt=&#34;image-20201128145208118&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201128145208118.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201128145226488.png&#34; alt=&#34;image-20201128145226488&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201128145226488.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201128145240371.png&#34; alt=&#34;image-20201128145240371&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201128145240371.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;常见 IO 模型；&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;bioblocking-io&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#bioblocking-io&#34;&gt;#&lt;/a&gt; BIO(Blocking IO)&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102235904.png&#34; alt=&#34;image-20201125102235904&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102235904.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;nionon-blocking-io&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#nionon-blocking-io&#34;&gt;#&lt;/a&gt; NIO(Non Blocking IO)&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102442397.png&#34; alt=&#34;image-20201125102442397&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102442397.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102645049.png&#34; alt=&#34;image-20201125102645049&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102645049.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102503638.png&#34; alt=&#34;image-20201125102503638&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102503638.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102517955.png&#34; alt=&#34;image-20201125102517955&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102517955.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102533041.png&#34; alt=&#34;image-20201125102533041&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102533041.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102607115.png&#34; alt=&#34;image-20201125102607115&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102607115.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102617571.png&#34; alt=&#34;image-20201125102617571&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102617571.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;aionio-20&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#aionio-20&#34;&gt;#&lt;/a&gt; AIO(NIO 2.0)&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201125102728096.png&#34; alt=&#34;image-20201125102728096&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201125102728096.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;jenkins 的 docker 容器如何装配 jdk maven 和 git&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;jenkins/jenkins:lts 容器安装这些工具，其实 jenkins 镜像中已经包含了 jdk，我们只不过把容器中这些工具的路径找出来，配置下路径即可，所以有如下两种方式：&lt;/p&gt;
&lt;h3 id=&#34;方式一推荐&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方式一推荐&#34;&gt;#&lt;/a&gt; 方式一（推荐）&lt;/h3&gt;
&lt;p&gt;先进入 jenkins 的容器中&lt;/p&gt;
&lt;p&gt;docker exec -it jenkins 容器 id /bin/bash&lt;/p&gt;
&lt;h4 id=&#34;jdk&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#jdk&#34;&gt;#&lt;/a&gt; jdk&lt;/h4&gt;
&lt;p&gt;然后通过 echo $JAVA_HOME 来查看 java 路径在 /usr/local 中，然后配置进 jenkins 的 JAVA_HOME 中即可&lt;/p&gt;
&lt;h4 id=&#34;git&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#git&#34;&gt;#&lt;/a&gt; git&lt;/h4&gt;
&lt;p&gt;通过 which git 查看 git 执行文件路径为 /usr/bin/git，把这个复制到 jenkins 路径中&lt;/p&gt;
&lt;h4 id=&#34;mvn&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mvn&#34;&gt;#&lt;/a&gt; mvn&lt;/h4&gt;
&lt;p&gt;jenkins 容器中一般没有 maven 提供的，所以 jenkins 配置中我使用 install automatically&lt;/p&gt;
&lt;h3 id=&#34;方式二&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方式二&#34;&gt;#&lt;/a&gt; 方式二&lt;/h3&gt;
&lt;p&gt;使用 jenkins 工具管理里头自动安装 jdk，git 和 maven，但是 jdk 自动安装需要 oracle 的账号密码，这个得自己申请，这种比较麻烦，不见这么做，既然镜像中已经存在了 jdk，我们可找下路径就可以直接使用，为何还需要专门自动安装一个呢？&lt;/p&gt;
&lt;p&gt;其他&lt;br&gt;
如果不是 docker 容器的方式，要么用自动安装使用下 oracle 账号，要么自己安装一个 jdk 到本地，然后配一下 JAVA_HOME 路径即可，至于具体怎么配 java 路径请看这篇 CentOS 下 JDK 安装及配置&lt;/p&gt;

 &lt;p&gt;Zookeeper 集群配置&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Zookeeper 集群模式一共有三种类型的角色&lt;br&gt;
&lt;strong&gt; Leader&lt;/strong&gt;:   处理所有的事务请求（写请求），可以处理读请求，集群中只能有一个 Leader&lt;br&gt;
&lt;strong&gt;Follower&lt;/strong&gt;：只能处理读请求，同时作为 Leader 的候选节点，即如果 Leader 宕机，Follower 节点要参与到新的 Leader 选举中，有可能成为新的 Leader 节点。&lt;br&gt;
&lt;strong&gt;Observer&lt;/strong&gt;：只能处理读请求。不能参与选举&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201121112920993.png&#34; alt=&#34;image-20201121112920993&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201121112920993.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;zookeeper集群模式安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#zookeeper集群模式安装&#34;&gt;#&lt;/a&gt; &lt;strong&gt;Zookeeper 集群模式安装&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;本例搭建的是伪集群模式，即一台机器上启动四个 Zookeeper 实例组成集群，真正的集群模式无非就是实例 IP 地址不同，搭建方法没有区别&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;配置 JAVA 环境，检验环境：保证是 &lt;code&gt;jdk7&lt;/code&gt;  及以上即可&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;java -version        &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;下载并解压 Zookeeper&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;wget https://mirror.bit.edu.cn/apache/zookeeper/zookeeper-3.5.8/apache-zookeeper-3.5.8-bin.tar.gz tar -zxvf apache-zookeeper-3.5.8-bin.tar.gz cd  apache-zookeeper-3.5.8-bin     &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;重命名 &lt;code&gt; zoo_sample.cfg&lt;/code&gt;  文件&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cp conf/zoo_sample.cfg conf/zoo-1.cfg &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;修改配置文件 &lt;code&gt;zoo-1.cfg&lt;/code&gt; ，原配置文件里有的，修改成下面的值，没有的则加上&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; vim conf/zoo-1.cfg&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dataDir=/usr/local/data/zookeeper-1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;clientPort=2181&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.1=127.0.0.1:2001:3001:participant// participant 可以不用写，默认就是participant&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.2=127.0.0.1:2002:3002:participant&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.3=127.0.0.1:2003:3003:participant&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server.4=127.0.0.1:2004:3004:observer&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;配置说明&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;tickTime&lt;/code&gt; ：用于配置 Zookeeper 中最小时间单位的长度，很多运行时的时间间隔都是使用 tickTime 的倍数来表示的。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;initLimit&lt;/code&gt; ：该参数用于配置 Leader 服务器等待 Follower 启动，并完成数据同步的时间。Follower 服务器再启动过程中，会与 Leader 建立连接并完成数据的同步，从而确定自己对外提供服务的起始状态。Leader 服务器允许 Follower 再 &lt;code&gt;initLimit &lt;/code&gt; 时间内完成这个工作。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;syncLimit：Leader&lt;/code&gt;  与 Follower 心跳检测的最大延时时间&lt;/li&gt;
&lt;li&gt;&lt;code&gt;dataDir&lt;/code&gt; ：顾名思义就是 Zookeeper 保存数据的目录，默认情况下，Zookeeper 将写数据的日志文件也保存在这个目录里。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;clientPort&lt;/code&gt; ：这个端口就是客户端连接 Zookeeper 服务器的端口，Zookeeper 会监听这个端口，接受客户端的访问请求。&lt;/li&gt;
&lt;li&gt;&lt;code&gt;server.A=B：C：D：E&lt;/code&gt;  其中 A 是一个数字，表示这个是第几号服务器；B 是这个服务器的 IP 地址；C 表示的是这个服务器与集群中的 Leader 服务器交换信息的端口；D 表示的是万一集群中的 Leader 服务器挂了，需要一个端口来重新进行选举，选出一个新的 Leader，而这个端口就是用来执行选举时服务器相互通信的端口。如果是伪集群的配置方式，由于 B 都是一样，所以不同的 Zookeeper 实例通信端口号不能一样，所以要给它们分配不同的端口号。如果需要通过添加不参与集群选举以及事务请求的过半机制的 Observer 节点，可以在 E 的位置，添加 observer 标识。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;再从 &lt;code&gt;zoo-1.cfg&lt;/code&gt;  复制三个配置文件 &lt;code&gt;zoo-2.cfg&lt;/code&gt; ， &lt;code&gt;zoo-3.cfg&lt;/code&gt;  和 &lt;code&gt;zoo-4.cfg&lt;/code&gt; ，只需修改 &lt;code&gt;dataDir&lt;/code&gt;  和 &lt;code&gt;clientPort&lt;/code&gt;  不同即可&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cp conf/zoo1.cfg conf/zoo2.cfg&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cp conf/zoo1.cfg conf/zoo3.cfg&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cp conf/zoo1.cfg conf/zoo4.cfg&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vim conf/zoo2.cfg&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dataDir=/usr/local/data/zookeeper2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;clientPort=2182&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vim conf/zoo3.cfg&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dataDir=/usr/local/data/zookeeper3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;clientPort=2183&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vim conf/zoo4.cfg&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dataDir=/usr/local/data/zookeeper4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;clientPort=2184&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;标识 Server ID，创建四个文件夹 &lt;code&gt;/usr/local/data/zookeeper-1&lt;/code&gt; ， &lt;code&gt;/usr/local/data/zookeeper-2&lt;/code&gt; ， &lt;code&gt;/usr/local/data/zookeeper-3&lt;/code&gt; ， &lt;code&gt;/usr/local/data/zookeeper-4&lt;/code&gt; ，在每个目录中创建文件 &lt;code&gt;myid&lt;/code&gt;  文件，写入当前实例的 server id，即 1，2，3，4&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cd /usr/local/data/zookeeper-1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; vim myid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; 1 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; cd /usr/local/data/zookeeper-2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; vim myid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; 2 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; cd /usr/local/data/zookeeper-3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; vim myid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; 3 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cd /usr/local/data/zookeeper-4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vim myid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;启动三个 Zookeeper 实例&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;bin/zkServer.sh start conf/zoo1.cfg&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bin/zkServer.sh start conf/zoo2.cfg&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bin/zkServer.sh start conf/zoo3.cfg&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;检测集群状态，也可以直接用命令  &lt;code&gt;zkServer.sh   status conf/zoo1.cfg&lt;/code&gt;   进行每台服务的状态查询&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201121113004525.png&#34; alt=&#34;image-20201121113004525&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201121113004525.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;bin/zkCli.sh -server ip1:port1,ip2:port2,ip3:port3 &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;可以通过 查看 / Zookeeper/config  节点数据来查看集群配置&lt;/p&gt;
&lt;h3 id=&#34;zookeeper典型使用场景实战&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#zookeeper典型使用场景实战&#34;&gt;#&lt;/a&gt; Zookeeper 典型使用场景实战&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;Zookeeper 非公平锁 / 公平锁 / 共享锁&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201121173453127.png&#34; alt=&#34;image-20201121173453127&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201121173453127.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201121173513915.png&#34; alt=&#34;image-20201121173513915&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201121173513915.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201121173540804.png&#34; alt=&#34;image-20201121173540804&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201121173540804.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Leader 选举在分布式场景中的应用&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Spring Cloud Zookeeper 注册中心实战&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;Zookeeper 一个分布式协调框架，是 &lt;code&gt;Apache Hadoop&lt;/code&gt;  的一个子项目，它主要是用来解决分布式应用中经常遇到的一些数据管理问题，如：统一命名服务、状态同步服务、集群管理、分布式应用配置项的管理等&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;核心概念&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#核心概念&#34;&gt;#&lt;/a&gt; 核心概念&lt;/h2&gt;
&lt;p&gt;一个用于存储少量数据的基于内存的数据库，主要有如下两个核心的概念：文件系统数据结构 + 监听通知机制。&lt;/p&gt;
&lt;h3 id=&#34;文件系统数据结构&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#文件系统数据结构&#34;&gt;#&lt;/a&gt; 文件系统数据结构&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;PERSISTENT - 持久化目录节点&lt;br&gt;
客户端与 Zookeeper 断开连接后，该节点依旧存在，只要不手动删除该节点，他将永远存在&lt;/li&gt;
&lt;li&gt;PERSISTENT_SEQUENTIAL - 持久化顺序编号目录节点&lt;br&gt;
客户端与 Zookeeper 断开连接后，该节点依旧存在，只是 Zookeeper 给该节点名称进行顺序编号&lt;/li&gt;
&lt;li&gt;EPHEMERAL - 临时目录节点&lt;br&gt;
客户端与 Zookeeper 断开连接后，该节点被删除&lt;/li&gt;
&lt;li&gt;EPHEMERAL_SEQUENTIAL - 临时顺序编号目录节点&lt;br&gt;
客户端与 Zookeeper 断开连接后，该节点被删除，只是 Zookeeper 给该节点名称进行顺序编号&lt;/li&gt;
&lt;li&gt;Container 节点（3.5.3 版本新增，如果 Container 节点下面没有子节点，则 Container 节点在未来会被 Zookeeper 自动清除，定时任务默认 60s 检查一次）&lt;/li&gt;
&lt;li&gt;TTL 节点 ( 默认禁用，只能通过系统配置  &lt;code&gt;zookeeper.extendedTypesEnabled=true&lt;/code&gt;  开启，不稳定)&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;监听通知机制&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#监听通知机制&#34;&gt;#&lt;/a&gt; 监听通知机制&lt;/h3&gt;
&lt;p&gt;客户端注册监听它关心的任意节点，或者目录节点及递归子目录节点&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;如果注册的是对某个节点的监听，则当这个节点被删除，或者被修改时，对应的客户端将被通知&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果注册的是对某个目录的监听，则当这个目录有子节点被创建，或者有子节点被删除，对应的客户端将被通知&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果注册的是对某个目录的递归子节点进行监听，则当这个目录下面的任意子节点有目录结构的变化（有子节点被创建，或被删除）或者根节点有数据变化时，对应的客户端将被通知。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;注：所有的通知都是一次性的，及无论是对节点还是对目录进行的监听，一旦触发，对应的监听即被移除。递归子节点，监听是对所有子节点的，所以，每个子节点下面的事件同样只会被触发一次。&lt;/p&gt;
&lt;h2 id=&#34;zookeeper安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#zookeeper安装&#34;&gt;#&lt;/a&gt; Zookeeper 安装&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;配置 JAVA 环境，检验环境：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;java -version  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;下载解压 Zookeeper&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;wget https://mirror.bit.edu.cn/apache/zookeeper/zookeeper-3.5.8/apache-zookeeper-3.5.8-bin.tar.gz tar -zxvf apache-zookeeper-3.5.8-bin.tar.gz cd  apache-zookeeper-3.5.8-bin&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;重命名配置文件   &lt;code&gt;zoo_sample.cfg&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cp zoo_sample.cfg  zoo.cfg&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;启动 Zookeeper&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 可以通过 bin/zkServer.sh  来查看都支持哪些参数  &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 进入安装目录&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bin/zkServer.sh start conf/zoo.cfg &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;检测是否启动成功&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;echo stat | nc 192.168.109.200 // 前提是配置文件中中讲 stat 四字命令设置了了白名单  如： 4lw.commands.whitelist=stat &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 或使用&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ps -ef | grep zookeeper&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;连接服务器&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;bin/zkCli.sh -server ip:port  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;命令行操作zookeeper&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#命令行操作zookeeper&#34;&gt;#&lt;/a&gt; 命令行操作 Zookeeper&lt;/h2&gt;
&lt;p&gt;命令 help 查看 Zookeeper 所支持的所有命令：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[zk: localhost:2181(CONNECTED) 80] help&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ZooKeeper -server host:port cmd args&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 输入认证授权信息，相当于注册用户信息，注册时输入明文密码，zk将以密文的形式存储 &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	addauth scheme auth&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	close &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	config [-c] [-w] [-s]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	connect host:port&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 创建zookeeper 节点命令&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; -s: 顺序节点&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # -e: 临时节点&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # -c: 容器节点&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # -t:  可以给节点添加过期时间，默认禁用，需要通过系统参数启用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # 创建子节点， 这里要注意，zookeeper是以节点组织数据的，没有相对路径这么一说，所以，所有的节点一定是以 / 开头。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # create 后跟一个 -e 创建临时节点 ， 临时节点不能创建子节点&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # 容器节点主要用来容纳字节点，如果没有给其创建子节点，容器节点表现和持久化节点一样，如果给容器节点创建了子节点，后续又把子节点清空，容器节点也会被zookeeper删除。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	create [-s] [-e] [-c] [-t ttl] path [data] [acl]   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	delete [-v version] path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	deleteall path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	delquota [-n|-b] path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 查看节点&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # -w: 针对节点的监听：一定事件触发，对应的注册立刻被移除，所以事件监听是一次性的&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	get [-s] [-w] path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 获取某个节点的acl权限信息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	getAcl [-s] path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	history &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	listquota path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; -R 区分大小写，一定用大写 &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # -w: 针对目录的监听&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	ls [-s] [-w] [-R] path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	ls2 path [watch]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	printwatches on|off&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	quit &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	reconfig [-s] [-v version] [[-file path] | [-members serverID=host:port1:port2;port3[,...]*]] | [-add serverId=host:port1:port2;port3[,...]]* [-remove serverId[,...]*]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	redo cmdno&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	removewatches path [-c|-d|-a] [-l]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	rmr path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 修改节点数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	set [-s] [-v version] path data&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 设置某个节点的acl权限信息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	setAcl [-s] [-v version] [-R] path acl&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	setquota -n|-b val path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 查看节点状态信息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; cZxid：创建znode的事务ID（Zxid的值）。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # mZxid：最后修改znode的事务ID。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # pZxid：最后添加或删除子节点的事务ID（子节点列表发生变化才会发生改变）。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # ctime：znode创建时间。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # mtime：znode最近修改时间。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # dataVersion：znode的当前数据版本。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # cversion：znode的子节点结果集版本（一个节点的子节点增加、删除都会影响这个版本）。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # aclVersion：表示对此znode的acl版本。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # ephemeralOwner：znode是临时znode时，表示znode所有者的 session ID。 如果znode不是临时znode，则该字段设置为零。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # dataLength：znode数据字段的长度。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; numChildren：znode的子znode的数量。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;	#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; [-w] 对节点进行监听，且获取元数据信息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	stat [-w] path&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	sync path&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;Zookeeper 事件类型：&lt;/p&gt;
&lt;p&gt;​            None: 连接建立事件&lt;br&gt;
​            NodeCreated： 节点创建&lt;br&gt;
​            NodeDeleted： 节点删除&lt;br&gt;
​            NodeDataChanged：节点数据变化&lt;br&gt;
​            NodeChildrenChanged：子节点列表变化&lt;br&gt;
​            DataWatchRemoved：节点监听被移除&lt;br&gt;
​            ChildWatchRemoved：子节点监听被移除&lt;/p&gt;
&lt;h2 id=&#34;acl-权限控制-access-control-list&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#acl-权限控制-access-control-list&#34;&gt;#&lt;/a&gt; ACL 权限控制 (Access Control   List)&lt;/h2&gt;
&lt;p&gt;控制节点的读写操作，保证数据的安全性，Zookeeper ACL 权限设置分为 3 部分组成，分别是：&lt;strong&gt;权限模式&lt;/strong&gt;（Scheme）、&lt;strong&gt;授权对象&lt;/strong&gt;（ID）、&lt;strong&gt;权限信息&lt;/strong&gt;（Permission）&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Scheme（权限模式）&lt;/strong&gt;：用来设置 Zookeeper 服务器进行权限验证的方式。&lt;/p&gt;
&lt;p&gt;一种是&lt;strong&gt;范围验证&lt;/strong&gt;。所谓的范围验证就是说 Zookeeper 可以针对一个 IP 或者一段 IP 地址授予某种权限。比如我们可以让一个 IP 地址为 &lt;code&gt;ip：192.168.0.110&lt;/code&gt;  的机器对服务器上的某个数据节点具有写入的权限。或者也可以通过 &lt;code&gt;ip:192.168.0.1/24&lt;/code&gt;  给一段 IP 地址的机器赋权。&lt;/p&gt;
&lt;p&gt;另一种是&lt;strong&gt;口令验证&lt;/strong&gt;，也可以理解为用户名密码的方式。在 Zookeeper 中这种验证方式是 Digest 认证，而 Digest 这种认证方式首先在客户端传送 &lt;code&gt;username:password&lt;/code&gt;  这种形式的权限表示符后，Zookeeper 服务端会对密码 部分使用  &lt;code&gt;SHA-1&lt;/code&gt;  和  &lt;code&gt;BASE64&lt;/code&gt;  算法进行加密，以保证安全性。&lt;/p&gt;
&lt;p&gt;还有一种 Super 权限模式，Super 可以认为是一种特殊的 Digest 认证。具有 Super 权限的客户端可以对 Zookeeper 上的任意数据节点进行任意操作。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;授权对象（ID）&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;授权对象就是说我们要把权限赋予谁，而对应于 4 种不同的权限模式来说，如果我们选择采用 IP 方式，使用的授权对象可以是一个 IP 地址或 IP 地址段；而如果使用 Digest 或 Super 方式，则对应于一个用户名。如果是 World 模式，是授权系统中所有的用户。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;权限信息（Permission）&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;权限就是指我们可以在数据节点上执行的操作种类，如下所示：在 Zookeeper 中已经定义好的权限有 5 种：&lt;/p&gt;
&lt;p&gt;数据节点（c: create）创建权限，授予权限的对象可以在数据节点下创建子节点；&lt;br&gt;
数据节点（w: wirte）更新权限，授予权限的对象可以更新该数据节点；&lt;br&gt;
数据节点（r: read）读取权限，授予权限的对象可以读取该节点的内容以及子节点的列表信息；&lt;br&gt;
数据节点（d: delete）删除权限，授予权限的对象可以删除该数据节点的子节点；&lt;br&gt;
数据节点（a: admin）管理者权限，授予权限的对象可以对该数据节点体进行 ACL 权限设置。&lt;/p&gt;
&lt;p&gt;通过系统参数 &lt;code&gt;zookeeper.skipACL=yes&lt;/code&gt;  进行配置，默认是 no, 可以配置为 true, 则配置过的 ACL 将不再进行权限检测&lt;/p&gt;
&lt;h3 id=&#34;生成授权id&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#生成授权id&#34;&gt;#&lt;/a&gt; 生成授权 ID&lt;/h3&gt;
&lt;p&gt;A - 代码生成 ID:&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Test&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;generateSuperDigest&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; NoSuchAlgorithmException &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String sId = DigestAuthenticationProvider.generateDigest(&lt;span class=&#34;string&#34;&gt;&amp;quot;gj:test&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(sId);&lt;span class=&#34;comment&#34;&gt;//  gj:X/NSthOB0fD/OT6iilJ55WJVado=&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;B - 在 x shell 中生成：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;echo -n &amp;lt;user&amp;gt;:&amp;lt;password&amp;gt; | openssl dgst -binary -sha1 | openssl base64&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;设置acl&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#设置acl&#34;&gt;#&lt;/a&gt; 设置 ACL&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 节点创建的同时设置ACL&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create [-s] [-e] [-c]   path [data] [acl]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create /zk-node datatest digest:gj:X/NSthOB0fD/OT6iilJ55WJVado=:cdrwa&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 用setAcl 设置&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;setAcl /zk-node  digest:gj:X/NSthOB0fD/OT6iilJ55WJVado=:cdrwa&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 添加授权信息后，不能直接访问，直接访问将报如下异常&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;=================================================================&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 访问前需要添加授权信息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;addauth digest gj:test&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;get /zk-node&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;datatest&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 另一种授权模式： auth 明文授权&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 使用之前需要先&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; addauth  digest username:password  注册用户信息，后续可以直接用明文授权&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;addauth digest u100:p100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create /node-1 node1data auth:u100:p100:cdwra&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 这是u100用户授权信息会被zk保存，可以认为当前的授权用户为u100&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;get /node-1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;node1data&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; IP授权模式：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;setAcl /node-ip ip:192.168.109.128:cdwra&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create /node-ip  data  ip:192.168.109.128:cdwra&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 多个指定IP可以通过逗号分隔， 如 setAcl /node-ip  ip:IP1:rw,ip:IP2:a&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; Super 超级管理员模式&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 这是一种特殊的Digest模式， 在Super模式下超级管理员用户可以对Zookeeper上的节点进行任何的操作。需要在启动了上通过JVM 系统参数开启：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DigestAuthenticationProvider中定义&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-Dzookeeper.DigestAuthenticationProvider.superDigest=super:&amp;lt;base64encoded(SHA1(password))&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;zookeeper-内存数据和持久化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#zookeeper-内存数据和持久化&#34;&gt;#&lt;/a&gt; Zookeeper 内存数据和持久化&lt;/h2&gt;
&lt;p&gt;数据的组织形式为一个类似文件系统的数据结构，而这些数据都是存储在内存中的，所以我们可以认为，Zookeeper 是一个基于内存的小型数据库&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 内存中的数据：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;DataTree&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; ConcurrentHashMap&amp;lt;String, DataNode&amp;gt; nodes =&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ConcurrentHashMap&amp;lt;String, DataNode&amp;gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; WatchManager dataWatches = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; WatchManager();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; WatchManager childWatches = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; WatchManager();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// DataNode 是Zookeeper存储节点数据的最小单位&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;DataNode&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Record&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;byte&lt;/span&gt; data[];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Long acl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; StatPersisted stat;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; Set&amp;lt;String&amp;gt; children = &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;WebSocket 协议是基于 TCP 的一种新的网络协议。实现了浏览器与服务器全双工 (full-duplex) 通信 —— 允许服务器主动发送信息给客户端。http 协议通信只能由客户端发起请求，做不到服务器直接推送消息给客户端。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;maven依赖&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#maven依赖&#34;&gt;#&lt;/a&gt; Maven 依赖&lt;/h2&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;org.springframework.boot&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;spring-boot-starter-websocket&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;2.1.7.RELEASE&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;websocketconfig&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#websocketconfig&#34;&gt;#&lt;/a&gt; WebSocketConfig&lt;/h2&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.context.annotation.Bean;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.context.annotation.Configuration;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.web.socket.server.standard.ServerEndpointExporter;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 开启webSocket&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:00&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Configuration&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;WebSocketConfig&lt;/span&gt; &lt;/span&gt;&amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; ServerEndpointExporter &lt;span class=&#34;title&#34;&gt;serverEndpointExporter&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ServerEndpointExporter();  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;websocketserver&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#websocketserver&#34;&gt;#&lt;/a&gt; WebSocketServer&lt;/h2&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; com.alibaba.fastjson.JSON;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; com.alibaba.fastjson.JSONObject;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; lombok.extern.slf4j.Slf4j;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.stereotype.Component;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.util.StringUtils;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; javax.websocket.*;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; javax.websocket.server.PathParam;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; javax.websocket.server.ServerEndpoint;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.IOException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.util.concurrent.ConcurrentHashMap;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 接受客户端连接&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:00&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@ServerEndpoint(&amp;quot;/imserver/&amp;#123;userId&amp;#125;&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Component&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Slf4j&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;WebSocketServer&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * 静态变量，用来记录当前在线连接数。应该把它设计成线程安全的。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt; onlineCount = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * concurrent包的线程安全Set，用来存放每个客户端对应的MyWebSocket对象。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; ConcurrentHashMap&amp;lt;String, WebSocketServer&amp;gt; webSocketMap = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ConcurrentHashMap&amp;lt;&amp;gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * 与某个客户端的连接会话，需要通过它来给客户端发送数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; Session session;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * 接收userId&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; String userId = &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 建立成功后调用的方法&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:02&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@OnOpen&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;onOpen&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(Session session, &lt;span class=&#34;meta&#34;&gt;@PathParam(&amp;quot;userId&amp;quot;)&lt;/span&gt; String userId)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.session = session;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.userId = userId;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (webSocketMap.containsKey(userId)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            webSocketMap.remove(userId);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            webSocketMap.put(userId, &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            webSocketMap.put(userId, &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// 在线人数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            addOnlineCount();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        log.info(&lt;span class=&#34;string&#34;&gt;&amp;quot;用户连接:&amp;quot;&lt;/span&gt; + userId + &lt;span class=&#34;string&#34;&gt;&amp;quot;,当前在线人数为:&amp;quot;&lt;/span&gt; + getOnlineCount());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            sendMessage(&lt;span class=&#34;string&#34;&gt;&amp;quot;连接成功&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (IOException e) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            log.error(&lt;span class=&#34;string&#34;&gt;&amp;quot;用户:&amp;quot;&lt;/span&gt; + userId + &lt;span class=&#34;string&#34;&gt;&amp;quot;,网络异常!!!!!!&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 连接关闭调用的方法&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:04&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@OnClose&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;onClose&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (webSocketMap.containsKey(userId)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//从set中删除&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            webSocketMap.remove(userId);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            subOnlineCount();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        log.info(&lt;span class=&#34;string&#34;&gt;&amp;quot;用户退出:&amp;quot;&lt;/span&gt; + userId + &lt;span class=&#34;string&#34;&gt;&amp;quot;,当前在线人数为:&amp;quot;&lt;/span&gt; + getOnlineCount());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@description&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@param&lt;/span&gt; message 客户端发送过来的消息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@param&lt;/span&gt; session 客户端session&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:04&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@OnMessage&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;onMessage&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String message, Session session)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        log.info(&lt;span class=&#34;string&#34;&gt;&amp;quot;用户消息:&amp;quot;&lt;/span&gt; + userId + &lt;span class=&#34;string&#34;&gt;&amp;quot;,报文:&amp;quot;&lt;/span&gt; + message);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//可以群发消息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//消息保存到数据库、redis&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!StringUtils.isEmpty(message)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;//解析发送的报文&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                JSONObject jsonObject = JSON.parseObject(message);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;//追加发送人(防止串改)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                jsonObject.put(&lt;span class=&#34;string&#34;&gt;&amp;quot;fromUserId&amp;quot;&lt;/span&gt;, &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.userId);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                String toUserId = jsonObject.getString(&lt;span class=&#34;string&#34;&gt;&amp;quot;toUserId&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;//传送给对应toUserId用户的websocket&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!StringUtils.isEmpty(toUserId) &amp;amp;&amp;amp; webSocketMap.containsKey(toUserId)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    webSocketMap.get(toUserId).sendMessage(jsonObject.toJSONString());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    log.error(&lt;span class=&#34;string&#34;&gt;&amp;quot;请求的userId:&amp;quot;&lt;/span&gt; + toUserId + &lt;span class=&#34;string&#34;&gt;&amp;quot;不在该服务器上&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;comment&#34;&gt;//否则不在这个服务器上，发送到mysql或者redis&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (Exception e) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                e.printStackTrace();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 发送消息错误时&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@param&lt;/span&gt; session 客户端session&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@param&lt;/span&gt; error 错误&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:07&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@OnError&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;onError&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(Session session, Throwable error)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        log.error(&lt;span class=&#34;string&#34;&gt;&amp;quot;用户错误:&amp;quot;&lt;/span&gt; + &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.userId + &lt;span class=&#34;string&#34;&gt;&amp;quot;,原因:&amp;quot;&lt;/span&gt; + error.getMessage());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        error.printStackTrace();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 服务器主动推送消息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:09&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sendMessage&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String message)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; IOException &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.session.getBasicRemote().sendText(message);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 发送自定义消息&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:10&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sendInfo&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String message, &lt;span class=&#34;meta&#34;&gt;@PathParam(&amp;quot;userId&amp;quot;)&lt;/span&gt; String userId)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; IOException &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        log.info(&lt;span class=&#34;string&#34;&gt;&amp;quot;发送消息到:&amp;quot;&lt;/span&gt; + userId + &lt;span class=&#34;string&#34;&gt;&amp;quot;，报文:&amp;quot;&lt;/span&gt; + message);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!StringUtils.isEmpty(userId) &amp;amp;&amp;amp; webSocketMap.containsKey(userId)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            webSocketMap.get(userId).sendMessage(message);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            log.error(&lt;span class=&#34;string&#34;&gt;&amp;quot;用户&amp;quot;&lt;/span&gt; + userId + &lt;span class=&#34;string&#34;&gt;&amp;quot;,不在线！&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 获取当前在线人数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:10&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;synchronized&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;getOnlineCount&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; onlineCount;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 增加在线人数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:10&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;synchronized&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;addOnlineCount&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        WebSocketServer.onlineCount++;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 在线人数减1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:11&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;synchronized&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;subOnlineCount&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        WebSocketServer.onlineCount--;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;测试controller&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#测试controller&#34;&gt;#&lt;/a&gt; 测试 Controller&lt;/h2&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; com.sunfy.config.WebSocketServer;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.http.ResponseEntity;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.web.bind.annotation.GetMapping;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.web.bind.annotation.PathVariable;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.web.bind.annotation.RequestMapping;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.web.bind.annotation.RestController;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.web.servlet.ModelAndView;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.io.IOException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 测试Controller&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/11/18 上午9:13&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RestController&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;DemoController&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@GetMapping(&amp;quot;index&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; ResponseEntity&amp;lt;String&amp;gt; &lt;span class=&#34;title&#34;&gt;index&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; ResponseEntity.ok(&lt;span class=&#34;string&#34;&gt;&amp;quot;请求成功&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@GetMapping(&amp;quot;page&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; ModelAndView &lt;span class=&#34;title&#34;&gt;page&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ModelAndView(&lt;span class=&#34;string&#34;&gt;&amp;quot;websocket&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@RequestMapping(&amp;quot;/push/&amp;#123;toUserId&amp;#125;&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; ResponseEntity&amp;lt;String&amp;gt; &lt;span class=&#34;title&#34;&gt;pushToWeb&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String message, &lt;span class=&#34;meta&#34;&gt;@PathVariable&lt;/span&gt; String toUserId)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; IOException &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        WebSocketServer.sendInfo(message,toUserId);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; ResponseEntity.ok(&lt;span class=&#34;string&#34;&gt;&amp;quot;MSG SEND SUCCESS&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;前端测试代码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#前端测试代码&#34;&gt;#&lt;/a&gt; 前端测试代码&lt;/h2&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;!DOCTYPE &lt;span class=&#34;meta-keyword&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;head&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;meta&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;charset&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;utf-8&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;title&lt;/span&gt;&amp;gt;&lt;/span&gt;websocket通讯&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;title&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;head&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;script&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;https://cdn.bootcss.com/jquery/3.3.1/jquery.js&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;script&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;script&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; socket;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;openSocket&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (&lt;span class=&#34;keyword&#34;&gt;typeof&lt;/span&gt; (WebSocket) == &lt;span class=&#34;string&#34;&gt;&amp;quot;undefined&amp;quot;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(&lt;span class=&#34;string&#34;&gt;&amp;quot;您的浏览器不支持WebSocket&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(&lt;span class=&#34;string&#34;&gt;&amp;quot;您的浏览器支持WebSocket&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//实现化WebSocket对象，指定要连接的服务器地址与端口  建立连接&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//等同于socket = new WebSocket(&amp;quot;ws://localhost:8888/xxxx/im/25&amp;quot;);&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//var socketUrl=&amp;quot;$&amp;#123;request.contextPath&amp;#125;/im/&amp;quot;+$(&amp;quot;#userId&amp;quot;).val();&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; socketUrl = &lt;span class=&#34;string&#34;&gt;&amp;quot;http://localhost:8080/imserver/&amp;quot;&lt;/span&gt; + $(&lt;span class=&#34;string&#34;&gt;&amp;quot;#userId&amp;quot;&lt;/span&gt;).val();&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            socketUrl = socketUrl.replace(&lt;span class=&#34;string&#34;&gt;&amp;quot;https&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;ws&amp;quot;&lt;/span&gt;).replace(&lt;span class=&#34;string&#34;&gt;&amp;quot;http&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;ws&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(socketUrl);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (socket != &lt;span class=&#34;literal&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                socket.close();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;                socket = &lt;span class=&#34;literal&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            socket = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; WebSocket(socketUrl);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//打开事件&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            socket.onopen = &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;                &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(&lt;span class=&#34;string&#34;&gt;&amp;quot;websocket已打开&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;//socket.send(&amp;quot;这是来自客户端的消息&amp;quot; + location.href + new Date());&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//获得消息事件&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            socket.onmessage = &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;msg&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;                &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(msg.data);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;//发现消息进入    开始处理前端触发逻辑&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//关闭事件&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            socket.onclose = &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;                &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(&lt;span class=&#34;string&#34;&gt;&amp;quot;websocket已关闭&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//发生了错误事件&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            socket.onerror = &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;                &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(&lt;span class=&#34;string&#34;&gt;&amp;quot;websocket发生了错误&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sendMessage&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (&lt;span class=&#34;keyword&#34;&gt;typeof&lt;/span&gt; (WebSocket) == &lt;span class=&#34;string&#34;&gt;&amp;quot;undefined&amp;quot;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(&lt;span class=&#34;string&#34;&gt;&amp;quot;您的浏览器不支持WebSocket&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(&lt;span class=&#34;string&#34;&gt;&amp;quot;您的浏览器支持WebSocket&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            &lt;span class=&#34;built_in&#34;&gt;console&lt;/span&gt;.log(&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#123;&amp;quot;toUserId&amp;quot;:&amp;quot;&amp;#x27;&lt;/span&gt; + $(&lt;span class=&#34;string&#34;&gt;&amp;quot;#toUserId&amp;quot;&lt;/span&gt;).val() + &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;,&amp;quot;contentText&amp;quot;:&amp;quot;&amp;#x27;&lt;/span&gt; + $(&lt;span class=&#34;string&#34;&gt;&amp;quot;#contentText&amp;quot;&lt;/span&gt;).val() + &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#125;&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;javascript&#34;&gt;            socket.send(&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#123;&amp;quot;toUserId&amp;quot;:&amp;quot;&amp;#x27;&lt;/span&gt; + $(&lt;span class=&#34;string&#34;&gt;&amp;quot;#toUserId&amp;quot;&lt;/span&gt;).val() + &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;,&amp;quot;contentText&amp;quot;:&amp;quot;&amp;#x27;&lt;/span&gt; + $(&lt;span class=&#34;string&#34;&gt;&amp;quot;#contentText&amp;quot;&lt;/span&gt;).val() + &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#125;&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;script&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;body&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;p&lt;/span&gt;&amp;gt;&lt;/span&gt;【userId】：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;input&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;id&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;userId&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;name&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;userId&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;value&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;10&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;p&lt;/span&gt;&amp;gt;&lt;/span&gt;【toUserId】：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;input&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;id&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;toUserId&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;name&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;toUserId&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;value&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;20&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;p&lt;/span&gt;&amp;gt;&lt;/span&gt;【toUserId】：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;input&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;id&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;contentText&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;name&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;contentText&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;value&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;hello websocket&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;p&lt;/span&gt;&amp;gt;&lt;/span&gt;【操作】：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;onclick&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;openSocket()&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;开启socket&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;a&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;p&lt;/span&gt;&amp;gt;&lt;/span&gt;【操作】：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;onclick&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;sendMessage()&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;发送消息&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;a&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;body&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;SPI ，全称为 Service Provider Interface，是一种服务发现机制。在 ClassPath 路径下的 META-INF/services 文件夹查找文件，自动加载文件里所定义的类。&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;h2 id=&#34;一-什么是spi&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#一-什么是spi&#34;&gt;#&lt;/a&gt; 一、什么是 SPI&lt;/h2&gt;
&lt;p&gt;SPI ，全称为 Service Provider Interface，是一种服务发现机制。通过在 ClassPath 路径下的 META-INF/services 文件夹查找文件，自动加载文件里所定义的类。&lt;/p&gt;
&lt;p&gt;这一机制为很多框架扩展提供了可能，比如在 Dubbo、JDBC 中都使用到了 SPI 机制。我们先通过一个很简单的例子来看下它是怎么用的。&lt;/p&gt;
&lt;h3 id=&#34;1-例子&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-例子&#34;&gt;#&lt;/a&gt; 1、例子&lt;/h3&gt;
&lt;p&gt;首先，我们需要定义一个接口，Animal&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.sunfy.Animal;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;interface&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Animal&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;noise&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后，定义两个实现类，没任何具体业务，简单输出一句话。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.sunfy.Animal;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Dog&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Animal&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;noise&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;wang&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--------------------------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.sunfy.Animal;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Cat&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Animal&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;noise&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;miao&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;最后呢，要在 ClassPath 路径下配置添加一个文件。文件名字是接口的全限定类名，内容是实现类的全限定类名，多个实现类用换行符分隔。&lt;br&gt;
文件路径如下：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210117225311670.png&#34; alt=&#34;image-20210117225311670&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210117225311670.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;SPI 配置文件位置&lt;/p&gt;
&lt;p&gt;内容就是实现类的全限定类名：&lt;/p&gt;
&lt;figure class=&#34;highlight css&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;com&lt;/span&gt;&lt;span class=&#34;selector-class&#34;&gt;.sunfy&lt;/span&gt;&lt;span class=&#34;selector-class&#34;&gt;.Animal&lt;/span&gt;&lt;span class=&#34;selector-class&#34;&gt;.Cat&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;com&lt;/span&gt;&lt;span class=&#34;selector-class&#34;&gt;.sunfy&lt;/span&gt;&lt;span class=&#34;selector-class&#34;&gt;.Animal&lt;/span&gt;&lt;span class=&#34;selector-class&#34;&gt;.Dog&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-测试&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-测试&#34;&gt;#&lt;/a&gt; 2、测试&lt;/h3&gt;
&lt;p&gt;然后我们就可以通过 &lt;code&gt;ServiceLoader.load或者Service.providers&lt;/code&gt;  方法拿到实现类的实例。其中， &lt;code&gt;Service.providers&lt;/code&gt;  包位于 &lt;code&gt;sun.misc.Service&lt;/code&gt; ，而 &lt;code&gt;ServiceLoader.load&lt;/code&gt;  包位于 &lt;code&gt;java.util.ServiceLoader&lt;/code&gt; 。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.sunfy;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; com.sunfy.Animal.Animal;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; sun.misc.Service;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.util.Iterator;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.util.ServiceLoader;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;SpiDemoMain&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String[] args)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// Spi机制获取Animal接口所有的实现类，在不修改业务代码的基础上，很方便的进行数据扩展&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ServiceLoader&amp;lt;Animal&amp;gt; animals = ServiceLoader.load(Animal.class);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        animals.forEach(animal -&amp;gt; animal.noise());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;--------------------------------&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Iterator&amp;lt;Animal&amp;gt; providers = Service.providers(Animal.class);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ServiceLoader&amp;lt;Animal&amp;gt; load = ServiceLoader.load(Animal.class);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt;(providers.hasNext()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Animal animal = providers.next();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            animal.noise();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;--------------------------------&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Iterator&amp;lt;Animal&amp;gt; iterator = load.iterator();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt;(iterator.hasNext()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Animal animal = iterator.next();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            animal.noise();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;两种方式的输出结果是一致的：&lt;/p&gt;
&lt;figure class=&#34;highlight css&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;miao&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;wang&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;--------------------------------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;miao&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;wang&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;--------------------------------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;miao&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;selector-tag&#34;&gt;wang&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;二-源码分析&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二-源码分析&#34;&gt;#&lt;/a&gt; 二、源码分析&lt;/h2&gt;
&lt;p&gt;我们看到一个位于 &lt;code&gt;sun.misc包&lt;/code&gt; ，一个位于 &lt;code&gt;java.util包&lt;/code&gt; ，sun 包下的源码看不到。我们就以 ServiceLoader.load 为例，通过源码看看它里面到底怎么做的。&lt;/p&gt;
&lt;h3 id=&#34;1-serviceloader&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-serviceloader&#34;&gt;#&lt;/a&gt; 1、ServiceLoader&lt;/h3&gt;
&lt;p&gt;首先，我们先来了解下 ServiceLoader，看看它的类结构。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ServiceLoader&lt;/span&gt;&amp;lt;&lt;span class=&#34;title&#34;&gt;S&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;class&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Iterable&lt;/span&gt;&amp;lt;&lt;span class=&#34;title&#34;&gt;S&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;class&#34;&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 配置文件路径&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; String PREFIX = &lt;span class=&#34;string&#34;&gt;&amp;quot;META-INF/services/&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// The class or interface representing the service being loaded&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 加载的服务类或接口&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; Class&amp;lt;S&amp;gt; service;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// The class loader used to locate, load, and instantiate providers&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 类加载器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; ClassLoader loader;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// The access control context taken when the ServiceLoader is created&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;final&lt;/span&gt; AccessControlContext acc;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// Cached providers, in instantiation order&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 已加载的服务类集合&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; LinkedHashMap&amp;lt;String,S&amp;gt; providers = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; LinkedHashMap&amp;lt;&amp;gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// The current lazy-lookup iterator&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 当前的惰性查找迭代器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; LazyIterator lookupIterator;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-load&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-load&#34;&gt;#&lt;/a&gt; 2、Load&lt;/h3&gt;
&lt;p&gt;load 方法创建了一些属性，重要的是实例化了内部类，LazyIterator。最后返回 ServiceLoader 的实例。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;reload&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    providers.clear();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 实例化ServiceLoader&amp;lt;S&amp;gt; 内部类&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    lookupIterator = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; LazyIterator(service, loader);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ServiceLoader&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(Class&amp;lt;S&amp;gt; svc, ClassLoader cl)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// svc，要加载类接口 非空校验&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    service = Objects.requireNonNull(svc, &lt;span class=&#34;string&#34;&gt;&amp;quot;Service interface cannot be null&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 返回用于委托的系统类加载器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    loader = (cl == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) ? ClassLoader.getSystemClassLoader() : cl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 获取系统安全性接口，及访问权限&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    acc = (System.getSecurityManager() != &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) ? AccessController.getContext() : &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 重新加载系统接口&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    reload();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;3-查找实现类&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-查找实现类&#34;&gt;#&lt;/a&gt; 3、查找实现类&lt;/h3&gt;
&lt;p&gt;查找实现类和创建实现类的过程，都在 LazyIterator 完成。当我们调用 iterator.hasNext 和 iterator.next 方法的时候，实际上调用的都是 LazyIterator 的相应方法。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &amp;lt;S&amp;gt; &lt;span class=&#34;function&#34;&gt;ServiceLoader&amp;lt;S&amp;gt; &lt;span class=&#34;title&#34;&gt;load&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(Class&amp;lt;S&amp;gt; service,&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;params&#34;&gt;                                        ClassLoader loader)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 调用load方法，最终还是调用ServiceLoader初始化方法，调用---》new LazyIterator(service, loader)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ServiceLoader&amp;lt;&amp;gt;(service, loader);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &amp;lt;S&amp;gt; &lt;span class=&#34;function&#34;&gt;ServiceLoader&amp;lt;S&amp;gt; &lt;span class=&#34;title&#34;&gt;load&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(Class&amp;lt;S&amp;gt; service)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ClassLoader cl = Thread.currentThread().getContextClassLoader();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; ServiceLoader.load(service, cl);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Iterator&amp;lt;S&amp;gt; &lt;span class=&#34;title&#34;&gt;iterator&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Iterator&amp;lt;S&amp;gt;() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;boolean&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;hasNext&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; lookupIterator.hasNext();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; S &lt;span class=&#34;title&#34;&gt;next&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; lookupIterator.next();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        .......&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;所以，我们重点关注 lookupIterator.hasNext () 方法，它最终会调用到 hasNextService。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//sunfy- SPI核心的获取实现类的方法&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;boolean&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;hasNextService&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 类名不等于Null,代表类已经加载完成&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (nextName != &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;true&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (configs == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// 待加载文件路径&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// PREFIX = &amp;quot;META-INF/services/&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// service.getName() 为自定义的类的全限定名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// META-INF/services/com.sunfy.Animal.Animal&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            String fullName = PREFIX + service.getName();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// 判断是否有传入类的加载器，如果传入则使用传入的，否则使用默认的类加载器加载&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (loader == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                configs = ClassLoader.getSystemResources(fullName);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                configs = loader.getResources(fullName);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (IOException x) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            fail(service, &lt;span class=&#34;string&#34;&gt;&amp;quot;Error locating configuration files&amp;quot;&lt;/span&gt;, x);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; ((pending == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) || !pending.hasNext()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!configs.hasMoreElements()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;false&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 将给定URL的内容解析为提供程序配置文件。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    	&lt;span class=&#34;comment&#34;&gt;// parse方法中，真正的解析文件，读取文件内容，并将读取内容封装后返回（此处只是读取到类的全限定名，还没有创建类对象）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        pending = parse(service, configs.nextElement());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 拿到第一个实现类的类名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    nextName = pending.next();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;true&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210118093328741.png&#34; alt=&#34;image-20210118093328741&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210118093328741.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210118093511722.png&#34; alt=&#34;image-20210118093511722&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210118093511722.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;4-创建实例&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-创建实例&#34;&gt;#&lt;/a&gt; 4、创建实例&lt;/h3&gt;
&lt;p&gt;当然，调用 next 方法的时候，实际调用到的是，lookupIterator.nextService。它通过反射的方式，创建实现类的实例并返回。&lt;/p&gt;
&lt;figure class=&#34;highlight&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; S &lt;span class=&#34;title&#34;&gt;next&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; ServiceConfigurationError &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!&lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.hasNext()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;throw&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; NoSuchElementException();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String var1 = &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.nextName;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.nextName = &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Class var2 = &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            var2 = Class.forName(var1, &lt;span class=&#34;keyword&#34;&gt;false&lt;/span&gt;, &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.loader);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            ......&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-------------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# 无论调用的是哪种便利的方法，都会在next的遍历方法中调用Class.forName()反射生成最终的我们所需要的类对象&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;看到这儿，我想已经很清楚了。获取到类的实例，我们自然就可以对它为所欲为了！&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210118095331736.png&#34; alt=&#34;image-20210118095331736&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210118095331736.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;三-jdbc中的应用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三-jdbc中的应用&#34;&gt;#&lt;/a&gt; 三、JDBC 中的应用&lt;/h2&gt;
&lt;p&gt;我们开头说，SPI 机制为很多框架的扩展提供了可能，其实 JDBC 就应用到了这一机制。回忆一下 JDBC 获取数据库连接的过程。在早期版本中，需要先设置数据库驱动的连接，再通过 DriverManager.getConnection 获取一个 Connection。&lt;/p&gt;
&lt;figure class=&#34;highlight dart&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;String&lt;/span&gt; url = &lt;span class=&#34;string&#34;&gt;&amp;quot;jdbc:mysql:///consult?serverTimezone=UTC&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;String&lt;/span&gt; user = &lt;span class=&#34;string&#34;&gt;&amp;quot;root&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;String&lt;/span&gt; password = &lt;span class=&#34;string&#34;&gt;&amp;quot;root&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Class.forName(&lt;span class=&#34;string&#34;&gt;&amp;quot;com.mysql.jdbc.Driver&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Connection connection = DriverManager.getConnection(url, user, password);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;在较新版本中，设置数据库驱动连接，这一步骤就不再需要，那么它是怎么分辨是哪种数据库的呢？答案就是 SPI 机制。&lt;/p&gt;
&lt;h3 id=&#34;1-加载&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-加载&#34;&gt;#&lt;/a&gt; 1、加载&lt;/h3&gt;
&lt;p&gt;我们把目光回到 &lt;code&gt;DriverManager&lt;/code&gt;  类，它在静态代码块里面做了一件比较重要的事。很明显，它已经通过 SPI 机制， 把数据库驱动连接初始化了。&lt;/p&gt;
&lt;figure class=&#34;highlight swift&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;DriverManager&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        loadInitialDrivers();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;built_in&#34;&gt;println&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;JDBC DriverManager initialized&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;具体过程还得看 loadInitialDrivers，它在里面查找的是 Driver 接口的服务类，所以它的文件路径就是：META-INF/services/java.sql.Driver。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;DriverManager&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;loadInitialDrivers&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        AccessController.doPrivileged(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; PrivilegedAction&amp;lt;Void&amp;gt;() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Void &lt;span class=&#34;title&#34;&gt;run&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;//很明显，它要加载Driver接口的服务类，Driver接口的包为:java.sql.Driver&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;//所以它要找的就是META-INF/services/java.sql.Driver文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                ServiceLoader&amp;lt;Driver&amp;gt; loadedDrivers = ServiceLoader.load(Driver.class);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Iterator&amp;lt;Driver&amp;gt; driversIterator = loadedDrivers.iterator();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;comment&#34;&gt;//查到之后创建对象&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt;(driversIterator.hasNext()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                        driversIterator.next();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt;(Throwable t) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;comment&#34;&gt;// Do nothing&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;那么，这个文件哪里有呢？我们来看 MySQL 的 jar 包，就是这个文件，文件内容为： &lt;code&gt;com.mysql.cj.jdbc.Driver&lt;/code&gt; 。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210118104816954.png&#34; alt=&#34;image-20210118104816954&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210118104816954.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210118102603390.png&#34; alt=&#34;image-20210118102603390&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210118102603390.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;MySQL SPI 文件&lt;/p&gt;
&lt;h3 id=&#34;2-创建实例&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-创建实例&#34;&gt;#&lt;/a&gt; 2、创建实例&lt;/h3&gt;
&lt;p&gt;上一步已经找到了 MySQL 中的 com.mysql.cj.jdbc.Driver 全限定类名，当调用 next 方法时，就会创建这个类的实例。它就完成了一件事，向 DriverManager 注册自身的实例。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.mysql.jdbc;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Driver&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;NonRegisteringDriver&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;java&lt;/span&gt;.&lt;span class=&#34;title&#34;&gt;sql&lt;/span&gt;.&lt;span class=&#34;title&#34;&gt;Driver&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//注册&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//调用DriverManager类的注册方法&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//往registeredDrivers集合中加入实例&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            java.sql.DriverManager.registerDriver(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Driver());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (SQLException E) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;throw&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; RuntimeException(&lt;span class=&#34;string&#34;&gt;&amp;quot;Can&amp;#x27;t register driver!&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Driver&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; SQLException &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// Required for Class.forName().newInstance()&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;3-创建connection&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-创建connection&#34;&gt;#&lt;/a&gt; 3、创建 Connection&lt;/h3&gt;
&lt;p&gt;在 DriverManager.getConnection () 方法就是创建连接的地方，它通过循环已注册的数据库驱动程序，调用其 connect 方法，获取连接并返回。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; Connection &lt;span class=&#34;title&#34;&gt;getConnection&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;params&#34;&gt;        String url, java.util.Properties info, Class&amp;lt;?&amp;gt; caller)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; SQLException &lt;/span&gt;&amp;#123;   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//registeredDrivers中就包含com.mysql.cj.jdbc.Driver实例&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt;(DriverInfo aDriver : registeredDrivers) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(isDriverAllowed(aDriver.driver, callerCL)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;comment&#34;&gt;//调用connect方法创建连接&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Connection con = aDriver.driver.connect(url, info);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (con != &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; (con);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (SQLException ex) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (reason == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    reason = ex;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            println(&lt;span class=&#34;string&#34;&gt;&amp;quot;    skipping: &amp;quot;&lt;/span&gt; + aDriver.getClass().getName());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;4-再扩展&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-再扩展&#34;&gt;#&lt;/a&gt; 4、再扩展&lt;/h3&gt;
&lt;p&gt;既然我们知道 JDBC 是这样创建数据库连接的，我们能不能再扩展一下呢？如果我们自己也创建一个 java.sql.Driver 文件，自定义实现类 MyDriver，那么，在获取连接的前后就可以动态修改一些信息。&lt;/p&gt;
&lt;p&gt;还是先在项目 ClassPath 下创建文件，文件内容为自定义驱动类 &lt;code&gt;com.viewscenes.netsupervisor.spi.MyDriver&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;自定义数据库驱动程序&lt;/p&gt;
&lt;p&gt;我们的 MyDriver 实现类，继承自 MySQL 中的 NonRegisteringDriver，还要实现 java.sql.Driver 接口。这样，在调用 connect 方法的时候，就会调用到此类，但实际创建的过程还靠 MySQL 完成。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;package&lt;/span&gt; com.viewscenes.netsupervisor.spi&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;MyDriver&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;NonRegisteringDriver&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Driver&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            java.sql.DriverManager.registerDriver(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; MyDriver());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (SQLException E) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;throw&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; RuntimeException(&lt;span class=&#34;string&#34;&gt;&amp;quot;Can&amp;#x27;t register driver!&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;MyDriver&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; SQLException &lt;/span&gt;&amp;#123;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Connection &lt;span class=&#34;title&#34;&gt;connect&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String url, Properties info)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; SQLException &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;准备创建数据库连接.url:&amp;quot;&lt;/span&gt;+url);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;JDBC配置信息：&amp;quot;&lt;/span&gt;+info);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        info.setProperty(&lt;span class=&#34;string&#34;&gt;&amp;quot;user&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;root&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Connection connection =  &lt;span class=&#34;keyword&#34;&gt;super&lt;/span&gt;.connect(url, info);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;数据库连接创建完成!&amp;quot;&lt;/span&gt;+connection.toString());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; connection;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--------------------输出结果---------------------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;准备创建数据库连接.url:jdbc:mysql:&lt;span class=&#34;comment&#34;&gt;///consult?serverTimezone=UTC&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;JDBC配置信息：&amp;#123;user=root, password=root&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;数据库连接创建完成!com.mysql.cj.jdbc.ConnectionImpl@&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;cf10a6f&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;四-其他应用场景&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#四-其他应用场景&#34;&gt;#&lt;/a&gt; 四、其他应用场景&lt;/h2&gt;
&lt;h4 id=&#34;shardingsphere&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#shardingsphere&#34;&gt;#&lt;/a&gt; ShardingSphere&lt;/h4&gt;
&lt;p&gt;分布式数据库中间件中使用了非常多的 SPI 来提高 ShardingSphere 的可扩展性&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210118104256438.png&#34; alt=&#34;image-20210118104256438&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210118104256438.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;Docker 搭建 Jenkins 实现自动部署&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;自动化部署（持续集成 / CI + 持续交付 / CD）不仅可以提升开发效率，让程序员更专注产品与业务的开发，还可以节省很多运维成本以及提升运维效率。其中，Jenkins 是自动化部署中最流行的工具，尤其是 Docker+Jenkins 的完美搭配，每个程序员都应该掌握这两个工具的使用。&lt;/p&gt;
&lt;p&gt;环境配置&lt;br&gt;
操作系统：CentOS Linux release 7.6.1810&lt;br&gt;
Docker 版本：19.03.5&lt;br&gt;
Jenkins 版本：2.204.1&lt;br&gt;
Docker 安装 Jenkins&lt;br&gt;
Docker 下载 Jenkins&lt;br&gt;
docker pull jenkins/jenkins:lts // 最新版&lt;br&gt;
查看 Jenkins 镜像&lt;br&gt;
 docker images&lt;br&gt;
docker inspect jenkins 镜像 ID&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230257822.png&#34; alt=&#34;image-20210222230257822&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230257822.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;创建一个 Jenkins 目录&lt;br&gt;
 mkdir /data/jenkins_home;&lt;br&gt;
 安装启动 Jenkins 容器&lt;br&gt;
 docker run -d --name jenkins -p 8081:8080 -v /data/jenkins_home:/var/jenkins_home jenkins/jenkins:lts;&lt;br&gt;
 备注：&lt;br&gt;
-d // 启动在后台&lt;br&gt;
–name // 容器名字&lt;br&gt;
 - p // 端口映射（8081：宿主主机端口，8080：容器内部端口）&lt;br&gt;
-v // 数据卷挂载映射（/data/jenkins_home：宿主主机目录，另外一个即是容器目录）&lt;br&gt;
enkins/jenkins:lts //Jenkins 镜像（最新版）&lt;br&gt;
查看 Jenkins 启动情况&lt;br&gt;
 docker ps | grep jenkins;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230336460.png&#34; alt=&#34;image-20210222230336460&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230336460.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;安装过程遇到的小问题&lt;br&gt;
 Jenkins 容器 docker run 之后状态总是 Exited&lt;br&gt;
 查看 docker 日志 ：&lt;br&gt;
docker logs jenkins&lt;br&gt;
 发现是目前权限问题&lt;br&gt;
因为 /data/jenkins_home 目录是 root 权限&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230353895.png&#34; alt=&#34;image-20210222230353895&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230353895.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230422305.png&#34; alt=&#34;image-20210222230422305&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230422305.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;解决：&lt;br&gt;
chown -R 1000:1000 /data/jenkins_home// 用户组改变&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230437518.png&#34; alt=&#34;image-20210222230437518&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230437518.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;宿主主机端口要开启&lt;br&gt;
因为本操作是在阿里云 ECS 上进行安装的，需要在安全组里开放 8081 此端口。&lt;br&gt;
访问 Jenkins&lt;br&gt;
&lt;a href=&#34;http://120.26.50.165:8081&#34;&gt;http://120.26.50.165:8081&lt;/a&gt; //ip: 端口号&lt;br&gt;
管理配置 Jenkins&lt;br&gt;
 解锁&lt;br&gt;
在安装完成后，默认生成了一个登录密码，首次登录需要这个密码。&lt;br&gt;
密码路径：var/jenkins_home/secrets/initialAdminPassword// 容器内部&lt;br&gt;
查找密码：&lt;br&gt;
docker exec -it jenkins_01 bash // 进入 jenkins 容器&lt;br&gt;
 cat /var/jenkins_home/secrets/initialAdminPassword// 查看密码&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230458505.png&#34; alt=&#34;image-20210222230458505&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230458505.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;安装插件&lt;br&gt;
新手安装建议选择：Install suggested plugins，安装过程大概半个多小时。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230522215.png&#34; alt=&#34;image-20210222230522215&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230522215.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230703546.png&#34; alt=&#34;image-20210222230703546&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230703546.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;管理用户创建&lt;br&gt;
这个用户就是最大管理者权限，相当于 admin&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230604348.png&#34; alt=&#34;image-20210222230604348&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230604348.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;Jenkins 配置完成&lt;br&gt;
到此步，安装就大功告成！&lt;br&gt;
&lt;a href=&#34;http://120.26.50.165:8081&#34;&gt;http://120.26.50.165:8081&lt;/a&gt; //ip: 端口号&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230616065.png&#34; alt=&#34;image-20210222230616065&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230616065.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210222230629441.png&#34; alt=&#34;image-20210222230629441&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210222230629441.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;实现自动化部署&lt;br&gt;
有了 Jenkins，接下来就是代码的自动部署过程了。&lt;/p&gt;

 &lt;p&gt;shiro 授权框架，个人理解主要适合单体应用，分布式应用和微服务架构模式下需要改造重新实现一些功能才能使用。 &lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;基础环境&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基础环境&#34;&gt;#&lt;/a&gt; 基础环境&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;maven 依赖&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;org.apache.shiro&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;shiro-spring-boot-starter&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!-- shiro使用的是slf4j日志门面 --&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;log4j&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;log4j&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;基本配置类&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.authc.credential.HashedCredentialsMatcher;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.authc.pam.AtLeastOneSuccessfulStrategy;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.authc.pam.ModularRealmAuthenticator;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.cache.MemoryConstrainedCacheManager;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.realm.AuthenticatingRealm;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.realm.AuthorizingRealm;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.spring.web.ShiroFilterFactoryBean;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.web.mgt.CookieRememberMeManager;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.web.mgt.DefaultWebSecurityManager;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.web.servlet.Cookie;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.web.servlet.SimpleCookie;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.context.annotation.Bean;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.context.annotation.Configuration;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.util.Arrays;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.util.HashMap;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.util.Map;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/10/19 上午11:18&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Configuration&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;shiroConfig&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * Realm  系统资源&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * MyRealm类中已经注入，此处不需要重复&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     *&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//    @Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//    public Realm myRealm() &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//        return new MyRealm();&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//    &amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * SecurityManager 流程控制&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * 构造方法的形式引入，创建对象的时候就可以引入Realm&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; DefaultWebSecurityManager &lt;span class=&#34;title&#34;&gt;mySecurityManager&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(AuthorizingRealm myRealm, AuthenticatingRealm mobileRealm)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        DefaultWebSecurityManager securityManager = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; DefaultWebSecurityManager();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//密码加密&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HashedCredentialsMatcher matcher = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; HashedCredentialsMatcher();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 算法名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        matcher.setHashAlgorithmName(&lt;span class=&#34;string&#34;&gt;&amp;quot;MD5&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 迭代次数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        matcher.setHashIterations(&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        private String hashAlgorithm;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        private int hashIterations;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        private boolean hashSalted;   已经过时&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        private boolean storedCredentialsHexEncoded;  设置默认的&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        myRealm.setCredentialsMatcher(matcher);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mobileRealm.setCredentialsMatcher(matcher);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        securityManager.setRealms(Arrays.asList(myRealm, mobileRealm));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        securityManager.setRealm(myRealm);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 设置认证策略&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ModularRealmAuthenticator authenticator = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ModularRealmAuthenticator();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 设置认证策略为有一个成功即可&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        authenticator.setAuthenticationStrategy(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; AtLeastOneSuccessfulStrategy());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 设置所有的认证策略都返回成功&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        authenticator.setAuthenticationStrategy(new AllSuccessfulStrategy());&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 设置第一个认证策略返回成功后不再认证后续的&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        authenticator.setAuthenticationStrategy(new FirstSuccessfulStrategy());&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        authenticator.setRealms(Arrays.asList(myRealm, mobileRealm));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        securityManager.setAuthenticator(authenticator);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        CookieRememberMeManager cookieRememberMeManager = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; CookieRememberMeManager();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Cookie cookie = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; SimpleCookie(&lt;span class=&#34;string&#34;&gt;&amp;quot;rememberMe&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cookie.setHttpOnly(&lt;span class=&#34;keyword&#34;&gt;true&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cookie.setMaxAge(&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cookieRememberMeManager.setCookie(cookie);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         * 分布式环境需要自己改造以下功能&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;         */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 设置记住我功能&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        securityManager.setRememberMeManager(cookieRememberMeManager);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// session 共享&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        securityManager.setSessionManager();&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 缓存&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        MemoryConstrainedCacheManager memoryConstrainedCacheManager = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; MemoryConstrainedCacheManager();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        securityManager.setCacheManager(memoryConstrainedCacheManager);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; securityManager;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * ShiroFilterFactoryBean 请求过滤器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; ShiroFilterFactoryBean &lt;span class=&#34;title&#34;&gt;getShiroFilterFactoryBean&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DefaultWebSecurityManager mySecurityManager)&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ShiroFilterFactoryBean factoryBean = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ShiroFilterFactoryBean();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        factoryBean.setSecurityManager(mySecurityManager);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 配置路径经过过滤器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Map&amp;lt;String, String&amp;gt; fifterMap = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; HashMap&amp;lt;&amp;gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// key是ant路径，value配置shiro的默认过滤器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// shiro的默认过滤器，配置DefaultFilter&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// anon(AnonymousFilter.class), 匿名过滤器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// authc(FormAuthenticationFilter.class), 认证（登录）使用&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// authcBasic(BasicHttpAuthenticationFilter.class),  认证不通过跳转登录页&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// authcBearer(BearerHttpAuthenticationFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// logout(LogoutFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// noSessionCreation(NoSessionCreationFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// perms(PermissionsAuthorizationFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// port(PortFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// rest(HttpMethodPermissionFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// roles(RolesAuthorizationFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// ssl(SslFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// user(UserFilter.class),&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// invalidRequest(InvalidRequestFilter.class);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        fifterMap.put(&amp;quot;/mobile/**&amp;quot;, &amp;quot;authc, perms[mobile]&amp;quot;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        fifterMap.put(&lt;span class=&#34;string&#34;&gt;&amp;quot;/salary/**&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;authc, perms[salary]&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 相当与登出方法 使用shiro提供的logout过滤器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        fifterMap.put(&lt;span class=&#34;string&#34;&gt;&amp;quot;/common/logout&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;logout&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 设置登录页&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        factoryBean.setLoginUrl(&lt;span class=&#34;string&#34;&gt;&amp;quot;/index.html&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 定制未授权页面&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        factoryBean.setUnauthorizedUrl(&lt;span class=&#34;string&#34;&gt;&amp;quot;/common/unAuth&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// iml文件中进行相应的配置，也可以直接手动写&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        factoryBean.setFilterChainDefinitions(&amp;quot;/mobile/**=authc&amp;quot;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        factoryBean.setFilterChainDefinitionMap(fifterMap);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; factoryBean;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;实现登录验证功能&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#实现登录验证功能&#34;&gt;#&lt;/a&gt; 实现登录验证功能&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;创建 Realm 对象，继承  &lt;code&gt;AuthorizingRealm&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;实现父类的方法
&lt;ol&gt;
&lt;li&gt;授权方法 &lt;code&gt;doGetAuthorizationInfo&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;认证方法 &lt;code&gt;doGetAuthenticationInfo&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// Realm配置文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; com.sunfy.shiroWeb.bean.UserBean;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; com.sunfy.shiroWeb.service.UserService;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.authc.*;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.authz.AuthorizationInfo;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.authz.SimpleAuthorizationInfo;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.realm.AuthorizingRealm;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.subject.PrincipalCollection;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.util.ByteSource;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.slf4j.Logger;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.slf4j.LoggerFactory;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.beans.factory.annotation.Autowired;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.context.annotation.Configuration;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/10/19 上午11:21&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Configuration&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;MyRealm&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;AuthorizingRealm&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Autowired&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; UserService userService;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; Logger logger = LoggerFactory.getLogger(MyRealm.class);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * 授权&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@param&lt;/span&gt; principalCollection&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; AuthorizationInfo &lt;span class=&#34;title&#34;&gt;doGetAuthorizationInfo&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(PrincipalCollection principalCollection)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        logger.info(&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;gt;&amp;gt;&amp;gt;entered MyRealm doGetAuthorizationInfo method&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        SimpleAuthorizationInfo simpleAuthorizationInfo = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; SimpleAuthorizationInfo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 获得当前用户&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        UserBean userBean = (UserBean) principalCollection.asList().get(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 绑定角色和资源&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        simpleAuthorizationInfo.addRoles(userBean.getUserRoles());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        simpleAuthorizationInfo.addStringPermissions(userBean.getUserPerms());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; simpleAuthorizationInfo;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * 认证&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@param&lt;/span&gt; authenticationToken&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@throws&lt;/span&gt; AuthenticationException&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; AuthenticationInfo &lt;span class=&#34;title&#34;&gt;doGetAuthenticationInfo&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(AuthenticationToken authenticationToken)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; AuthenticationException &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        logger.info(&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;&amp;lt;&amp;lt;entered MyRealm doGetAuthenticationInfo method&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 获得当前用户&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        UsernamePasswordToken userToken = (UsernamePasswordToken) authenticationToken;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String userName = userToken.getUsername();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 获得数据库中密码，来跟当前用户进行比对，认证。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        UserBean userBean = userService.queryUserByName(userName);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 如果没有查到，没有这个用户&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (userBean == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// shiro判断 抛出 UnknownAccountException 异常提醒&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ByteSource salt = ByteSource.Util.bytes(&lt;span class=&#34;string&#34;&gt;&amp;quot;salt&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 返回 AuthenticationInfo 完成认证流程（密码比较认证shiro进行认证）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        SimpleAuthenticationInfo simpleAuthenticationInfo =&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; SimpleAuthenticationInfo(userBean, userBean.getUserPass(),salt,&lt;span class=&#34;string&#34;&gt;&amp;quot;myRealm&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; simpleAuthenticationInfo;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;认证错误访问情况设置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#认证错误访问情况设置&#34;&gt;#&lt;/a&gt; 认证错误访问情况设置&lt;/h3&gt;
&lt;p&gt;设置登录页、登录成功也、未授权页面&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 设置登录页&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;factoryBean.setLoginUrl(&lt;span class=&#34;string&#34;&gt;&amp;quot;/index.html&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 定制未授权页面&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;factoryBean.setUnauthorizedUrl(&lt;span class=&#34;string&#34;&gt;&amp;quot;/common/unAuth&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;登出&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 相当与登出方法 使用shiro提供的logout过滤器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fifterMap.put(&lt;span class=&#34;string&#34;&gt;&amp;quot;/common/logout&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;logout&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;授权功能&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#授权功能&#34;&gt;#&lt;/a&gt; 授权功能&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;控制主页上按钮的访问权限&lt;/p&gt;
&lt;p&gt;&lt;code&gt;currentUser.getPricipal()&lt;/code&gt;  来自  &lt;code&gt;MyRealm&lt;/code&gt;  中 &lt;code&gt;doGetAuthenticationInfo&lt;/code&gt;  认证返回的 &lt;code&gt;simpleAuthenticationInfo&lt;/code&gt;  对象的第一个属性&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;控制后台资源路径的访问权限&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;方法 1：硬编码的方法，自行判断权限。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RequestMapping(&amp;quot;query&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;query&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Subject subject = SecurityUtils.getSubject();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (subject.isPermitted(&lt;span class=&#34;string&#34;&gt;&amp;quot;mobile&amp;quot;&lt;/span&gt;)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;mobile&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;error&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;方法 2：使用 shiro 提供的 &lt;code&gt;perms&lt;/code&gt;  过滤器，集中配置权限信息&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;fifterMap.put(&lt;span class=&#34;string&#34;&gt;&amp;quot;/mobile/**&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;authc, perms[mobile]&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fifterMap.put(&lt;span class=&#34;string&#34;&gt;&amp;quot;/salary/**&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;authc, perms[salary]&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;错误补充机制：没有权限就会进入到 &lt;code&gt;ShiroFilterFactoryBean&lt;/code&gt;  中配置的 &lt;code&gt;UnauthorizedUrl&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;方法 3：使用 shiro 提供的注解，实现方法级别的权限控制。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RequiresAuthentication&lt;/span&gt; 需要完成用户登录&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RequiresGuest&lt;/span&gt;			未登录用户可以访问，登录用户不可访问&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RequiresPermissions&lt;/span&gt;	需要有对应资源权限&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RequiresRoles&lt;/span&gt;			需要有对应的角色&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RequiresUser&lt;/span&gt;			需要完成用户登录并且实现了记住我功能&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;错误补充机制：没有权限会抛出异常（500 错误）&lt;/p&gt;
&lt;p&gt;如果基本框架使用的是 Spring Boot 可以捕获异常处理：&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.authz.AuthorizationException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.web.bind.annotation.ExceptionHandler;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.springframework.web.bind.annotation.RestControllerAdvice;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: springBoot方式捕获异常处理&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/10/19 下午3:39&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RestControllerAdvice&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;MyExceptionHandler&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@ExceptionHandler(AuthorizationException.class)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Object &lt;span class=&#34;title&#34;&gt;unAuth&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;没有资源访问权限&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;密码加密&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#密码加密&#34;&gt;#&lt;/a&gt; 密码加密&lt;/h3&gt;
&lt;p&gt;shiro 会获得一个 &lt;code&gt;CredentialsMatcher&lt;/code&gt;  对象，来进行密码比对。&lt;/p&gt;
&lt;p&gt;如果想使用 MD 5 加密，可以使用 &lt;code&gt;HashedCredentialsMatcher&lt;/code&gt; ， &lt;code&gt;Md5CredentialsMatcher&lt;/code&gt;  已经过期&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//密码加密&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;HashedCredentialsMatcher matcher = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; HashedCredentialsMatcher();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 算法名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;matcher.setHashAlgorithmName(&lt;span class=&#34;string&#34;&gt;&amp;quot;MD5&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 迭代次数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;matcher.setHashIterations(&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        private String hashAlgorithm; 				算法名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        private int hashIterations; 					迭代次数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        private boolean hashSalted;   				已经过时&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//        private boolean storedCredentialsHexEncoded;  设置默认的&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;myRealm.setCredentialsMatcher(matcher);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;数据库数据加密方法&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.crypto.hash.SimpleHash;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.apache.shiro.util.ByteSource;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 密码加密&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/10/19 下午4:40&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt; */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;PasswordEncoder&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;encoder&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String password)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        SimpleHash simpleHash = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; SimpleHash(&lt;span class=&#34;string&#34;&gt;&amp;quot;MD5&amp;quot;&lt;/span&gt;, ByteSource.Util.bytes(password), ByteSource.Util.bytes(&lt;span class=&#34;string&#34;&gt;&amp;quot;salt&amp;quot;&lt;/span&gt;), &lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; simpleHash.toString();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String[] args)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(encoder(&lt;span class=&#34;string&#34;&gt;&amp;quot;manager&amp;quot;&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;多realm认证&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#多realm认证&#34;&gt;#&lt;/a&gt; 多 Realm 认证&lt;/h3&gt;
&lt;p&gt;可用于实现用户名和手机号都可以登录。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;org.apache.shiro.authz.ModularRealmAuthorizer&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; AuthenticationInfo &lt;span class=&#34;title&#34;&gt;doAuthenticate&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(AuthenticationToken authenticationToken)&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;throws&lt;/span&gt; AuthenticationException &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        assertRealmsConfigured();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Collection&amp;lt;Realm&amp;gt; realms = getRealms();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (realms.size() == &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; doSingleRealmAuthentication(realms.iterator().next(), authenticationToken);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; doMultiRealmAuthentication(realms, authenticationToken);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;实现多个 Realm 完成不同的认证功能，通过增加一个 Realm，事项按照手机号也可以登录的功能&lt;/p&gt;
&lt;p&gt;注意可以设置不同的认证策略：&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 创建认证策略&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ModularRealmAuthenticator authenticator = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ModularRealmAuthenticator();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 设置认证策略为至少有一个成功&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;authenticator.setAuthenticationStrategy(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; AtLeastOneSuccessfulStrategy());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 设置所有的认证策略都返回成功&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;authenticator.setAuthenticationStrategy(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; AllSuccessfulStrategy());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 设置第一个认证策略返回成功后不再认证后续的&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;authenticator.setAuthenticationStrategy(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; FirstSuccessfulStrategy());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 设置多个Realm&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;authenticator.setRealms(Arrays.asList(myRealm, mobileRealm));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 设置认证策略&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;securityManager.setAuthenticator(authenticator);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;记住我功能&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#记住我功能&#34;&gt;#&lt;/a&gt; 记住我功能&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 记住我功能&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;token.setRememberMe(&lt;span class=&#34;keyword&#34;&gt;true&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;记住我功能对应了默认的 user 过滤器。&lt;/p&gt;
&lt;p&gt;怎么设置记住我时常，以及记住我功能记录保存位置&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;CookieRememberMeManager cookieRememberMeManager = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; CookieRememberMeManager();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Cookie cookie = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; SimpleCookie(&lt;span class=&#34;string&#34;&gt;&amp;quot;rememberMe&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cookie.setHttpOnly(&lt;span class=&#34;keyword&#34;&gt;true&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cookie.setMaxAge(&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cookieRememberMeManager.setCookie(cookie);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;securityManager.setRememberMeManager(cookieRememberMeManager);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;会话管理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#会话管理&#34;&gt;#&lt;/a&gt; 会话管理&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;securityManager.setSessionManager();&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;认证缓存&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#认证缓存&#34;&gt;#&lt;/a&gt; 认证缓存&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MemoryConstrainedCacheManager memoryConstrainedCacheManager = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; MemoryConstrainedCacheManager();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        securityManager.setCacheManager(memoryConstrainedCacheManager);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;备注：记住我、会话管理以及认证缓存，都可以通过扩展对应的 &lt;code&gt;manager&lt;/code&gt;  接口的方式，实现自己的灵活扩展，比如将对应的数据信心存储在 redis 中。&lt;/p&gt;
&lt;h3 id=&#34;realm类型关系图&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#realm类型关系图&#34;&gt;#&lt;/a&gt; Realm 类型关系图&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201020144848997.png&#34; alt=&#34;image-20201020144848997&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201020144848997.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;Ubuntu 系统更新后，打开 VMware 提示需要更新安装，点击安装失败问题解决&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;提示框&lt;img src=&#34;/img/image-20201016160643674.png&#34; alt=&#34;image-20201016160643674&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201016160643674.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;安装失败&lt;img src=&#34;/img/image-20201016160730834.png&#34; alt=&#34;image-20201016160730834&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201016160730834.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;--处理方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--打开终端执行如下代码&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VMWARE_VERSION=workstation-15.5.1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;TMP_FOLDER=/tmp/patch-vmware&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rm -fdr $TMP_FOLDER&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mkdir -p $TMP_FOLDER&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cd $TMP_FOLDER&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git clone https://github.com/mkubecek/vmware-host-modules.git&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cd $TMP_FOLDER/vmware-host-modules&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git checkout $VMWARE_VERSION&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git fetch&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;make&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-- 执行如下代码时需要输入管理员密码，输入完成后执行当前代码，但是后续的代码会终止，需要手动拷贝未执行其余命令继续操作，全部命令执行完成后，VMware即可正常使用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo make install&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo rm /usr/lib/vmware/lib/libz.so.1/libz.so.1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo ln -s /lib/x86_64-linux-gnu/libz.so.1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/usr/lib/vmware/lib/libz.so.1/libz.so.1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo /etc/init.d/vmware restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;Ubuntu 桌面被误删除，Ubuntu 在重启时会校验当前设置路径是否存在，不存在会默认设置一个路径，我 Ubuntu20.04 版本删除桌面文件夹被删除后，将桌面路径默认为根目录，导致桌面一下子出现了很多文件，为了恢复桌面的清爽，而进行如下操作。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;终端打开自己根目录&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;进入隐藏文件夹 .config&lt;img src=&#34;/img/image-20201016154927244.png&#34; alt=&#34;image-20201016154927244&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201016154927244.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
   &lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;-- 查看当前目录下所有文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ls -la&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;
&lt;p&gt;编辑文件 vim user-dirs.dirs &lt;img src=&#34;/img/image-20201016155127768.png&#34; alt=&#34;image-20201016155127768&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201016155127768.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;进行如下修改，此处修改的路径需要自己先行在对应路径创建文件夹，然后重启即可。&lt;img src=&#34;/img/image-20201016155252812.png&#34; alt=&#34;image-20201016155252812&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201016155252812.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;SpringBoot 自动集成 starter 使用实例，SpringBoot 自定义集成 Druid。Apache Druid 是一个高性能的实时分析数据库。&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://druid.apache.org/&#34;&gt;druid 官网&lt;/a&gt;&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;1-druid简介&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-druid简介&#34;&gt;#&lt;/a&gt; 1、druid 简介&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210120090838570.png&#34; alt=&#34;image-20210120090838570&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210120090838570.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;2-页面展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-页面展示&#34;&gt;#&lt;/a&gt; 2、页面展示&lt;/h2&gt;
&lt;p&gt;集成后访问链接 &lt;code&gt;127.0.0.1:8080/druid&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210120092042057.png&#34; alt=&#34;image-20210120092042057&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210120092042057.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210120092107600.png&#34; alt=&#34;image-20210120092107600&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210120092107600.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;3-手动集成&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-手动集成&#34;&gt;#&lt;/a&gt; 3、手动集成&lt;/h2&gt;
&lt;p&gt;创建一个 SpringBoot 项目，按照 SpringBoot 常规的三个步骤进行&lt;/p&gt;
&lt;h3 id=&#34;1-引入依赖&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-引入依赖&#34;&gt;#&lt;/a&gt; 1. 引入依赖&lt;/h3&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!--JDBC，数据库链接最基础--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;org.springframework.boot&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;spring-boot-starter-jdbc&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!--web--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;org.springframework.boot&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;spring-boot-starter-web&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!--手动导入druid--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;com.alibaba&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;druid&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;1.2.3&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!--当前使用数据库驱动包--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;mysql&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;mysql-connector-java&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-添加配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-添加配置&#34;&gt;#&lt;/a&gt; 2.  添加配置&lt;/h3&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# 数据源&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;spring:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;datasource:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;username:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;root&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;password:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;xxxx&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;url:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;jdbc:mysql://192.168.88.88:3306/springboot_mybatis?characterEncoding=utf8&amp;amp;useSSL=false&amp;amp;serverTimezone=UTC&amp;amp;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;driver-class-name:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;com.mysql.cj.jdbc.Driver&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;type:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;com.alibaba.druid.pool.DruidDataSource&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;#   数据源其他配置&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;initialSize:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;minIdle:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;maxActive:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;20&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;maxWait:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;60000&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;timeBetweenEvictionRunsMillis:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;60000&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;minEvictableIdleTimeMillis:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;300000&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;validationQuery:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;SELECT&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;FROM&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;DUAL&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;testWhileIdle:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;testOnBorrow:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;testOnReturn:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;poolPreparedStatements:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;#   配置监控统计拦截的filters，去掉后监控界面sql无法统计，&amp;#x27;wall&amp;#x27;用于防火墙&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;filters:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;stat,wall&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;maxPoolPreparedStatementPerConnectionSize:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;20&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;useGlobalDataSourceStat:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;connectionProperties:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;druid.stat.mergeSql=true;druid.stat.slowSqlMillis=500&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;#初始化时运行sql脚本&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;schema:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;classpath:sql/schema.sql&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;initialization-mode:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;always&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;3-添加注解业务逻辑&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-添加注解业务逻辑&#34;&gt;#&lt;/a&gt; 3. 添加注解 / 业务逻辑&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Configuration&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@ConditionalOnProperty(&amp;quot;spring.datasource.type&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;DruidConfiguration&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; DataSource &lt;span class=&#34;title&#34;&gt;dataSource&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DataSourceProperties properties)&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &lt;span class=&#34;comment&#34;&gt;// 根据配置动态构建一个DataSource，这个方式是DataSourceProperties独有的&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; properties.initializeDataSourceBuilder().build();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; ServletRegistrationBean &lt;span class=&#34;title&#34;&gt;statViewServlet&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ServletRegistrationBean servletRegistrationBean = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ServletRegistrationBean();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        servletRegistrationBean.setServlet(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; StatViewServlet());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        servletRegistrationBean.addUrlMappings(&lt;span class=&#34;string&#34;&gt;&amp;quot;/druid/*&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 添加IP白名单&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        servletRegistrationBean.addInitParameter(&lt;span class=&#34;string&#34;&gt;&amp;quot;allow&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;127.0.0.1&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 添加控制台管理用户&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        servletRegistrationBean.addInitParameter(&lt;span class=&#34;string&#34;&gt;&amp;quot;loginUsername&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;admin&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        servletRegistrationBean.addInitParameter(&lt;span class=&#34;string&#34;&gt;&amp;quot;loginPassword&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;123456&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 是否能够重置数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        servletRegistrationBean.addInitParameter(&lt;span class=&#34;string&#34;&gt;&amp;quot;resetEnable&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;false&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; servletRegistrationBean;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; FilterRegistrationBean &lt;span class=&#34;title&#34;&gt;statFilter&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        FilterRegistrationBean filterRegistrationBean = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; FilterRegistrationBean();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        filterRegistrationBean.setFilter(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; WebStatFilter());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 添加过滤规则&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        filterRegistrationBean.addUrlPatterns(&lt;span class=&#34;string&#34;&gt;&amp;quot;/*&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 忽略过滤格式&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        filterRegistrationBean.addInitParameter(&lt;span class=&#34;string&#34;&gt;&amp;quot;exclusions&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;*.js,*.gif,*.jpg,*.png,*.css,*.ico,/druid/*,&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; filterRegistrationBean;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;4-data-source数据注入&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-data-source数据注入&#34;&gt;#&lt;/a&gt; 4、Data Source 数据注入&lt;/h2&gt;
&lt;h3 id=&#34;1-configurationproperties注解&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-configurationproperties注解&#34;&gt;#&lt;/a&gt; 1.  &lt;code&gt;@ConfigurationProperties&lt;/code&gt;  注解&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;该注解可以使用在类上，则该类下对应的属性会自动注入配置文件中配置信息&lt;/li&gt;
&lt;li&gt;同样该类也可以使用在方法上，在方法中 new 对象同样可以自动注入，前提是该方法必须注册为 Bean 对象（即添加 @Bean 注解）&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@ConfigurationProperties(prefix = &amp;quot;spring.datasource&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; DataSource &lt;span class=&#34;title&#34;&gt;dataSource&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DataSourceProperties properties)&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//        DruidDataSource druidDataSource = new DruidDataSource();&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//        druidDataSource.setMinIdle(1);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// new的druidDataSource中存在配置文件中配置信息的set方法，可以直接返回new 对象，就可以注入&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 添加@ConfigurationProperties注解会将配置文件中的信息自动注入在DruidDataSource对象中&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 这种方法可以很灵活的应用到各个场景&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; DruidDataSource();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2datasourceproperties&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2datasourceproperties&#34;&gt;#&lt;/a&gt; 2. &lt;code&gt;DataSourceProperties&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;DataSourceProperties&lt;/code&gt;  对象提供的方法 &lt;code&gt;initializeDataSourceBuilder&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;配置文件中的属性都是引用的该方法， &lt;code&gt;initializeDataSourceBuilder&lt;/code&gt;  的作用就是帮我们去构建一个 &lt;code&gt;DataSource&lt;/code&gt;  对象。该方法采用了建造者的设计模式，一般建造者模式都有一个 build 方法创建相应对象。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;此方法为 &lt;code&gt;DataSourceProperties&lt;/code&gt;  独有的方法&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; DataSource &lt;span class=&#34;title&#34;&gt;dataSource&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(DataSourceProperties properties)&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 根据配置动态构建一个DataSource，这个方式是DataSourceProperties独有的&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; properties.initializeDataSourceBuilder().build();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;5-配置类注解说明&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5-配置类注解说明&#34;&gt;#&lt;/a&gt; 5、配置类注解说明&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;@Configuration：标注当前类为配置类，SpringBoot 启动扫描就可以扫描到当前类&lt;/li&gt;
&lt;li&gt;&lt;code&gt;@ConditionalOnProperty(&amp;quot;spring.datasource.type&amp;quot;)&lt;/code&gt; ： 配置当前对象必须在配置 spring.datasource.type 后该类才会生效&lt;/li&gt;
&lt;li&gt;两个注解在 SpringBoot 的各个 Starter 中是不可或缺的&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;6-官方starter&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6-官方starter&#34;&gt;#&lt;/a&gt; 6、官方 Starter&lt;/h2&gt;
&lt;p&gt;经过上面的一番配置，我们实现了想要的功能，我们实现的功能也就是 Druid Starter 中所具备的功能，接下来我们在有上面自定义配置的基础上看下官方提供的 Starter 又是如何实现的呢？&lt;/p&gt;
&lt;h3 id=&#34;1-添加注解&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-添加注解&#34;&gt;#&lt;/a&gt; 1. 添加注解&lt;/h3&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!--可以去掉手动配置时引入的druid包&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;dependency&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;    &amp;lt;groupId&amp;gt;com.alibaba&amp;lt;/groupId&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;    &amp;lt;artifactId&amp;gt;druid&amp;lt;/artifactId&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;    &amp;lt;version&amp;gt;1.2.3&amp;lt;/version&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;/dependency&amp;gt;--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;&amp;lt;!--导入druid starter--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;com.alibaba&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;druid-spring-boot-starter&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;1.2.3&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-添加配置-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-添加配置-2&#34;&gt;#&lt;/a&gt; 2. 添加配置&lt;/h3&gt;
&lt;figure class=&#34;highlight yaml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;spring:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;datasource:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;druid:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;#开启druid 监控台servlet&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;stat-view-servlet:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;enabled:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;login-username:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;admin&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;loginPassword:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;123456&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;comment&#34;&gt;#开启druid 监控filter&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;web-stat-filter:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;enabled:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;同我们手动配置时一样，配置&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;开启 druid 监控台&lt;/li&gt;
&lt;li&gt;启用 druid 监控 filter&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-注释自定义配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-注释自定义配置&#34;&gt;#&lt;/a&gt; 3. 注释自定义配置&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//@Configuration&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//@ConditionalOnProperty(&amp;quot;spring.datasource.type&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;DruidConfiguration&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;注释掉自定义配置，则我们的自定义配置则全部不会生效。&lt;/p&gt;
&lt;h3 id=&#34;4-启动项目&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-启动项目&#34;&gt;#&lt;/a&gt; 4. 启动项目&lt;/h3&gt;
&lt;p&gt;此时启动项目，durid 控制台依然是可以正常访问的。这样我们就可以很好的理解和体会 SpringBoot 的开箱即用&lt;/p&gt;
&lt;h3 id=&#34;5-starter配置文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5-starter配置文件&#34;&gt;#&lt;/a&gt; 5. Starter 配置文件&lt;/h3&gt;
&lt;p&gt;使用我们学到了，具体的 Starter 中又是如何配置的呢，看配置&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210120101026229.png&#34; alt=&#34;image-20210120101026229&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210120101026229.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210120101235996.png&#34; alt=&#34;image-20210120101235996&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210120101235996.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;从这我们可以看出我们配置文件中配置的开启 druid 控制台，必须配置 &lt;code&gt;spring.datasource.druid.stat-view-servlet.enabled&lt;/code&gt;  属性为 true，才可以生效&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210120101408857.png&#34; alt=&#34;image-20210120101408857&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210120101408857.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;配置 druid 拦截器，都也是同样的原理&lt;/p&gt;
&lt;h2 id=&#34;7-总结&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#7-总结&#34;&gt;#&lt;/a&gt; 7、总结&lt;/h2&gt;
&lt;p&gt;通过 durid 这个插件，自定义与 SpringBoot 集成以及直接引入 Starter 两种方式，体验 Springboot 将我们常用的场景抽取成 starter (场景启动器) 后给我们带来的便利。体验 SpringBoot 的开箱即用的便捷的同时，又了解 starter 具体的实现原理，让我们不至于成为一个简单的操作机器，知其然而知其所以然。&lt;/p&gt;

 &lt;p&gt;SpringBoot 最强大的功能就是把我们常用的场景抽取成了一个个 starter（场景启动器），我们通过引入 springboot 为我提供的这些场景启动器，我们再进行少量的配置就能使用相应的功能。即使是这样，springboot 也不能囊括我们所有的使用场景，往往我们需要自定义 starter，来简化我们对 springboot 的使用。&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://docs.spring.io/spring-boot/docs/2.3.8.RELEASE/reference/html/using-spring-boot.html#using-boot-starter&#34;&gt;官网中 starter 的相关介绍&lt;/a&gt;&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;1-官网简介&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-官网简介&#34;&gt;#&lt;/a&gt; 1、官网简介&lt;/h2&gt;
&lt;p&gt;入门程序是一组便捷的依赖项描述符，您可以在应用程序中包括它们。您可以一站式购买所需的所有 Spring 和相关技术，而不必遍历示例代码和依赖描述符的复制粘贴负载。例如，如果要开始使用 Spring 和 JPA 进行数据库访问，请 &lt;code&gt;spring-boot-starter-data-jpa&lt;/code&gt;  在项目中包括依赖项。&lt;/p&gt;
&lt;p&gt;入门程序包含许多启动项目并快速运行所需的依赖项，并且具有一组受支持的受管传递性依赖项。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210119111957403.png&#34; alt=&#34;image-20210119111957403&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210119111957403.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;2-官网推荐命名&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-官网推荐命名&#34;&gt;#&lt;/a&gt; 2、官网推荐命名&lt;/h2&gt;
&lt;p&gt;官方 starter 名称&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210119112125961.png&#34; alt=&#34;image-20210119112125961&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210119112125961.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;推荐的自建 starter 命名&lt;/p&gt;
&lt;p&gt;&lt;code&gt;thirdpartyproject-spring-boot-starter&lt;/code&gt; .&lt;/p&gt;
&lt;p&gt;官方命名空间&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;前缀：spring-boot-starter-&lt;/li&gt;
&lt;li&gt;模式：spring-boot-starter - 模块名&lt;/li&gt;
&lt;li&gt;举例：spring-boot-starter-web、spring-boot-starter-jdbc&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;自定义命名空间&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;后缀：-spring-boot-starter&lt;/li&gt;
&lt;li&gt;模式：模块 - spring-boot-starter&lt;/li&gt;
&lt;li&gt;举例：mybatis-spring-boot-starter&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;命名规范可以参看 myBatis 命名，SpringBoot 关于 MyBatis 的 Stater 是 MyBatis 提供的，并非 SpringBoot 提供。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210119112849108.png&#34; alt=&#34;image-20210119112849108&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210119112849108.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210119112928679.png&#34; alt=&#34;image-20210119112928679&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210119112928679.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;mybatis-spring-boot-starter 依赖 mybatis-spring-boot-autoconfigure&lt;/p&gt;
&lt;h2 id=&#34;3-自定义starter&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-自定义starter&#34;&gt;#&lt;/a&gt; 3、自定义 starter&lt;/h2&gt;
&lt;h3 id=&#34;1-启动器模块&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-启动器模块&#34;&gt;#&lt;/a&gt; 1.  启动器模块&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;根据命名规范创建模块&lt;/li&gt;
&lt;li&gt;空的 jar 文件，仅仅提供辅助性依赖管理，这些依赖可能用于自动装配或其他类库。&lt;/li&gt;
&lt;li&gt;需要专门写一个类似 spring-boot-autoconfigure 的配置模块&lt;/li&gt;
&lt;li&gt;pom 依赖中添加 autoconfigure 项目依赖&lt;/li&gt;
&lt;li&gt;用的时候只需要引入启动器 starter，就可以使用自动配置了&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2-自动配置模块&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-自动配置模块&#34;&gt;#&lt;/a&gt; 2. 自动配置模块&lt;/h3&gt;
&lt;p&gt;创建 xxxxx-spring-boot-autoconfigure 项目，并配置自动配置类&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;不需要启动类&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Configuration&lt;/span&gt;  &lt;span class=&#34;comment&#34;&gt;//指定这个类是一个配置类&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@ConditionalOnXXX&lt;/span&gt;  &lt;span class=&#34;comment&#34;&gt;//指定条件成立的情况下自动配置类生效&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@AutoConfigureOrder&lt;/span&gt;  &lt;span class=&#34;comment&#34;&gt;//指定自动配置类的顺序&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;  &lt;span class=&#34;comment&#34;&gt;//向容器中添加组件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@ConfigurationProperties&lt;/span&gt;  &lt;span class=&#34;comment&#34;&gt;//结合相关xxxProperties来绑定相关的配置&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@EnableConfigurationProperties&lt;/span&gt;  &lt;span class=&#34;comment&#34;&gt;//让xxxProperties生效加入到容器中&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 自动配置类要能加载需要将自动配置类，配置在META-INF/spring.factories中&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// demo&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;org.springframework.boot.autoconfigure.EnableAutoConfiguration=\&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;org.springframework.boot.autoconfigure.admin.SpringApplicationAdminJmxAutoConfiguration,\&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;org.springframework.boot.autoconfigure.aop.AopAutoConfiguration,\&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// -------------自动配置类-------------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Configuration&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@ConditionalOnProperty(value = &amp;quot;hello.name&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@EnableConfigurationProperties(HelloProperties.class)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;HelloAutoConfitguration&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Autowired&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    HelloProperties helloProperties;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Bean&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; IndexController &lt;span class=&#34;title&#34;&gt;indexController&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; IndexController(helloProperties);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// -------------属性注入-------------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@ConfigurationProperties(&amp;quot;hello&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;HelloProperties&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; String name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;getName&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;setName&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String name)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.name = name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// -------------具体业务处理-------------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@RestController&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;IndexController&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    HelloProperties helloProperties;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;IndexController&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(HelloProperties helloProperties)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.helloProperties=helloProperties;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@RequestMapping(&amp;quot;/&amp;quot;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;index&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; helloProperties.getName();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight yaml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;//&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;-------------spring.factories配置类-------------&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;org.springframework.boot.autoconfigure.EnableAutoConfiguration=\&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;string&#34;&gt;com.starter.HelloAutoConfitguration&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;4-项目安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-项目安装&#34;&gt;#&lt;/a&gt; 4、项目安装&lt;/h2&gt;
&lt;p&gt;使用 maven 命令将两个项目安装至 maven 仓库，然后在其他项目中就可以引入 starter，配置文件中根据自定义的 starter 规则配置，直接就可以实现开箱即用。&lt;/p&gt;

 &lt;p&gt;配置文件到底能写什么？怎么写？自动配置原理；&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://docs.spring.io/spring-boot/docs/current/reference/html/appendix-application-properties.html#common-application-properties&#34;&gt;配置文件属性参照&lt;/a&gt;&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;配置文件加载顺序&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#配置文件加载顺序&#34;&gt;#&lt;/a&gt; 配置文件加载顺序&lt;/h3&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;include&lt;/span&gt;&amp;gt;&lt;/span&gt;**/application*.yml&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;include&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;include&lt;/span&gt;&amp;gt;&lt;/span&gt;**/application*.yaml&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;include&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;include&lt;/span&gt;&amp;gt;&lt;/span&gt;**/application*.properties&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;include&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;optional:classpath:/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;optional:classpath:/config/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;optional:file:./&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;optional:file:./config/*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;optional:file:./config/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;optional:classpath:custom-config/      --spring.config.location&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;optional:file:./custom-config/         --spring.config.location&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;所有配置文件按以下顺序考虑： 优先级从低到高&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;打包在jar中配置文件  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;打包在jar中profile &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;打包的jar之外的配置文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;打包的jar之外的profile&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;源码查看入口&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;meta&#34;&gt;@interface&lt;/span&gt; SpringBootApplication&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;@SpringBootApplication&lt;/code&gt; : Spring Boot 应用标注在某个类上说明这个类是 Spring Boot 的主配置类，Spring Boot 需要运行这个类的 main 方法来启动 Spring Boot 应用；&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;@EnableAutoConfiguration&lt;/code&gt;  开启自动配置功能；自动扫描所有的配置类，扫描到并满足条件才会生效&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Target(ElementType.TYPE)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Retention(RetentionPolicy.RUNTIME)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Documented&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Inherited&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@AutoConfigurationPackage&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Import(AutoConfigurationImportSelector.class)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;meta&#34;&gt;@interface&lt;/span&gt; EnableAutoConfiguration &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;@Import(AutoConfigurationImportSelector.class)&lt;/code&gt;  SpringBoot 实现自动配置的关键类&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 实现接口DeferredImportSelector（一个ImportSelector的变种，不会执行ImportSelector）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 解析@Import(AutoConfigurationImportSelector.class)注解时，调用getAutoConfigurationEntry&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;AutoConfigurationImportSelector&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;DeferredImportSelector&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;BeanClassLoaderAware&lt;/span&gt;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;class&#34;&gt;		&lt;span class=&#34;title&#34;&gt;ResourceLoaderAware&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;BeanFactoryAware&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;EnvironmentAware&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;Ordered&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;// sunfy-AutoConf 自动配置重要入口&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;code&gt;AutoConfigurationImportSelector&lt;/code&gt;  实现接口  &lt;code&gt;DeferredImportSelector&lt;/code&gt; ，判断是否重写 &lt;code&gt;getImportGroup&lt;/code&gt;  方法，如果没有重写 &lt;code&gt;selectImports&lt;/code&gt;  返回一个数组，将数组中的完整类名注册为 bean&lt;/li&gt;
&lt;li&gt;重写 &lt;code&gt;getImportGroup&lt;/code&gt;  方法，返回一个自定义的实现了 &lt;code&gt;DeferredImportSelector.Group&lt;/code&gt;  的类&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;SpringBoot 通过重写，返回自定义的 &lt;code&gt;DeferredImportSelector.Group&lt;/code&gt;  的类&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;process 中获取所有的配置并根据实际引入进行过滤&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;process&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(AnnotationMetadata annotationMetadata, DeferredImportSelector deferredImportSelector)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Assert.state(deferredImportSelector &lt;span class=&#34;keyword&#34;&gt;instanceof&lt;/span&gt; AutoConfigurationImportSelector,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                 () -&amp;gt; String.format(&lt;span class=&#34;string&#34;&gt;&amp;quot;Only %s implementations are supported, got %s&amp;quot;&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                     AutoConfigurationImportSelector.class.getSimpleName(),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                     deferredImportSelector.getClass().getName()));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    AutoConfigurationEntry autoConfigurationEntry = ((AutoConfigurationImportSelector) deferredImportSelector)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// sunfy-autoConf 获取所有的有效自动配置类&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        .getAutoConfigurationEntry(annotationMetadata);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// selectImports 方法中获取到的配置&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.autoConfigurationEntries.add(autoConfigurationEntry);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (String importClassName : autoConfigurationEntry.getConfigurations()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;this&lt;/span&gt;.entries.putIfAbsent(importClassName, annotationMetadata);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;getAutoConfigurationEntry&lt;/code&gt;  获取所有有效自动配置类，进入方法&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// sunfy-autoConf 获取所有的有效自动配置类&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; AutoConfigurationEntry &lt;span class=&#34;title&#34;&gt;getAutoConfigurationEntry&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(AnnotationMetadata annotationMetadata)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!isEnabled(annotationMetadata)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; EMPTY_ENTRY;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    AnnotationAttributes attributes = getAttributes(annotationMetadata);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// sunfy-autoconf 获取所有的配置类1XX个&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    List&amp;lt;String&amp;gt; configurations = getCandidateConfigurations(annotationMetadata, attributes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    configurations = removeDuplicates(configurations);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Set&amp;lt;String&amp;gt; exclusions = getExclusions(annotationMetadata, attributes);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    checkExcludedClasses(configurations, exclusions);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    configurations.removeAll(exclusions);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// sunfy-AutoConf 根据pom依赖中添加starter过滤出来的有效配置类&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    configurations = getConfigurationClassFilter().filter(configurations);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    fireAutoConfigurationImportEvents(configurations, exclusions);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; AutoConfigurationEntry(configurations, exclusions);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;code&gt;getCandidateConfigurations&lt;/code&gt;  中获取到 SpringBoot 项目中所有的 Stater 配置，总共有 &lt;code&gt;1xx&lt;/code&gt;  多个&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210118114003369.png&#34; alt=&#34;image-20210118114003369&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210118114003369.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;进入 &lt;code&gt;getCandidateConfigurations&lt;/code&gt;  方法中&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;protected&lt;/span&gt; List&amp;lt;String&amp;gt; &lt;span class=&#34;title&#34;&gt;getCandidateConfigurations&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(AnnotationMetadata metadata, AnnotationAttributes attributes)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// sunfy-autoconf 加载所有配置文件，jar中可能都存在，都进行读取&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    List&amp;lt;String&amp;gt; configurations = SpringFactoriesLoader.loadFactoryNames(getSpringFactoriesLoaderFactoryClass(),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                                                         getBeanClassLoader());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Assert.notEmpty(configurations, &lt;span class=&#34;string&#34;&gt;&amp;quot;No auto configuration classes found in META-INF/spring.factories. If you are using a custom packaging, make sure that file is correct.&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; configurations;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;code&gt;loadFactoryNames&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; List&amp;lt;String&amp;gt; &lt;span class=&#34;title&#34;&gt;loadFactoryNames&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(Class&amp;lt;?&amp;gt; factoryType, &lt;span class=&#34;meta&#34;&gt;@Nullable&lt;/span&gt; ClassLoader classLoader)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 要获取的自动配置类的全限定名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String factoryTypeName = factoryType.getName();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; loadSpringFactories(classLoader).getOrDefault(factoryTypeName, Collections.emptyList());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;pre&gt;&lt;code&gt;  ![image-20210118210142763](/img/image-20210118210142763.png)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;code&gt;loadSpringFactories&lt;/code&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;  &lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; Map&amp;lt;String, List&amp;lt;String&amp;gt;&amp;gt; loadSpringFactories(&lt;span class=&#34;meta&#34;&gt;@Nullable&lt;/span&gt; ClassLoader classLoader) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 此时会尝试从缓存中进行获取，因为在SpringBoot启动时就会加载其他配置文件，因为加载所有的配置文件是一个很耗时耗内存的过程，在第一次加载完成后会放在cache中，方便后续获取&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    MultiValueMap&amp;lt;String, String&amp;gt; result = cache.get(classLoader);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (result != &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; result;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// public static final String FACTORIES_RESOURCE_LOCATION = &amp;quot;META-INF/spring.factories&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 不难看出都会到对应的jar包中读取META-INF/spring.factories文件中的内容&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Enumeration&amp;lt;URL&amp;gt; urls = (classLoader != &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt; ?&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                 classLoader.getResources(FACTORIES_RESOURCE_LOCATION) :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                                 ClassLoader.getSystemResources(FACTORIES_RESOURCE_LOCATION));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        result = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; LinkedMultiValueMap&amp;lt;&amp;gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; (urls.hasMoreElements()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            URL url = urls.nextElement();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            UrlResource resource = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; UrlResource(url);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Properties properties = PropertiesLoaderUtils.loadProperties(resource);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (Map.Entry&amp;lt;?, ?&amp;gt; entry : properties.entrySet()) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                String factoryTypeName = ((String) entry.getKey()).trim();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (String factoryImplementationName : StringUtils.commaDelimitedListToStringArray((String) entry.getValue())) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    result.add(factoryTypeName, factoryImplementationName.trim());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 将获取到的内容放入到缓存中&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cache.put(classLoader, result);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; result;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (IOException ex) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;throw&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; IllegalArgumentException(&lt;span class=&#34;string&#34;&gt;&amp;quot;Unable to load factories from location [&amp;quot;&lt;/span&gt; + FACTORIES_RESOURCE_LOCATION + &lt;span class=&#34;string&#34;&gt;&amp;quot;]&amp;quot;&lt;/span&gt;, ex);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

  ![image-20210118114603645](/img/image-20210118114603645.png)
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;遍历每个 jar 包下的每个 &lt;code&gt;META-INF/spring.factories&lt;/code&gt;  文件内容&lt;/p&gt;
&lt;p&gt;​	   &lt;img src=&#34;/img/image-20210118115041776.png&#34; alt=&#34;image-20210118115041776&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210118115041776.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;&lt;code&gt;getConfigurationClassFilter().filter(configurations)&lt;/code&gt;  根据 &lt;code&gt;pom&lt;/code&gt;  依赖中添加 starter 过滤出来的有效配置类&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;至此所有的自动配置就全部获取到了&lt;/p&gt;

 &lt;p&gt;mySQL 数据库在使用过程中遇到的一些问题记录&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;linux登录mysql报错&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#linux登录mysql报错&#34;&gt;#&lt;/a&gt; linux，登录 mysql 报错&lt;/h3&gt;
&lt;p&gt;ERROR 2002 (HY000): Can’t connect to local MySQL server through socket ‘/var/lib/mysql.sock’&lt;/p&gt;
&lt;p&gt;首先检查 /etc 下的是否有 my.cnf 文件，这是启动时基本配置文件&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[mysqld]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log-bin&amp;#x3D;mysql-bin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server-id&amp;#x3D;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# Remove leading # and set to the amount of RAM for the most important data&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# cache in MySQL. Start at 70% of total RAM for dedicated server, else 10%.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;innodb_buffer_pool_size &amp;#x3D; 8M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# Remove leading # to turn on a very important data integrity option: logging&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# changes to the binary log between backups.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# log_bin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# Remove leading # to set options mainly useful for reporting servers.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# The server defaults are faster for transactions and fast SELECTs.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# Adjust sizes as needed, experiment to find the optimal values.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;join_buffer_size &amp;#x3D; 8M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sort_buffer_size &amp;#x3D; 2M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;read_rnd_buffer_size &amp;#x3D; 2M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;datadir&amp;#x3D;&amp;#x2F;var&amp;#x2F;lib&amp;#x2F;mysql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;socket&amp;#x3D;&amp;#x2F;var&amp;#x2F;lib&amp;#x2F;mysql&amp;#x2F;mysql.sock&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log-bin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;max_binlog_size&amp;#x3D;50M&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;expire_logs_days&amp;#x3D;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# 关闭所有网络链接,开启后只能使用mysql客户端链接&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#skip-networking&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#default-time-zone &amp;#x3D; &amp;#39;+8:00&amp;#39;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;performance_schema_max_table_instances&amp;#x3D;200&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;table_definition_cache&amp;#x3D;200&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;table_open_cache&amp;#x3D;128&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bind-address &amp;#x3D; 0.0.0.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#skip-grant-tables&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# Disabling symbolic-links is recommended to prevent assorted security risks&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;symbolic-links&amp;#x3D;0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# Recommended in standard MySQL setup&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sql_mode&amp;#x3D;NO_ENGINE_SUBSTITUTION,STRICT_TRANS_TABLES&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[mysqld_safe]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log-error&amp;#x3D;&amp;#x2F;var&amp;#x2F;log&amp;#x2F;mysqld.log&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pid-file&amp;#x3D;&amp;#x2F;var&amp;#x2F;run&amp;#x2F;mysqld&amp;#x2F;mysqld.pid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#配置开启binlog&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log‐bin&amp;#x3D;&amp;#x2F;usr&amp;#x2F;local&amp;#x2F;software&amp;#x2F;mysql&amp;#x2F;binlog&amp;#x2F;mysql‐bin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;##注意5.7以及更高版本需要配置本项:server‐id&amp;#x3D;123454(自定义,保证唯一性);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;###binlog格式,有3种statement,row,mixed&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;binlog‐format&amp;#x3D;ROW&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;###表示每1次执行写入就与硬盘同步,会影响性能,为0时表示,事务提交时mysql不做刷盘操作,由系统决定&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sync‐binlog&amp;#x3D;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;关闭进程指令：ps aux |grep ‘mysql*’&lt;br&gt;
关闭 mysql 的所有进程&lt;/p&gt;
&lt;p&gt;启动 mysql: systemctl start mysqld&lt;/p&gt;
&lt;h3 id=&#34;server-id问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#server-id问题&#34;&gt;#&lt;/a&gt; server-id 问题&lt;/h3&gt;
&lt;p&gt;[ERROR] You have enabled the binary log, but you haven’t provided the mandatory server-id.&lt;/p&gt;
&lt;p&gt;报错的原因：&lt;/p&gt;
&lt;p&gt;在设置 bin log 日志的时候，没有设置 server_id 参数。server-id 参数用于在复制中，为主库和备库提供一个独立的 ID，以区分主库和备库；开启二进制文件的时候，需要设置这个参数。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[root@mysql bin]# vi &amp;#x2F;etc&amp;#x2F;my.cnf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#add&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[mysqld]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log-bin&amp;#x3D;mysql-bin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server-id&amp;#x3D;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;远程登录授权&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#远程登录授权&#34;&gt;#&lt;/a&gt; 远程登录授权&lt;/h3&gt;
&lt;p&gt;Access denied for user ‘root’@’%’ to database ‘XXXX’&lt;/p&gt;
&lt;p&gt;解决方法&lt;br&gt;
最后发现是 user 表中’root’@’%’没有 grant 的权限&lt;br&gt;
可以用如下命令查看：&lt;/p&gt;
&lt;p&gt;可以看到现在这两个权限都是 N&lt;br&gt;
 然后我们更新它们为 Y，然后重启 mysql&lt;/p&gt;
&lt;p&gt;update mysql.user set Grant_priv=‘Y’,Super_priv=‘Y’ where user = ‘root’ and host = ‘%’;&lt;/p&gt;
&lt;h3 id=&#34;mysql57简单密码错误&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mysql57简单密码错误&#34;&gt;#&lt;/a&gt; mysql5.7 简单密码错误&lt;/h3&gt;
&lt;p&gt;ERROR 1819 (HY000): Your password does not satisfy the current policy requirements&lt;/p&gt;
&lt;p&gt;有时候，只是为了自己测试，不想密码设置得那么复杂，譬如只想设置 root 的密码为 123456。&lt;/p&gt;
&lt;p&gt;SET PASSWORD FOR ‘root’@‘localhost’ = PASSWORD(‘123456’);&lt;/p&gt;
&lt;p&gt;但是会报错：&lt;/p&gt;
&lt;figure class=&#34;highlight delphi&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; &lt;span class=&#34;keyword&#34;&gt;SET&lt;/span&gt; PASSWORD &lt;span class=&#34;keyword&#34;&gt;FOR&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;root&amp;#x27;&lt;/span&gt;@&lt;span class=&#34;string&#34;&gt;&amp;#x27;localhost&amp;#x27;&lt;/span&gt; = PASSWORD(&lt;span class=&#34;string&#34;&gt;&amp;#x27;123&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ERROR &lt;span class=&#34;number&#34;&gt;1819&lt;/span&gt; (HY000): Your password does &lt;span class=&#34;keyword&#34;&gt;not&lt;/span&gt; satisfy the current policy requirements&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;【原因】&lt;/p&gt;
&lt;p&gt;原来 MySQL5.6.6 版本之后增加了密码强度验证插件 validate_password，相关参数设置的较为严格。&lt;br&gt;
使用了该插件会检查设置的密码是否符合当前设置的强度规则，若不满足则拒绝设置。影响的语句和函数有：create user,grant,set password,password (),old password。&lt;br&gt;
【解决】&lt;/p&gt;
&lt;p&gt;1） 查看 mysql 全局参数配置&lt;/p&gt;
&lt;p&gt;该问题其实与 mysql 的 validate_password_policy 的值有关。&lt;br&gt;
查看一下 msyql 密码相关的几个全局参数：&lt;/p&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; select @@validate_password_policy;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;----------------------------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| @@validate_password_policy |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;----------------------------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| MEDIUM                     |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;----------------------------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1 row in &lt;span class=&#34;keyword&#34;&gt;set&lt;/span&gt; (&lt;span class=&#34;number&#34;&gt;0.00&lt;/span&gt; sec)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; &lt;span class=&#34;keyword&#34;&gt;SHOW&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;VARIABLES&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;LIKE&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;validate_password%&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;--------------------------------------+--------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| Variable_name                        | Value  |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;--------------------------------------+--------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_dictionary_file    |        |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_length             | 8      |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_mixed_case_count   | 1      |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_number_count       | 1      |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_policy             | MEDIUM |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_special_char_count | 1      |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;--------------------------------------+--------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6 rows in &lt;span class=&#34;keyword&#34;&gt;set&lt;/span&gt; (&lt;span class=&#34;number&#34;&gt;0.08&lt;/span&gt; sec)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;2）参数解释&lt;/p&gt;
&lt;p&gt;validate_password_dictionary_file&lt;br&gt;
 插件用于验证密码强度的字典文件路径。&lt;/p&gt;
&lt;p&gt;validate_password_length&lt;br&gt;
 密码最小长度，参数默认为 8，它有最小值的限制，最小值为：validate_password_number_count + validate_password_special_char_count + (2 * validate_password_mixed_case_count)&lt;/p&gt;
&lt;p&gt;validate_password_mixed_case_count&lt;br&gt;
 密码至少要包含的小写字母个数和大写字母个数。&lt;/p&gt;
&lt;p&gt;validate_password_number_count&lt;br&gt;
 密码至少要包含的数字个数。&lt;/p&gt;
&lt;p&gt;validate_password_policy&lt;br&gt;
 密码强度检查等级，0/LOW、1/MEDIUM、2/STRONG。有以下取值：&lt;br&gt;
&lt;strong&gt;Policy         Tests Performed&lt;/strong&gt;&lt;br&gt;
0 or LOW        Length&lt;br&gt;
1 or MEDIUM     Length; numeric, lowercase/uppercase, and special characters&lt;br&gt;
2 or STRONG     Length; numeric, lowercase/uppercase, and special characters; dictionary file&lt;br&gt;
 默认是 1，即 MEDIUM，所以刚开始设置的密码必须符合长度，且必须含有数字，小写或大写字母，特殊字符。&lt;/p&gt;
&lt;p&gt;validate_password_special_char_count&lt;br&gt;
 密码至少要包含的特殊字符数。&lt;/p&gt;
&lt;p&gt;3）修改 mysql 参数配置&lt;/p&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; set global validate_password_policy=0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Query OK, 0 rows affected (0.05 sec)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; set global validate_password_mixed_case_count=0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Query OK, 0 rows affected (0.00 sec)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; set global validate_password_number_count=3;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Query OK, 0 rows affected (0.00 sec)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; set global validate_password_special_char_count=0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Query OK, 0 rows affected (0.00 sec)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; set global validate_password_length=3;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Query OK, 0 rows affected (0.00 sec)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; SHOW VARIABLES LIKE &amp;#x27;validate_password%&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;--------------------------------------+-------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| Variable_name                        | Value |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;--------------------------------------+-------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_dictionary_file    |       |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_length             | 3     |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_mixed_case_count   | 0     |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_number_count       | 3     |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_policy             | LOW   |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| validate_password_special_char_count | 0     |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+&lt;span class=&#34;comment&#34;&gt;--------------------------------------+-------+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6 rows in &lt;span class=&#34;keyword&#34;&gt;set&lt;/span&gt; (&lt;span class=&#34;number&#34;&gt;0.00&lt;/span&gt; sec)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;4）修改简单密码：&lt;/p&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mysql&amp;gt; SET PASSWORD FOR &amp;#x27;root&amp;#x27;@&amp;#x27;localhost&amp;#x27; = PASSWORD(&amp;#x27;123&amp;#x27;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Query OK, 0 rows affected, 1 warning (0.00 sec)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;Ubuntu 系统在升级 20.04 后不兼容 easyconnect 问题处理&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;ubuntu-2004-下安装easyconnect记录&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ubuntu-2004-下安装easyconnect记录&#34;&gt;#&lt;/a&gt; Ubuntu 20.04 下安装 easyconnect 记录&lt;/h3&gt;
&lt;p&gt;1、easyconnect 在 Ubuntu 20 下无法打开；&lt;br&gt;
2、在解决第一个问题后在 easyconnect 登陆过程中闪退。&lt;/p&gt;
&lt;p&gt;解决方案主要参考了以下两个博客&lt;br&gt;
&lt;a href=&#34;https://www.cnblogs.com/cocode/p/12890684.html&#34;&gt; Ubuntu 20.04 下 EasyConnect 兼容性问题临时解决方案&lt;/a&gt;&lt;br&gt;
&lt;a href=&#34;https://bbs.sangfor.com.cn/forum.php?mod=viewthread&amp;amp;tid=111229&#34;&gt; Ubuntu 18.04 系统解决 EasyConnect 登录后闪退问题&lt;/a&gt;&lt;br&gt;
流程：&lt;br&gt;
首先是解决 easyconnect 不兼容 Ubuntu 20 的问题&lt;br&gt;
 1、&lt;a href=&#34;https://packages.ubuntu.com/eoan/libpango-1.0-0&#34;&gt;https://packages.ubuntu.com/eoan/libpango-1.0-0&lt;/a&gt;&lt;br&gt;
&lt;a href=&#34;https://packages.ubuntu.com/eoan/libpangocairo-1.0-0&#34;&gt;https://packages.ubuntu.com/eoan/libpangocairo-1.0-0&lt;/a&gt;&lt;br&gt;
&lt;a href=&#34;https://packages.ubuntu.com/eoan/libpangoft2-1.0-0&#34;&gt;https://packages.ubuntu.com/eoan/libpangoft2-1.0-0&lt;/a&gt;&lt;br&gt;
 或者使用下面网盘下载&lt;br&gt;
 &lt;code&gt;https://wws.lanzous.com/b01nmd4sh 密码:76yn&lt;/code&gt; &lt;br&gt;
 分别下载这三个包。&lt;br&gt;
使用命令行进入下载的三个包所在的目录，用命令&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;dpkg -X  libpangoxxxx  ./ &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;解压下载的三个.deb 包&lt;br&gt;
 2、进入解压的目录&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;cd&lt;/span&gt; usr/lib/x86_64-linux-gnu&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3、将解压得到的.so 文件拷贝到 easyconnect 目录下&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo cp * /usr/share/sangfor/EasyConnect&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;4、此时在 &lt;code&gt;/usr/share/sangfor/EasyConnect&lt;/code&gt;  目录下输入命令&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ ldd EasyConnect | grep pango&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;显示应为（ &lt;code&gt;libpango&lt;/code&gt; &lt;a href=&#34;http://xn--rcrm18ivzkd1hm7hlv9aei6bf2j.so&#34;&gt; 应链接到复制过去的.so&lt;/a&gt;）：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;libpangocairo-1.0.so.0 =&amp;gt; /usr/share/sangfor/EasyConnect/./libpangocairo-1.0.so.0 (0x00007f16ce009000)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	libpango-1.0.so.0 =&amp;gt; /usr/share/sangfor/EasyConnect/./libpango-1.0.so.0 (0x00007f16cde72000)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	libpangoft2-1.0.so.0 =&amp;gt; /usr/share/sangfor/EasyConnect/./libpangoft2-1.0.so.0 (0x00007f16cc1cb000)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后便可以正常打开 easyconnect。可能会遇到闪退问题，此时在登录进度条大概 70% 左右执行命令&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo /bin/bash /usr/share/sangfor/EasyConnect/resources/shell/sslservice.sh&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;可以解决登录几秒后闪退问题&lt;/p&gt;

 &lt;p&gt;CentOS 安装 Docker 图形化工具&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;一docker图形化工具&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#一docker图形化工具&#34;&gt;#&lt;/a&gt; 一.Docker 图形化工具&lt;/h2&gt;
&lt;p&gt;​    docker 图形页面管理工具常用的有三种，DockerUI ，Portainer ，Shipyard 。DockerUI 是 Portainer 的前身，这三个工具通过 docker api 来获取管理的资源信息。平时我们常常对着 shell 对着这些命令行客户端，审美会很疲劳，如果有漂亮的图形化界面可以直观查看 docker 资源信息，也是非常方便的。今天我们就搭建单机版的三种常用图形页面管理工具。这三种图形化管理工具以 Portainer 最为受欢迎。&lt;/p&gt;
&lt;h2 id=&#34;二dockerui&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二dockerui&#34;&gt;#&lt;/a&gt; 二.DockerUI&lt;/h2&gt;
&lt;p&gt;轻量级图形页面管理之 DockerUI&lt;/p&gt;
&lt;p&gt;1. 查看 dockerui 镜像&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[root@localhost ~]# docker search dockerui&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/1385722-20180921161812839-1161447728.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/1385722-20180921161812839-1161447728.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;2. 选择喜欢的 dockerui 风格镜像，下载&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[root@localhost ~]# docker pull abh1nav&amp;#x2F;dockerui&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3. 启动 dockerui 容器，这里需要注意带上 privileged 参数，提升权限&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[root@localhost ~]# docker run -d --privileged --name dockerui -p 9000:9000 -v &amp;#x2F;var&amp;#x2F;run&amp;#x2F;docker.sock:&amp;#x2F;var&amp;#x2F;run&amp;#x2F;docker.sock abh1nav&amp;#x2F;dockerui&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;前往网页查看之前，你需要打开服务器的 9000 端口：   firewall-cmd --permanent --zone=public --add-port=9000/tcpfirewall-cmd --reload&lt;/p&gt;
&lt;p&gt;4. 浏览器查看 dockerui：&lt;a href=&#34;http://192.168.2.119:9000/&#34;&gt;http://192.168.2.119:9000&lt;/a&gt;   或者 curl &lt;a href=&#34;http://192.168.2.119:9000&#34;&gt;http://192.168.2.119:9000&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/1385722-20180921160841743-448633112.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/1385722-20180921160841743-448633112.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;三shipyard&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三shipyard&#34;&gt;#&lt;/a&gt; 三.Shipyard&lt;/h2&gt;
&lt;p&gt;轻量级图形页面管理之 Shipyard&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/1385722-20180921163444930-1449197767.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/1385722-20180921163444930-1449197767.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;四portainer&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#四portainer&#34;&gt;#&lt;/a&gt; 四.Portainer&lt;/h2&gt;
&lt;p&gt;轻量级图形页面管理之 Portainer&lt;/p&gt;
&lt;p&gt;1. 查看 portainer 镜像&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[root@localhost ~]# docker search portainer&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/1385722-20180921161723460-1361137261.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/1385722-20180921161723460-1361137261.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;2. 选择喜欢的 portainer 风格镜像，下载&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[root@localhost ~]# docker pull portainer&amp;#x2F;portainer &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3. 启动 dockerui 容器&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[root@localhost ~]# docker run -d --name portainerUI -p 9000:9000 -v &amp;#x2F;var&amp;#x2F;run&amp;#x2F;docker.sock:&amp;#x2F;var&amp;#x2F;run&amp;#x2F;docker.sock portainer&amp;#x2F;portainer&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;4. 浏览器访问 &lt;a href=&#34;http://192.168.2.119:9000/&#34;&gt;http://192.168.2.119:9000&lt;/a&gt; , 设置一个密码即可，点击创建用户&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/1385722-20180921162528714-901461854.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/1385722-20180921162528714-901461854.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/u=1997667158,3125340408&amp;amp;fm=173&amp;amp;app=25&amp;amp;f=JPEG&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/u=1997667158,3125340408&amp;amp;fm=173&amp;amp;app=25&amp;amp;f=JPEG&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;我们搭建的是单机版，直接选择 Local ，点击连接&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/1385722-20180921162717769-145855775.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/1385722-20180921162717769-145855775.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/u=1266655624,1442914627&amp;amp;fm=173&amp;amp;app=25&amp;amp;f=JPEG&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/u=1266655624,1442914627&amp;amp;fm=173&amp;amp;app=25&amp;amp;f=JPEG&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;现在就可以使用了，点击 Local 进入仪表盘主页面。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/1385722-20180921165040584-1231389831.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/1385722-20180921165040584-1231389831.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;容器页面&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/1385722-20180921164941854-544053238.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/1385722-20180921164941854-544053238.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/u=1156235942,926832626&amp;amp;fm=173&amp;amp;app=25&amp;amp;f=JPEG&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/u=1156235942,926832626&amp;amp;fm=173&amp;amp;app=25&amp;amp;f=JPEG&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/u=3237575840,3806081523&amp;amp;fm=173&amp;amp;app=25&amp;amp;f=JPEG&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/u=3237575840,3806081523&amp;amp;fm=173&amp;amp;app=25&amp;amp;f=JPEG&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;docker 客户端非常简单，我们可以直接输入 docker 命令来查看到 Docker 客户端的所有命令选项。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;docker安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#docker安装&#34;&gt;#&lt;/a&gt; docker 安装&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;curl -fsSL https://get.docker.com | bash -s docker --mirror Aliyun&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;Docker Compose 的安装&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;Compose 的安装有多种方式，例如通过 shell 安装、通过 pip 安装、以及将 compose 作为容器安装等等。本文讲解通过 shell 安装的方式。其他安装方式如有兴趣，可以查看 Docker 的官方文档：&lt;a href=&#34;https://docs.docker.com/compose/install/&#34;&gt;https://docs.docker.com/compose/install/&lt;/a&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; docker compose安装步骤&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo curl -L &amp;quot;https://github.com/docker/compose/releases/download/1.25.5/docker-compose-$(uname -s)-$(uname -m)&amp;quot; -o /usr/local/bin/docker-compose&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo chmod +x /usr/local/bin/docker-compose&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;docker-compose --version&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;docker服务器重启&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#docker服务器重启&#34;&gt;#&lt;/a&gt; docker 服务器重启&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;service docker restart&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;docker&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#docker&#34;&gt;#&lt;/a&gt; docker&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210122101233015.png&#34; alt=&#34;image-20210122101233015&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122101233015.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以通过命令 &lt;strong&gt;docker command --help&lt;/strong&gt; 更深入的了解指定的 Docker 命令使用方法。&lt;/p&gt;
&lt;p&gt;例如我们要查看 &lt;strong&gt;docker stats&lt;/strong&gt; 指令的具体使用方法：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker stats --help&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210122101335591.png&#34; alt=&#34;image-20210122101335591&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210122101335591.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;搜索镜像&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#搜索镜像&#34;&gt;#&lt;/a&gt; 搜索镜像&lt;/h3&gt;
&lt;p&gt;官网查看镜像版本地址&lt;/p&gt;
&lt;p&gt;&lt;code&gt;https://hub.docker.com/&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker search httpd&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;获取镜像&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#获取镜像&#34;&gt;#&lt;/a&gt; 获取镜像&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker pull xxxx&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;新建并启动容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#新建并启动容器&#34;&gt;#&lt;/a&gt; 新建并启动容器&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker run &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;docker run ‐d ‐p 8761:8761 microservice‐eureka‐server:0.0.1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 使用 -v 可以挂载一个主机上的目录到容器的目录&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;docker run ‐p 8761:8761 ‐v /log:/container‐log microservice‐eureka‐server:0.0.1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;启动容器已创建的&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#启动容器已创建的&#34;&gt;#&lt;/a&gt; 启动容器（已创建的）&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker start &amp;lt;CONTAINER ID&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;查看启动容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看启动容器&#34;&gt;#&lt;/a&gt; 查看启动容器&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker ps&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;查看所有容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看所有容器&#34;&gt;#&lt;/a&gt; 查看所有容器&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker ps -a&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;停止容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#停止容器&#34;&gt;#&lt;/a&gt; 停止容器&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker stop &amp;lt;容器 ID&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;重启容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#重启容器&#34;&gt;#&lt;/a&gt; 重启容器&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker restart &amp;lt;容器 ID&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;进入容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#进入容器&#34;&gt;#&lt;/a&gt; 进入容器&lt;/h3&gt;
&lt;p&gt;在使用 &lt;strong&gt;-d&lt;/strong&gt; 参数时，容器启动后会进入后台。此时想要进入容器，可以通过以下指令进入：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;docker attach&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;docker exec&lt;/strong&gt;：推荐大家使用 docker exec 命令，因为此退出容器终端，不会导致容器的停止。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;attach 命令&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;下面演示了使用 docker attach 命令。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ docker attach 1e560fca3906 &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a href=&#34;https://www.runoob.com/wp-content/uploads/2016/05/docker-attach.png&#34;&gt;&lt;img src=&#34;/img/docker-attach.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/docker-attach.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;注意：&lt;/strong&gt; 如果从这个容器退出，会导致容器的停止。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;exec 命令&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;下面演示了使用 docker exec 命令。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker exec -it 243c32535da7 &amp;#x2F;bin&amp;#x2F;bash&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a href=&#34;https://www.runoob.com/wp-content/uploads/2016/05/docker-exec.png&#34;&gt;&lt;img src=&#34;/img/docker-exec.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/docker-exec.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;注意：&lt;/strong&gt; 如果从这个容器退出，容器不会停止，这就是为什么推荐大家使用 &lt;strong&gt;docker exec&lt;/strong&gt; 的原因。&lt;/p&gt;
&lt;p&gt;更多参数说明请使用 &lt;strong&gt;docker exec --help&lt;/strong&gt; 命令查看。&lt;/p&gt;
&lt;h3 id=&#34;获得容器root权限&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#获得容器root权限&#34;&gt;#&lt;/a&gt; 获得容器 root 权限&lt;/h3&gt;
&lt;p&gt;第一步：查看容器的 CONTAINER ID&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker ps&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;ps: 需要运行中的容器&lt;/p&gt;
&lt;p&gt;第二步：获取 root 权限，例如需要进入的 CONTAINER ID 为 2209371edd48&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker exec -ti -u root 2209371edd48 bash&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;导出和导入容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#导出和导入容器&#34;&gt;#&lt;/a&gt; 导出和导入容器&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;导出容器&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;如果要导出本地某个容器，可以使用 &lt;strong&gt;docker export&lt;/strong&gt; 命令。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker export 1e560fca3906 &amp;gt; ubuntu.tar&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;导出容器 1e560fca3906 快照到本地文件 ubuntu.tar。&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://www.runoob.com/wp-content/uploads/2016/05/docker-export.png&#34;&gt;&lt;img src=&#34;/img/docker-export.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/docker-export.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;这样将导出容器快照到本地文件。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;导入容器快照&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;可以使用 docker import 从容器快照文件中再导入为镜像，以下实例将快照文件 ubuntu.tar 导入到镜像 test/ubuntu:v1:&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cat docker&amp;#x2F;ubuntu.tar | docker import - test&amp;#x2F;ubuntu:v1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a href=&#34;https://www.runoob.com/wp-content/uploads/2016/05/docker-import.png&#34;&gt;&lt;img src=&#34;/img/docker-import.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/docker-import.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;此外，也可以通过指定 URL 或者某个目录来导入，例如：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker import http:&amp;#x2F;&amp;#x2F;example.com&amp;#x2F;exampleimage.tgz example&amp;#x2F;imagerepo&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;删除容器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#删除容器&#34;&gt;#&lt;/a&gt; 删除容器&lt;/h3&gt;
&lt;p&gt;删除容器使用 &lt;strong&gt;docker rm&lt;/strong&gt; 命令：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker rm -f 1e560fca3906&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;a href=&#34;https://www.runoob.com/wp-content/uploads/2016/05/docker-container-rmi.png&#34;&gt;&lt;img src=&#34;/img/docker-container-rmi.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/docker-container-rmi.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;下面的命令可以清理掉所有处于终止状态的容器。&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker container prune&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;设置容器自动启动&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#设置容器自动启动&#34;&gt;#&lt;/a&gt; 设置容器自动启动&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 在运行docker容器时可以加如下参数来保证每次docker服务重启后容器也自动重启：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;docker run --restart=always&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 如果已经启动了则可以使用如下命令：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;docker update --restart=always &amp;lt;CONTAINER ID&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;docker-cp-命令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#docker-cp-命令&#34;&gt;#&lt;/a&gt; Docker cp 命令&lt;/h3&gt;
&lt;hr&gt;
&lt;p&gt;**docker cp 😗* 用于容器与主机之间的数据拷贝。&lt;/p&gt;
&lt;h4 id=&#34;语法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#语法&#34;&gt;#&lt;/a&gt; 语法&lt;/h4&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker cp [OPTIONS] CONTAINER:SRC_PATH DEST_PATH|-&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;docker cp [OPTIONS] SRC_PATH|- CONTAINER:DEST_PATH&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;OPTIONS 说明：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;**-L 😗* 保持源目标中的链接&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;实例&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#实例&#34;&gt;#&lt;/a&gt; 实例&lt;/h4&gt;
&lt;p&gt;将主机 /www/runoob 目录拷贝到容器 96f7f14e99ab 的 /www 目录下。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker cp &amp;#x2F;www&amp;#x2F;runoob 96f7f14e99ab:&amp;#x2F;www&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;将主机 /www/runoob 目录拷贝到容器 96f7f14e99ab 中，目录重命名为 www。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker cp &amp;#x2F;www&amp;#x2F;runoob 96f7f14e99ab:&amp;#x2F;www&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;将容器 96f7f14e99ab 的 /www 目录拷贝到主机的 /tmp 目录中。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;docker cp  96f7f14e99ab:&amp;#x2F;www &amp;#x2F;tmp&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;附录&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#附录&#34;&gt;#&lt;/a&gt; 附录&lt;/h3&gt;
&lt;p&gt;菜鸟教程 - docker  &lt;code&gt;https://www.runoob.com/docker/docker-tutorial.html&lt;/code&gt;&lt;/p&gt;

 &lt;p&gt;jmeter 在 ubuntu 下面的配置以及使用&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;前言&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#前言&#34;&gt;#&lt;/a&gt; 前言&lt;/h2&gt;
&lt;p&gt;jmeter 是 apache 的一个开源压力测试工具。&lt;br&gt;
话说，实在很好奇开发出来的程序性能如何。所以抽空配置一下 jmeter，后续还会有实际压测例子。&lt;/p&gt;
&lt;p&gt;对了，可以先看看文章，参考：&lt;br&gt;
&lt;a href=&#34;https://www.cnblogs.com/MING-FBUG/p/9153016.html&#34;&gt;Jmeter 环境搭建与使用（Linux）&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://www.cnblogs.com/yangxia-test/p/3964881.html&#34;&gt;JMeter 学习（一）工具简单介绍&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://www.cnblogs.com/stulzq/p/8971531.html&#34;&gt;使用 JMeter 进行压力测试&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;几个重要地址：&lt;br&gt;
&lt;a href=&#34;https://jmeter.apache.org/&#34;&gt;jmeter 官网&lt;/a&gt;&lt;br&gt;
&lt;a href=&#34;https://jmeter.apache.org/usermanual/get-started.html&#34;&gt;官方指导&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;这里先预告一下，&lt;br&gt;
下面这个网站看起来是相当专业的，&lt;br&gt;
&lt;a href=&#34;http://www.techempower.com/benchmarks/#section=data-r17&amp;amp;hw=ph&amp;amp;test=json&#34;&gt;Web Framework Benchmarks&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;第一页，json 格式化性能：&lt;br&gt;
&lt;img src=&#34;/img/20190125192323368.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125192323368.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;额，前面几个看不到 spring，spring 在这里呢：&lt;br&gt;
&lt;img src=&#34;/img/20190125192407432.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125192407432.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;单条数据库查询：&lt;br&gt;
&lt;img src=&#34;/img/20190125192557216.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125192557216.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;额，spring 在后面呢：&lt;br&gt;
&lt;img src=&#34;/img/20190125192611518.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125192611518.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;写完这篇文章以后，下一个目标是，重做 benchmark 试验 ---- 当然就针对 java web 框架，譬如：vert.x 还有 spring 什么的，还 spring 一个正名。额，当然用的是自己的渣渣机器，然而没问题，只要得出胜负就可以了。&lt;/em&gt;&lt;/p&gt;
&lt;h2 id=&#34;配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#配置&#34;&gt;#&lt;/a&gt; 配置&lt;/h2&gt;
&lt;p&gt;在官网下载 jmeter，额，这里：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo wget http:&amp;#x2F;&amp;#x2F;mirrors.shu.edu.cn&amp;#x2F;apache&amp;#x2F;&amp;#x2F;jmeter&amp;#x2F;binaries&amp;#x2F;apache-jmeter-5.0.tgz&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125193112828.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125193112828.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;解压缩到目标文件：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo mkdir -p &amp;#x2F;usr&amp;#x2F;local&amp;#x2F;jmeter&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-- 解压到目标目录：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo tar -zxvf apache-jmeter-5.0.tgz -C &amp;#x2F;usr&amp;#x2F;local&amp;#x2F;jmeter&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125193257314.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125193257314.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以得知，文件现在的 jmeter 的正式目录是：&lt;br&gt;
/usr/local/jmeter/apache-jmeter-5.0/&lt;/p&gt;
&lt;p&gt;好了，将 bin 路径加入到环境变量中去：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo vim &amp;#x2F;etc&amp;#x2F;profile&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;写入以下内容：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#配置jmeter&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;export PATH&amp;#x3D;&amp;#x2F;usr&amp;#x2F;local&amp;#x2F;jmeter&amp;#x2F;apache-jmeter-5.0&amp;#x2F;bin:$PATH&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125193658222.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125193658222.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
然后，&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;source &amp;#x2F;etc&amp;#x2F;profile&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;再试试能不能运行 jmeter：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;jmeter -v&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125193750436.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125193750436.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;成功运行，嗯，这样就配置好了。&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;进行一个单机web网站测试&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#进行一个单机web网站测试&#34;&gt;#&lt;/a&gt; 进行一个单机 web 网站测试&lt;/h2&gt;
&lt;h3 id=&#34;受测网站准备&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#受测网站准备&#34;&gt;#&lt;/a&gt; 受测网站准备&lt;/h3&gt;
&lt;p&gt;好了，作为程序员，身边肯定会有一些网站可以随便开启随便测试的，下面我就随便测试其中一个网站，是前几篇博文提到的 fileserver webapp：&lt;br&gt;
&lt;img src=&#34;/img/20190125194337529.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125194337529.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;测试的接口是这个。&lt;/p&gt;
&lt;h3 id=&#34;测试计划&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#测试计划&#34;&gt;#&lt;/a&gt; 测试计划&lt;/h3&gt;
&lt;p&gt;在命令行输入：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;jmeter&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;可启动客户端，&lt;br&gt;
&lt;img src=&#34;/img/2019012519460212.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/2019012519460212.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
好了，现在来制定测试计划&lt;/p&gt;
&lt;p&gt;&lt;em&gt;下面部分照着&lt;/em&gt;&lt;br&gt;
&lt;a href=&#34;https://www.cnblogs.com/stulzq/p/8971531.html&#34;&gt;使用 JMeter 进行压力测试&lt;/a&gt;&lt;br&gt;
&lt;em&gt;来做&lt;/em&gt;，尤其是，&lt;strong&gt;我压根没办法截取菜单的图片，直接引用&lt;/strong&gt;&lt;/p&gt;
&lt;h4 id=&#34;1创建线程组&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1创建线程组&#34;&gt;#&lt;/a&gt; 1. 创建线程组&lt;/h4&gt;
&lt;p&gt;在 “测试计划” 上右键 【添加】–&amp;gt;【Threads (Users)】–&amp;gt;【线程组】。&lt;br&gt;
&lt;img src=&#34;/img/20190125201333113.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125201333113.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;然后，额，根据他的来是 500 的，这个恐怕有点高了，不过没关系，设为 500：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;设置线程数和循环次数。我这里设置线程数为 500，循环一次。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125201507611.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125201507611.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;2配置元件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2配置元件&#34;&gt;#&lt;/a&gt; 2. 配置元件&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;在我们刚刚创建的线程组上右键 【添加】–&amp;gt;【配置元件】–&amp;gt;【HTTP 请求默认值】。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125201642264.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125201642264.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;配置我们需要进行测试的程序协议、地址和端口&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;em&gt;譬如，我本地的是：&lt;/em&gt;&lt;br&gt;
&lt;img src=&#34;/img/20190125202007458.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125202007458.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;当所有的接口测试的访问域名和端口都一样时，可以使用该元件，一旦服务器地址变更，只需要修改请求默认值即可。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;3构造http请求&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3构造http请求&#34;&gt;#&lt;/a&gt; 3. 构造 HTTP 请求&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;在 “线程组” 右键 【添加 -】-&amp;gt;【samlper】–&amp;gt;【HTTP 请求】设置我们需要测试的 API 的请求路径和数据。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125202225571.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125202225571.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;根据实际情况，应该这样：&lt;/em&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125203950235.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125203950235.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;注意，参数不要有空格等特殊符号 — 除非你将空格自己手动转为 url 认可的编码。&lt;/p&gt;
&lt;h3 id=&#34;4添加http请求头&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4添加http请求头&#34;&gt;#&lt;/a&gt; 4. 添加 HTTP 请求头&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125202650438.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125202650438.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;这个。。也加上去。。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125202812321.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125202812321.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;5添加断言&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5添加断言&#34;&gt;#&lt;/a&gt; 5. 添加断言&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;在我们刚刚创建的线程组上右键 【添加】–&amp;gt;【断言】–&amp;gt;【响应断言】。根据响应的数据来判断请求是否正常。我在这里只判断的响应代码是否为 200。还可以配置错误信息&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;/img/2019012520321973.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/2019012520321973.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;好了，按实际情况，&lt;/em&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125203305757.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125203305757.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;6添加察看结果树&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6添加察看结果树&#34;&gt;#&lt;/a&gt; 6. 添加察看结果树&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;在我们刚刚创建的线程组上右键 【添加】–&amp;gt;【监听器】–&amp;gt;【察看结果树】。直接添加，然后点击运行按钮就可以看到结果了。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125203533863.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125203533863.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
实际响应情况：&lt;br&gt;
&lt;img src=&#34;/img/20190125204115824.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125204115824.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;7添加summary-report&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#7添加summary-report&#34;&gt;#&lt;/a&gt; 7. 添加 Summary Report&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;在我们刚刚创建的线程组上右键 【添加】–&amp;gt;【监听器】–&amp;gt;【Summary Report】。直接添加，然后点击运行按钮就可以看到结果了。&lt;br&gt;
&lt;img src=&#34;/img/20190125204307331.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125204307331.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;实际情况：&lt;br&gt;
&lt;img src=&#34;/img/20190125204434827.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125204434827.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;8测试计划创建完成&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#8测试计划创建完成&#34;&gt;#&lt;/a&gt; 8. 测试计划创建完成&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;记得点保存。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;执行测试计划&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#执行测试计划&#34;&gt;#&lt;/a&gt; 执行测试计划&lt;/h2&gt;
&lt;p&gt;先参考：&lt;br&gt;
&lt;img src=&#34;/img/20190125204641669.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125204641669.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
实际情况：&lt;br&gt;
&lt;img src=&#34;/img/20190125204800977.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125204800977.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;本地的保存地址为：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;home&amp;#x2F;too-white&amp;#x2F;测试计划&amp;#x2F;file-server-web-app-test1.jmx&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;实际命令为：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cd &amp;#x2F;home&amp;#x2F;too-white&amp;#x2F;测试计划&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mkdir -p testplan&amp;#x2F;webreport&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;jmeter -n -t file-server-web-app-test1.jmx  -l result.txt -e -o testplan&amp;#x2F;webreport&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;执行结果：&lt;br&gt;
&lt;img src=&#34;/img/20190125210626864.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125210626864.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;话说不知道为什么每次都要 source /etc/profile 才能识别到 jmeter 的目录&lt;/em&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125210805445.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125210805445.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;附录&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#附录&#34;&gt;#&lt;/a&gt; 附录&lt;/h2&gt;
&lt;p&gt;&lt;a href=&#34;https://www.cnblogs.com/yangxia-test/p/3964881.html&#34;&gt;JMeter 学习（一）工具简单介绍&lt;/a&gt;&lt;br&gt;
该文章的部分内容&lt;br&gt;
&lt;img src=&#34;/img/20190125195744129.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125195744129.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125195752486.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125195752486.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125195759746.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125195759746.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
&lt;img src=&#34;/img/20190125195831146.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125195831146.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
&lt;img src=&#34;/img/20190125195858443.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125195858443.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
&lt;img src=&#34;/img/20190125195924279.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125195924279.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
&lt;img src=&#34;/img/20190125195951896.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125195951896.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20190125200031728.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125200031728.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
&lt;img src=&#34;/img/20190125200055470.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125200055470.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;br&gt;
&lt;img src=&#34;/img/20190125200133287.png&#34; alt=&#34;在这里插入图片描述&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20190125200133287.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;git 项目同时提交至多个远程仓库&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;我创建了一个项目，然后通过下面的命令  &lt;code&gt;push&lt;/code&gt;  到了 Git Hub 上。如何再将这个项目  &lt;code&gt;push&lt;/code&gt;  到其他远程仓库呢？&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git remote add github https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;zxbetter&amp;#x2F;test.git&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git push -u github master&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;方法一-使用-git-remote-add-命令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法一-使用-git-remote-add-命令&#34;&gt;#&lt;/a&gt; 方法一：使用  &lt;code&gt;git remote add&lt;/code&gt;  命令&lt;/h4&gt;
&lt;p&gt;1.1# 如下命令查看远程仓库的情况，可以看到只有一个叫  &lt;code&gt;github&lt;/code&gt;  的远程仓库。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git remote&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git remote -v&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github  https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;zxbetter&amp;#x2F;test.git (fetch)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github  https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;zxbetter&amp;#x2F;test.git (push)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;1.2# 使用如下命令再添加一个远程仓库（这里以码云为例）&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git remote add oschina https:&amp;#x2F;&amp;#x2F;git.oschina.net&amp;#x2F;zxbetter&amp;#x2F;test.git&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;1.3# 再次查看远程仓库的情况，可以看到已经有两个远程仓库了。然后再使用相应的命令  &lt;code&gt;push&lt;/code&gt;  到对应的仓库就行了。&lt;em&gt;这种方法的缺点是每次要  &lt;code&gt;push&lt;/code&gt;  两次。&lt;/em&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git remote&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;oschina&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git remote -v&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github  https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;zxbetter&amp;#x2F;test.git (fetch)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github  https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;zxbetter&amp;#x2F;test.git (push)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;oschina https:&amp;#x2F;&amp;#x2F;git.oschina.net&amp;#x2F;zxbetter&amp;#x2F;test.git (fetch)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;oschina https:&amp;#x2F;&amp;#x2F;git.oschina.net&amp;#x2F;zxbetter&amp;#x2F;test.git (push)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;方法二-使用-git-remote-set-url-命令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法二-使用-git-remote-set-url-命令&#34;&gt;#&lt;/a&gt; 方法二：使用  &lt;code&gt;git remote set-url&lt;/code&gt;  命令&lt;/h4&gt;
&lt;p&gt;2.1# 删除方法一的  &lt;code&gt;oschina&lt;/code&gt;  远程仓库。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git remote rm oschina&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;2.2# 使用如下命令添加远程仓库。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git remote set-url --add github https:&amp;#x2F;&amp;#x2F;git.oschina.net&amp;#x2F;zxbetter&amp;#x2F;test.git&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;2.3# 查看远程仓库情况。可以看到  &lt;code&gt;github&lt;/code&gt;  远程仓库有两个  &lt;code&gt;push&lt;/code&gt;  地址。&lt;em&gt;这种方法的好处是每次只需要  &lt;code&gt;push&lt;/code&gt;  一次就行了。&lt;/em&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git remote -v&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github  https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;zxbetter&amp;#x2F;test.git (fetch)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github  https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;zxbetter&amp;#x2F;test.git (push)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;github  https:&amp;#x2F;&amp;#x2F;git.oschina.net&amp;#x2F;zxbetter&amp;#x2F;test.git (push)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;方法三-修改配置文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法三-修改配置文件&#34;&gt;#&lt;/a&gt; 方法三：修改配置文件&lt;/h4&gt;
&lt;p&gt;打开  &lt;code&gt;.git/config&lt;/code&gt;  找到  &lt;code&gt;[remote &amp;quot;github&amp;quot;]&lt;/code&gt; ，添加对应的  &lt;code&gt;url&lt;/code&gt;  即可，效果如下。这种方法其实和方法二是一样的。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[remote &amp;quot;github&amp;quot;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    url &amp;#x3D; https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;zxbetter&amp;#x2F;test.git&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    fetch &amp;#x3D; +refs&amp;#x2F;heads&amp;#x2F;*:refs&amp;#x2F;remotes&amp;#x2F;github&amp;#x2F;*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    url &amp;#x3D; https:&amp;#x2F;&amp;#x2F;git.oschina.net&amp;#x2F;zxbetter&amp;#x2F;test.git&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;关于-git-pull&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关于-git-pull&#34;&gt;#&lt;/a&gt; 关于  &lt;code&gt;git pull&lt;/code&gt;&lt;/h4&gt;
&lt;p&gt;方法二和三在  &lt;code&gt;push&lt;/code&gt;  的时候比较方便。但是在  &lt;code&gt;pull&lt;/code&gt;  的时候只能从方法三中的第一个  &lt;code&gt;url&lt;/code&gt;  地址拉取代码。而方法一则不存在这种问题（可能要解决冲突）。&lt;br&gt;
所以，如果只进行  &lt;code&gt;push&lt;/code&gt;  操作，推荐方法二和三，如果也要进行  &lt;code&gt;pull&lt;/code&gt;  操作，推荐方法一。&lt;/p&gt;

 &lt;p&gt;通过配置文件的方式配置这些参数加载配置。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;./bin/mongod --config ./conf/mongodb.conf (或./bin/mongod -f ./conf/mongodb.conf)&lt;/p&gt;
&lt;p&gt;配置（mongod.conf）参数说明如下。&lt;/p&gt;
&lt;h3 id=&#34;基本配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基本配置&#34;&gt;#&lt;/a&gt; &lt;strong&gt;基本配置&lt;/strong&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight yaml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#verbose：日志信息冗余。默认false。提高内部报告标准输出或记录到logpath配置的日志文件中。要启用verbose或启用verbosity 用vvvv参数&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;verbose&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#启动verbose冗长信息，它的级别有 vv~vvvvv，v越多级别越高，在日志文件中记录的信息越详细。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;vvvv&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#port：端口。默认27017，MongoDB的默认服务TCP端口，监听客户端连接。要是端口设置小于1024，比如1021，则需要root权限启动，不能用mongodb帐号启动&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;port&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;27017&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#bind_ip：绑定地址。默认127.0.0.1，只能通过本地连接。进程绑定和监听来自这个地址上的应用连接。要是需要给其他服务器连接，则需要注释掉这个或则把IP改成本机地址，可以用一个逗号分隔的列表绑定多个IP地址。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;bind_ip&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;127.0&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;.0&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;.1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#maxConns：最大连接数。默认值：取决于系统（即的ulimit和文件描述符）限制。MongoDB中不会限制其自身的连接。当设置大于系统的限制，则无效，以系统限制为准。这对于客户端创建很多“表”，允许连接超时而不关闭“表”的时候很有用。设置该值的高于连接池和总连接数的大小，以防止尖峰时候的连接。注意：不能设置该值大于20000。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;maxConns&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1000&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#objcheck:强制验证客户端请求。2.4的默认设置为objcheck成为true，在早期版本objcheck默认为false。因为它强制验证客户端请求，确保客户端绝不插入无效文件到数据库中。对于嵌套文档的对象，会有一点性能影响。设置noobjcheck 关闭。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;objcheck&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#noobjcheck = false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#logpath：指定日志文件，该文件将保存所有的日志记录、诊断信息。除非另有指定，mongod将所有的日志信息输出到标准输出。如果没有指定logappend，重启则日志会进行覆盖操作。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;logpath=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;/home/mongo/mongodb-2.6.8/logs/mongodb.log&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#logappend：写日志的模式：设置为true为追加。默认是覆盖。如果未指定此设置，启动时MongoDB的将覆盖现有的日志文件。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;logappend=true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#syslog：日志输出都发送到主机的syslog系统，而不是标准输出到logpath指定日志文件。syslog和logpath不能一起用，会报错：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;syslog&lt;/span&gt;  &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#pidfilepath：进程ID，没有指定则启动时候就没有PID文件。默认缺省。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;pidfilepath&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;/home/mongo/mongodb-2.6.8/data/mongo.pid&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#keyFile：指定存储身份验证信息的密钥文件的路径。默认缺省。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;keyFile&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;/home/mongo/mongodb-2.6.8/data/keyfile&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#nounixsocket：套接字文件，默认为false，有生成socket文件。当设置为true时，不会生成socket文件。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;nounixsocket&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#unixSocketPrefix：套接字文件路径，默认/tmp&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;unixSocketPrefix&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;/home/mongo/mongodb-2.6.8/tmp&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#fork：是否后台运行，设置为true 启动 进程在后台运行的守护进程模式。默认false。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;fork&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#auth：用户认证，默认false。不需要认证。当设置为true时候，进入数据库需要auth验证，当数据库里没有用户，则不需要验证也可以操作。直到创建了第一个用户，之后操作都需要验证。比如：通过db.addUser(&amp;#x27;sa&amp;#x27;,&amp;#x27;sa&amp;#x27;)在admin库下面创建一个超级用户，只能在在admin库下面先认证完毕了：ab.auth(&amp;#x27;sa&amp;#x27;,&amp;#x27;sa&amp;#x27;)，才能去别的库操作，不能在其他库验证。这样连接数据库也需要指定库：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#mongo -usa -psa admin     #sa 帐号连接admin&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#mongo -uaa -paa test      #aa 帐号连接test&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;auth&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#noauth：禁止用户认证，默认true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;noauth&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#cpu：设置为true会强制mongodb每4s报告cpu利用率和io等待，把日志信息写到标准输出或日志文件。默认为false。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;cpu&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#dbpath：数据存放目录。默认：/data/db/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;dbpath=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;/home/mongo/mongodb-2.6.8/data/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#diaglog：创建一个非常详细的故障排除和各种错误的诊断日志记录。默认0。设置为1，为在dbpath目录里生成一个diaglog.开头的日志文件，设置不等于0，日志会每分钟flush一次。产生的日志可以用mongosniff来查看，当重新设置成0，会停止写入文件，但mongod还是继续保持打开该文件，即使它不再写入数据文件。如果你想重命名，移动或删除诊断日志，你必须完全关闭mongod实例。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;    &lt;span class=&#34;string&#34;&gt;off.&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;No&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;logging.&lt;/span&gt;       &lt;span class=&#34;comment&#34;&gt;#关闭。没有记录。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#1    Log write operations.  #写操作&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#2    Log read operations.   #读操作&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#3    Log both read and write operations. #读写操作&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#7    Log write and some read operations. #写和一些读操作&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#directoryperdb：设置为true，修改数据目录存储模式，每个数据库的文件存储在DBPATH指定目录的不同的文件夹中。使用此选项，可以配置的MongoDB将数据存储在不同的磁盘设备上，以提高写入吞吐量或磁盘容量。默认为false。要是在运行一段时间的数据库中，开启该参数，会导致原始的数据都会消失（注释参数则会回来）。因为数据目录都不同了，除非迁移现有的数据文件到directoryperdb产生的数据库目录中，所以需要在规划好之后确定是否要开启。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;directoryperdb&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;ture&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#journal：日志，（redo log，更多的介绍请看这里和这里）。默认值：（在64位系统）true。默认值：（32位系统）false。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#设置为true，启用操作日志，以确保写入持久性和数据的一致性，会在dbpath目录下创建journal目录。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#设置为false，以防止日志持久性的情况下，并不需要开销。为了减少磁盘上使用的日志的影响，您可以启用nojournal，并设置为true。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#注意：在64位系统上禁用日志必须使用带有nojournal的。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;journal&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#nojournal:禁止日志，默认值：（在64位系统）false。默认值：（32位系统）true。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#设置nojournal为true关闭日志，64位，2.0版本后的mongodb默认是启用 journal日志。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;nojournal&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#journalCommitInterval：刷写提交机制，默认是30ms或则100ms。较低的值，会更消耗磁盘的性能。此选项接受2和300毫秒之间的值：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#如果单块设备提供日志和数据文件，默认的日记提交时间间隔为100毫秒。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#如果不同的块设备提供的日志和数据文件，默认的日记提交的时间间隔为30毫秒。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;journalCommitInterval&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;100&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#ipv6：是否支持ipv6，默认false。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;ipv6&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#jsonp：是否允许JSONP访问通过一个HTTP接口，默认false。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;jsonp&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#nohttpinterface：是否禁止http接口，即28017 端口开启的服务。默认false，支持。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;nohttpinterface&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#noprealloc：预分配方式。默认false：使用预分配方式来保证写入性能的稳定，预分配在后台进行，并且每个预分配的文件都用0进行填充。这会让MongoDB始终保持额外的空间和空余的数据文件，从而避免了数据增长过快而带来的分配磁盘空间引起的阻塞。设置noprealloc= true来禁用预分配的数据文件，会缩短启动时间，但在正常操作过程中，可能会导致性能显著下降。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;noprealloc&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#noscripting：是否禁止脚本引擎。默认是false：不禁止。ture：禁止,要是设置成true：运行一些脚本的时候会出现：&amp;quot;server-side JavaScript execution is disabled&amp;quot; &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;noscripting&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#notablescan：是否禁止表扫描操作。默认false：不禁止，ture：禁止,禁止要是执行表扫描会出现：&amp;quot;table scans not allowed&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;notablescan&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#nssize:命名空间的文件（即NS）的默认大小，默认16M，最大2G。所有新创建的默认大小命名空间的文件（即NS）。此选项不会影响现有的命名空间的文件的大小。默认值是16M字节，最大大小为2 GB。让小数据库不让浪费太多的磁盘空间，同时让大数据在磁盘上有连续的空间。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;nssize&lt;/span&gt;  &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;16&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#profile：数据库分析等级设置。记录一些操作性能到标准输出或则指定的logpath的日志文件中，默认0:关闭。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#0 关。无分析。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#1 开。仅包括慢操作。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#2 开。包括所有操作。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#控制 Profiling  的开关和级别：2种,第一种是直接在启动参数里直接进行设置或则启动MongoDB时加上–profile=级别，其信息保存在 生成的system.profile 中。第二种是在客户端用db.setProfilingLevel(级别)命令来实时配置，其信息保存在 生成的system.profile 中。默认情况下，mongod的禁用分析。数据库分析可以影响数据库的性能，因为分析器必须记录和处理所有的数据库操作。所以在需要的时候用动态修改就可以了。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;profile&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#slowms：记录profile分析的慢查询的时间，默认是100毫秒。具体同上。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;slowms&lt;/span&gt;  &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;200&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#quota：配额，默认false。是否开启配置每个数据库的最多文件数的限制。当为true则用quotaFiles来配置最多文件的数量。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;quota&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#quotaFiles：配额数量。每个数据库的数据文件数量的限制。此选项需要quota为true。默认为8。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;quotaFiles&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#rest： 默认false，设置为true，使一个简单的 REST API。设置为true，开启后，在MongoDB默认会开启一个HTTP协议的端口提供REST的服务（nohttpinterface=false），这个端口是你Server端口加上1000，即28017，默认的HTTP端口是数据库状态页面，（开启后，web页面的Commands行中的命令都可以点进去）。mongodb自带的REST，不支持增、删、改，同时也不支持 权限认证。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;rest&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#repair：修复数据库操作，默认是false。设置为true时，启动后修复所有数据库，设置这个选项最好在命令行上，而不是在配置文件或控制脚本。启动时修复，需要关闭journal.并且启动时,用控制文件指定参数和配置文件里指定参数的方式进行修复之后，（修复信息见log），需要再禁用repair参数才能启用mongodb。注意：mongod修复时，需要重写所有的数据库文件。如果在同一个帐号下不能运行修复，则需要运行chown修改数据库文件的权限。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;repair&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#repairpath：修复路径，默认是在dbpath路径下的_tmp 目录。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;repairpath&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;_tmp&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#smallfiles：是否使用较小的默认文件。默认为false，不使用。设置为true，使用较小的默认数据文件大小。smallfiles减少数据文件的初始大小，并限制他们到512M，也减少了日志文件的大小，并限制他们到128M。如果数据库很大，各持有少量的数据，会导致mongodb创建很多文件，会影响性能。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;smallfiles&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#syncdelay：刷写数据到日志的频率，通过fsync操作数据。默认60秒。默认就可以，不需要设置。不会对日志文件（journal files）有影响。警告：如果设置为0，SYNCDELAY 不会同步到磁盘的内存映射文件。在生产系统上，不要设置这个值。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;syncdelay&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;60&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#sysinfo：系统信息，默认false。设置为true，mongod会诊断系统有关的页面大小，数量的物理页面，可用物理??页面的数量输出到标准输出。当开启sysinfo参数的时候，只会打印上面的信息，不会启动mongodb的程序。所以要关闭该参数，才能开启mongodb。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;sysinfo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#upgrade:升级。默认为false。当设置为true，指定DBPATH，升级磁盘上的数据格式的文件到最新版本。会影响数据库操作，更新元数据。大部分情况下，不需要设置该值。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;upgrade&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#traceExceptions：是否使用内部诊断。默认false。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;traceExceptions&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#quiet：安静模式。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;quiet&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#setParameter：2.4的新参数，指定启动选项配置。想设置多个选项则用一个setParameter选项指定.格式：setParameter = &amp;lt;parameter&amp;gt;=&amp;lt;value&amp;gt;,如配置文件里设置syncdelay：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;setParameter&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;syncdelay=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;55&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;,notablescan&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;,journalCommitInterval&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;,traceExceptions&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;复制选项replication-options&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#复制选项replication-options&#34;&gt;#&lt;/a&gt; &lt;strong&gt;复制选项（Replication Options）&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;replSet：使用此设置来配置复制副本集。指定一个副本集名称作为参数，所有主机都必须有相同的名称作为同一个副本集。&lt;br&gt;
oplogSize：指定的复制操作日志（OPLOG）的最大大小。mongod 创建一个 OPLOG 的大小基于最大可用空间量。对于 64 位系统，OPLOG 通常是 5％的可用磁盘空间。&lt;br&gt;
一旦 mongod 第一次创建 OPLOG，改变 oplogSize 将不会影响 OPLOG 的大小。&lt;br&gt;
fastsync：默认为 false。在副本集下，设置为 true，从一个 dbpath 里启用从库复制服务，该 dbpath 的数据库是主库的快照，可用于快速启用同步，否则的 mongod 将尝试执行初始同步。注意：如果数据不完全同步，mongod 指定 fastsync 开启，secondary 或 slave 与主永久不同步，这可能会导致显着的一致性问题。&lt;br&gt;
replIndexPrefetch：2.2 版本出现的新参数，默认是 all。可以设置的值有：all, none, and _id_only。只能在副本集（replSet）中使用。默认情况下，secondary 副本集的成员将加载所有索引到内存中（从 OPLOG 之前的操作有关的）。您可以修改此行为，使 secondary 只会加载_id 索引。指定_id_或 none，防止 mongod 的任何索引加载到内存。&lt;/p&gt;
&lt;h3 id=&#34;主从复制的相关设置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#主从复制的相关设置&#34;&gt;#&lt;/a&gt; &lt;strong&gt;主从复制的相关设置&lt;/strong&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight ini&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#master：默认为false，当设置为true，则配置当前实例作为主实例。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;master&lt;/span&gt; = &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#slave：默认为false，当设置为true，则配置当前实例作为从实例。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;slave&lt;/span&gt; = &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#source：默认为空，格式为：&amp;lt;host&amp;gt;&amp;lt;:port&amp;gt;。用于从实例的复制：设置从的时候指定该选项会让从复制指定主的实例。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;source&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;127.0&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;0.1&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;30001&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#only：默认为空，用于从选项，指定一个数据库进行复制。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;only&lt;/span&gt; = abc          &lt;span class=&#34;comment&#34;&gt;#只同步abc集合（库）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#slavedelay：设置从库同步主库的延迟时间，用于从设置，默认为0。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;slavedelay&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;60&lt;/span&gt;     &lt;span class=&#34;comment&#34;&gt;#延迟60s同步主数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#autoresync：默认为false，用于从设置。是否自动重新同步。设置为true，如果落后主超过10秒，会强制从自动重新同步。如果oplogSize太小，此设置可能有问题。如果OPLOG大小不足以存储主的变化状态和从的状态变化之间的差异，这种情况下强制重新同步是不必要的。当设置autoresync选项设置为false，10分钟内从不会进行大于1次的自动重新同步。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;autoresync&lt;/span&gt; = &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;分片集群设置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#分片集群设置&#34;&gt;#&lt;/a&gt; &lt;strong&gt;分片集群设置&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;configsvr  #设置是否是配置服务，默认端口 27019，默认目录 /data/configdb&lt;/p&gt;
&lt;p&gt;shardsvr  #设置是否分片，默认端口 27018&lt;/p&gt;
&lt;p&gt;配置实例：conf/mongod.conf&lt;/p&gt;
&lt;figure class=&#34;highlight ini&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#port 端口号&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;port&lt;/span&gt;=&lt;span class=&#34;number&#34;&gt;23000&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#dbpath 数据库存储文件目录&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;dbpath&lt;/span&gt;=/home/mongo/mongodb-&lt;span class=&#34;number&#34;&gt;2.6&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;/data&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#logpath 日志路径&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;logpath&lt;/span&gt;=/home/mongo/mongodb-&lt;span class=&#34;number&#34;&gt;2.6&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;/logs/mongodb.log&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#logappend 日志追加形式  false:重新启动覆盖文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;logappend&lt;/span&gt;=&lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#fork 后台启动&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;fork&lt;/span&gt;=&lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#设置日志级别&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#0 - 关闭性能分析，测试环境可以打开，生成环境关闭，对性能有很大影响;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#1 - 开启慢查询日志，执行时间大于100毫秒的语句&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#2 - 开启所有操作日志&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;profile&lt;/span&gt;=&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;启动：./bin/mongod -f conf/mongod.conf&lt;/p&gt;

 &lt;p&gt;测试环境为 CentOS7&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;一、通过定时任务备份 mysql 数据库&lt;/p&gt;
&lt;h3 id=&#34;前提条件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#前提条件&#34;&gt;#&lt;/a&gt; 前提条件：&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;首先在备份机上安装 mysql 的客户端，或者直接安装 mysql 也可以。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;开始备份&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#开始备份&#34;&gt;#&lt;/a&gt; 开始备份&lt;/h3&gt;
&lt;h4 id=&#34;1-创建备份文件存储路径&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-创建备份文件存储路径&#34;&gt;#&lt;/a&gt; 1、 创建备份文件存储路径&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mkdir /data/backup/test/&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;2-创建备份脚本&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-创建备份脚本&#34;&gt;#&lt;/a&gt; 2、创建备份脚本&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;vim backup.sh&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;写入 shell：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; -u用户名 -p密码 这两者中间不能添加空格，存在空格会备份失败&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysqldump -h 需要备份数据库所在机器ip -u用户名 -p密码 备份的数据库名 --opt -Q -R --skip-lock-tables &amp;gt; 备份文件所在路径&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;实例：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 此处的文件保存路径一定要写绝对路径，相对路径会有问题&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysqldump -h 192.168.0.11 -uroot -p123456 test --opt -Q -R --skip-lock-tables &amp;gt; /data/backup/test/test_$(date +%Y%m%d_%H%M%S).sql&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;在创建成功之后可以先运行测试一下看看，相应的路径下面是否有备份的 sql 文件生成。&lt;/p&gt;
&lt;h4 id=&#34;3-创建定时任务&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-创建定时任务&#34;&gt;#&lt;/a&gt; 3、创建定时任务&lt;/h4&gt;
&lt;h5 id=&#34;31安装-crontab&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#31安装-crontab&#34;&gt;#&lt;/a&gt; 3.1 安装 &lt;a href=&#34;https://www.baidu.com/s?wd=cron&amp;amp;tn=24004469_oem_dg&amp;amp;rsv_dl=gh_pl_sl_csd&#34;&gt;cron&lt;/a&gt;tab&lt;/h5&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;查看crontab是否安装&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;crontab -l&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;no crontab &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; root  未安装&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;安装crontab&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yum -y install vixie-cron     # crontabs的核心依赖&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yum install crontabs&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;服务状态控制&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/sbin/service crond start //启动服务 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/sbin/service crond stop //关闭服务 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/sbin/service crond restart //重启服务 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/sbin/service crond reload //重新载入配置 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/sbin/service crond status //查看状态&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;或者使用&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;service crond start &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;service crond stop &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;service crond restart &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;service crond reload &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;service crond status&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;开机启动&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vim /etc/rc.d/rc.local&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/sbin/service crond start&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;32加入计划任务&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#32加入计划任务&#34;&gt;#&lt;/a&gt; 3.2 加入计划任务&lt;/h5&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;crontab -e&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 1 * * * sh /data/backup.sh&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;查看计划任务是否执行：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;命令类似tomcat的日志查看&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;tail -f /var/log/cron&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;至此，其实定时备份已经完成了，不过还可以有个小优化，在每次执行备份的时候检查一下，多长时间之外的备份文件就不要了，不然备份文件日积月累会越来越多，把磁盘挤爆。。。。&lt;/p&gt;
&lt;p&gt;在 backup.sh 中加入下面语句：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;rm -rf $(find /data/backup/ -mtime +30 -name &amp;quot;*.sql&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;这样就能只备份最近一个月的文件了。&lt;/p&gt;
&lt;h3 id=&#34;配置参数说明&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#配置参数说明&#34;&gt;#&lt;/a&gt; 配置参数说明&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;基本格式 :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*　　*　　*　　*　　*　　command&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;分　时　日　月　周　命令&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第1列表示分钟1～59 每分钟用*或者 */1表示&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第2列表示小时1～23（0表示0点）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第3列表示日期1～31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第4列表示月份1～12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第5列标识号星期0～6（0表示星期天）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第6列要运行的命令&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;crontab文件的一些例子：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30 21 * * * /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;上面的例子表示每晚的21:30重启apache。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45 4 1,10,22 * * /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;上面的例子表示每月1、10、22日的4 : 45重启apache。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10 1 * * 6,0 /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;上面的例子表示每周六、周日的1 : 10重启apache。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0,30 18-23 * * * /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;上面的例子表示在每天18 : 00至23 : 00之间每隔30分钟重启apache。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 23 * * 6 /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;上面的例子表示每星期六的11 : 00 pm重启apache。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;* */1 * * * /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;每一小时重启apache&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;* 23-7/1 * * * /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;晚上11点到早上7点之间，每隔一小时重启apache&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 11 4 * mon-wed /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;每月的4号与每周一到周三的11点重启apache&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0 4 1 jan * /usr/local/etc/rc.d/lighttpd restart&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;一月一号的4点重启apache&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;可能出现的问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#可能出现的问题&#34;&gt;#&lt;/a&gt; 可能出现的问题&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210106132325967.png&#34; alt=&#34;image-20210106132325967&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210106132325967.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;定时任务执行时提示错误 &lt;code&gt;0x004b#012&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;需要修改一个配置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;vim /etc/postfix/main.cf&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210106132521335.png&#34; alt=&#34;image-20210106132521335&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210106132521335.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;CentOS 根目录（/）下会有很多不同的子目录&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;演示环境&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#演示环境&#34;&gt;#&lt;/a&gt; 演示环境&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[root@hwc ~]# cat /etc/redhat-release&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;CentOS Linux release 7.6.1810 (Core)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;操作步骤&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#操作步骤&#34;&gt;#&lt;/a&gt; 操作步骤&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;编辑&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;etc&amp;#x2F;vimrc&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;文件&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;vim /etc/vimrc&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;在文件最后添加以下内容&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;set ts=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set autoindent&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set softtabstop=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set shiftwidth=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set noexpandtab&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set pastetoggle=&amp;lt;F9&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set nu&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;说明&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#说明&#34;&gt;#&lt;/a&gt; 说明&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;ts: (ts 是 tabstop 的缩写) 一个 tab 显示多少个空格的长度，vim 默认 8。&lt;/li&gt;
&lt;li&gt;autoindent: 前行有缩进时，后续的新行将会自动缩进到相同的位置。&lt;/li&gt;
&lt;li&gt;softtabstop: 编辑模式的时候按退格键的时候退回缩进的长度。&lt;/li&gt;
&lt;li&gt;shiftwidth: 每一级缩进的长度，一般设置成跟 softtabstop 一样。&lt;/li&gt;
&lt;li&gt;expandtab: 缩进用空格来表示。&lt;/li&gt;
&lt;li&gt;noexpandtab: 缩进用制表符表示。&lt;/li&gt;
&lt;li&gt;pastetoggle：开启粘贴模式，换行不自动缩进&lt;/li&gt;
&lt;li&gt;set nu: 默认显示行号&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;注：expandtab /noexpandtab 二选一。&lt;/strong&gt;&lt;/p&gt;

 &lt;p&gt;CentOS 根目录（/）下会有很多不同的子目录&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;bin&lt;/strong&gt; : 存放普通用户可执行的指令，即使在单用户模式下也能够执行处理&lt;/li&gt;
&lt;li&gt;**boot ：** 开机引导目录，包括 Linux 内核文件与开机所需要的文件&lt;/li&gt;
&lt;li&gt;**dev ：** 设备目录，所有的硬件设备及周边均放置在这个设备目录中&lt;/li&gt;
&lt;li&gt;**etc：** 各种配置文件目录，大部分配置属性均存放在这里&lt;/li&gt;
&lt;li&gt;**home：** 这里主要存放你的个人数据，具体每个用户的设置文件，用户的桌面文件夹，还有用户的数据都放在这里。每个用户都有自己的用户目录，位置为：/home/ 用户名。当然，root 用户除外。&lt;/li&gt;
&lt;li&gt;**lib：** 开机时常用的动态链接库，bin 及 sbin 指令也会调用对应的 lib 库&lt;/li&gt;
&lt;li&gt;**lib64：** 开机时常用的动态链接库 64 位，bin 及 sbin 指令也会调用对应的 lib 库&lt;/li&gt;
&lt;li&gt;**lost+found：** 是一个特殊目录，用途是用来存放文件系统错误导致文件丢失后找回数据的；如果你不小心删除了 lost+found 目录，不用使用 mkdir 命令创建 lost+found 目录，应该使用 mklost+found 命令创建 lost+found 目录。&lt;/li&gt;
&lt;li&gt;**media：** 可移除设备挂载目录，类似软盘 U 盘 光盘等临时挂放目录&lt;/li&gt;
&lt;li&gt;**mnt：** 用户临时挂载其他的文件系统，额外的设备可挂载在这里，相对临时而言&lt;/li&gt;
&lt;li&gt;**opt：** 第三方软件安装目录，现在习惯性的放置在 /usr/local 中&lt;/li&gt;
&lt;li&gt;**proc：** 虚拟文件系统，通常是内存中的映射，特别注意在误删除数据文件后，比如 DB，只要系 统不重启，还是有很大几率能将数据找回来&lt;/li&gt;
&lt;li&gt;**root：** 系统管理员主目录，除 root 之外，其他用户均放置在 /home 目录下&lt;/li&gt;
&lt;li&gt;**run：** 系统运行是所需文件，以前防止在 /var/run 中，后来拆分成独立的 /run 目录。重启后重新生成对应的目录数据&lt;/li&gt;
&lt;li&gt;**sbin：** 只有 root 才能运行的管理指令，跟 bin 类似，但只属于 root 管理员&lt;/li&gt;
&lt;li&gt;**srv：** 服务启动后需要访问的数据目录，&lt;/li&gt;
&lt;li&gt;**sys：** 跟 proc 一样虚拟文件系统，记录核心系统硬件信息&lt;/li&gt;
&lt;li&gt;**tmp：** 存放临时文件目录，所有用户对该目录均可读写&lt;/li&gt;
&lt;li&gt;**usr：** 应用程序放置目录，&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;var&lt;/strong&gt; ：存放系统执行过程经常改变的文件，&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;vmlinuz :&lt;/strong&gt; 是可引导的，压缩的 linux 内核，“vm” 代表的 “virtual memory”, 一般是一个软连接.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;还有一个重要的目录就是：/var/log/ 目录，主要存放的是系统日志文件：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;**/var/log/message 😗* 系统启动后的信息和错误日志，是 Linux 中最常用的日志之一&lt;/li&gt;
&lt;li&gt;**/var/log/secure 😗* 与安全相关的日志信息&lt;/li&gt;
&lt;li&gt;**/var/log/maillog 😗* 与邮件相关的日志信息&lt;/li&gt;
&lt;li&gt;**/var/log/cron 😗* 与定时任务相关的日志信息&lt;/li&gt;
&lt;li&gt;**/var/log/spooler 😗* 与 UUCP 和 news 设备相关的日志信息&lt;/li&gt;
&lt;li&gt;**/var/log/boot.log 😗* 守护进程启动和停止相关的日志消息&lt;/li&gt;
&lt;/ul&gt;

 &lt;p&gt;解决 Ubuntu 中解压 Windows 下的 zip 文件时乱码问题&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;三种方法 :&lt;/p&gt;
&lt;h3 id=&#34;1通过指定字符集解压&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1通过指定字符集解压&#34;&gt;#&lt;/a&gt; 1. 通过指定字符集解压:&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;unzip -O CP936 file.zip    #将file修改成你要解压的压缩包名&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2环境变量中指定参数&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2环境变量中指定参数&#34;&gt;#&lt;/a&gt; 2. 环境变量中指定参数:&lt;/h3&gt;
&lt;p&gt;1) 打开环境变量文件&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo gedit /etc/environment&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;2) 在文件中添加两行内容后并保存:&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;UNZIP=&amp;quot;-O CP936&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ZIPINFO=&amp;quot;-O CP936&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3) 使上一步的更改生效 (此步骤一定要做):&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;source /etc/environment&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;3使用其他的解压工具unar&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3使用其他的解压工具unar&#34;&gt;#&lt;/a&gt; 3. 使用其他的解压工具 unar:&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt install unar&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;然后使用命令解压文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;unar file.zip&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;hr&gt;
&lt;h2 id=&#34;1-分析&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-分析&#34;&gt;#&lt;/a&gt; 1. 分析&lt;/h2&gt;
&lt;h3 id=&#34;11-zip解压时文件乱码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#11-zip解压时文件乱码&#34;&gt;#&lt;/a&gt; 1.1 zip 解压时文件乱码&lt;/h3&gt;
&lt;p&gt;本质问题还是 zip 格式的缺陷，没有字段标志出文件名的编码格式。&lt;br&gt;
ZIP 在压缩与解压缩的时候默认使用了系统的本地编码，如 windows 中文环境下的编码多为 gbk，gb2312，日文环境下是 JIS，linux 默认编码为 UTF8 等；那么在不同系统环境下，只要压缩与解压缩的编码不一致，就会出现乱码。&lt;a href=&#34;http://godsing.top/2018/01/31/Ubuntu%E8%A7%A3%E5%8E%8B%E7%BC%A9%E4%B8%8E%E6%96%87%E4%BB%B6(%E5%90%8D)%E4%B9%B1%E7%A0%81%E9%97%AE%E9%A2%98/#fn_1&#34;&gt;1&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;12-tarxz-文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#12-tarxz-文件&#34;&gt;#&lt;/a&gt; 1.2 tar.xz 文件&lt;/h3&gt;
&lt;p&gt;tar.xz 结尾的压缩文件，解决方法如下：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$xz -d file.tar.xz # 会得到 file.tar 文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$tar -xvf  file.tar -C your-directory&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;这个压缩包也是打包后再压缩，外面是 xz 压缩方式，里层是 tar 打包方式。&lt;/p&gt;
&lt;h3 id=&#34;13-targz即tgz解压&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#13-targz即tgz解压&#34;&gt;#&lt;/a&gt; 1.3 tar.gz (即.tgz) 解压&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;tar -zxvf File.tgz -C Your-Directory&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;2-文件名乱码解决方案&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-文件名乱码解决方案&#34;&gt;#&lt;/a&gt; 2. 文件名 | 乱码解决方案&lt;/h2&gt;
&lt;h3 id=&#34;21-unzip方案&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#21-unzip方案&#34;&gt;#&lt;/a&gt; 2.1 unzip 方案&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# 先试试&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;unzip -O GB18030 file.zip -d directory&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# 不行再试试 GBK也可写成CP936，这是gbk编码在windows里的别称&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;unzip -O GBK file.zip -d directory &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# 再不行继续试试&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;unzip -O GB2312 file.zip -d directory&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;这么试的原因是，编码技术的演进方向为：GB2312 ⇒ GBK (=CP936) ⇒ GB18030，最新的一般能兼容旧的编码技术，遇到不兼容的情况再用旧的编码去尝试。如果无法使用  &lt;code&gt;-O&lt;/code&gt;  参数，参考以下链接打补丁。&lt;/p&gt;
&lt;h4 id=&#34;缺参数则给unzip打补丁&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#缺参数则给unzip打补丁&#34;&gt;#&lt;/a&gt; 缺参数，则给 unzip 打补丁&lt;/h4&gt;
&lt;p&gt;参考 &lt;a href=&#34;https://github.com/ikohara/dpkg-unzip-iconv&#34;&gt;https://github.com/ikohara/dpkg-unzip-iconv&lt;/a&gt; ；按步骤给 unzip 打补丁，打完即可使用 &lt;code&gt;-O&lt;/code&gt;  参数了。&lt;/p&gt;
&lt;h3 id=&#34;22-unar方案&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#22-unar方案&#34;&gt;#&lt;/a&gt; 2.2 unar 方案&lt;/h3&gt;
&lt;p&gt;如果是 Debian，已经默认安装了 unar，这个工具会自动检测文件的编码，也可以通过 - e 来指定：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install unar&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;unar file.zip&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;即可解压出中文文件。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;1. 安装&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install unar&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;2. 列出压缩包内容&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;lsar test.zip&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;3. 解压压缩包&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;unar test.zip&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;4.unar 常用选项解释&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;-o&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;解释：指定解压结果保存的位置&lt;br&gt;
 &lt;code&gt;unar test.zip -o /home/dir/&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;-e&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;解释：指定编码&lt;br&gt;
 &lt;code&gt;unar -e GBK test.zip&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;-p&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;解释：指定解压密码&lt;br&gt;
 &lt;code&gt;unar -p 123456 test.zip&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;strong&gt;3. 解决 linux 解压压缩包中文文件名乱码问题&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;lsar test.zip&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;###若发现乱码，可指定压缩包文件名使用的编码格式##&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;lsar -e GB18030 test.zip&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;###若能正常列出文件名，可解压###&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;unar -e GB18030 test.zip&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;23-7z和convmv结合方案&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#23-7z和convmv结合方案&#34;&gt;#&lt;/a&gt; 2.3 7z 和 convmv 结合方案&lt;/h3&gt;
&lt;p&gt;在 ubuntu 下的安装命令是&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install p7zip-full convmv&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;安装完之后，就可以用 &lt;code&gt;7z&lt;/code&gt;  和 &lt;code&gt;convmv&lt;/code&gt;  两个命令完成解压缩任务。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;LANG&amp;#x3D;C 7z x zip-file.zip&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;convmv -f GBK -t utf8 --notest -r your_unzipped_file_floder&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;# 或者先cd到解压好的地方&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;convmv -f gbk -t utf8 --notest  .&amp;#x2F;* （其实应该一个点 . 就行了，而不用 .&amp;#x2F;*）&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;第一条命令用于解压缩，而 LANG=C 表示以 US-ASCII 这样的编码输出文件名，如果没有这个语言设置，它同样会输出乱码，只不过是 UTF8 格式的乱码 ( &lt;code&gt;convmv&lt;/code&gt;  会忽略这样的乱码)。&lt;/p&gt;
&lt;p&gt;第二条命令是将 GBK 编码的文件名转化为 UTF8 编码， &lt;code&gt;-r&lt;/code&gt;  表示递归访问目录，即对当前目录中所有文件进行转换。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;convmv 支持的部分参数如下：&lt;/p&gt;
&lt;p&gt;&lt;code&gt;-f&lt;/code&gt;  源编码&lt;/p&gt;
&lt;p&gt;&lt;code&gt;-t&lt;/code&gt;  目标编码&lt;/p&gt;
&lt;p&gt;&lt;code&gt;--notest&lt;/code&gt;  convmv 默认只会显示文件名转换后的结果而不会实际进行转换。使用这个参数使 convmv 对文件名进行实际的编码转换。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;--list&lt;/code&gt;  列出 convmv 支持的所有编码&lt;/p&gt;
&lt;p&gt;&lt;code&gt;-r&lt;/code&gt;  递归转换所有子目录的文件名编码&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;24-7z方案&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#24-7z方案&#34;&gt;#&lt;/a&gt; 2.4 7z 方案&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;apt-get install p7zip-full&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;7zip 命令有 7z 和 7za，7za 是精简版部分格式不支持，7z 是全功能版的，建议使用 7z。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;7z &amp;#123;a|d|l|e|u|x&amp;#125; 压缩包文件名 &amp;#123;文件列表或目录，可选&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;a 向压缩包里添加文件或创建压缩包，如向 deepvps.7z 添加 deepvps001.jpg，执行：7z a deepvps.7z deepvps001.jpg；将 deepvps 目录打包执行：7z a deepvps.7z deepvps；&lt;/li&gt;
&lt;li&gt;d 从压缩里删除文件，如将 deepvps.7z 里的 test.jpg 删除，执行：7z d deepvps.7z test.jpg&lt;/li&gt;
&lt;li&gt;l 列出压缩包里的文件，如列出 deepvps.7z 里的文件，执行：7z l deepvps.7z&lt;/li&gt;
&lt;li&gt;e 解压到当前目录，目录结构会被破坏，如 deepvps.rar 内有如下目录及文件 123/456/789.html，执行：7z e deepvps.rar，目录 123 和 456 及文件 789.html 都会存放在当前目录下。&lt;/li&gt;
&lt;li&gt;x 以完整路径解压。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;由于 zip 文件中没有声明其编码，所以在 Linux 上使用 unzip 解压以默认编码解压，中文文件名会出现乱码。&lt;/p&gt;
&lt;p&gt;使用 7z 解压即可解决： &lt;code&gt;7z x deepvps.zip&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;也可以使用： &lt;code&gt;jar xvf deepvps.zip&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;3-文件内容乱码解决方案&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-文件内容乱码解决方案&#34;&gt;#&lt;/a&gt; 3 文件内容 | 乱码解决方案&lt;/h2&gt;
&lt;h3 id=&#34;21-iconv工具&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#21-iconv工具&#34;&gt;#&lt;/a&gt; 2.1 iconv 工具&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;iconv -f gbk -t utf-8 file1 -o file2  # gbk编码转换为utf-8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;命令很简单，可以 man 出手册或者 &lt;code&gt;--help&lt;/code&gt;  看一下。&lt;/p&gt;
&lt;h3 id=&#34;22-enca工具&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#22-enca工具&#34;&gt;#&lt;/a&gt; 2.2 enca 工具&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;# -L指明文件语言，一般可以省略&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;enca -L zh_CN file # 检查文件的编码&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;enca -L zh_CN -x UTF-8 file # 将文件编码转换为&amp;quot;UTF-8&amp;quot;编码&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;enca -L zh_CN -x UTF-8 file1 file2 # 如果不想覆盖原文件可以这样&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;说说遇到的坑：非得让我指定语言，不指定还不行，说可以用  &lt;code&gt;-L none&lt;/code&gt; ，然而根本识别不了。然后又试了 zh_CN，一样不行。用  &lt;code&gt;enca --list language&lt;/code&gt;  查看所支持的语言列表，然而写那么多一堆，居然没有 English，逗我？！而且，这列表里的项不能直接当作  &lt;code&gt;-L&lt;/code&gt;  的参数，不知道参数去哪里查！然后就懒得继续查了，毕竟问题已解决。&lt;/p&gt;
&lt;h3 id=&#34;23-查看文件编码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#23-查看文件编码&#34;&gt;#&lt;/a&gt; 2.3 查看文件编码&lt;/h3&gt;
&lt;h4 id=&#34;231-用vim查看&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#231-用vim查看&#34;&gt;#&lt;/a&gt; 2.3.1 用 vim 查看&lt;/h4&gt;
&lt;p&gt;用 vim 打开文件，输入：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;:set fileencoding&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;回车便可看到编码，但是&lt;strong&gt;不一定可信&lt;/strong&gt;！&lt;/p&gt;
&lt;p&gt;我的一个本地文件 besttrace4linux.txt ，明明是 GB18030 编码，但用 vim 查询显示是 latin1 编码，搞死我了！&lt;/p&gt;
&lt;p&gt;用 &lt;code&gt;iconv&lt;/code&gt;  试着把该文件从 latin1, ascii 转成 utf-8, iso88592, gb2312 各种错！最后试着转到 GB18030，发现居然能转过去，只是转过去后仍然是乱码。此时我灵机一动，该不会原本就是这个编码吧？然后回到我的 zsh，发现果然在 zsh 打印的信息里显示了正确的中文！我屮艸芔茻，花了一个小时终于见到曙光了。这时候，一句：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;iconv -f gb18030 -t utf-8 besttrace4linux.txt -o readme.txt&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;哇！世界从未如此美好，成功！至此，知道&lt;strong&gt;用 vim 查看编码是会骗人的&lt;/strong&gt;！！！&lt;/p&gt;

 &lt;p&gt;前端基本开发环境安装，node、npm、cnpm、@angular&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;安装nodejs&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装nodejs&#34;&gt;#&lt;/a&gt; 安装 nodejs&lt;/h2&gt;
&lt;p&gt;第一步，去 nodejs 官网 &lt;a href=&#34;https://nodejs.org/&#34;&gt;https://nodejs.org&lt;/a&gt; 看最新的版本号；&lt;img src=&#34;/img/image-20210123213318414.png&#34; alt=&#34;image-20210123213318414&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210123213318414.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;求稳的话建议选 LTS 版。&lt;/p&gt;
&lt;p&gt;第二步，添加源后安装&lt;br&gt;
重点来了，nodejs 的每个大版本号都有相对应的源，比如这里的 14.x.x 版本的源是 https://deb.nodesource.com/setup_14.x。&lt;/p&gt;
&lt;p&gt;所以在终端执行：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;curl -sL https://deb.nodesource.com/setup_14.x | sudo -E bash - &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;稍等片刻，源已经添加完毕，再执行：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install -y nodejs&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;等待安装完成。&lt;/p&gt;
&lt;h2 id=&#34;安装npm&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装npm&#34;&gt;#&lt;/a&gt; 安装 npm&lt;/h2&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt install npm&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210123213822768.png&#34; alt=&#34;image-20210123213822768&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210123213822768.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;淘宝npm镜像-cnpm&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#淘宝npm镜像-cnpm&#34;&gt;#&lt;/a&gt; 淘宝 npm 镜像 cnpm&lt;/h2&gt;
&lt;p&gt;国内直接使用 npm 的官方镜像是非常慢的，这里推荐使用淘宝 NPM 镜像。&lt;/p&gt;
&lt;p&gt;淘宝 NPM 镜像是一个完整 &lt;a href=&#34;http://npmjs.org&#34;&gt;npmjs.org&lt;/a&gt; 镜像，可以用此代替官方版本 (只读)，同步频率目前为 10 分钟 一次以保证尽量与官方服务同步。&lt;/p&gt;
&lt;p&gt;用 npm 安装 cnm&lt;/p&gt;
&lt;figure class=&#34;highlight sql&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm &lt;span class=&#34;keyword&#34;&gt;install&lt;/span&gt; -g cnpm &lt;span class=&#34;comment&#34;&gt;--registry=https://registry.npm.taobao.org&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;错误&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#错误&#34;&gt;#&lt;/a&gt; 错误&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210123214230438.png&#34; alt=&#34;image-20210123214230438&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210123214230438.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;错误原因&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#错误原因&#34;&gt;#&lt;/a&gt; 错误原因&lt;/h2&gt;
&lt;p&gt;找到报错的文件，会看到它的所有者是  &lt;code&gt;root&lt;/code&gt; 。&lt;br&gt;
之前用  &lt;code&gt;root&lt;/code&gt;  进行了局部的安装操作，导致这个文件的所有者是  &lt;code&gt;root&lt;/code&gt;  ，还包括  &lt;code&gt;.npm&lt;/code&gt;  文件夹下部分文件夹的所有权，也是  &lt;code&gt;root&lt;/code&gt; ，普通用户当然就无权访问了。就会报权限错误。&lt;/p&gt;
&lt;h2 id=&#34;解决办法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解决办法&#34;&gt;#&lt;/a&gt; 解决办法&lt;/h2&gt;
&lt;p&gt;就是把用户目录下的  &lt;code&gt;.npm&lt;/code&gt;  文件夹所有权都改成当前用户即可。&lt;br&gt;
比如：当前用户名为 sunfy&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo chown -R sunfy ~/.npm&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;安装angular&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装angular&#34;&gt;#&lt;/a&gt; 安装 Angular&lt;/h2&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install -g @angular/cli&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210123214609372.png&#34; alt=&#34;image-20210123214609372&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210123214609372.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;npm安装后提示命令不存在&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#npm安装后提示命令不存在&#34;&gt;#&lt;/a&gt; npm 安装后提示命令不存在&lt;/h2&gt;
&lt;p&gt;解决方案：用一个通用的命令配置环境变量&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;echo -e &amp;quot;export PATH&amp;#x3D;$(npm prefix -g)&amp;#x2F;bin:$PATH&amp;quot; &amp;gt;&amp;gt; ~&amp;#x2F;.bashrc &amp;amp;&amp;amp; source ~&amp;#x2F;.bashrc&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;JRebel&lt;/p&gt;
&lt;p&gt;JRebel 是一款 JVM 插件，它使得 Java 代码修改后不用重启系统，立即生效。IDEA 上原生是不支持热部署的，一般更新了 Java 文件后要手动重启 Tomcat 服务器，才能生效，浪费时间浪费生命。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;目前对于 idea 热部署最好的解决方案就是安装 JRebel 插件。&lt;/p&gt;
&lt;h2 id=&#34;简单破解&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#简单破解&#34;&gt;#&lt;/a&gt; 简单破解&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;步骤 1: 生成一个 GUID：
&lt;ul&gt;
&lt;li&gt;生成 GUID 网站如下&lt;/li&gt;
&lt;li&gt;&lt;img src=&#34;/img/image-20210112092008958.png&#34; alt=&#34;image-20210112092008958&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210112092008958.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.guidgen.com/&#34;&gt;在线生成 GUID 地址&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;步骤 2: 根据反向代理服务器地址拼接激活地址
&lt;ul&gt;
&lt;li GUID=&#34;&#34;&gt;服务器地址： &lt;a href=&#34;https://jrebel.qekang.com/&#34;&gt;https://jrebel.qekang.com/&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;如果失效刷新 GUID 替换就可以！&lt;/p&gt;
&lt;p&gt;步骤 3: 打开 jrebel 激活面板。选择 Connect to online licensing service .&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210112092413865.png&#34; alt=&#34;image-20210112092413865&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210112092413865.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;激活成功的界面：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210112092457213.png&#34; alt=&#34;image-20210112092457213&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210112092457213.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://shimo.im/docs/tcy38p6VTxQ8tcdv/read&#34;&gt;https://shimo.im/docs/tcy38p6VTxQ8tcdv/read&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;前面的安装步骤这里就不赘述了，直接开始正式的激活工作。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/LHyOVDkGstOUaHyr.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/LHyOVDkGstOUaHyr.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;第一步：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;打开我提供的激活文件&lt;/p&gt;
&lt;p&gt;** 激活文件获取方式，微信扫描下方二维码，回复：**&lt;strong&gt;dg2021&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/DBtAbKadtH2FOOuY.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/DBtAbKadtH2FOOuY.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;img src=&#34;../../img/qcCjmEDdiZ7kkthv.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/qcCjmEDdiZ7kkthv.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;reset_script&lt;/code&gt;  这里面有两个脚本，根据自己的操作系统执行不同的脚本。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/7crBriRDrPFdtDzO.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/7crBriRDrPFdtDzO.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;根据自己的操作系统执行对应脚本&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;windows 系统执行&lt;/strong&gt;：reset_jetbrains_eval_windows.vbs&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;linux/mac 系统执行&lt;/strong&gt;：reset_jetbrains_eval_mac_linux.sh&lt;/p&gt;
&lt;p&gt;出现下方界面代表执行完毕&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/zshQ59319R3ebtq9.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/zshQ59319R3ebtq9.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;第二步：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;安装将文件内的 &lt;code&gt;BetterIntelliJ.zip&lt;/code&gt;  补丁插件&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;安装方法一：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;直接拖入   &lt;code&gt;DataGrip&lt;/code&gt;  界面，然后重启即可。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/YgzTxn93hoRNeLEJ.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/YgzTxn93hoRNeLEJ.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;安装方法二：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;通过菜单栏的 File-&amp;gt;settings-&amp;gt;Plugins 安装插件，选择   &lt;code&gt;install Plugin from Disk&lt;/code&gt;  然后选择补丁文件，重启即可。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/2ItJhLtqETbi3Wtj.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/2ItJhLtqETbi3Wtj.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;第三步：输入激活码&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;4-输入激活码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4-输入激活码&#34;&gt;#&lt;/a&gt; 4、输入激活码&lt;/h3&gt;
&lt;p&gt;重启完毕之后，输入我提供的激活码。（在  &lt;code&gt;激活补丁key.txt&lt;/code&gt;  这个文件中）&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/ATxsPTtsU4cITTZR.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/ATxsPTtsU4cITTZR.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/6gSQCkBgOMMvnWPC.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/6gSQCkBgOMMvnWPC.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;注意事项&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#注意事项&#34;&gt;#&lt;/a&gt; 注意事项&lt;/h2&gt;
&lt;p&gt;1、&lt;/p&gt;
&lt;p&gt;插件安装完成后，建议检查一下是否安装成功，点击菜单： &lt;code&gt;Help -&amp;gt; Edit Custom VM Options...&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/3wWFTZbcwqF9K5Ys.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/3wWFTZbcwqF9K5Ys.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;打开  &lt;code&gt;.vmoptions&lt;/code&gt;  配置文件，如果插件安装成功，会在文件中添加以  &lt;code&gt;-javaagent&lt;/code&gt;  为前缀的配置，如下图所示:&lt;/p&gt;
&lt;p&gt;Plain  Text&lt;/p&gt;
&lt;p&gt;## 以 windows 为例，正确配置如下：&lt;/p&gt;
&lt;p&gt;-javaagent:C:\Users\Public.BetterIntelliJ\BetterIntelliJ - 版本号.jar&lt;/p&gt;
&lt;p&gt;## 以 unix 为例，正确配置如下：&lt;/p&gt;
&lt;p&gt;-javaagent:${HOME}//.BetterIntelliJ/BetterIntelliJ - 版本号.jar&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;../../img/koB6HONmEnQ7lbtG.png!thumbnail&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;../../img/koB6HONmEnQ7lbtG.png!thumbnail&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;注意：如果你之前配置了其他的&lt;/strong&gt;  &lt;code&gt;-javaagent&lt;/code&gt;  路径，请一定要先删除掉 ！！！ 否则会激活不成功 ！！！&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;注意：如果你之前配置了其他的&lt;/strong&gt;  &lt;code&gt;-javaagent&lt;/code&gt;  路径，请一定要先删除掉 ！！！ 否则会激活不成功 ！！！&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;注意：如果你之前配置了其他的&lt;/strong&gt;  &lt;code&gt;-javaagent&lt;/code&gt;  路径，请一定要先删除掉 ！！！ 否则会激活不成功 ！！！&lt;/p&gt;
&lt;p&gt;2、&lt;/p&gt;
&lt;p&gt;如果激活码输入错误，请重启 DataGrip 后重试&lt;/p&gt;

 &lt;p&gt;Redis 缓存常见问题及相应问题的解决方案&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;缓存穿透&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#缓存穿透&#34;&gt;#&lt;/a&gt; 缓存穿透&lt;/h2&gt;
&lt;p&gt;查询一个根本不存在的数据， 缓存层和存储层都不会命中， 通常出于容错的考虑， 如果从存储层查不到数据则不写入缓存层。缓存穿透将导致不存在的数据每次请求都要到存储层去查询， 失去了缓存保护后端存储的意义。&lt;/p&gt;
&lt;h3 id=&#34;基本原因&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基本原因&#34;&gt;#&lt;/a&gt; 基本原因&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;自身业务代码或者数据出现问题。&lt;/li&gt;
&lt;li&gt;一些恶意攻击、 爬虫等造成大量空命中。&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;解决方案&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解决方案&#34;&gt;#&lt;/a&gt; 解决方案&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;缓存空对象&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;String &lt;span class=&#34;title&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String key)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 从缓存中获取数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String cacheValue = cache.get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 缓存为空&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (StringUtils.isBlank(cacheValue)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 从存储中获取&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String storageValue = storage.get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cache.set(key, storageValue);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 如果存储数据为空， 需要设置一个过期时间(300秒)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (storageValue == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cache.expire(key, &lt;span class=&#34;number&#34;&gt;60&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; storageValue;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 缓存非空&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; cacheValue;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;布隆过滤器：&lt;strong&gt;一个大型的位数组和几个不一样的无偏 hash 函数&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201117131001593.png&#34; alt=&#34;image-20201117131001593&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201117131001593.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201117131021438.png&#34; alt=&#34;image-20201117131021438&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201117131021438.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;示例代码&lt;/p&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;org.redisson&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;redisson&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;3.6.5&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dependency&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.redisson.Redisson;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.redisson.api.RBloomFilter;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.redisson.api.RedissonClient;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; org.redisson.config.Config;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;RedissonBloomFilter&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String[] args)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Config config = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Config();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        config.useSingleServer().setAddress(&lt;span class=&#34;string&#34;&gt;&amp;quot;redis://localhost:6379&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//构造Redisson&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        RedissonClient redisson = Redisson.create(config);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        RBloomFilter&amp;lt;String&amp;gt; bloomFilter = redisson.getBloomFilter(&lt;span class=&#34;string&#34;&gt;&amp;quot;nameList&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//初始化布隆过滤器：预计元素为100000000L,误差率为3%,根据这两个参数会计算出底层的bit数组大小&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bloomFilter.tryInit(&lt;span class=&#34;number&#34;&gt;100000000L&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;0.03&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//将zhuge插入到布隆过滤器中&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bloomFilter.add(&lt;span class=&#34;string&#34;&gt;&amp;quot;zhuge&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//判断下面号码是否在布隆过滤器中&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(bloomFilter.contains(&lt;span class=&#34;string&#34;&gt;&amp;quot;guojia&amp;quot;&lt;/span&gt;));&lt;span class=&#34;comment&#34;&gt;//false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(bloomFilter.contains(&lt;span class=&#34;string&#34;&gt;&amp;quot;baiqi&amp;quot;&lt;/span&gt;));&lt;span class=&#34;comment&#34;&gt;//false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(bloomFilter.contains(&lt;span class=&#34;string&#34;&gt;&amp;quot;zhuge&amp;quot;&lt;/span&gt;));&lt;span class=&#34;comment&#34;&gt;//true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;使用布隆过滤器需要把所有数据提前放入布隆过滤器，并且在增加数据时也要往布隆过滤器里放。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//初始化布隆过滤器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;RBloomFilter&amp;lt;String&amp;gt; bloomFilter = redisson.getBloomFilter(&lt;span class=&#34;string&#34;&gt;&amp;quot;nameList&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//初始化布隆过滤器：预计元素为100000000L,误差率为3%&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bloomFilter.tryInit(&lt;span class=&#34;number&#34;&gt;100000000L&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;0.03&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//把所有数据存入布隆过滤器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;init&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (String key: keys) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        bloomFilter.put(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;String &lt;span class=&#34;title&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String key)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 从布隆过滤器这一级缓存判断下key是否存在&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Boolean exist = bloomFilter.contains(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(!exist)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 从缓存中获取数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String cacheValue = cache.get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 缓存为空&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (StringUtils.isBlank(cacheValue)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 从存储中获取&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String storageValue = storage.get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cache.set(key, storageValue);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 如果存储数据为空， 需要设置一个过期时间(300秒)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (storageValue == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cache.expire(key, &lt;span class=&#34;number&#34;&gt;60&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; storageValue;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 缓存非空&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; cacheValue;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;注意：布隆过滤器不能删除数据，如果要删除得重新初始化数据。&lt;/strong&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;缓存失效缓存击穿&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#缓存失效缓存击穿&#34;&gt;#&lt;/a&gt; 缓存失效（缓存击穿）&lt;/h2&gt;
&lt;p&gt;由于大批量缓存在同一时间失效可能导致大量请求同时穿透缓存直达数据库，可能会造成数据库瞬间压力过大甚至挂掉。&lt;/p&gt;
&lt;p&gt;批量缓存数据时增加一个随机过期时间，保证不会在同一时刻有大量的缓存失效。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;String &lt;span class=&#34;title&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String key)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 从缓存中获取数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String cacheValue = cache.get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 缓存为空&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (StringUtils.isBlank(cacheValue)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 从存储中获取&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String storageValue = storage.get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cache.set(key, storageValue);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;//设置一个过期时间(300到600之间的一个随机数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt; expireTime = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Random().nextInt(&lt;span class=&#34;number&#34;&gt;300&lt;/span&gt;)  + &lt;span class=&#34;number&#34;&gt;300&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (storageValue == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cache.expire(key, expireTime);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; storageValue;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 缓存非空&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; cacheValue;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;缓存雪崩&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#缓存雪崩&#34;&gt;#&lt;/a&gt; 缓存雪崩&lt;/h2&gt;
&lt;p&gt;缓存层支撑不住或宕掉后， 流量会像奔逃的野牛一样， 打向后端存储层。&lt;/p&gt;
&lt;h3 id=&#34;预防和解决&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#预防和解决&#34;&gt;#&lt;/a&gt; 预防和解决&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;缓存层服务高可用性，比如使用 Redis Sentinel 或 Redis Cluster。&lt;/li&gt;
&lt;li&gt;依赖隔离组件为后端限流熔断并降级。比如使用 Sentinel 或 &lt;code&gt;Hystrix&lt;/code&gt;  限流降级组件&lt;/li&gt;
&lt;li&gt;提前演练。 在项目上线前， 演练缓存层宕掉后， 应用以及后端的负载情况以及可能出现的问题， 在此基础上做一些预案设定。&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;热点缓存key重建优化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#热点缓存key重建优化&#34;&gt;#&lt;/a&gt; 热点缓存 key 重建优化&lt;/h2&gt;
&lt;h3 id=&#34;问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#问题&#34;&gt;#&lt;/a&gt; 问题&lt;/h3&gt;
&lt;p&gt;缓存失效的瞬间， 有大量线程来重建缓存， 造成后端负载加大， 甚至可能会让应用崩溃。&lt;/p&gt;
&lt;h3 id=&#34;解决方案-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解决方案-2&#34;&gt;#&lt;/a&gt; 解决方案&lt;/h3&gt;
&lt;p&gt;解决这个问题主要就是要避免大量线程同时重建缓存。我们可以利用互斥锁来解决，此方法只允许一个线程重建缓存， 其他线程等待重建缓存的线程执行完， 重新从缓存获取数据即可。&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// 伪代码&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;String &lt;span class=&#34;title&#34;&gt;get&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String key)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 从Redis中获取数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String value = redis.get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 如果value为空， 则开始重构缓存&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (value == &lt;span class=&#34;keyword&#34;&gt;null&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;// 只允许一个线程重建缓存， 使用nx， 并设置过期时间ex&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String mutexKey = &lt;span class=&#34;string&#34;&gt;&amp;quot;mutext:key:&amp;quot;&lt;/span&gt; + key;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (redis.set(mutexKey, &lt;span class=&#34;string&#34;&gt;&amp;quot;1&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;ex 180&amp;quot;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;quot;nx&amp;quot;&lt;/span&gt;)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &lt;span class=&#34;comment&#34;&gt;// 从数据源获取数据&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            value = db.get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// 回写Redis， 并设置过期时间&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            redis.setex(key, timeout, value);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;// 删除key_mutex&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            redis.delete(mutexKey);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;span class=&#34;comment&#34;&gt;// 其他线程休息50毫秒后重试&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Thread.sleep(&lt;span class=&#34;number&#34;&gt;50&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            get(key);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; value;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;缓存与数据库双写不一致&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#缓存与数据库双写不一致&#34;&gt;#&lt;/a&gt; 缓存与数据库双写不一致&lt;/h2&gt;
&lt;p&gt;高并发情况下，同时操作数据库与缓存会存在数据不一致性问题。&lt;/p&gt;
&lt;h3 id=&#34;双写不一致&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#双写不一致&#34;&gt;#&lt;/a&gt; 双写不一致&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201117131812003.png&#34; alt=&#34;image-20201117131812003&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201117131812003.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;读写并发不一致&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#读写并发不一致&#34;&gt;#&lt;/a&gt; 读写并发不一致&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201117131856465.png&#34; alt=&#34;image-20201117131856465&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201117131856465.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;解决方案-3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#解决方案-3&#34;&gt;#&lt;/a&gt; 解决方案：&lt;/h3&gt;
&lt;p&gt;1、并发几率很小的数据 (如个人维度的订单数据、用户数据等)，这种几乎不用考虑这个问题，很少会发生缓存不一致，可以给缓存数据加上过期时间，每隔一段时间触发读的主动更新即可。&lt;/p&gt;
&lt;p&gt;2、并发很高，如果业务上能容忍短时间的缓存数据不一致 (如商品名称，商品分类菜单等)，缓存加上过期时间依然可以解决大部分业务对于缓存的要求。&lt;/p&gt;
&lt;p&gt;3、如果不能容忍缓存数据不一致，可以通过加&lt;strong&gt;读写锁&lt;/strong&gt;保证并发读写或写写的时候按顺序排好队，&lt;strong&gt;读读的时候相当于无锁&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;4、也可以用阿里开源的 canal 通过监听数据库的 binlog 日志及时的去修改缓存，但是引入了新的中间件，增加了系统的复杂度。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201117132005635.png&#34; alt=&#34;image-20201117132005635&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201117132005635.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;总结&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#总结&#34;&gt;#&lt;/a&gt; 总结&lt;/h3&gt;
&lt;p&gt;以上我们针对的都是&lt;strong&gt;读多写少&lt;/strong&gt;的情况加入缓存提高性能，如果&lt;strong&gt;写多读多&lt;/strong&gt;的情况又不能容忍缓存数据不一致，那就没必要加缓存了，可以直接操作数据库。放入缓存的数据应该是对实时性、一致性要求不是很高的数据。切记不要为了用缓存，同时又要保证绝对的一致性做大量的过度设计和控制，增加系统复杂性！&lt;/p&gt;

 &lt;p&gt;各个系统下批量修改文件后缀名（Windows,Ubuntu,CentOS） &lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;windows修改&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#windows修改&#34;&gt;#&lt;/a&gt; windows 修改&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;在所需修改的文件目录下，新建 txt 文件．此处什么类型的文件都可以，主要就是新建一个文件，通过命令修改。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;打开新建的文件，填写&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ren *.png *.txt&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;
&lt;p&gt;说明：此处命令将当前文件所在目录下的 png 后缀修改为 txt&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;将新建文件后缀名修改为 bat，将文件放在要修改目录下双击即可完成。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;ubuntu修改&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ubuntu修改&#34;&gt;#&lt;/a&gt; Ubuntu 修改&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 当前目录下的后缀名为.c的文件更改为.h的文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 格式  :&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 原字符串：将文件名需要替换的字符串；&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 目标字符串：将文件名中含有的原字符替换成目标字符串；&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 文件：指定要改变文件名的文件列表。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; rename &lt;span class=&#34;string&#34;&gt;&amp;#x27;命令参数/原串/替换后的串/&amp;#x27;&lt;/span&gt; 目录文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; s       表示替换&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rename &amp;#x27;s/\.c/\.h/&amp;#x27;  ./*&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;centos修改&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#centos修改&#34;&gt;#&lt;/a&gt; CentOS 修改&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 把当前目录下的后缀名为.c的文件更改为.h的文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rename .c .h *.c&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;shell脚本解决&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#shell脚本解决&#34;&gt;#&lt;/a&gt; Shell 脚本解决&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;!/bin/bash&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;find ./ -name *.c | while read i&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;do&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    echo &amp;quot;$i&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    mv $i.c $i.h&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;done &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;find-xargs-解决&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#find-xargs-解决&#34;&gt;#&lt;/a&gt; find xargs 解决&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 递归的更改，会更改当前目录下及其子目录下所有匹配文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;find ./ -name &amp;quot;*.c&amp;quot; | awk -F &amp;quot;.&amp;quot; &amp;#x27;&amp;#123;print $2&amp;#125;&amp;#x27; | xargs -i -t mv ./&amp;#123;&amp;#125;.c ./&amp;#123;&amp;#125;.h&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;Redis 集群架构搭建。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;基本步骤&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基本步骤&#34;&gt;#&lt;/a&gt; 基本步骤&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;第一步：在第一台机器的/usr/local下创建文件夹redis-cluster，然后在其下面分别创建2个文件夾如下&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	（1）mkdir -p /usr/local/redis-cluster&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	（2）mkdir 8001 8004&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第一步：把之前的redis.conf配置文件copy到8001下，修改如下内容：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	（1）daemonize yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （2）port 8001（分别对每个机器的端口号进行设置）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （3）dir /usr/local/redis-cluster/8001/（指定数据文件存放位置，必须要指定不同的目录位置，不然会丢失数据）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （4）cluster-enabled yes（启动集群模式）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （5）cluster-config-file nodes-8001.conf（集群节点信息文件，这里800x最好和port对应上）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （6）cluster-node-timeout 5000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （7）# bind 127.0.0.1（bind绑定的是自己机器网卡的ip，如果有多块网卡可以配多个ip，代表允许客户端通过机器的哪些网卡ip去访问，内网一般可以不配置bind，注释掉即可）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     (8)protected-mode  no   （关闭保护模式）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     (9)appendonly yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;设置密码需要增加如下配置：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     (10)requirepass zhuge     (设置redis访问密码)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     (11)masterauth zhuge      (设置集群节点间访问密码，跟上面一致)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第三步：把修改后的配置文件，copy到8004，修改第2、3、5项里的端口号，可以用批量替换：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;:%s/源字符串/目的字符串/g &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第四步：另外两台机器也需要做上面几步操作，第二台机器用8002和8005，第三台机器用8003和8006&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第五步：分别启动6个redis实例，然后检查是否启动成功&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （1）src/redis-server /usr/local/redis-cluster/800*/redis.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （2）ps -ef | grep redis 查看是否启动成功&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第六步：用redis-cli创建整个redis集群(redis5以前的版本集群是依靠ruby脚本redis-trib.rb实现)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 下面命令里的1代表为每个创建的主服务器节点创建一个从服务器节点&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 执行这条命令需要确认三台机器之间的redis实例要能相互访问，可以先简单把所有机器防火墙关掉，如果不关闭防火墙则需要打开redis服务端口和集群节点gossip通信端口16379(默认是在redis端口号上加1W)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 关闭防火墙&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; systemctl stop firewalld &lt;span class=&#34;comment&#34;&gt;# 临时关闭防火墙&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; systemctl &lt;span class=&#34;built_in&#34;&gt;disable&lt;/span&gt; firewalld &lt;span class=&#34;comment&#34;&gt;# 禁止开机启动&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	（1）/src/redis-cli -a [password] --cluster create --cluster-replicas 1 192.168.0.61:8001 192.168.0.62:8002 192.168.0.63:8003 192.168.0.61:8004 192.168.0.62:8005 192.168.0.63:8006 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;第七步：验证集群：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （1）连接任意一个客户端即可：./redis-cli -c -h -p (-a访问服务端密码，-c表示集群模式，指定ip地址和端口号）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        如：/src/redis-cli -a zhuge -c -h 192.168.0.61 -p 800*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （2）进行验证： cluster info（查看集群信息）、cluster nodes（查看节点列表）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    （3）进行数据操作验证&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	（4）关闭集群则需要逐个进行关闭，使用命令：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/src/redis-cli -a zhuge -c -h 192.168.0.60 -p 800* shutdown&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;构建集群确认截图&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#构建集群确认截图&#34;&gt;#&lt;/a&gt; 构建集群确认截图&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201106095855589.png&#34; alt=&#34;image-20201106095855589&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201106095855589.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;集群搭建确认&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#集群搭建确认&#34;&gt;#&lt;/a&gt; 集群搭建确认&lt;/h3&gt;
&lt;p&gt;任意链接一台集群内客户端，cluster info 查看信息&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201106100219837.png&#34; alt=&#34;image-20201106100219837&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201106100219837.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;节点信息查看&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#节点信息查看&#34;&gt;#&lt;/a&gt; 节点信息查看&lt;/h3&gt;
&lt;p&gt;使用命令 cluster nodes, 也可以在对应的配置目录下找到 &lt;code&gt;nodes.conf&lt;/code&gt;  文件中查看，集群内的所有服务都会有一个对应的 nodes 文件&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201106100305703.png&#34; alt=&#34;image-20201106100305703&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201106100305703.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;集群横向扩容&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#集群横向扩容&#34;&gt;#&lt;/a&gt; 集群横向扩容&lt;/h3&gt;
&lt;p&gt;配置文件如上，把对应的端口号修改即可&lt;/p&gt;
&lt;p&gt;向集群内添加节点&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;src/redis-cli -a [password] --cluster add-node [要添加的ip:端口号] [集群内任一节点ip：端口号]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;此刻可以查看集群节点信息内已经可以看到新增节点信息，新加入节点都是 master 节点&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201106112240260.png&#34; alt=&#34;image-20201106112240260&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201106112240260.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;新加入节点并不能直接使用，因为新加入节点没有 hash 槽，接下来就是分配 hash 槽&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;src/redis-cli -a [password] --cluster reshard [集群内任一节点ip：端口号]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;How many slots do you want to move (from 1 to 16384)? [输入要给新加入节点分配的槽位个数]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;What is the receiving node ID? [待分配槽位节点ID]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Please enter all the source node IDs.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  Type &amp;#x27;all&amp;#x27; to use all the nodes as source nodes for the hash slots.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  Type &amp;#x27;done&amp;#x27; once you entered all the source nodes IDs.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  [输入all会从所有主节点中抽取槽位，分配给新节点]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Source node 1:all&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Do you want to proceed with the proposed reshard plan (yes/no)? yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;随后等待分配槽位完成&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;分配槽位完成后查看节点信息如下：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201106112529469.png&#34; alt=&#34;image-20201106112529469&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201106112529469.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;然后将 8008 节点加入集群，加入后同样默认为主节点，然后将 8008 修改为 8007 的从节点&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 连接要变更节点信息的节点&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;src/redis-cli -a zhuge -c -h [变更节点信息的ip] -p [变更节点信息的端口]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 执行如下命令&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cluster replicate [将当前节点分配给哪个主节点的id]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;节点分配前后节点信息对比查看&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201106115432547.png&#34; alt=&#34;image-20201106115432547&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201106115432547.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;添加节点的工作就完成了&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;删除节点&lt;/p&gt;
&lt;p&gt;删除从节点可以直接进行删除，但是主节点不可以，如果直接删除主节点会造成数据丢失&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;src/redis-cli -a [password] --cluster del-node [要删除节点ip:端口] [删除节点id]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;删除主节点之前需要将主节点的槽位转移给别的槽位，如下操作&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;src/redis-cli -a [password] --cluster reshard [要转移槽位节点ip:端口] [转移槽位节点id]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;How many slots do you want to move (from 1 to 16384)? [转移槽位个数]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;What is the receiving node ID? [将槽位转移到哪个节点的id]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Please enter all the source node IDs.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  Type &amp;#x27;all&amp;#x27; to use all the nodes as source nodes for the hash slots.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  Type &amp;#x27;done&amp;#x27; once you entered all the source nodes IDs.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Source node 1:[待转移槽位的id]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Source node 2:done&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;(ps:这里直接输入done 开始生成迁移计划)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; ... ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Do you want to proceed with the proposed reshard plan (yes/no)? Yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;(ps:这里输入yes开始迁移)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;槽位转移前后节点信息对比&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201106120214347.png&#34; alt=&#34;image-20201106120214347&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201106120214347.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;转移槽位完成后就可以通过上面删除槽位的命令删除对应的槽位即可&lt;/p&gt;

 &lt;p&gt;mySQL5.7 数据库在 CentOS 服务器上安装&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h1 id=&#34;一-安装yum-repo&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#一-安装yum-repo&#34;&gt;#&lt;/a&gt; 一、安装 YUM Repo&lt;/h1&gt;
&lt;h3 id=&#34;1-由于centos-的yum源中没有mysql需要到mysql的官网下载yum-repo配置文件&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-由于centos-的yum源中没有mysql需要到mysql的官网下载yum-repo配置文件&#34;&gt;#&lt;/a&gt; 1、由于 CentOS 的 yum 源中没有 mysql，需要到 mysql 的官网下载 yum repo 配置文件。&lt;/h3&gt;
&lt;p&gt;下载命令：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;wget https://dev.mysql.com/get/mysql57-community-release-el7-9.noarch.rpm&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-然后进行repo的安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-然后进行repo的安装&#34;&gt;#&lt;/a&gt; 2、然后进行 repo 的安装：&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;rpm -ivh mysql57-community-release-el7-9.noarch.rpm&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;执行完成后会在 /etc/yum.repos.d/ 目录下生成两个 repo 文件 mysql-community.repo mysql-community-source.repo&lt;/p&gt;
&lt;h1 id=&#34;二-使用yum命令即可完成安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二-使用yum命令即可完成安装&#34;&gt;#&lt;/a&gt; 二、使用 yum 命令即可完成安装&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;注意：必须进入到 /etc/yum.repos.d/ 目录后再执行以下脚本&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 1、安装命令：&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yum install mysql-server&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 2、启动msyql：&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl start mysqld #启动MySQL&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 3、获取安装时的临时密码（在第一次登录时就是用这个密码）：&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;grep &amp;#x27;temporary password&amp;#x27; /var/log/mysqld.log&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 4、倘若没有获取临时密码，则&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4.1、删除原来安装过的mysql残留的数据&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rm -rf /var/lib/mysql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4.2.再启动mysql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl start mysqld #启动MySQL&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;三-登录&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三-登录&#34;&gt;#&lt;/a&gt; 三、登录：&lt;/h1&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 1、方式一（已验证）：&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql -u root -p&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;然后输入密码（刚刚获取的临时密码）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 2、方式二（未验证）：&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;进入mysql数据库&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;root@test:/home# mysql -uroot -proot  &amp;lt;uroot是用户名，proot是密码&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;如：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;root@test:/home# mysql -root -XXXX&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;3-若登录不了则进行以下配置跳过登录验证&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-若登录不了则进行以下配置跳过登录验证&#34;&gt;#&lt;/a&gt; 3、若登录不了，则进行以下配置，跳过登录验证&lt;/h3&gt;
&lt;p&gt;3.1、重置密码的第一步就是跳过 MySQL 的密码认证过程，方法如下：&lt;/p&gt;
&lt;p&gt;3.2、vim /etc/my.cnf (注：windows 下修改的是 my.ini)&lt;/p&gt;
&lt;p&gt;在文档内搜索 mysqld 定位到 [mysqld] 文本段：&lt;/p&gt;
&lt;p&gt;/mysqld (在 vim 编辑状态下直接输入该命令可搜索文本内容)&lt;/p&gt;
&lt;p&gt;在 [mysqld] 后面任意一行添加 “skip-grant-tables” 用来跳过密码验证的过程，如下图所示：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/20190417160900803.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dvaGl1c2Rhc2hp,size_16,color_FFFFFF,t_70&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/20190417160900803.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dvaGl1c2Rhc2hp,size_16,color_FFFFFF,t_70&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;3.3、保存文档并退出：&lt;/p&gt;
&lt;p&gt;#:wq&lt;/p&gt;
&lt;p&gt;3.4、&lt;strong&gt;接下来我们需要重启 MySQL：&lt;/strong&gt;&lt;/p&gt;
&lt;h1 id=&#34;四-登录成功后修改密码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#四-登录成功后修改密码&#34;&gt;#&lt;/a&gt; 四、登录成功后修改密码&lt;/h1&gt;
&lt;h3 id=&#34;1-注意这里会进行密码强度校验密码设置时必须包含大小写字母-特殊符号-数字并且长度大于8位&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-注意这里会进行密码强度校验密码设置时必须包含大小写字母-特殊符号-数字并且长度大于8位&#34;&gt;#&lt;/a&gt; 1、注意：这里会进行密码强度校验（密码设置时必须包含大小写字母、特殊符号、数字，并且长度大于 8 位）&lt;/h3&gt;
&lt;h3 id=&#34;2-如不满足以上条件则会报错如下图&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-如不满足以上条件则会报错如下图&#34;&gt;#&lt;/a&gt; 2、如不满足以上条件则会报错，如下图：&lt;/h3&gt;
&lt;p&gt;密码策略问题异常信息：&lt;/p&gt;
&lt;p&gt;ERROR 1819 (HY000): Your password does not satisfy the current policy requirements&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/20190417161754664.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dvaGl1c2Rhc2hp,size_16,color_FFFFFF,t_70&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/20190417161754664.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dvaGl1c2Rhc2hp,size_16,color_FFFFFF,t_70&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;3-解决办法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3-解决办法&#34;&gt;#&lt;/a&gt; 3、解决办法：&lt;/h3&gt;
&lt;p&gt;3.1、查看 mysql 初始的密码策略，&lt;/p&gt;
 &lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;输入语句 “ SHOW VARIABLES LIKE &amp;#x27;validate_password%&amp;#x27;; ” 进行查看，&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;如下图：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/20190417161937367.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dvaGl1c2Rhc2hp,size_16,color_FFFFFF,t_70&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/20190417161937367.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dvaGl1c2Rhc2hp,size_16,color_FFFFFF,t_70&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;3.2、首先需要设置密码的验证强度等级，设置 validate_password_policy 的全局参数为 LOW 即可，&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;输入设值语句 “ set global validate_password_policy=LOW; ” 进行设值，&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3.3、当前密码长度为 8 ，如果不介意的话就不用修改了，按照通用的来讲，设置为 6 位的密码，设置 validate_password_length 的全局参数为 6 即可，&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;输入设值语句 “ set global validate_password_length=6; ” 进行设值，&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3.4、现在可以为 mysql 设置简单密码了，只要满足六位的长度即可，&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;输入修改语句 “ ALTER USER &amp;#x27;root&amp;#x27;@&amp;#x27;localhost&amp;#x27; IDENTIFIED BY &amp;#x27;123456&amp;#x27;; ” 可以看到修改成功，表示密码策略修改成功了！！！&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3.5、注：在默认密码的长度最小值为 4 ，由 大 / 小写字母各一个 + 阿拉伯数字一个 + 特殊字符一个，&lt;/p&gt;
&lt;p&gt;只要设置密码的长度小于 3 ，都将自动设值为 4 ，&lt;/p&gt;
&lt;p&gt;3.6、关于 mysql 密码策略相关参数；&lt;/p&gt;
&lt;p&gt;1）、validate_password_length  固定密码的总长度；&lt;/p&gt;
&lt;p&gt;2）、validate_password_dictionary_file 指定密码验证的文件路径；&lt;/p&gt;
&lt;p&gt;3）、validate_password_mixed_case_count  整个密码中至少要包含大 / 小写字母的总个数；&lt;/p&gt;
&lt;p&gt;4）、validate_password_number_count  整个密码中至少要包含阿拉伯数字的个数；&lt;/p&gt;
&lt;p&gt;5）、validate_password_policy 指定密码的强度验证等级，默认为 MEDIUM；&lt;/p&gt;
&lt;p&gt;关于 validate_password_policy 的取值：&lt;/p&gt;
&lt;p&gt;LOW：只验证长度；&lt;/p&gt;
&lt;p&gt;1/MEDIUM：验证长度、数字、大小写、特殊字符；&lt;/p&gt;
&lt;p&gt;2/STRONG：验证长度、数字、大小写、特殊字符、字典文件；&lt;/p&gt;
&lt;p&gt;6）、validate_password_special_char_count 整个密码中至少要包含特殊字符的个数；&lt;/p&gt;
&lt;h1 id=&#34;五-修改密码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#五-修改密码&#34;&gt;#&lt;/a&gt; 五、修改密码&lt;/h1&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 1、方式一（已验证）：&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ALTER USER &amp;#x27;root&amp;#x27;@&amp;#x27;localhost&amp;#x27; IDENTIFIED BY &amp;#x27;@abcd123456&amp;#x27;; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 2、方式二（未验证）&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;set password=password(&amp;quot;yourpassword&amp;quot;); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;方法1： 用SET PASSWORD命令 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;首先登录MySQL。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;格式：mysql&amp;gt; set password for 用户名@localhost = password(‘新密码’); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;例子：mysql&amp;gt; set password for root@localhost = password(‘123’);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;方法2：用mysqladmin &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;格式：mysqladmin -u用户名 -p旧密码 password 新密码 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;例子：mysqladmin -uroot -p123456 password 123&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;方法3：用UPDATE直接编辑user表 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;首先登录MySQL。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;mysql&amp;gt;&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; use mysql; &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;mysql&amp;gt;&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; update user &lt;span class=&#34;built_in&#34;&gt;set&lt;/span&gt; password=password(‘123’) &lt;span class=&#34;built_in&#34;&gt;where&lt;/span&gt; user=’root’ and host=’localhost’; &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;mysql&amp;gt;&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; flush privileges;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;方法4：在忘记root密码的时候，可以这样 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;以windows为例： &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1. 关闭正在运行的MySQL服务。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2. 打开DOS窗口，转到mysql\bin目录。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3. 输入mysqld –skip-grant-tables 回车。–skip-grant-tables 的意思是启动MySQL服务的时候跳过权限表认证。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4. 再开一个DOS窗口（因为刚才那个DOS窗口已经不能动了），转到mysql\bin目录。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5. 输入mysql回车，如果成功，将出现MySQL提示符 &amp;gt;。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6. 连接权限数据库： use mysql; 。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6. 改密码：update user set password=password(“123”) where user=”root”;（别忘了最后加分号） 。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7. 刷新权限（必须步骤）：flush privileges;　。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8. 退出 quit。 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9. 注销系统，再进入，使用用户名root和刚才设置的新密码123登录。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;六-开启远程控制&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#六-开启远程控制&#34;&gt;#&lt;/a&gt; 六、开启远程控制&lt;/h1&gt;
&lt;p&gt;MySQL 默认是没有开启远程控制的，必须添加远程访问的用户，即默认是只能自己访问，别的机器是访问不了的。&lt;/p&gt;
&lt;h3 id=&#34;1-方式一已验证&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-方式一已验证&#34;&gt;#&lt;/a&gt; 1、方式一（已验证）：&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1.1、连接服务器: mysql -u root -p&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1.2、看当前所有数据库：show databases;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1.3、进入mysql数据库：use mysql;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1.4、查看mysql数据库中所有的表：show tables;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1.5、查看user表中的数据：select Host, User,Password from user;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1.6、修改user表中的Host:  update user set Host=&amp;#x27;%&amp;#x27; where User=&amp;#x27;root&amp;#x27;; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;说明： % 代表任意的客户端,可替换成具体IP地址。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1.7、最后刷新一下：flush privileges;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1.8、注意：一定要记得在写sql的时候要在语句完成后加上&amp;quot; ; &amp;quot;**&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-方式二未验证&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-方式二未验证&#34;&gt;#&lt;/a&gt; 2、方式二（未验证）：&lt;/h3&gt;
&lt;h3 id=&#34;1-使用-grant-命令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-使用-grant-命令&#34;&gt;#&lt;/a&gt; 1、使用 grant 命令&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;grant all privileges on 数据库名.表名 to 创建的用户名(root)@&amp;quot;%&amp;quot; identified by &amp;quot;密码&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-格式说明&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-格式说明&#34;&gt;#&lt;/a&gt; 2、格式说明：&lt;/h3&gt;
&lt;p&gt;数据库名。表名 如果写成 *.* 代表授权所有的数据库 flush privileges; #刷新刚才的内容&lt;/p&gt;
&lt;p&gt;如：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;grant all privileges on *.* to root@&amp;quot;113.123.123.1&amp;quot; identified by &amp;quot;123456789&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;@ 后面是访问mysql的客户端IP地址（或是 主机名） % 代表任意的客户端，如果填写 localhost 为本地访问（那此用户就不能远程访问该mysql数据库了）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;七-其他配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#七-其他配置&#34;&gt;#&lt;/a&gt; 七、其他配置&lt;/h1&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 1、设置安全选项：&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysql_secure_installation&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 2、关闭MySQL&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl stop mysqld &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 3、重启MySQL&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl restart mysqld &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 4、查看MySQL运行状态&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl status mysqld &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 5、设置开机启动&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl enable mysqld &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 6、关闭开机启动&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl disable mysqld &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 7、配置默认编码为utf8：&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vi /etc/my.cnf #添加 [mysqld] character_set_server=utf8 init_connect=&amp;#x27;SET NAMES utf8&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;其他默认配置文件路径： &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;配置文件：/etc/my.cnf 日志文件：/var/log//var/log/mysqld.log 服务启动脚本：/usr/lib/systemd/system/mysqld.service socket文件：/var/run/mysqld/mysqld.pid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## 8、查看版本&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;select version();&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;Redis 数据持久化的三种方式，基本的架构模型，主从架构和哨兵架构。主从架构是哨兵架构以及后续的分布式集群架构的基础。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;redis持久化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#redis持久化&#34;&gt;#&lt;/a&gt; Redis 持久化&lt;/h2&gt;
&lt;h3 id=&#34;rdb快照snapshot&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#rdb快照snapshot&#34;&gt;#&lt;/a&gt; RDB 快照（snapShot）&lt;/h3&gt;
&lt;p&gt;基本设置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 在redis配置文件中做如下配置即可，redis在满足配置时就会自动进行持久化到本地文件中&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 60秒内至少改动1000个键值对，就会触发&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;save 60 1000 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 保存的为二进制内容&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;save 和 bgsave&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;命令&lt;/th&gt;
&lt;th&gt;save&lt;/th&gt;
&lt;th&gt;bgsave&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;IO 类型&lt;/td&gt;
&lt;td&gt;同步&lt;/td&gt;
&lt;td&gt;异步&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;是否阻塞 Redis 其他命令&lt;/td&gt;
&lt;td&gt;是（操作时会阻塞，所有命令无法继续写入）&lt;/td&gt;
&lt;td&gt;否（生成子进程执行调用 fork 函数时，会有短暂阻塞）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;复杂度&lt;/td&gt;
&lt;td&gt;O(n)&lt;/td&gt;
&lt;td&gt;O(n)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;优点&lt;/td&gt;
&lt;td&gt;不会消耗额外内存&lt;/td&gt;
&lt;td&gt;不阻塞客户端命令&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;缺点&lt;/td&gt;
&lt;td&gt;阻塞客户端命令&lt;/td&gt;
&lt;td&gt;需要 fork 子进程，消耗内存&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;aofappend-only-file&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#aofappend-only-file&#34;&gt;#&lt;/a&gt; AOF(append-only file)&lt;/h3&gt;
&lt;p&gt;基本配置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;appendonly yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 具体配置项说明&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;appendfsync always：每次有新命令追加到 AOF 文件时就执行一次 fsync ，非常慢，也非常安全。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;appendfsync everysec：每秒 fsync 一次，足够快，并且在故障时只会丢失 1 秒钟的数据。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;appendfsync no：从不 fsync ，将数据交给操作系统来处理。更快，也更不安全的选择。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;aof 保存的是最新的 set 操作命令&lt;/p&gt;
&lt;h3 id=&#34;aof重写&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#aof重写&#34;&gt;#&lt;/a&gt; AOF 重写&lt;/h3&gt;
&lt;p&gt;基本配置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; aof重写会将一些无用命令重新合并，最终数据肯定还是和原先的一致&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; aof文件至少要达到64M才会自动重写，文件太小恢复速度本来就很快，重写的意义不大&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;auto-aof-rewrite-min-size 64mb   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; aof文件自上一次重写后文件大小增长了100%则再次触发重写&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;auto-aof-rewrite-percentage 100  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;AOF 还可以手动重写，进入 redis 客户端执行命令&lt;strong&gt; bgrewriteaof&lt;/strong&gt; 重写 AOF&lt;/p&gt;
&lt;p&gt;注意，&lt;strong&gt;AOF 重写 redis 会 fork 出一个子进程去做 (与 bgsave 命令类似)，不会对 redis 正常命令处理有太多影响&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;rdb和aof对比&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#rdb和aof对比&#34;&gt;#&lt;/a&gt; RDB 和 AOF 对比&lt;/h3&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;&lt;strong&gt;命令&lt;/strong&gt;&lt;/th&gt;
&lt;th&gt;&lt;strong&gt;RDB&lt;/strong&gt;&lt;/th&gt;
&lt;th&gt;&lt;strong&gt;AOF&lt;/strong&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;启动优先级&lt;/td&gt;
&lt;td&gt;低&lt;/td&gt;
&lt;td&gt;高&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;体积&lt;/td&gt;
&lt;td&gt;小&lt;/td&gt;
&lt;td&gt;大&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;恢复速度&lt;/td&gt;
&lt;td&gt;快&lt;/td&gt;
&lt;td&gt;慢&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;数据安全性&lt;/td&gt;
&lt;td&gt;容易丢数据&lt;/td&gt;
&lt;td&gt;根据策略决定&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;redis40后的混合持久化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#redis40后的混合持久化&#34;&gt;#&lt;/a&gt; Redis4.0 后的混合持久化&lt;/h3&gt;
&lt;p&gt;基本配置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 混合持久化是基于aof持久化的优化，使用混合持久化必须先开启aof&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;aof-use-rdb-preamble yes   &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;redis数据备份策略&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#redis数据备份策略&#34;&gt;#&lt;/a&gt; Redis 数据备份策略&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;写 crontab 定时脚本，每个小时复制一份 Redis 持久化文件&lt;/li&gt;
&lt;li&gt;每天都保留一份数据，保留最新一月或根据需求保存，方便可随时恢复至任意日期&lt;/li&gt;
&lt;li&gt;每天复制数据时，删除最早数据，以免浪费内存&lt;/li&gt;
&lt;li&gt;多机备份，定期将备份文件复制只不同数据备份机器&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;Redis 数据恢复&lt;/p&gt;
&lt;p&gt;将 Reids 备份文件，放在 Redis 对应的备份文件路径下重启服务即可&lt;/p&gt;
&lt;h2 id=&#34;redis主从架构&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#redis主从架构&#34;&gt;#&lt;/a&gt; Redis 主从架构&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201102105859265.png&#34; alt=&#34;image-20201102105859265&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201102105859265.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;基本配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基本配置&#34;&gt;#&lt;/a&gt; 基本配置&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1、复制一份redis.conf文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2、将相关配置修改为如下值：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;port 6380&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pidfile /var/run/redis_6380.pid  # 把pid进程号写入pidfile配置的文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logfile &amp;quot;6380.log&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dir /usr/local/redis-5.0.3/data/6380  # 指定数据存放目录&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3、配置主从复制&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;replicaof 192.168.0.60 6379   # 从本机6379的redis实例复制数据，Redis 5.0之前使用slaveof&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;replica-read-only yes  # 配置从节点只读&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4、启动从节点&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;redis-server redis.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5、连接从节点&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;redis-cli -p 6380&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6、测试在6379实例上写数据，6380实例是否能及时同步新修改数据&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7、可以自己再配置一个6381的从节点&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;全量复制&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#全量复制&#34;&gt;#&lt;/a&gt; 全量复制&lt;/h3&gt;
&lt;p&gt;从节点首次同步数据或长时间断开链接，主节点和从节点之前数据差超过了 master 节点缓存队列中的数据时会采用全量复制&lt;/p&gt;
&lt;h3 id=&#34;部分复制&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#部分复制&#34;&gt;#&lt;/a&gt; 部分复制&lt;/h3&gt;
&lt;p&gt;master 会在其内存中创建一个复制数据用的缓存队列，缓存最近一段时间的数据，master 和它所有的 slave 都维护了复制的数据下标 offset 和 master 的进程 id，因此，当网络连接断开后，slave 会请求 master 继续进行未完成的复制，从所记录的数据下标开始。如果 master 进程 id 变化了，或者从节点数据下标 offset 太旧，已经不在 master 的缓存队列里了，那么将会进行一次全量数据的复制。&lt;/p&gt;
&lt;h3 id=&#34;主从复制风暴&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#主从复制风暴&#34;&gt;#&lt;/a&gt; 主从复制风暴&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201102110501109.png&#34; alt=&#34;image-20201102110501109&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201102110501109.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;redis哨兵高可用架构&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#redis哨兵高可用架构&#34;&gt;#&lt;/a&gt; Redis 哨兵高可用架构&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201102110615982.png&#34; alt=&#34;image-20201102110615982&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201102110615982.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;基本配置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1、复制一份sentinel.conf文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cp sentinel.conf sentinel-26379.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2、将相关配置修改为如下值：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;port 26379&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;daemonize yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pidfile &amp;quot;/var/run/redis-sentinel-26379.pid&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logfile &amp;quot;26379.log&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dir &amp;quot;/usr/local/redis-5.0.3/data&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; sentinel monitor &amp;lt;master-redis-name&amp;gt; &amp;lt;master-redis-ip&amp;gt; &amp;lt;master-redis-port&amp;gt; &amp;lt;quorum&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; quorum是一个数字，指明当有多少个sentinel认为一个master失效时(值一般为：sentinel总数/2 + 1)，master才算真正失效&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sentinel monitor mymaster 192.168.0.60 6379 2   # mymaster这个名字随便取，客户端访问时会用到&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3、启动sentinel哨兵实例&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;src/redis-sentinel sentinel-26379.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4、查看sentinel的info信息&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;src/redis-cli -p 26379&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;127.0.0.1:26379&amp;gt;info&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;可以看到Sentinel的info里已经识别出了redis的主从&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5、可以自己再配置两个sentinel，端口26380和26381，注意上述配置文件里的对应数字都要修改&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;操作中遇到的问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#操作中遇到的问题&#34;&gt;#&lt;/a&gt; 操作中遇到的问题&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;配置主从模式时，要注意主节点不能配置 replicaof&lt;/li&gt;
&lt;li&gt;bind 0.0.0.0&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;MyBatis 源码阅读环境编译，能够更方便阅读源码，可以切换源码版本！&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;1-源码下载&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1-源码下载&#34;&gt;#&lt;/a&gt; 1、源码下载&lt;/h3&gt;
&lt;p&gt;下载地址：&lt;a href=&#34;https://github.com/mybatis/mybatis-3&#34;&gt;https://github.com/mybatis/mybatis-3&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201022133141200.png&#34; alt=&#34;image-20201022133141200&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201022133141200.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;--下载源码&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git clone https://github.com/mybatis/mybatis-3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--进入到刚clone的目录文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--创建分支，切换至最新版本（from tag）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git checkout -b [branchname] [tagname]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-build&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2-build&#34;&gt;#&lt;/a&gt; 2、build&lt;/h3&gt;
&lt;p&gt;IDEA 打开刚才创建的分支，Maven 先 clean intstall&lt;/p&gt;
&lt;p&gt;或者命令行操作&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mvn clean &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mvn install -Dmaven.test.skip=true&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;最终结果：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201022133938087.png&#34; alt=&#34;image-20201022133938087&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201022133938087.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;IDEA 插件 Statistic 使用，主要代码行数，将代码数量统计并直观展示出来.&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;1插件安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1插件安装&#34;&gt;#&lt;/a&gt; 1. 插件安装&lt;/h3&gt;
&lt;p&gt;IDEA–&amp;gt;file–&amp;gt;settings–&amp;gt;plugins–&amp;gt; 搜索插件 (Statistic)&lt;/p&gt;
&lt;img src=&#34;/img/image-20200914103816130.png&#34; alt=&#34;image-20200914103816130&#34; style=&#34;zoom:67%;&#34; / srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20200914103816130.png&#34; class=&#34;lozad post-image&#34;&gt;
&lt;p&gt;我这里已经安装，还未重启 IDE, 点击 Install 安装插件，安装完成后根据提重启 IDE&lt;/p&gt;
&lt;h3 id=&#34;2插件使用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2插件使用&#34;&gt;#&lt;/a&gt; 2. 插件使用&lt;/h3&gt;
&lt;p&gt;重启 IDE 后，在屏幕下方会有一个 statistic 按钮，点击后可以看到如下页面:&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20200916110627597.png&#34; alt=&#34;image-20200916110627597&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20200916110627597.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;单击 refresh 按钮后可以查看实时代码统计情况:&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20200916110737414.png&#34; alt=&#34;image-20200916110737414&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20200916110737414.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20200916111558837.png&#34; alt=&#34;image-20200916111558837&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20200916111558837.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;Redis 基本数据结构及常用操作命令以及对应的使用场景&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;字符串string&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字符串string&#34;&gt;#&lt;/a&gt; 字符串（String）&lt;/h2&gt;
&lt;h3 id=&#34;常用操作命令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#常用操作命令&#34;&gt;#&lt;/a&gt; 常用操作命令&lt;/h3&gt;
&lt;figure class=&#34;highlight cmd&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;help&lt;/span&gt; @String&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;built_in&#34;&gt;APPEND&lt;/span&gt; key value&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; summary: &lt;span class=&#34;title&#34;&gt;Append&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（向键追加一个值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;BITCOUNT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;start&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;end&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Count&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;bits&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt;（对字符串中的位进行计数）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.6.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;BITFIELD&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;GET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;type&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;SET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;type&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;INCRBY&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;type&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;increment&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;OVERFLOW&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;WRAP&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;SAT&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;FAIL&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Perform&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;arbitrary&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;bitfield&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;integer&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;operations&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;on&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;strings&lt;/span&gt;（对字符串执行任意位域整数操作）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 3.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;BITOP&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;operation&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;destkey&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; ...]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Perform&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;bitwise&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;operations&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;between&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;strings&lt;/span&gt;（在字符串之间执行按位操作）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.6.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;BITPOS&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;bit&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;start&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;end&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Find&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;first&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;bit&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;clear&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt;（查找字符串中设置或清除的第一个位）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.8.7&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;DECR&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Decrement&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;integer&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;one&lt;/span&gt;（键的整数值递减1）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;DECRBY&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;decrement&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Decrement&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;integer&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;number&lt;/span&gt;（按给定的数字递减键值的整数值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;GET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Get&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（获取键的值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;GETBIT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Returns&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;bit&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stored&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（返回存储在键中的字符串值的偏移位值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;GETRANGE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;start&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;end&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Get&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;substring&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stored&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（获取存储在键上的字符串的子字符串）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.4.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;GETSET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;its&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;old&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;（设置键的字符串值并返回其旧值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;INCR&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Increment&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;integer&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;one&lt;/span&gt;（将键的整数值增加1）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;INCRBY&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;increment&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Increment&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;integer&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;amount&lt;/span&gt;（将键的整数值按给定的量递增）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;INCRBYFLOAT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;increment&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Increment&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;amount&lt;/span&gt;（将键的浮点值按给定的数量递增）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.6.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;MGET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; ...]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Get&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;values&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;all&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;keys&lt;/span&gt;（获取所有给定键的值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;MSET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; ...]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;keys&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;values&lt;/span&gt;（将多个键设置为多个值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;MSETNX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; ...]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;keys&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;values&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;only&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;none&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;keys&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;exist&lt;/span&gt;（将多个键设置为多个值，仅当这些键不存在时才设置）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;PSETEX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;milliseconds&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;expiration&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;milliseconds&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（置键的值和到期时间(以毫秒为单位)）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.6.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;expiration&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;EX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;seconds&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;PX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;milliseconds&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;NX&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;XX&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（设置键的字符串值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SETBIT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Sets&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;clears&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;bit&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stored&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（设置或清除存储在键上的字符串值中的偏移位）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SETEX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;seconds&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;expiration&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（设置键的值和过期时间）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SETNX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;only&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;does&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;not&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;exist&lt;/span&gt;（设置键值，仅当键不存在时才设置）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SETRANGE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Overwrite&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;part&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;starting&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;specified&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt;（覆盖从指定偏移量开始的键处的字符串部分）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;STRLEN&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Get&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;length&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stored&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（获取存储在键中的值的长度）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
