;title&#34;&gt;all&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;within&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt;(删除给定分数内排序集合中的所有成员)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZREVRANGE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;start&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stop&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;WITHSCORES&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Return&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;range&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;index&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ordered&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;high&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;low&lt;/span&gt;(按索引返回排序集合中成员的范围，分数从高到低排序)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZREVRANGEBYLEX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;max&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;min&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;LIMIT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;count&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Return&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;range&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;lexicographical&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;range&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;ordered&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;higher&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;lower&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;strings&lt;/span&gt;.(按字典顺序从较高的字符串到较低的字符串，返回已排序集合中成员的范围。)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.8.9&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZREVRANGEBYSCORE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;max&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;min&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;WITHSCORES&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;LIMIT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;count&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Return&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;range&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;score&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ordered&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;high&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;low&lt;/span&gt;(按分数返回排序集中的成员范围，分数从高到低排序)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZREVRANK&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Determine&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;index&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ordered&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;high&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;low&lt;/span&gt;(根据分数从高到低的顺序，确定排序集合中成员的索引)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZSCAN&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;cursor&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;MATCH&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;pattern&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;COUNT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;count&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Incrementally&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;iterate&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sets&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;elements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;associated&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt;(增量迭代已排序的集合元素和相关分数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.8.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZSCORE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Get&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;score&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;associated&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;(获取排序集中与给定成员关联的分数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZUNIONSTORE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;destination&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;numkeys&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; ...] [&lt;span class=&#34;title&#34;&gt;WEIGHTS&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;weight&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;AGGREGATE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;SUM&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;MIN&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;MAX&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Add&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sets&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;store&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;resulting&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;(添加多个排序集，并将结果排序集存储到一个新键中)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;使用场景&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;ZSet&lt;/code&gt;  集合操作实现排行榜&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;Linux 系统 Ubuntu 截图工具推荐使用&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;h3 id=&#34;前言&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#前言&#34;&gt;#&lt;/a&gt; 前言&lt;/h3&gt;
&lt;p&gt;Windows 上习惯了 QQ 的截图工具，本工具类似 QQ 截图工具功能，在习惯 QQ 截图的情况下可以很方便的使用。效果图：&lt;img src=&#34;/img/image-20201020151914799.png&#34; alt=&#34;image-20201020151914799&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201020151914799.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;安装过程&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装过程&#34;&gt;#&lt;/a&gt; 安装过程&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install flameshot&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;启动命令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#启动命令&#34;&gt;#&lt;/a&gt; 启动命令&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flameshot gui&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;设置快捷方式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#设置快捷方式&#34;&gt;#&lt;/a&gt; 设置快捷方式&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201020152205127.png&#34; alt=&#34;image-20201020152205127&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201020152205127.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;本机操作系统版本为 Ubuntu 20.04, 不同版本可能设置快捷键位置名称有些不同，可以自行根据系统版本设置&lt;/p&gt;
&lt;p&gt;具体设置&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201020152406303.png&#34; alt=&#34;image-20201020152406303&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201020152406303.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;软件设置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#软件设置&#34;&gt;#&lt;/a&gt; 软件设置&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201020152618648.png&#34; alt=&#34;image-20201020152618648&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201020152618648.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;Ubuntu 系统在安装后应该做的一些基本优化配置，包括了系统基本的软件安装以及桌面样式优化等相关内容。&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;h3 id=&#34;添加用户并赋予sudo权限&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#添加用户并赋予sudo权限&#34;&gt;#&lt;/a&gt; 添加用户并赋予 sudo 权限&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 1. 添加用户&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo adduser username &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 2. 添加sudo权限&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo usermod -G sudo username &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 3.添加root权限&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 如果需要让此用户有root权限，执行命令：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo vim /etc/sudoers&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 修改文件如下：&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; User privilege specification&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;root ALL=(ALL) ALL&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;username ALL=(ALL) ALL&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 保存退出，username 用户就拥有了root权限。&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;开机挂载磁盘&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#开机挂载磁盘&#34;&gt;#&lt;/a&gt; 开机挂载磁盘&lt;/h3&gt;
&lt;p&gt;开机挂在需要编辑的文件为： &lt;code&gt;/etc/fstab&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;非系统盘在刚开机时不会自动挂在非系统盘，想要在开机加载非系统盘需要做如下设置&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; /etc/fstab: static file system information.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; Use &lt;span class=&#34;string&#34;&gt;&amp;#x27;blkid&amp;#x27;&lt;/span&gt; to &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt; the universally unique identifier &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; a&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; device; this may be used with UUID= as a more robust way to name devices&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; that works even &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; disks are added and removed. See fstab(5).&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; &amp;lt;file system&amp;gt; &amp;lt;mount point&amp;gt;   &amp;lt;&lt;span class=&#34;built_in&#34;&gt;type&lt;/span&gt;&amp;gt;  &amp;lt;options&amp;gt;       &amp;lt;dump&amp;gt;  &amp;lt;pass&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; / was on /dev/sdb2 during installation&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UUID=c3a3e15c-a5c8-4ea2-a569-fc2804d1c723 /        ext4    errors=remount-ro 0       1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; /boot/efi was on /dev/sdb1 during installation&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UUID=343E-5C25  /boot/efi       vfat    umask=0077      0       1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/swapfile                            none            swap    sw              0       0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#####以上内容为文件中原有内容&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UUID=f86192d0-f81b-474c-aa58-5e978ddb1307 /media/sunfy/ubuntu  ext4    defaults 0       0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UUID=99651901-f991-41b7-af94-3974d192f6f8 /media/sunfy/project ext4    defaults 0       0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UUID=0d159994-e3ba-40f6-9f2d-a8b477746826 /media/sunfy/Folder  ext4    defaults 0       0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;文件内容填写内容来源&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#文件内容填写内容来源&#34;&gt;#&lt;/a&gt; 文件内容填写内容来源&lt;/h4&gt;
&lt;h5 id=&#34;使用命令查看分区&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#使用命令查看分区&#34;&gt;#&lt;/a&gt; 使用命令查看分区&lt;/h5&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo fdisk -l  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;查询挂载硬盘uuid&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查询挂载硬盘uuid&#34;&gt;#&lt;/a&gt; 查询挂载硬盘 &lt;code&gt;UUID&lt;/code&gt;&lt;/h5&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo blkid /dev/sda2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;其余字段解析&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#其余字段解析&#34;&gt;#&lt;/a&gt; 其余字段解析&lt;/h5&gt;
&lt;p&gt;第一个数字：0 表示开机不检查磁盘，1 表示开机检查磁盘；&lt;br&gt;
第二个数字：0 表示交换分区，1 代表启动分区（Linux），2 表示普通分区&lt;br&gt;
我挂载的分区是在 Win 系统下创建的分区，磁盘格式为 ntfs&lt;/p&gt;
&lt;h3 id=&#34;gnome插件安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gnome插件安装&#34;&gt;#&lt;/a&gt; gnome 插件安装&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 官方网站 https://extensions.gnome.org/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 可以安装一些基本的有效的插件，更方便使用&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get update&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get upgrade&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install chrome-gnome-shell &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 安装插件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 应用间切换动画&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Coverflow Alt-Tab&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; cpu监控查看&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cpufreq&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 系统dock高度自定义&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Dash to Dock &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 几个常用按键切换提示&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Lock Keys&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 系统基本内容监控，包括cpu、磁盘、系统、风扇、网速等&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Vitals&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;安装微信-qq等&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装微信-qq等&#34;&gt;#&lt;/a&gt; 安装微信、QQ 等&lt;/h3&gt;
&lt;h4 id=&#34;1安装前准备&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1安装前准备&#34;&gt;#&lt;/a&gt; 1. 安装前准备&lt;/h4&gt;
&lt;p&gt;安装必要的工具及 deepin-wine 依赖&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt install wget g++ git     #如已安装可自行跳过&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;2安装deepin-wine&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2安装deepin-wine&#34;&gt;#&lt;/a&gt; 2. 安装 deepin-wine&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git clone &amp;quot;https://gitee.com/wszqkzqk/deepin-wine-for-ubuntu.git&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cd deepin-wine                    #切换到下载目录&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo ./install.sh                 #执行安装&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;deepin-wine 容器安装完成，然后获取到 deb 安装直接双击安装即可。&lt;/p&gt;
&lt;h4 id=&#34;3托盘悬浮&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3托盘悬浮&#34;&gt;#&lt;/a&gt; 3. 托盘悬浮&lt;/h4&gt;
&lt;p&gt;正常安装后 wine 窗口为独立窗口，为了便于美观建议安装如下插件：&lt;/p&gt;
&lt;p&gt;Gnome Shell 插件：&lt;a href=&#34;https://link.zhihu.com/?target=https%3A//extensions.gnome.org/extension/1031/topicons/&#34;&gt;TopIcons Plus&lt;/a&gt;&lt;/p&gt;
&lt;h4 id=&#34;4卸载方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4卸载方法&#34;&gt;#&lt;/a&gt; 4. 卸载方法&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;uninstall.sh&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 卸载具体软件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt remove deepin.com.qq.im&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;5系统非中文语言环境时软件设置为中文&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5系统非中文语言环境时软件设置为中文&#34;&gt;#&lt;/a&gt; 5. 系统非中文语言环境时软件设置为中文&lt;/h4&gt;
&lt;p&gt;修改 &lt;code&gt;/opt/deepinwine/tools/run.sh&lt;/code&gt;  文件，将  &lt;code&gt;WINE_CMD &lt;/code&gt; 那一行修改为  &lt;code&gt;WINE_CMD=&amp;quot;LC_ALL=zh_CN.UTF-8 deepin-wine&amp;quot;&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight text&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo vim /opt/deepinwine/tools/run.sh       #打开文件进行修改&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;6软件更新&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6软件更新&#34;&gt;#&lt;/a&gt; 6. 软件更新&lt;/h4&gt;
&lt;figure class=&#34;highlight text&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;wget -qO- https://deepin-wine.i-m.dev/setup.sh | sudo sh&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install deepin.com.qq.office      #安装/更新TIM&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install deepin.com.qq.im          #安装/更新QQ&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install deepin.com.wechat         #安装/更新微信&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;阿里云仓库地址：https://mirrors.aliyun.com/deepin/pool/non-free/d/（微信、qq等软件已经下架）&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;7解决微信中文乱码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#7解决微信中文乱码&#34;&gt;#&lt;/a&gt; 7. 解决微信中文乱码&lt;/h4&gt;
&lt;p&gt;1. 下载字体包 &lt;code&gt;msyh.ttc&lt;/code&gt; ：&lt;br&gt;
&lt;a href=&#34;https://www.lanzous.com/i5wivmd&#34;&gt;链接&lt;/a&gt;&lt;br&gt;
下载后解压，&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;cp msyh.ttc ~/.deepinwine/Deepin-WeChat/drive_c/windows/Fonts&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;2. 修改注册序列表&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;gedit ~/.deepinwine/Deepin-WeChat/system.reg&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;修改 &lt;code&gt;MS Shell Dlg&lt;/code&gt;  和 &lt;code&gt;MS Shell Dlg2&lt;/code&gt;  的值如下&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;MS Shell Dlg&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;MS Shell Dlg 2&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3. 注册字体&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;gedit msyh_config.reg&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;将一下内容添加在 &lt;code&gt;msyh_config.reg&lt;/code&gt;  中&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;REGEDIT4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[HKEY_LOCAL_MACHINE\Software\Microsoft\Windows NT\CurrentVersion\FontLink\SystemLink]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;Lucida Sans Unicode&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh.ttc&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;Microsoft Sans Serif&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh.ttc&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;MS Sans Serif&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh.ttc&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;Tahoma&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh.ttc&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;Tahoma Bold&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyhbd.ttc&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh.ttc&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;Arial&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh.ttc&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;&amp;quot;Arial Black&amp;quot;&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;msyh.ttc&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;4. 注册&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;deepin-wine regedit msyh_config.reg&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后在重启微信就成功了。目前阶段没有出现问题。后续有问题进行更新。&lt;/p&gt;
&lt;h3 id=&#34;微信双开&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#微信双开&#34;&gt;#&lt;/a&gt; 微信双开&lt;/h3&gt;
&lt;h4 id=&#34;原理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#原理&#34;&gt;#&lt;/a&gt; 原理&lt;/h4&gt;
&lt;p&gt;其实原理很简单就是打开两个 deepin-wine 允许微信。按照这个原理理论上运行多少个微信都是没问题的。&lt;/p&gt;
&lt;h4 id=&#34;具体实现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#具体实现&#34;&gt;#&lt;/a&gt; 具体实现&lt;/h4&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1.需要登录一个微信，然后成功后退出。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2.进入/home/自己用户名/.deepinwine目录，复制Deepin-WeChat文件夹到Deepin-WeChat2。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3.然后编辑/opt/deepinwine/apps/Deepin-WeChat/run.sh：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo gedit /opt/apps/com.qq.weixin.deepin/files/run.sh&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;!/bin/sh&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;   Copyright (C) 2016 Deepin, Inc.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;   Author:     Li LongYu &amp;lt;lilongyu@linuxdeepin.com&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;               Peng Hao &amp;lt;penghao@linuxdeepin.com&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;BOTTLENAME=&amp;quot;Deepin-WeChat&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;APPVER=&amp;quot;2.6.2.31deepin0&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;/opt/deepinwine/tools/run.sh &lt;span class=&#34;variable&#34;&gt;$BOTTLENAME&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$APPVER&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$1&lt;/span&gt;&amp;quot;&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$2&lt;/span&gt;&amp;quot;&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$3&lt;/span&gt;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;BOTTLENAME=&amp;quot;Deepin-WeChat&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/opt/deepinwine/tools/run.sh $BOTTLENAME $APPVER &amp;quot;$1&amp;quot; &amp;quot;$2&amp;quot; &amp;quot;$3&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;BOTTLENAME=&amp;quot;Deepin-WeChat2&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/opt/deepinwine/tools/run.sh $BOTTLENAME $APPVER &amp;quot;$1&amp;quot; &amp;quot;$2&amp;quot; &amp;quot;$3&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;----------&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4.修改/opt/deepinwine/tools/run.sh&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1）CallApp函数内的case $BOTTLENAME in 下添加如下代码&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&amp;quot;Deepin-WeChat2&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            CallWeChat2 &amp;quot;$1&amp;quot; &amp;quot;$2&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            ;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2） 在CallWeChat函数下面添加如下函数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;CallWeChat2()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    if [ &amp;quot;autostart&amp;quot; == &amp;quot;$1&amp;quot; ]; then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       env WINEPREFIX=&amp;quot;$WINEPREFIX&amp;quot; $WINE_CMD /opt/deepinwine/tools/startbottle.exe &amp;amp;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   else&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        debug_log &amp;quot;Disable auto update&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        _DeleteRegistry &amp;quot;HKCU\\Software\\Tencent\\WeChat&amp;quot; &amp;quot;UpdateFailCnt&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        _DeleteRegistry &amp;quot;HKCU\\Software\\Tencent\\WeChat&amp;quot; &amp;quot;NeedUpdateType&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        rm &amp;quot;$&amp;#123;WINEPREFIX&amp;#125;/drive_c/users/$&amp;#123;USER&amp;#125;/Application Data/Tencent/WeChat/All Users/config/configEx.ini&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        export DISABLE_RENDER_CLIPBOARD=1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        export ATTACH_FILE_DIALOG=1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        debug_log &amp;quot;start running...&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        env WINEPREFIX=&amp;quot;$WINEPREFIX&amp;quot; $WINE_CMD &amp;quot;c:\\Program Files\\Tencent\\WeChat\\WeChat.exe&amp;quot; &amp;amp;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    fi&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;tim更新&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#tim更新&#34;&gt;#&lt;/a&gt; TIM 更新&lt;/h3&gt;
&lt;p&gt;问题描述&lt;/p&gt;
&lt;p&gt;TIM 登录提示版本太低，无法登录&lt;/p&gt;
&lt;p&gt;解决方法&lt;/p&gt;
&lt;p&gt;在 shell 终端输入：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mkdir tim&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;新建任意位置的文件夹&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;cd&lt;/span&gt; tim&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;进入该文件夹&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;wget&lt;/span&gt; https://dldir1.qq.com/qqfile/qq/PCTIM/TIM3.&lt;span class=&#34;number&#34;&gt;3.0&lt;/span&gt;/TIM3.&lt;span class=&#34;number&#34;&gt;3.0&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;21970&lt;/span&gt;.exe&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;从官网下载 exe 安装包&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;env WINEPREFIX=~/.deepinwine/Deepin&lt;span class=&#34;literal&#34;&gt;-TIM&lt;/span&gt;/ deepin&lt;span class=&#34;literal&#34;&gt;-wine&lt;/span&gt; TIM3.&lt;span class=&#34;number&#34;&gt;3.0&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;21970&lt;/span&gt;.exe&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;这边 &lt;code&gt;deepin-wine TIM3.3.0.21970.exe&lt;/code&gt;  改为你下载的安装包的名字&lt;br&gt;
然后让它安装就 ok 了&lt;/p&gt;
&lt;h3 id=&#34;qq和tim无法展示图片&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#qq和tim无法展示图片&#34;&gt;#&lt;/a&gt; QQ 和 TIM 无法展示图片&lt;/h3&gt;
&lt;p&gt;这是禁用本机的 IPV6 就可以正常展示，根据本机使用网路，禁用所有网络的 ipv6, 命令行验证不再出现 Ipv6 的地址&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210127150327350.png&#34; alt=&#34;image-20210127150327350&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210127150327350.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;deepin安装企业微信&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#deepin安装企业微信&#34;&gt;#&lt;/a&gt; deepin 安装企业微信&lt;/h3&gt;
&lt;p&gt;1. 执行命令：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;wget -O- https://deepin-wine.i-m.dev/setup.sh | sh&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;2. 执行命令：&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install deepin.com.weixin.work&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 微信&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install com.qq.weixin.deepin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; QQ&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install com.qq.im.deepin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;com.dingtalk.deepin                  com.qq.video.deepin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;com.foxmail.deepin                   com.qq.weixin.deepin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;com.freepiano.deepin                 com.qq.weixin.work.deepin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;com.iqiyi.deepin                     com.taobao.aliclient.qianniu.deepin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;com.meituxiuxiu.deepin               com.taobao.wangwang.deepin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;com.qq.im.deepin                     com.utau.deepin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;com.qq.music.deepin    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin-app-store-runtime  deepin-libwine-dbg        deepin-voice-recorder&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin-calculator         deepin-libwine-dev        deepin-wine&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin.com.qq.im          deepin-menu               deepin-wine32-tools&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin.com.qq.office      deepin-movie              deepin-wine5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin.com.wechat         deepin-music              deepin-wine5-i386&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin-deb-installer      deepin-notifications      deepin-wine-binfmt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin-fonts-wine         deepin-picker             deepin-wine-helper&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin-gettext-tools      deepin-screen-recorder    deepin-wine-helper64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin-icon-theme         deepin-screenshot         deepin-wine-plugin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin-image-viewer       deepin-shortcut-viewer    deepnano&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;deepin-libwine            deepin-terminal           deepnano-data&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;上述两条命令执行完，企业微信已经安装成功，接下来的步骤自行选择&lt;/p&gt;
&lt;p&gt;但是字体是为楷体，看着难受，下面是修改字体；&lt;/p&gt;
&lt;p&gt;1、在目录 /usr/share/fonts 创建 windows 目录，consola.ttf 和 msyh.ttf 拷贝到 ubuntu 下的 /usr/share/fonts/windows 下，记得给 windows 目录和.ttf 文件修改权限．（consola.ttf 文件我已上传资源，msyh.ttf 上传时提示已存在）&lt;/p&gt;
&lt;p&gt;2、在 /usr/share/fonts/windows 下执行下面几条命令&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo mkfontscale #生成核心字体信息&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo mkfontdir&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo fc-cache -fv&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3. 重启企业微信&lt;/p&gt;
&lt;h3 id=&#34;安装vmware&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装vmware&#34;&gt;#&lt;/a&gt; 安装 VMware&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 查看安装的虚拟机&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vmware-installer -l&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 安装&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt update &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt install gcc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt install build-essential&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo bash  VMware-Workstation-Full-15.5.2-15785246.x86_64.bundle&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 卸载&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;vmware-installer -u vmware-workstation。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight text&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;激活密钥&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VMware永久激活密钥&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UG5J2-0ME12-M89WY-NPWXX-WQH88&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;GA590-86Y05-4806Y-X4PEE-ZV8E0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;YA18K-0WY8P-H85DY-L4NZG-X7RAD&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UA5DR-2ZD4H-089FY-6YQ5T-YPRX6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;B806Y-86Y05-GA590-X4PEE-ZV8E0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ZF582-0NW5N-H8D2P-0XZEE-Z22VA&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VMware Workstation Pro 15 激活许可证&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UY758-0RXEQ-M81WP-8ZM7Z-Y3HDA&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VF750-4MX5Q-488DQ-9WZE9-ZY2D6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UU54R-FVD91-488PP-7NNGC-ZFAX6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;YC74H-FGF92-081VZ-R5QNG-P6RY4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;YC34H-6WWDK-085MQ-JYPNX-NZRA2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VMware Workstation Pro 14 激活许可证&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;FF31K-AHZD1-H8ETZ-8WWEZ-WUUVA&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;CV7T2-6WY5Q-48EWP-ZXY7X-QGUWD&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VMware Workstation Pro 12 激活许可证&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5A02H-AU243-TZJ49-GTC7K-3C61N&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VF5XA-FNDDJ-085GZ-4NXZ9-N20E6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UC5MR-8NE16-H81WY-R7QGV-QG2D8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ZG1WH-ATY96-H80QP-X7PEX-Y30V4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;AA3E0-0VDE1-0893Z-KGZ59-QGAVF&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VMware Workstation Pro 10 激活许可证&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;1Z0G9-67285-FZG78-ZL3Q2-234JG&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4C4EK-89KDL-5ZFP9-1LA5P-2A0J0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;HY086-4T01N-CZ3U0-CV0QM-13DNU&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;VMware Workstation Pro 16 许可证密钥，批量永久激活！ &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ZF3R0-FHED2-M80TY-8QYGC-NPKYF &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;YF390-0HF8P-M81RQ-2DXQE-M2UT6 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ZF71R-DMX85-08DQY-8YMNC-PPHV8 &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;Vmware16 pro 密钥&lt;/p&gt;
&lt;p&gt;ZF3R0-FHED2-M80TY-8QYGC-NPKYF&lt;br&gt;
YF390-0HF8P-M81RQ-2DXQE-M2UT6&lt;br&gt;
ZF71R-DMX85-08DQY-8YMNC-PPHV8&lt;/p&gt;
&lt;h3 id=&#34;安装typora&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装typora&#34;&gt;#&lt;/a&gt; 安装 Typora&lt;/h3&gt;
&lt;h4 id=&#34;步骤&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤&#34;&gt;#&lt;/a&gt; 步骤：&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;设置密钥&lt;/strong&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;sudo apt-key adv --keyserver keyserver.ubuntu.com --recv-keys BA300B7755AFCFAE&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;或&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;wget -qO - https://typora.io/linux/public-key.asc | sudo apt-key add -&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;添加 Typora 的远程仓库&lt;/strong&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;sudo add-apt-repository &#39;deb https://typora.io/linux ./&#39;&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;更新&lt;/strong&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;sudo apt-get update&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;安装&lt;/strong&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;code&gt;sudo apt-get install typora&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;应用程序列表与默认应用程序&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#应用程序列表与默认应用程序&#34;&gt;#&lt;/a&gt; 应用程序列表与默认应用程序&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 应用程序列表&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/usr/local/aaplications&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 出现openwith清单中，添加参数后即可在应用程序列表中就能看到对应的应用&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Exec一行中添加 %F&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;中文输入法安装步骤&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#中文输入法安装步骤&#34;&gt;#&lt;/a&gt; 中文输入法安装步骤&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 安装fcitx-googlepinyin（谷歌输入法）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install fcitx-googlepinyin&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;设置 language support，打开后如果中文环境会提示安装对应环境的语言，点击安装&lt;/p&gt;
&lt;p&gt;安装好后就能进入语言支持界面，最下面一行 Keyboard input method system，默认是 &lt;code&gt;iBus&lt;/code&gt; ，点击下拉单切换到 fcitx（系统初始没有 &lt;code&gt;fctix&lt;/code&gt; ，安装 &lt;code&gt;fcitx-googlepinyin&lt;/code&gt;  的时候会装好 &lt;code&gt;fcitx&lt;/code&gt; ）。然后重启电脑。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201220151823562.png&#34; alt=&#34;image-20201220151823562&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201220151823562.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;重启之后在右上角状态栏点击键盘图标，在下拉单里选择倒数第三个 Configure 进入配置界面。&lt;/p&gt;
&lt;p&gt;输入 pinyin 搜索到系统现有的拼音输入法。选择 Google Pinyin 并点击 OK 确认。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20201220151854087.png&#34; alt=&#34;image-20201220151854087&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20201220151854087.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;修改npm全局安装包的位置解决eacces权限拒绝问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#修改npm全局安装包的位置解决eacces权限拒绝问题&#34;&gt;#&lt;/a&gt; 修改 npm 全局安装包的位置，解决 EACCES 权限拒绝问题&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 查看当前npm的默认位置&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;npm config ls&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 修改npm使用新的全局安装路径&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;npm config set prefix &amp;#x27;your url&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;redis桌面可视化访问工具&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#redis桌面可视化访问工具&#34;&gt;#&lt;/a&gt; redis 桌面可视化访问工具&lt;/h3&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 参考工具&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;https://snapcraft.io/redis-desktop-manager&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;gitkraken-chinese&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gitkraken-chinese&#34;&gt;#&lt;/a&gt; gitkraken-chinese&lt;/h3&gt;
&lt;h4 id=&#34;原理-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#原理-2&#34;&gt;#&lt;/a&gt; 原理&lt;/h4&gt;
&lt;p&gt;&lt;a href=&#34;https://github.com/k-skye/gitkraken-chinese&#34;&gt;https://github.com/k-skye/gitkraken-chinese&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;通过修改软件目录下 english 语言对应的一个 json 文件内容来完成汉化目的&lt;/p&gt;
&lt;h4 id=&#34;操作步骤&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#操作步骤&#34;&gt;#&lt;/a&gt; 操作步骤&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;将项目中的  &lt;code&gt;strings.json&lt;/code&gt;  替换到 GitKraken 语言目录下的  &lt;code&gt;strings.json&lt;/code&gt; .&lt;br&gt;
(实际目录可能会不一样，但文件名一定是 strings.json)
&lt;ul&gt;
&lt;li&gt;Windows:  &lt;code&gt;%程序安装目录%\gitkraken\app-x.x.x\resources\app\src\strings.json&lt;/code&gt;  (x.x.x 是你的 GitKraken 版本)&lt;/li&gt;
&lt;li&gt;Mac:  &lt;code&gt;/Applications/GitKraken.app/Contents/Resources/app/src/strings.json&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;Linux:  &lt;code&gt;/usr/share/gitkraken/resources/app.asar.unpacked/src&lt;/code&gt;  (感谢 @lyydhy 10.31 补充 Gitkraken 是 deepin 通过 deb 安装的)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;重启 GitKraken.&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;issue&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#issue&#34;&gt;#&lt;/a&gt; issue&lt;/h4&gt;
&lt;p&gt;GitKraken 旧版本目录不一样，应该是以下目录：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Windows:  &lt;code&gt;%程序安装目录%\gitkraken\app-x.x.x\resources\app.asar.unpacked\src\strings.json&lt;/code&gt;  (x.x.x 是你的 GitKraken 版本)&lt;/li&gt;
&lt;li&gt;Mac:  &lt;code&gt;/Applications/GitKraken.app/Contents/Resources/app.asar.unpacked/src/strings.json&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;openvpn客户端&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#openvpn客户端&#34;&gt;#&lt;/a&gt; openVpn 客户端&lt;/h3&gt;
&lt;h4 id=&#34;安装openvpn&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装openvpn&#34;&gt;#&lt;/a&gt; 安装 openvpn&lt;/h4&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo apt-get install openvpn&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;配置openvpn&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#配置openvpn&#34;&gt;#&lt;/a&gt; 配置 openvpn&lt;/h4&gt;
&lt;p&gt;作为客户端，OpenVPN 并没有特定的配置文件，而是由服务器提供方给出一个配置文件。对于认证，OpenVPN 提供了两种认证方法：基于用户名 / 密码的认证与 SSL 证书认证。用户名 / 密码的认证方法无法（或较难）限制一个账号同时连接多个客户端，而采用证书，则可保证同一证书同一时间只能有 一个客户端连接。当然，这些都是由服务器端决定的，不需要客户端进行选择。&lt;/p&gt;
&lt;p&gt;首先将 OpenVPN 服务器提供商发给你的配置文件解压，并将所有文件都复制到 /etc/openvpn/ 中，一共六个文件：ca.crt, ca.key, client.crt , client.csr , client.key ,client.ovpn。 &lt;strong&gt;红色的 client 文件为客户名称。&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;如果没有.ovpn 文件需要手动差 u 创建一个：client.ovpn。格式如下：&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;client &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dev tun &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;proto tcp      --红色的两行需要根据openvpn服务器配置进行设置（dev tap　　proto tcp-client）remote openvpn服务器IP（10.0.0.1）  端口号（默认：1194）resolv-retry infinite&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;nobind&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mute-replay-warnings&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;redirect-gateway&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ca &amp;#x2F;etc&amp;#x2F;openvpn&amp;#x2F;ca.crt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cert &amp;#x2F;etc&amp;#x2F;openvpn&amp;#x2F;client.crt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;key &amp;#x2F;etc&amp;#x2F;openvpn&amp;#x2F;client.key&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;comp-lzo &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;verb 5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;连接openvpn&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#连接openvpn&#34;&gt;#&lt;/a&gt; 连接 openvpn&lt;/h4&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo openvpn &amp;#x2F;etc&amp;#x2F;openvpn&amp;#x2F;client.ovpn&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;用别名来优化开启openvpn的命令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#用别名来优化开启openvpn的命令&#34;&gt;#&lt;/a&gt; 用别名来优化开启 openvpn 的命令&lt;/h4&gt;
&lt;p&gt;&lt;strong&gt;编辑.bashrc 文件，在文件中如下图后边加入一行&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo vim .bashrc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;alias vpn&amp;#x3D;&amp;#39;sudo openvpn &amp;#x2F;etc&amp;#x2F;openvpn&amp;#x2F;client.ovpn&amp;#39; (插入之文件）&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;保存后，执行 &lt;strong&gt;vpn&lt;/strong&gt; 就可以直接连接 openvpn。&lt;/p&gt;
&lt;h4 id=&#34;用ctrlc强制断开vpn连接&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#用ctrlc强制断开vpn连接&#34;&gt;#&lt;/a&gt; 用 ctrl+c 强制断开 vpn 连接。&lt;/h4&gt;

 &lt;h3 id=&#34;本机调试&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#本机调试&#34;&gt;#&lt;/a&gt; &lt;strong&gt;本机调试&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;此处不做过多解释，相信考虑远程 debug 调试的，肯定对本机调试是有一定了解的。说下自己在本机调试 spring Boot 项目时遇到的项目长时间卡顿，这个时候可能是因为本机环境中 debug 断点太多，去除一下后即可正常启动；&lt;/p&gt;
&lt;h3 id=&#34;远程调试&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#远程调试&#34;&gt;#&lt;/a&gt; &lt;strong&gt;远程调试&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;远程调试一个大前提就是我们需要保证远程代码和本地代码一致；&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;此处部署为 war 包项目&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;在远程环境中要开启允许远程 debug 调试&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;windows 环境–》bin 目录–》 &lt;code&gt;startup.bat&lt;/code&gt;  增加设置 (此处设置 debug 端口为 address=8081，可以根据实际条件自行设置)&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;SET CATALINA_OPTS&amp;#x3D;-server -Xdebug -Xnoagent -Djava.compiler&amp;#x3D;NONE -Xrunjdwp:transport&amp;#x3D;dt_socket,server&amp;#x3D;y,suspend&amp;#x3D;n,address&amp;#x3D;8081&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ol&gt;
&lt;li&gt;Linux 环境中–》 &lt;code&gt;catalina.sh&lt;/code&gt;  文件&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;CATALINA_OPTS&amp;#x3D;&amp;quot;-Xdebug -Xrunjdwp:transport&amp;#x3D;dt_socket,suspend&amp;#x3D;n,server&amp;#x3D;y,address&amp;#x3D;8081&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;IDEA 中创建 debug 调试&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/20190809174957123.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3NmeTEwMjYxMQ==,size_16,color_FFFFFF,t_70&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/20190809174957123.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3NmeTEwMjYxMQ==,size_16,color_FFFFFF,t_70&#34; class=&#34;lozad post-image&#34;&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/20190809175016989.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3NmeTEwMjYxMQ==,size_16,color_FFFFFF,t_70&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/20190809175016989.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3NmeTEwMjYxMQ==,size_16,color_FFFFFF,t_70&#34; class=&#34;lozad post-image&#34;&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/2019080917503035.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3NmeTEwMjYxMQ==,size_16,color_FFFFFF,t_70&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/2019080917503035.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3NmeTEwMjYxMQ==,size_16,color_FFFFFF,t_70&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;全部设置完成后，重启项目&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/20190809175100811.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/20190809175100811.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;然后 idea 中 debug 启动刚才新建的服务，在本机代码中打断点，发起相应请求即可进入 debug 模式；&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;若项目为 jar 项目应该使用&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/20190809175123597.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/20190809175123597.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;IDEA 翻译，插件安装及对应的代码消息提醒实时翻译&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;插件下载&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#插件下载&#34;&gt;#&lt;/a&gt; 插件下载&lt;/h3&gt;
&lt;p&gt;插件名称 &lt;code&gt;translation&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210108162128978.png&#34; alt=&#34;image-20210108162128978&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210108162128978.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;插件设置&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210108162236494.png&#34; alt=&#34;image-20210108162236494&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210108162236494.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;勾选下面的其他内容，才会实时翻译&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210108162315892.png&#34; alt=&#34;image-20210108162315892&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210108162315892.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;

 &lt;p&gt;Debug 用来追踪代码的运行流程，通常在程序运行过程中出现异常，启用 Debug 模式可以分析定位异常发生的位置，以及在运行过程中参数的变化。通常我们也可以启用 Debug 模式来跟踪代码的运行流程去学习三方框架的源码。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;所以学习下如何在 Intellij IDEA 中使用好 Debug，主要包括如下内容：&lt;/p&gt;
&lt;h2 id=&#34;debug基础与配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#debug基础与配置&#34;&gt;#&lt;/a&gt; Debug 基础与配置&lt;/h2&gt;
&lt;p&gt;首先看下 IDEA 中 Debug 模式下的界面。&lt;/p&gt;
&lt;p&gt;如下是在 IDEA 中启动 Debug 模式，进入断点后的界面，我这里是 Windows，可能和 Mac 的图标等会有些不一样。就简单说下图中标注的 8 个地方：&lt;/p&gt;
&lt;p&gt;① 以 Debug 模式启动服务，左边的一个按钮则是以 Run 模式启动。在开发中，我一般会直接启动 Debug 模式，方便随时调试代码。&lt;/p&gt;
&lt;p&gt;② 断点：在左边行号栏单击左键，或者快捷键 Ctrl+F8 打上 / 取消断点，断点行的颜色可自己去设置。&lt;/p&gt;
&lt;p&gt;③ Debug 窗口：访问请求到达第一个断点后，会自动激活 Debug 窗口。如果没有自动激活，可以去设置里设置，如图 1.2。&lt;/p&gt;
&lt;p&gt;④ 调试按钮：一共有 8 个按钮，调试的主要功能就对应着这几个按钮，鼠标悬停在按钮上可以查看对应的快捷键。在菜单栏 Run 里可以找到同样的对应的功能，如图 1.4。&lt;/p&gt;
&lt;p&gt;⑤ 服务按钮：可以在这里关闭 / 启动服务，设置断点等。&lt;/p&gt;
&lt;p&gt;⑥ 方法调用栈：这里显示了该线程调试所经过的所有方法，勾选右上角的 [Show All Frames] 按钮，就不会显示其它类库的方法了，否则这里会有一大堆的方法。&lt;/p&gt;
&lt;p&gt;⑦ Variables：在变量区可以查看当前断点之前的当前方法内的变量。&lt;/p&gt;
&lt;p&gt;⑧ Watches：查看变量，可以将 Variables 区中的变量拖到 Watches 中查看&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905221418147-1205043020.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905221418147-1205043020.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;[图 1.2]：在设置里勾选 Show debug window on breakpoint，则请求进入到断点后自动激活 Debug 窗口&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905111655647-1134637623.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905111655647-1134637623.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;​		如果你的 IDEA 底部没有显示工具栏或状态栏，可以在 View 里打开，显示出工具栏会方便我们使用。可以自己去尝试下这四个选项。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905112617351-1554043487.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905112617351-1554043487.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;在菜单栏 Run 里有调试对应的功能，同时可以查看对应的快捷键。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905124338444-556465721.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905124338444-556465721.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;基本用法快捷键&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基本用法快捷键&#34;&gt;#&lt;/a&gt; 基本用法 &amp;amp; 快捷键&lt;/h2&gt;
&lt;p&gt;Debug 调试的功能主要对应着图一中 4 和 5 两组按钮：&lt;/p&gt;
&lt;p&gt;1、首先说第一组按钮，共 8 个按钮，从左到右依次如下：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905134837851-1615718043.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905134837851-1615718043.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&amp;gt; Show Execution Point (Alt + F10)：如果你的光标在其它行或其它页面，点击这个按钮可跳转到当前代码执行的行。&lt;/p&gt;
&lt;p&gt;&amp;gt; Step Over (F8)：步过，一行一行地往下走，如果这一行上有方法不会进入方法。&lt;/p&gt;
&lt;p&gt;&amp;gt; Step Into (F7)：步入，如果当前行有方法，可以进入方法内部，一般用于进入自定义方法内，不会进入官方类库的方法，如第 25 行的 put 方法。&lt;/p&gt;
&lt;p&gt;&amp;gt; Force Step Into (Alt + Shift + F7)：强制步入，能进入任何方法，查看底层源码的时候可以用这个进入官方类库的方法。&lt;/p&gt;
&lt;p&gt;&amp;gt; Step Out (Shift + F8)：步出，从步入的方法内退出到方法调用处，此时方法已执行完毕，只是还没有完成赋值。&lt;/p&gt;
&lt;p&gt;&amp;gt; Drop Frame (默认无)：回退断点，后面章节详细说明。&lt;/p&gt;
&lt;p&gt;&amp;gt; Run to Cursor (Alt + F9)：运行到光标处，你可以将光标定位到你需要查看的那一行，然后使用这个功能，代码会运行至光标行，而不需要打断点。&lt;/p&gt;
&lt;p&gt;&amp;gt; Evaluate Expression (Alt + F8)：计算表达式，后面章节详细说明。&lt;/p&gt;
&lt;p&gt;2、第二组按钮，共 7 个按钮，从上到下依次如下：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905134011101-1824595229.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905134011101-1824595229.png&#34; class=&#34;lozad post-image&#34;&gt; [图 2.2]&lt;/p&gt;
&lt;p&gt;&amp;gt; Rerun ‘xxxx’：重新运行程序，会关闭服务后重新启动程序。&lt;/p&gt;
&lt;p&gt;&amp;gt; Update ‘tech’ application (Ctrl + F5)：更新程序，一般在你的代码有改动后可执行这个功能。而这个功能对应的操作则是在服务配置里，如图 2.3。&lt;/p&gt;
&lt;p&gt;&amp;gt; Resume Program (F9)：恢复程序，比如，你在第 20 行和 25 行有两个断点，当前运行至第 20 行，按 F9，则运行到下一个断点 (即第 25 行)，再按 F9，则运行完整个流程，因为后面已经没有断点了。&lt;/p&gt;
&lt;p&gt;&amp;gt; Pause Program：暂停程序，启用 Debug。目前没发现具体用法。&lt;/p&gt;
&lt;p&gt;&amp;gt; Stop ‘xxx’ (Ctrl + F2)：连续按两下，关闭程序。有时候你会发现关闭服务再启动时，报端口被占用，这是因为没完全关闭服务的原因，你就需要查杀所有 JVM 进程了。&lt;/p&gt;
&lt;p&gt;&amp;gt; View Breakpoints (Ctrl + Shift + F8)：查看所有断点，后面章节会涉及到。&lt;/p&gt;
&lt;p&gt;&amp;gt; Mute Breakpoints：哑的断点，选择这个后，所有断点变为灰色，断点失效，按 F9 则可以直接运行完程序。再次点击，断点变为红色，有效。如果只想使某一个断点失效，可以在断点上右键取消 Enabled，如图 2.4，则该行断点失效。&lt;/p&gt;
&lt;p&gt;更新程序，On ‘Update’ actions，执行更新操作时所做的事情，一般选择’Update classes and resources’，即更新类和资源文件。&lt;/p&gt;
&lt;p&gt;一般配合热部署插件会更好用，如 JRebel，这样就不用每次更改代码后还要去重新启动服务。如何激活 JRebel，在最后章节附上。&lt;/p&gt;
&lt;p&gt;下面的 On frame deactivation，在 IDEA 窗口失去焦点时触发，即一般你从 idea 切换到浏览器的时候，idea 会自动帮你做的事情，一般可以设置 Do nothing，频繁切换会比较消耗资源的。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905143932694-500925087.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905143932694-500925087.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905193821194-225518192.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905193821194-225518192.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;变量查看&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#变量查看&#34;&gt;#&lt;/a&gt; 变量查看&lt;/h2&gt;
&lt;p&gt;在 Debug 过程中，跟踪查看变量的变化是非常必要的，这里就简单说下 IDEA 中可以查看变量的几个地方，相信大部分人都了解。&lt;/p&gt;
&lt;p&gt;1、如下，在 IDEA 中，参数所在行后面会显示当前变量的值。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905154209179-9123997.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905154209179-9123997.png&#34; class=&#34;lozad post-image&#34;&gt; [图 3.1]&lt;/p&gt;
&lt;p&gt;2、光标悬停到参数上，显示当前变量信息。点击打开详情如图 3.3。我一般会使用这种方式，快捷方便。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905154425772-770303651.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905154425772-770303651.png&#34; class=&#34;lozad post-image&#34;&gt; [图 3.2]&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905154724866-160919363.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905154724866-160919363.png&#34; class=&#34;lozad post-image&#34;&gt; [图 3.3]&lt;/p&gt;
&lt;p&gt;3、在 Variables 里查看，这里显示当前方法里的所有变量。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905155339491-1166069157.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905155339491-1166069157.png&#34; class=&#34;lozad post-image&#34;&gt; [图 3.4]&lt;/p&gt;
&lt;p&gt;4、在 Watches 里，点击 New Watch，输入需要查看的变量。或者可以从 Variables 里拖到 Watche 里查看。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905160057038-750351531.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905160057038-750351531.png&#34; class=&#34;lozad post-image&#34;&gt; [图 3.5]&lt;/p&gt;
&lt;p&gt;如果你发现你没有 Watches，可能在下图所在的地方。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905160433710-2004658473.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905160433710-2004658473.png&#34; class=&#34;lozad post-image&#34;&gt; [图 3.6]&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905160515538-1647769062.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905160515538-1647769062.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;计算表达式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#计算表达式&#34;&gt;#&lt;/a&gt; 计算表达式&lt;/h2&gt;
&lt;p&gt;在前面提到的计算表达式如图 4.1 的按钮，Evaluate Expression (Alt + F8) 。可以使用这个操作在调试过程中计算某个表达式的值，而不用再去打印信息。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905160826444-1625048711.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905160826444-1625048711.png&#34; class=&#34;lozad post-image&#34;&gt; [图 4.1]&lt;/p&gt;
&lt;p&gt;1、按 Alt + F8 或按钮，或者，你可以选中某个表达式再 Alt + F8，弹出计算表达式的窗口，如下，回车或点击 Evaluate 计算表达式的值。&lt;/p&gt;
&lt;p&gt;这个表达式不仅可以是一般变量或参数，也可以是方法，当你的一行代码中调用了几个方法时，就可以通过这种方式查看查看某个方法的返回值。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905161614694-93470669.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905161614694-93470669.png&#34; class=&#34;lozad post-image&#34;&gt; [图 4.2]&lt;/p&gt;
&lt;p&gt;2、设置变量，在计算表达式的框里，可以改变变量的值，这样有时候就能很方便我们去调试各种值的情况了不是。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905162404288-824548249.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905162404288-824548249.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;智能步入&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#智能步入&#34;&gt;#&lt;/a&gt; 智能步入&lt;/h2&gt;
&lt;p&gt;想想，一行代码里有好几个方法，怎么只选择某一个方法进入。之前提到过使用 Step Into (Alt + F7) 或者 Force Step Into (Alt + Shift + F7) 进入到方法内部，但这两个操作会根据方法调用顺序依次进入，这比较麻烦。&lt;/p&gt;
&lt;p&gt;那么智能步入就很方便了，智能步入，这个功能在 Run 里可以看到，Smart Step Into (Shift + F7)，如图 5.1&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905152523304-803289488.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905152523304-803289488.png&#34; class=&#34;lozad post-image&#34;&gt; [图 5.1]&lt;/p&gt;
&lt;p&gt;按 Shift + F7，会自动定位到当前断点行，并列出需要进入的方法，如图 5.2，点击方法进入方法内部。&lt;/p&gt;
&lt;p&gt;如果只有一个方法，则直接进入，类似 Force Step Into。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905163730929-1374653206.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905163730929-1374653206.png&#34; class=&#34;lozad post-image&#34;&gt; [图 5.2]&lt;/p&gt;
&lt;h2 id=&#34;断点条件设置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#断点条件设置&#34;&gt;#&lt;/a&gt; 断点条件设置&lt;/h2&gt;
&lt;p&gt;通过设置断点条件，在满足条件时，才停在断点处，否则直接运行。&lt;/p&gt;
&lt;p&gt;通常，当我们在遍历一个比较大的集合或数组时，在循环内设置了一个断点，难道我们要一个一个去看变量的值？那肯定很累，说不定你还错过这个值得重新来一次。&lt;/p&gt;
&lt;p&gt;1、在断点上右键直接设置当前断点的条件，如图 6.1，我设置 exist 为 true 时断点才生效。&lt;/p&gt;
&lt;p&gt;![img]/img/856154-20170905165253944-1162138475.png) [图 6.1]&lt;/p&gt;
&lt;p&gt;2、点击 View Breakpoints (Ctrl + Shift + F8)，查看所有断点。&lt;/p&gt;
&lt;p&gt;Java Line Breakpoints 显示了所有的断点，在右边勾选 Condition，设置断点的条件。&lt;/p&gt;
&lt;p&gt;勾选 Log message to console，则会将当前断点行输出到控制台，如图 6.3&lt;/p&gt;
&lt;p&gt;勾选 Evaluate and log，可以在执行这行代码是计算表达式的值，并将结果输出到控制台。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905170655163-1805982960.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905170655163-1805982960.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905170947257-1667065155.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905170947257-1667065155.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;3、再说说右边的 Filters 过滤，这些一般情况下不常用，简单说下意思。&lt;/p&gt;
&lt;p&gt;Instance filters：实例过滤，输入实例 ID (如图 6.5 中的实例 ID)，但是我这里没有成功，不知道什么原因，知道的朋友留个言。&lt;/p&gt;
&lt;p&gt;Class filters：类过滤，根据类名过滤，同样没有成功…&lt;/p&gt;
&lt;p&gt;Pass count：用于循环中，如果断点在循环中，可以设置该值，循环多少次后停在断点处，之后的循环都会停在断点处。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905185247132-1922055922.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905185247132-1922055922.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905190253304-1057381593.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905190253304-1057381593.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;4、异常断点，通过设置异常断点，在程序中出现需要拦截的异常时，会自动定位到异常行。&lt;/p&gt;
&lt;p&gt;如图 6.6，点击 + 号添加 Java Exception Breakpoints，添加异常断点。然后输入需要断点的异常类，如图 6.7，之后可以在 Java Exception Breakpoints 里看到添加的异常断点。&lt;/p&gt;
&lt;p&gt;我这里添加了一个 NullPointerException 异常断点，如图 6.8，出现空指针异常后，自动定位在空指针异常行。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905200131851-150143203.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905200131851-150143203.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905200305147-527881101.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905200305147-527881101.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905200726069-688175303.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905200726069-688175303.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;多线程调试&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#多线程调试&#34;&gt;#&lt;/a&gt; 多线程调试&lt;/h2&gt;
&lt;p&gt;一般情况下我们调试的时候是在一个线程中的，一步一步往下走。但有时候你会发现在 Debug 的时候，想发起另外一个请求都无法进行了？&lt;/p&gt;
&lt;p&gt;那是因为 IDEA 在 Debug 时默认阻塞级别是 ALL，会阻塞其它线程，只有在当前调试线程走完时才会走其它线程。可以在 View Breakpoints 里选择 Thread，如图 7.1，然后点击 Make Default 设置为默认选项。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905204329757-1196950664.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905204329757-1196950664.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;切换线程，在图 7.2 中 Frames 的下拉列表里，可以切换当前的线程，如下我这里有两个 Debug 的线程，切换另外一个则进入另一个 Debug 的线程。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905205012663-56609868.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905205012663-56609868.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;回退断点&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#回退断点&#34;&gt;#&lt;/a&gt; 回退断点&lt;/h2&gt;
&lt;p&gt;在调试的时候，想要重新走一下流程而不用再次发起一个请求？&lt;/p&gt;
&lt;p&gt;1、首先认识下这个方法调用栈，如图 8.1，首先请求进入 DemoController 的 insertDemo 方法，然后调用 insert 方法，其它的 invoke 我们且先不管，最上面的方法是当前断点所在的方法。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905210917741-1095775464.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905210917741-1095775464.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;2、断点回退&lt;/p&gt;
&lt;p&gt;所谓的断点回退，其实就是回退到上一个方法调用的开始处，在 IDEA 里测试无法一行一行地回退或回到到上一个断点处，而是回到上一个方法。&lt;/p&gt;
&lt;p&gt;回退的方式有两种，一种是 Drop Frame 按钮 (图 8.2)，按调用的方法逐步回退，包括三方类库的其它方法 (取消 Show All Frames 按钮会显示三方类库的方法，如图 8.3)。&lt;/p&gt;
&lt;p&gt;第二种方式，在调用栈方法上选择要回退的方法，右键选择 Drop Frame (图 8.4)，回退到该方法的上一个方法调用处，此时再按 F9 (Resume Program)，可以看到程序进入到该方法的断点处了。&lt;/p&gt;
&lt;p&gt;但有一点需要注意，断点回退只能重新走一下流程，之前的某些参数 / 数据的状态已经改变了的是无法回退到之前的状态的，如对象、集合、更新了数据库数据等等。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905211428554-1617570377.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905211428554-1617570377.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905211723304-1223322879.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905211723304-1223322879.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905212138101-113776159.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905212138101-113776159.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;中断debug&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#中断debug&#34;&gt;#&lt;/a&gt; 中断 Debug&lt;/h2&gt;
&lt;p&gt;想要在 Debug 的时候，中断请求，不要再走剩余的流程了？&lt;/p&gt;
&lt;p&gt;有些时候，我们看到传入的参数有误后，不想走后面的流程了，怎么中断这次请求呢 (后面的流程要删除数据库数据呢…)，难道要关闭服务重新启动程序？嗯，我以前也是这么干的。&lt;/p&gt;
&lt;p&gt;确切的说，我也没发现可以直接中断请求的方式 (除了关闭服务)，但可以通过 Force Return，即强制返回来避免后续的流程，如图 9.1。&lt;/p&gt;
&lt;p&gt;点击 Force Return，弹出 Return Value 的窗口，我这个方法的返回类型为 Map，所以，我这里直接返回 results，来强制返回，从而不再进行后续的流程。或者你可以 new HashMap&amp;lt;&amp;gt;()。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905213656241-1998475384.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905213656241-1998475384.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/856154-20170905214031397-1943297392.png&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/856154-20170905214031397-1943297392.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;转载至：&lt;a href=&#34;http://www.cnblogs.com/chiangchou/&#34;&gt;http://www.cnblogs.com/chiangchou/&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;CentOS 安装 JDK 的几种方法及配置环境变量&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;一、下载 jdk&lt;/p&gt;
&lt;p&gt;jdk 下载地址：&lt;a href=&#34;http://www.oracle.com/technetwork/java/javase/downloads/jdk8-downloads-2133151.html&#34;&gt;http://www.oracle.com/technetwork/java/javase/downloads/jdk8-downloads-2133151.html&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;下载 jdk-8u152-linux-x64.rpm 或 jdk-8u152-linux-x64.tar.gz (根据自己的系统位数选择对应的包)&lt;/p&gt;
&lt;p&gt;如图：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210128110454225.png&#34; alt=&#34;image-20210128110454225&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210128110454225.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;二、安装 jdk&lt;/p&gt;
&lt;p&gt;因为我安装的 CentOS7.4 系统自带 jdk1.8，所以为了演示如何安装 jdk，我需要先卸载系统自带的 jdk&lt;/p&gt;
&lt;p&gt;查看当前系统 jdk 的版本：java -version&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210128110524600.png&#34; alt=&#34;image-20210128110524600&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210128110524600.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;列举匹配已安装的 java 的软件包：yum list installed | grep java&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20210128110535711.png&#34; alt=&#34;image-20210128110535711&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20210128110535711.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;卸载安装的 jdk：(yum 命令参考：&lt;a href=&#34;http://man.linuxde.net/yum&#34;&gt;http://man.linuxde.net/yum&lt;/a&gt;)&lt;/p&gt;
&lt;p&gt;yum -y remove java-1.7.0-openjdk*&lt;/p&gt;
&lt;p&gt;yum -y remove java-1.8.0-openjdk*&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171208142625386&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171208142625386&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171208142644577&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171208142644577&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;当结果出现了完毕！，就表示卸载成功。&lt;/p&gt;
&lt;p&gt;安装 jdk (介绍三种方法)&lt;/p&gt;
&lt;h3 id=&#34;方法一利用yum源来安装jdk&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法一利用yum源来安装jdk&#34;&gt;#&lt;/a&gt; 方法一：利用 yum 源来安装 jdk&lt;/h3&gt;
&lt;p&gt;（此方法不需要配置环境变量）&lt;/p&gt;
&lt;p&gt;查看 yum 库中的 java 安装包 ：yum -y list java*&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171208143606277&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171208143606277&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;安装需要的 jdk 版本的所有 java 程序：yum -y install java-1.8.0-openjdk*&lt;/p&gt;
&lt;p&gt;(安装完之后，默认的安装目录是在: /usr/lib/jvm/java-1.8.0-openjdk-1.8.0.151-1.b12.el7_4.x86_64)&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171208143844407&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171208143844407&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;当结果出现了完毕！即安装完成。&lt;/p&gt;
&lt;p&gt;查看 java 版本：java -version&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171208144426251&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171208144426251&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;方法二用rpm安装jdk&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法二用rpm安装jdk&#34;&gt;#&lt;/a&gt; 方法二：用 rpm 安装 jdk&lt;/h3&gt;
&lt;p&gt;(可以使用 man rpm 命令查看 rpm 的帮助文档)&lt;/p&gt;
&lt;p&gt;使用 Xftp 将下载好的 jdk-8u152-linux-x64.rpm 上传到 CentOs 上去，我这里放到了 /home/lisonglin 下&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171208161556789&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171208161556789&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;使用 rpm 命令安装： rpm -ivh jdk-8u152-linux-x64.rpm&lt;/p&gt;
&lt;p&gt;(默认安装在 /usr/java 目录下，不用配置环境变量)&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171213105005772&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171213105005772&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;方法三手动安装压缩包&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法三手动安装压缩包&#34;&gt;#&lt;/a&gt; 方法三：手动安装压缩包&lt;/h3&gt;
&lt;p&gt;手动解压 JDK 的压缩包，然后设置环境变量&lt;/p&gt;
&lt;p&gt;使用 Xftp 将下载好的 jdk-8u152-linux-x64.tar.gz 上传到 CentOs 上去，我这里放到了 /home/lisonglin 下&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171213112053683&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171213112053683&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;先将之前使用 rpm 方式安装的 jdk 卸载掉 (如果没有安装过可跳过此步骤)&lt;/p&gt;
&lt;p&gt;查询之前安装的 jdk 名称：rpm -qa | grep jdk&lt;/p&gt;
&lt;p&gt;卸载 jdk：rpm -e --nodeps jdk1.8  (此处也可以使用全名 jdk1.8-1.8.0_152-fcs.x86_64)&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171213112433031&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171213112433031&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;卸载完成！&lt;/p&gt;
&lt;p&gt;1、复制安装包到 /usr/java 目录中 (目录可以自己选)：cp jdk-8u152-linux-x64.tar.gz/usr/java&lt;/p&gt;
&lt;p&gt;2、切换到 /usr/java 目录下：cd /usr/java&lt;/p&gt;
&lt;p&gt;3、解压缩包：tar -zxvf jdk-8u152-linux-x64.tar.gz&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171213113924553&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171213113924553&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;解压成功（表式 JDK 已安装成功，可查看 jdk 的文件夹）&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171213114305546&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171213114305546&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;此时 java -version 命令还不能使用：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171213114609823&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171213114609823&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;4、配置环境变量&lt;/p&gt;
&lt;p&gt;使用 vim /etc/profile 编辑 profile 文件 输入： vim /etc/profile&lt;/p&gt;
&lt;p&gt;向文件里面追加以下内容：&lt;/p&gt;
&lt;p&gt;#set java environment&lt;br&gt;
JAVA_HOME=/usr/java/jdk1.8.0_152&lt;br&gt;
JRE_HOME=&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;J&lt;/mi&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;V&lt;/mi&gt;&lt;msub&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;H&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;P&lt;/mi&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mi&gt;H&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;JAVA_HOME/jre
PATH=&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.09618em;&#34;&gt;J&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;V&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.08125em;&#34;&gt;H&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;P&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.08125em;&#34;&gt;H&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;PATH:&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;J&lt;/mi&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;V&lt;/mi&gt;&lt;msub&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;H&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mo&gt;:&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;JAVA_HOME/bin:&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.09618em;&#34;&gt;J&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;V&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.08125em;&#34;&gt;H&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;:&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;JRE_HOME/bin&lt;br&gt;
CLASSPATH=.:&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;J&lt;/mi&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;V&lt;/mi&gt;&lt;msub&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;H&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;.&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mo&gt;:&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;JAVA_HOME/lib/dt.jar:&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.09618em;&#34;&gt;J&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;V&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.08125em;&#34;&gt;H&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;:&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;JAVA_HOME/lib/tools.jar:$JRE_HOME/lib&lt;br&gt;
export JAVA_HOME JRE_HOME PATH CLASSPATH&lt;/p&gt;
&lt;p&gt;注释：&lt;/p&gt;
&lt;p&gt;JAVA_HOME 指明 JDK 安装路径，就是刚才安装时所选择的路径，此路径下包括 lib，bin，jre 等文件夹（tomcat，Eclipse 的运行都需要依靠此变量）。&lt;/p&gt;
&lt;p&gt;CLASSPATH 为 java 加载类 (class or lib) 路径，只有类在 classpath 中，java 命令才能识别，设：.:&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;J&lt;/mi&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;V&lt;/mi&gt;&lt;msub&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;H&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;.&lt;/mi&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mo&gt;:&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;JAVA_HOME/lib/dt.jar:&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.09618em;&#34;&gt;J&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;V&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.08125em;&#34;&gt;H&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;:&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;JAVA_HOME/lib/tools.jar:$JRE_HOME/lib。CLASSPATH 变量值中的。表示当前目录&lt;/p&gt;
&lt;p&gt;PATH 使得系统可以在任何路径下识别 java 命令，设为：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;J&lt;/mi&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;V&lt;/mi&gt;&lt;msub&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;H&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;/&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mo&gt;:&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;JAVA_HOME/bin:&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.09618em;&#34;&gt;J&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;V&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.08125em;&#34;&gt;H&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;/&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;:&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;JRE_HOME/bin。&lt;/p&gt;
&lt;p&gt;特别注意：环境变量值的结尾没有任何符号，不同值之间用：隔开（windows 中用；）。&lt;/p&gt;
&lt;p&gt;5、使配置文件生效：source /etc/profile&lt;/p&gt;
&lt;p&gt;6、测试配置是否成功&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20171213135856977&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20171213135856977&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;查找yum默认安装jdk路径&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查找yum默认安装jdk路径&#34;&gt;#&lt;/a&gt; 查找 yum 默认安装 jdk 路径&lt;/h3&gt;
&lt;p&gt;为了图方便。使用 yum -y install jdk-9.0.1&lt;/p&gt;
&lt;p&gt;安装完成之后，发现在 centos7 中。jdk 的路径不在 /usr/lib/jvm 下面了。需要找到对应的路径。在此记录一下。&lt;/p&gt;
&lt;p&gt;1、先找到 java 执行文件路径&lt;/p&gt;
&lt;p&gt;whereis java&lt;br&gt;
 输出：java: /usr/bin/java&lt;br&gt;
2、根据执行文件找到对应的软链接指向的文件路径&lt;br&gt;
 ls -lrt  /usr/bin/java&lt;br&gt;
 输出：  /usr/bin/java -&amp;gt; /etc/alternatives/java&lt;br&gt;
3、进入 /etc/alternatives/ 目录，发现还不是源文件目录。继续找&lt;/p&gt;
&lt;p&gt;ls -lrt /etc/alternatives/java&lt;br&gt;
 输出：/etc/alternatives/java -&amp;gt; /usr/java/jdk-9.0.1/bin/java&lt;br&gt;
 看到 jdk 字样了。应该是源文件目录了。进入到路径&lt;/p&gt;
&lt;p&gt;cd /usr/java/jdk-9.0.1/&lt;br&gt;
 确实是 jdk-9 的路径了。&lt;/p&gt;

 &lt;p&gt;Java 设计模式，眼观六路，耳听八方，观察者很忙，随时监控着关注对象的一举一动。观察者模式解决了基于一对多对象结构关系间的互动问题，使观察者（多方买家）专主动为被动，被观察者（单方商家）转被动为主动，此情此景，需动静结合，先后有序，以【一方动多方静】取代【多方动一方静】的模式，大大的提高了沟通效率。&lt;!--header--&gt;&lt;/p&gt;
&lt;p&gt;先来看个图:&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/image-20200925163924556.png&#34; alt=&#34;image-20200925163924556&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/image-20200925163924556.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;观察者模式的中的三个基本部分：事件源 / 事件 / 时间监听器&lt;/p&gt;
&lt;h3 id=&#34;定义事件接口&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#定义事件接口&#34;&gt;#&lt;/a&gt; 定义事件接口&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;interface&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;EventSource&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;/**&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Description&lt;/span&gt;: 测试事件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Param&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@return&lt;/span&gt;: &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Author&lt;/span&gt;: sunfy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     * &lt;span class=&#34;doctag&#34;&gt;@Date&lt;/span&gt;: 2020/9/25 上午9:15&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;     */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;event&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String arg)&lt;/span&gt;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;事件接口实现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#事件接口实现&#34;&gt;#&lt;/a&gt; 事件接口实现&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;初始化监听器容器&lt;/li&gt;
&lt;li&gt;增加监听器&lt;/li&gt;
&lt;li&gt;移除监听器&lt;/li&gt;
&lt;li&gt;发布事件&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;EventSourceImpl&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 监听器容器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; List&amp;lt;EventSource&amp;gt; eventSources = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ArrayList&amp;lt;&amp;gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 增加监听器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;addListener&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(EventSource event)&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        eventSources.add(event);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 移除监听器&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;removeListener&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(EventSource event)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        eventSources.remove(event);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// 发布事件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;notifyEvent&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String things)&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (EventSource e : eventSources) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            e.event(things);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;事件监听器a&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#事件监听器a&#34;&gt;#&lt;/a&gt; 事件监听器 A&lt;/h3&gt;
&lt;p&gt;事件监听器需要实现接口并重新对应的方法，这样就可以在事件发布时，监听器根据自己的需求去自定义执行&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ListenerA&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;EventSource&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;event&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String arg)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;监听器A事件触发 arg = &amp;quot;&lt;/span&gt; + arg);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;事件监听器b&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#事件监听器b&#34;&gt;#&lt;/a&gt; 事件监听器 B&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ListenerB&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;EventSource&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;event&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String arg)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;事件监听器B触发 arg = &amp;quot;&lt;/span&gt; + arg);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;测试&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#测试&#34;&gt;#&lt;/a&gt; 测试&lt;/h3&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;EventTestMain&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String[] args)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        EventSourceImpl eventSource = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; EventSourceImpl();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ListenerA a = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ListenerA();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ListenerB b = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ListenerB();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        eventSource.addListener(a);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        eventSource.addListener(b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        eventSource.notifyEvent(&lt;span class=&#34;string&#34;&gt;&amp;quot;发布事件A&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        eventSource.removeListener(b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        eventSource.notifyEvent(&lt;span class=&#34;string&#34;&gt;&amp;quot;发布事件B&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;spring中的使用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#spring中的使用&#34;&gt;#&lt;/a&gt; Spring 中的使用&lt;/h3&gt;
&lt;p&gt;持续更新…&lt;/p&gt;

 &lt;p&gt;建造者模式（Builder Pattern）使用多个简单的对象一步一步构建成一个复杂的对象。这种类型的设计模式属于创建型模式，它提供了一种创建对象的最佳方式。&lt;/p&gt;
&lt;p&gt;一个 Builder 类会一步一步构造最终的对象。该 Builder 类是独立于其他对象的。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;介绍&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#介绍&#34;&gt;#&lt;/a&gt; 介绍&lt;/h2&gt;
&lt;p&gt;** 意图：** 将一个复杂的构建与其表示相分离，使得同样的构建过程可以创建不同的表示。&lt;/p&gt;
&lt;p&gt;** 主要解决：** 主要解决在软件系统中，有时候面临着 &amp;quot;一个复杂对象&amp;quot; 的创建工作，其通常由各个部分的子对象用一定的算法构成；由于需求的变化，这个复杂对象的各个部分经常面临着剧烈的变化，但是将它们组合在一起的算法却相对稳定。&lt;/p&gt;
&lt;p&gt;** 何时使用：** 一些基本部件不会变，而其组合经常变化的时候。&lt;/p&gt;
&lt;p&gt;** 如何解决：** 将变与不变分离开。&lt;/p&gt;
&lt;p&gt;** 关键代码：** 建造者：创建和提供实例，导演：管理建造出来的实例的依赖关系。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;应用实例：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;去肯德基，汉堡、可乐、薯条、炸鸡翅等是不变的，而其组合是经常变化的，生成出所谓的 &amp;quot;套餐&amp;quot;。&lt;/li&gt;
&lt;li&gt;JAVA 中的 StringBuilder。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;优点：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;建造者独立，易扩展。&lt;/li&gt;
&lt;li&gt;便于控制细节风险。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;缺点：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;产品必须有共同点，范围有限制。&lt;/li&gt;
&lt;li&gt;如内部变化复杂，会有很多的建造类。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;使用场景：&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;需要生成的对象具有复杂的内部结构。&lt;/li&gt;
&lt;li&gt;需要生成的对象内部属性本身相互依赖。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;** 注意事项：** 与工厂模式的区别是：建造者模式更加关注与零件装配的顺序。&lt;/p&gt;
&lt;h2 id=&#34;实现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#实现&#34;&gt;#&lt;/a&gt; 实现&lt;/h2&gt;
&lt;p&gt;我们假设一个快餐店的商业案例，其中，一个典型的套餐可以是一个汉堡（Burger）和一杯冷饮（Cold drink）。汉堡（Burger）可以是素食汉堡（Veg Burger）或鸡肉汉堡（Chicken Burger），它们是包在纸盒中。冷饮（Cold drink）可以是可口可乐（coke）或百事可乐（pepsi），它们是装在瓶子中。&lt;/p&gt;
&lt;p&gt;我们将创建一个表示食物条目（比如汉堡和冷饮）的 &lt;em&gt;Item&lt;/em&gt; 接口和实现 &lt;em&gt;Item&lt;/em&gt; 接口的实体类，以及一个表示食物包装的 &lt;em&gt;Packing&lt;/em&gt; 接口和实现 &lt;em&gt;Packing&lt;/em&gt; 接口的实体类，汉堡是包在纸盒中，冷饮是装在瓶子中。&lt;/p&gt;
&lt;p&gt;然后我们创建一个 &lt;em&gt;Meal&lt;/em&gt; 类，带有 &lt;em&gt;Item&lt;/em&gt; 的 &lt;em&gt;ArrayList&lt;/em&gt; 和一个通过结合 &lt;em&gt;Item&lt;/em&gt; 来创建不同类型的 &lt;em&gt;Meal&lt;/em&gt; 对象的 &lt;em&gt;MealBuilder&lt;/em&gt;。&lt;em&gt;BuilderPatternDemo&lt;/em&gt; 类使用 &lt;em&gt;MealBuilder&lt;/em&gt; 来创建一个 &lt;em&gt;Meal&lt;/em&gt;。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/20201015-builder-pattern.svg&#34; alt=&#34;建造者模式的 UML 图&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/20201015-builder-pattern.svg&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;步骤-1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤-1&#34;&gt;#&lt;/a&gt; 步骤 1&lt;/h3&gt;
&lt;p&gt;创建一个表示食物条目和食物包装的接口。&lt;/p&gt;
&lt;p&gt;Item.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;interface&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Item&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Packing &lt;span class=&#34;title&#34;&gt;packing&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;price&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;Packing.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;interface&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Packing&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;pack&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;步骤-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤-2&#34;&gt;#&lt;/a&gt; 步骤 2&lt;/h3&gt;
&lt;p&gt;创建实现 Packing 接口的实体类。&lt;/p&gt;
&lt;p&gt;Wrapper.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Wrapper&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Packing&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;pack&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Wrapper&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;Bottle.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Bottle&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Packing&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;pack&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Bottle&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;步骤-3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤-3&#34;&gt;#&lt;/a&gt; 步骤 3&lt;/h3&gt;
&lt;p&gt;创建实现 Item 接口的抽象类，该类提供了默认的功能。&lt;/p&gt;
&lt;p&gt;Burger.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;abstract&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Burger&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Item&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Packing &lt;span class=&#34;title&#34;&gt;packing&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Wrapper();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;abstract&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;price&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;ColdDrink.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;abstract&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ColdDrink&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;implements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Item&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Packing &lt;span class=&#34;title&#34;&gt;packing&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Bottle();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;abstract&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;price&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;步骤-4&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤-4&#34;&gt;#&lt;/a&gt; 步骤 4&lt;/h3&gt;
&lt;p&gt;创建扩展了 Burger 和 ColdDrink 的实体类。&lt;/p&gt;
&lt;p&gt;VegBurger.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;VegBurger&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Burger&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;price&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;25.0f&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Veg Burger&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;ChickenBurger.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ChickenBurger&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Burger&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;price&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;50.5f&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Chicken Burger&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;Coke.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Coke&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ColdDrink&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;price&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;30.0f&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Coke&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;Pepsi.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Pepsi&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;extends&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ColdDrink&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;price&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;35.0f&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;meta&#34;&gt;@Override&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; String &lt;span class=&#34;title&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Pepsi&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;步骤-5&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤-5&#34;&gt;#&lt;/a&gt; 步骤 5&lt;/h3&gt;
&lt;p&gt;创建一个 Meal 类，带有上面定义的 Item 对象。&lt;/p&gt;
&lt;p&gt;Meal.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.util.ArrayList;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; java.util.List;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;Meal&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;keyword&#34;&gt;private&lt;/span&gt; List&amp;lt;Item&amp;gt; items = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ArrayList&amp;lt;Item&amp;gt;();    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;addItem&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(Item item)&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      items.add(item);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;getCost&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;float&lt;/span&gt; cost = &lt;span class=&#34;number&#34;&gt;0.0f&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (Item item : items) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         cost += item.price();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; cost;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;showItems&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; (Item item : items) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         System.out.print(&lt;span class=&#34;string&#34;&gt;&amp;quot;Item : &amp;quot;&lt;/span&gt;+item.name());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         System.out.print(&lt;span class=&#34;string&#34;&gt;&amp;quot;, Packing : &amp;quot;&lt;/span&gt;+item.packing().pack());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;, Price : &amp;quot;&lt;/span&gt;+item.price());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;#125;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;步骤-6&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤-6&#34;&gt;#&lt;/a&gt; 步骤 6&lt;/h3&gt;
&lt;p&gt;创建一个 MealBuilder 类，实际的 builder 类负责创建 Meal 对象。&lt;/p&gt;
&lt;p&gt;MealBuilder.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;MealBuilder&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Meal &lt;span class=&#34;title&#34;&gt;prepareVegMeal&lt;/span&gt; &lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      Meal meal = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Meal();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      meal.addItem(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; VegBurger());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      meal.addItem(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Coke());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; meal;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; Meal &lt;span class=&#34;title&#34;&gt;prepareNonVegMeal&lt;/span&gt; &lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      Meal meal = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Meal();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      meal.addItem(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ChickenBurger());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      meal.addItem(&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; Pepsi());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; meal;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;步骤-7&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤-7&#34;&gt;#&lt;/a&gt; 步骤 7&lt;/h3&gt;
&lt;p&gt;BuiderPatternDemo 使用 MealBuider 来演示建造者模式（Builder Pattern）。&lt;/p&gt;
&lt;p&gt;BuilderPatternDemo.java&lt;/p&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;class&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;BuilderPatternDemo&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(String[] args)&lt;/span&gt; &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      MealBuilder mealBuilder = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; MealBuilder();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      Meal vegMeal = mealBuilder.prepareVegMeal();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;Veg Meal&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      vegMeal.showItems();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;Total Cost: &amp;quot;&lt;/span&gt; +vegMeal.getCost());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      Meal nonVegMeal = mealBuilder.prepareNonVegMeal();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;\n\nNon-Veg Meal&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      nonVegMeal.showItems();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      System.out.println(&lt;span class=&#34;string&#34;&gt;&amp;quot;Total Cost: &amp;quot;&lt;/span&gt; +nonVegMeal.getCost());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;步骤-8&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#步骤-8&#34;&gt;#&lt;/a&gt; 步骤 8&lt;/h3&gt;
&lt;p&gt;执行程序，输出结果：&lt;/p&gt;
&lt;figure class=&#34;highlight tex&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Veg Meal&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Item : Veg Burger, Packing : Wrapper, Price : 25.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Item : Coke, Packing : Bottle, Price : 30.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Total Cost: 55.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Non-Veg Meal&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Item : Chicken Burger, Packing : Wrapper, Price : 50.5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Item : Pepsi, Packing : Bottle, Price : 35.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Total Cost: 85.5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;java 设计模式：设计模式是被大多数人反复使用，在软件开发过程中所面临的一般问题的解决方案。是大多数人员经过较长时间所总结出来的的一套代码设计经验的总结；&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;什么是设计模式（ &lt;code&gt;Desin Pattern&lt;/code&gt; ）&lt;/p&gt;
&lt;p&gt;设计模式是被大多数人反复使用，在软件开发过程中所面临的一般问题的解决方案。是大多数人员经过较长时间所总结出来的的一套代码设计经验的总结；&lt;/p&gt;
&lt;p&gt;为什么使用设计模式？&lt;/p&gt;
&lt;p&gt;使用设计模式可以提高代码的重用性，一定程度保证代码的可靠性，也可以帮助阅读代码的人员快速理解；&lt;/p&gt;
&lt;p&gt;设计模式种类&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;创建型模式（5）：工厂方法模式、抽象工厂模式、单例模式、建造者模式、原型模式。&lt;/li&gt;
&lt;li&gt;结构型模式（7）：适配器模式、装饰器模式、代理模式、外观模式、桥接模式、组合模式、享元模式。&lt;/li&gt;
&lt;li&gt;行为型模式（11）：策略模式、模板方法模式、观察者模式、迭代子模式、责任链模式、命令模式、备忘录模式、状态模式、访问者模式、中介者模式、解释器模式。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;设计模式遵循的原则&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#设计模式遵循的原则&#34;&gt;#&lt;/a&gt; 设计模式遵循的原则&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;开闭原则（Open Close Principle）：对扩展开放，对修改关闭。&lt;/li&gt;
&lt;li&gt;里氏代换原则（Liskov Substitution Principle）：只有当衍生类可以替换掉基类，软件单位的功能不受影响时，基类才能真正被复用，而衍生类也能够在基类的基础上增加新的行为。&lt;/li&gt;
&lt;li&gt;依赖倒转原则（Dependence Inversion Principle）：这个是开闭原则的基础，对接口编程，依赖于抽象而不依赖于具体。&lt;/li&gt;
&lt;li&gt;接口隔离原则（Interface Segregation Principle）：使用多个隔离的接口来降低耦合度。&lt;/li&gt;
&lt;li&gt;迪米特法则（最少知道法则）（Demeter Principle）：一个实体应当尽量少的与其他实体之间发生相互作用，使得系统功能模块相对独立。&lt;/li&gt;
&lt;li&gt;合成复用原则（Composite Reuse Principle）：原则是尽量使用合成 / 聚合的方式，而不是使用继承。继承实际上破坏了类的封装性，超类的方法可能会被子类修改，&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;单例模式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#单例模式&#34;&gt;#&lt;/a&gt; 单例模式&lt;/h2&gt;
&lt;p&gt;单例模式主要适用于在整个系统中，我们只需要一个（有且仅有一个），若存在多个，可能会出现一些不应有的状况，比如资源占用过多、与预期值不同等后果。主要用在配置文件、线程池、缓存、日志对象等；&lt;/p&gt;
&lt;p&gt;分类：&lt;/p&gt;
&lt;h3 id=&#34;饿汉模式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#饿汉模式&#34;&gt;#&lt;/a&gt; 饿汉模式&lt;/h3&gt;
&lt;p&gt;主要特点是，在类文件加载的时候就会创建，不论是否有无方法对其进行调用。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;package com.sunfy.singleton;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * static 静态的成员，是类所有，这样的对象会在类加载时就会创建类的唯一一个实例（饿汉模式）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; *&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Singleton &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#x2F;&amp;#x2F;1.将构造方法私有化，不允许外部直接创建对象&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private Singleton()&amp;#123;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#x2F;&amp;#x2F;2.创建类的唯一实例，使用private(控制访问，安全考虑) static修饰&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private static Singleton instance&amp;#x3D;new Singleton();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#x2F;&amp;#x2F;3.提供一个用于获取实例的方法，使用public static（改为类所有，可以直接点）修饰&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static Singleton getInstance()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return instance;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;懒汉模式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#懒汉模式&#34;&gt;#&lt;/a&gt; 懒汉模式&lt;/h3&gt;
&lt;p&gt;主要特点是：加载类文件时不会进行创建，只有当调用该对象时才会创建，而且只有第一次调用时会创建。&lt;/p&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;package com.sunfy.singleton;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * 懒汉模式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; *&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Singleton2 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#x2F;&amp;#x2F;1.将构造方式私有化，不允许外边直接创建对象&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private Singleton2()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#x2F;&amp;#x2F;2.声明类的唯一实例，使用private static修饰&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#x2F;&amp;#x2F;  只是声明，没有直接进行创建，当第一次获取的时候会创建&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private static Singleton2 instance;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#x2F;&amp;#x2F;3.提供一个用于获取实例的方法，使用public static修饰&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static Singleton2 getInstance()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if(instance&amp;#x3D;&amp;#x3D;null)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            instance&amp;#x3D;new Singleton2();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return instance;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;二者区别&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二者区别&#34;&gt;#&lt;/a&gt; 二者区别&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;饿汉模式的特点是加载类时比较慢，但运行时获取对象的速度比较快，线程安全&lt;/li&gt;
&lt;li&gt;懒汉模式的特点是加载类时比较快，但运行时获取对象的速度比较慢，线程不安全&lt;/li&gt;
&lt;/ul&gt;

 &lt;p&gt;git 基本操作，本博客只是最基本操作说明和相应图解&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/git/50.png&#34; alt=&#34;image-20200908222733250&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;/img/git/50.png&#34; class=&#34;lozad post-image&#34;&gt;&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;Git 下载&lt;/p&gt;
&lt;p&gt;git 下载安装地址：&lt;a href=&#34;https://git-scm.com/downloads&#34;&gt;https://git-scm.com/downloads&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;安装过程基本属于一路 next，这里不做介绍，主要介绍 git 的操作命令&lt;/p&gt;
&lt;p&gt;Git 工作流程&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://img-blog.csdnimg.cn/20190809111904278.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3NmeTEwMjYxMQ==,size_16,color_FFFFFF,t_70&#34; alt=&#34;img&#34; srcset=&#34;data:image/svg+xml,%3Csvg%20xmlns=&#39;http://www.w3.org/2000/svg&#39;%20viewBox=&#39;0%200%20300%20300&#39;%3E%3C/svg%3E&#34; data-src=&#34;https://img-blog.csdnimg.cn/20190809111904278.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3NmeTEwMjYxMQ==,size_16,color_FFFFFF,t_70&#34; class=&#34;lozad post-image&#34;&gt;&lt;/p&gt;
&lt;p&gt;git 基本命令&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 将当前目录初始化为一个git仓库&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git init&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 在当前目录下创建&lt;span class=&#34;built_in&#34;&gt;test&lt;/span&gt;目录，并初始化为一个git仓库&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git init test&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 查看本地仓库中文件状态&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git status&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 将本地文件添加至暂存区&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 当前目录下的所有文件全部添加&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git add -A&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 只将当前选中的文件添加至暂存区&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git add [filename]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 将暂存区文件提交至本地仓库&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git commit -m &amp;quot;提交备注&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 将本地仓库关联至远程仓库&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git remote add orgin https://github.com/xxxxx/xxx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 提交本地仓库至远程仓库&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git push origin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 此时由于本地仓库没有找到上游仓库位置，git会提示设置上游仓库命令&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git push --set-upstream origin master&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;##################################################&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 至此，git仓库就已经提交完成，在远程仓库中可以看到和本地仓库同步的内容&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 当再次修改本地仓库内容后，可以直接使用 &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git add -A;git commit -m &amp;quot;提交备注&amp;quot;;git push;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 用以上命令进行代码提交同步&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt;&lt;span class=&#34;comment&#34;&gt;##################################################&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 上图中右侧位置是已经存在远程仓库，在本地并没有创建仓库而是直接使用以下命令获取远程仓库内容&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; git clone [远程仓库地址]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt; #&lt;/span&gt;&lt;span class=&#34;bash&#34;&gt; 然后就可以通过上述的git基本命令就行git操作&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;git 切换仓库地址&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;git remote remove origin&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git remote add origin git@192.168.1.240:root/poba-angular-pc.git&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;git push -u origin develop&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;Centos 设置静态 IP&lt;/p&gt;
&lt;p&gt;Vmware workstation 中的 centos ip 地址会在没重启的情况下发生变化。 虚拟机的 IP 租约过期后，IP 就会自动重新分配，从而造成 IP 地址自行变化。&lt;/p&gt;
&lt;p&gt;为了应用方便，需要设置 centos 的固定 ip。 版本 centos7&lt;/p&gt;
&lt;p&gt;设置步骤 1.ifconfig 找到当前的 centos 的 ip&lt;/p&gt;
&lt;p&gt;2. 进入文件 vim /etc/sysconfig/network-scripts/ifcfg-ens33&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;TYPE=Ethernet&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;PROXY_METHOD=none&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;BROWSER_ONLY=no&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;BOOTPROTO=static&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DEFROUTE=yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IPV4_FAILURE_FATAL=no&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IPV6INIT=yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IPV6_AUTOCONF=yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IPV6_DEFROUTE=yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IPV6_FAILURE_FATAL=no&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IPV6_ADDR_GEN_MODE=stable-privacy&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;NAME=ens33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;UUID=529b576d-4e86-4dd1-9446-43ab40dbfd27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DEVICE=ens33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ONBOOT=yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IPADDR=192.168.88.88&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;NETMASK=255.255.255.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;GATEWAY=192.168.88.2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DNS1=192.168.88.2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;3. 重启网络服务 使用命令 systemctl restart network.service&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;--关闭网络管理器NetwokManager&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl stop NetworkManager&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl disable NetworkManager&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;service network restart&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;IDEA 使用前的一些基本配置。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://shimo.im/docs/qctkkyThpTgtKpPW/read&#34;&gt;参考链接&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;idea激活&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#idea激活&#34;&gt;#&lt;/a&gt; idea 激活&lt;/h3&gt;
&lt;p&gt;设置仓库地址：&lt;a href=&#34;https://repo.idechajian.com&#34;&gt;https://repo.idechajian.com&lt;/a&gt; ，如下图所示&lt;/p&gt;
&lt;p&gt;点击 OK，便可以在插件中心，搜索关键字 “BetterIntellij”，如下图所示&lt;/p&gt;
&lt;p&gt;百度网盘连接：&lt;a href=&#34;https://pan.baidu.com/s/10XZfOxsb9Enf5tmUFJQlnA%E6%8F%90%E5%8F%96%E7%A0%81:&#34;&gt;https://pan.baidu.com/s/10XZfOxsb9Enf5tmUFJQlnA 提取码:&lt;/a&gt; yetp&lt;/p&gt;
&lt;h3 id=&#34;激活码2099&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#激活码2099&#34;&gt;#&lt;/a&gt; 激活码 ×（2099）&lt;/h3&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;BISACXYELK--H7NUmWcLyUNV1ctnlzc4P79j15qL56G0jeIYWPk&amp;#x2F;HViNdMg1MqPM7BR+aHR28yyuxK7Odb2bFDS8CeHNUtv7nT+4fUs85JJiqc3wc1psRpZq5R77apXLOmvmossWpbAw8T1hOGV9IPUm1f2O1+kLBxrOkdqPpv9+JanbdL7bvchAid2v4&amp;#x2F;dyQMBYJme&amp;#x2F;feZ0Dy2l7Jjpwno1TeblEAu0KZmarEo15or5RUNwtaGBL5+396TLhnw1qL904&amp;#x2F;uPnGftjxWYluLjabO&amp;#x2F;uRu&amp;#x2F;+5td8UA&amp;#x2F;39a1nvGU2nORNLk2IdRGIheiwIiuirAZrII9+OxB+p52i3TIv7ugtkw0E3Jpkw&amp;#x3D;&amp;#x3D;-&amp;#x2F;lp9ylp95GiIIDo4ydYje8vlTWDq02bkyWW&amp;#x2F;G7gZ3hkbBhRUK&amp;#x2F;WnNyr2vwWoOgwx5CfTRMjKkPkfD&amp;#x2F;+jffkfNfdGmGcg9yfnqPP9&amp;#x2F;AizKzWTsXSeS+0jZ8Nw5tiYFW+lpceqlzwzKdTHug7Vs0QomUPccRtZB&amp;#x2F;TBBEuiC7YzrvLg4Amu0I48ETAcch&amp;#x2F;ztt00nx&amp;#x2F;oj&amp;#x2F;fu1DTnz4Iz4ilrNY+WVIEfDz&amp;#x2F;n3mz+PKI9kM+ZeB0jAuyLsiC7skGpIVGX&amp;#x2F;&amp;#x2F;ao&amp;#x2F;x&amp;#x2F;be4DD&amp;#x2F;k&amp;#x2F;byWqW4Rb8OSYCshX&amp;#x2F;fNI4Xu+hxazh179taHX4NaH92ReLVyXNYsooq7mE5YhR9Qsiy35ORviQLrgFrMCGCxT9DWlFBuiPWIOqN544sL9OzFMz+bjqjCoAE&amp;#x2F;xfIJjI7H7SqGFNrx&amp;#x2F;8&amp;#x2F;IuF0hvZbO3bLIz+BOR1L2O+qT728wK6womnp2LLANTPbwu7nf39rpP182WW+xw2z9MKYwwMDwGR1iTYnD4&amp;#x2F;Sjw&amp;#x3D;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;设置启动时不自动打开上次项目&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#设置启动时不自动打开上次项目&#34;&gt;#&lt;/a&gt; 设置启动时不自动打开上次项目&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;打开 File &amp;gt; Setting (快捷键：Ctrl+Alt+S)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;打开 Appearance &amp;amp; Behavior - System Setting&lt;br&gt;
- 去勾选 Reopen last project on startup （启动时重新打开上一个项目）&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;p&gt;-DskipTests，不执行测试用例，但编译测试用例类生成相应的 class 文件至 target/test-classes 下。&lt;/p&gt;
&lt;p&gt;-Dmaven.test.skip=true，不执行测试用例，也不编译测试用例类。&lt;/p&gt;
&lt;p&gt;不执行测试用例，但编译测试用例类生成相应的 class 文件至 target/test-classes 下。&lt;/p&gt;
&lt;p&gt;一 使用 maven.test.skip，不但跳过单元测试的运行，也跳过测试代码的编译。&lt;/p&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mvn package -Dmaven.test.skip=true  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;也可以在 pom.xml 文件中修改&lt;/p&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;plugin&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;org.apache.maven.plugin&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;maven-compiler-plugin&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;2.1&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;configuration&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;skip&lt;/span&gt;&amp;gt;&lt;/span&gt;true&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;skip&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;configuration&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;plugin&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;plugin&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;org.apache.maven.plugins&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;maven-surefire-plugin&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;2.5&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;configuration&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;skip&lt;/span&gt;&amp;gt;&lt;/span&gt;true&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;skip&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;configuration&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;plugin&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;二 使用 mvn package -DskipTests 跳过单元测试，但是会继续编译；如果没时间修改单元测试的 bug，或者单元测试编译错误。使用上面的，不要用这个&lt;/p&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;plugin&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;org.apache.maven.plugins&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;groupId&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;maven-surefire-plugin&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;artifactId&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;2.5&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;version&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;configuration&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;skipTests&lt;/span&gt;&amp;gt;&lt;/span&gt;true&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;skipTests&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;configuration&lt;/span&gt;&amp;gt;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;plugin&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

